INSERT INTO public.questions (id, exam_id, topic_id, question_text, question_type, difficulty, question_version, product_version_id, source_version, verified_against_version, superseded_by_question_id, retired_at, content_hash, duplicate_group_id, canonical_question_id, status, source_import_id, given_answer, ai_verified_answer, confidence_score, confidence_level, needs_human_review, review_reason, last_verified_at, next_verification_due_at, verification_ttl_days, stale_status, source_locator, created_at, updated_at, deleted_at, row_version) VALUES (1458, 1, NULL, 'A company has multiple AWS accounts. A CloudOps engineer uses a sandbox account to create and verify IAM policies for use in a production account. The CloudOps engineer uses AWS CloudFormation to deploy policies to the sandbox account for testing. When tests pass, the CloudOps engineer deploys the policies to production. The CloudOps engineer has configured AWS CloudTrail in both the sandbox account and the production account. The CloudOps engineer wants to detect any changes to the IAM policies after the policies have been deployed by CloudFormation. The CloudOps engineer must receive notifications for any changes to the policies. Which solution will meet these requirements with the LEAST administrative effort?', 'single', 'medium', 1, NULL, NULL, NULL, NULL, NULL, 'de01e371aa963aeccd353ce1377b23bbe9f69c1aeedd76928299c3f20e1cfeeb', NULL, NULL, 'published', 146, 'B', NULL, NULL, 'unknown', false, NULL, '2026-05-08 16:47:15.60409+00', NULL, 90, 'fresh', '{"file_name": "646b6d2013bb103e361af8674630dcb6_2.pdf", "import_id": 146, "row_number": 110, "sheet_name": "qblock_pdf", "import_item_id": 943}', '2026-05-04 15:49:23.153851+00', '2026-05-05 09:02:49.504321+00', NULL, 0);
