INSERT INTO public.questions (id, exam_id, topic_id, question_text, question_type, difficulty, question_version, product_version_id, source_version, verified_against_version, superseded_by_question_id, retired_at, content_hash, duplicate_group_id, canonical_question_id, status, source_import_id, given_answer, ai_verified_answer, confidence_score, confidence_level, needs_human_review, review_reason, last_verified_at, next_verification_due_at, verification_ttl_days, stale_status, source_locator, created_at, updated_at, deleted_at, row_version) VALUES (1511, 1, NULL, 'A media company hosts a public news and video portal on AWS. The portal uses an Amazon DynamoDB table with provisioned capacity to maintain an index of video files that are stored in an Amazon S3 bucket. During a recent event, millions of visitors came to the portal for news. This increase in traffic caused read requests to be throttled in the DynamoDB table. Videos could not be displayed in the portal. The company''s operations team manually increased the provisioned capacity on a temporary basis to meet the demand. The company wants the operations team to receive an alert before the table is throttled in the future. The company has created an Amazon Simple Notification Service (Amazon SNS) topic and has subscribed the operations team''s email address to the SNS topic. What should the company do next to meet these requirements?', 'single', 'medium', 1, NULL, NULL, NULL, NULL, NULL, '40e8888f4f82e5e47d45c67bc5e3ade27388873b1d981f2b0a9e099a2941bfa1', NULL, NULL, 'published', 146, 'A', NULL, NULL, 'unknown', false, NULL, '2026-05-08 16:47:15.60409+00', NULL, 90, 'fresh', '{"file_name": "646b6d2013bb103e361af8674630dcb6_2.pdf", "import_id": 146, "row_number": 164, "sheet_name": "qblock_pdf", "import_item_id": 997}', '2026-05-04 15:49:23.153851+00', '2026-05-05 09:02:49.504321+00', NULL, 0);
INSERT INTO public.questions (id, exam_id, topic_id, question_text, question_type, difficulty, question_version, product_version_id, source_version, verified_against_version, superseded_by_question_id, retired_at, content_hash, duplicate_group_id, canonical_question_id, status, source_import_id, given_answer, ai_verified_answer, confidence_score, confidence_level, needs_human_review, review_reason, last_verified_at, next_verification_due_at, verification_ttl_days, stale_status, source_locator, created_at, updated_at, deleted_at, row_version) VALUES (1512, 1, NULL, 'A company runs a retail website on multiple Amazon EC2 instances behind an Application Load Balancer (ALB). The company must secure traffic to the website over an HTTPS connection. Which combination of actions should a SysOps administrator take to meet these requirements? Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com (Choose two.)', 'multiple', 'medium', 1, NULL, NULL, NULL, NULL, NULL, 'ff930387ad06e18945d28d863f72aaced91846f998d68f0e3a3a1a0c55169e29', NULL, NULL, 'published', 146, 'B,D', NULL, NULL, 'unknown', false, NULL, '2026-05-08 16:47:15.60409+00', NULL, 90, 'fresh', '{"file_name": "646b6d2013bb103e361af8674630dcb6_2.pdf", "import_id": 146, "row_number": 165, "sheet_name": "qblock_pdf", "import_item_id": 998}', '2026-05-04 15:49:23.153851+00', '2026-05-05 09:02:49.504321+00', NULL, 0);
INSERT INTO public.questions (id, exam_id, topic_id, question_text, question_type, difficulty, question_version, product_version_id, source_version, verified_against_version, superseded_by_question_id, retired_at, content_hash, duplicate_group_id, canonical_question_id, status, source_import_id, given_answer, ai_verified_answer, confidence_score, confidence_level, needs_human_review, review_reason, last_verified_at, next_verification_due_at, verification_ttl_days, stale_status, source_locator, created_at, updated_at, deleted_at, row_version) VALUES (1513, 1, NULL, 'A company is running an ecommerce application on AWS. The application maintains many open but idle connections to an Amazon Aurora DB cluster. During times of peak usage, the database produces the following error message: "Too many connections." The database clients are also experiencing errors. Which solution will resolve these errors?', 'single', 'medium', 1, NULL, NULL, NULL, NULL, NULL, '7cca6d9f8c7687a1ce04b4f970fa23f4d0ab0f17cdea6ec20ede3c1d8b47e74e', NULL, NULL, 'published', 146, 'B', NULL, NULL, 'unknown', false, NULL, '2026-05-08 16:47:15.60409+00', NULL, 90, 'fresh', '{"file_name": "646b6d2013bb103e361af8674630dcb6_2.pdf", "import_id": 146, "row_number": 166, "sheet_name": "qblock_pdf", "import_item_id": 999}', '2026-05-04 15:49:23.153851+00', '2026-05-05 09:02:49.504321+00', NULL, 0);
INSERT INTO public.questions (id, exam_id, topic_id, question_text, question_type, difficulty, question_version, product_version_id, source_version, verified_against_version, superseded_by_question_id, retired_at, content_hash, duplicate_group_id, canonical_question_id, status, source_import_id, given_answer, ai_verified_answer, confidence_score, confidence_level, needs_human_review, review_reason, last_verified_at, next_verification_due_at, verification_ttl_days, stale_status, source_locator, created_at, updated_at, deleted_at, row_version) VALUES (1514, 1, NULL, 'A SysOps administrator creates a custom Amazon Machine Image (AMI) in the eu-west-2 Region and uses the AMI to launch Amazon EC2 instances. The SysOps administrator needs to use the Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com same AMI to launch EC2 instances in two other Regions: us-east-1 and us-east-2. What must the SysOps administrator do to use the custom AMI in the additional Regions?', 'single', 'medium', 1, NULL, NULL, NULL, NULL, NULL, '772a5f393c09627e7fa3e4fc19af447fa366aa9dbea78ef86d54e6ce557d1e70', NULL, NULL, 'published', 146, 'A', NULL, NULL, 'unknown', false, NULL, '2026-05-08 16:47:15.60409+00', NULL, 90, 'fresh', '{"file_name": "646b6d2013bb103e361af8674630dcb6_2.pdf", "import_id": 146, "row_number": 167, "sheet_name": "qblock_pdf", "import_item_id": 1000}', '2026-05-04 15:49:23.153851+00', '2026-05-05 09:02:49.504321+00', NULL, 0);
