INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (686, 143, 7, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "The network 192.168.1.0/24 is subnetted by borrowing 1 bit. Which one of the following is the one of subnets that we have from the above subnetting?", "question_type": "one_choice", "correct_answer": "1", "combined_options": "192.168.1.0/25;192.168.1.224/27;192.168.1.32/26;192.168.1.96/30;192.168.1.192/25"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "192.168.1.0/25"], ["B", "192.168.1.224/27"], ["C", "192.168.1.32/26"], ["D", "192.168.1.96/30"], ["E", "192.168.1.192/25"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "The network 192.168.1.0/24 is subnetted by borrowing 1 bit. Which one of the following is the one of subnets that we have from the above subnetting?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '1987ef99c58a15a99ec570486bdd521415d9994be384f50532dad13abdd80fd9', 1260, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (689, 143, 10, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which of the following is the true statement about static routing?", "question_type": "one_choice", "correct_answer": "2", "combined_options": "This kind of routing is not used on routers nowadays;The administrator has to manually declare destination network addresses into the routing table and the appropriate directions to these destinations;Routers interact with each other by a fixed protocol, exchange information by messages with static structure;None of above is true"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "This kind of routing is not used on routers nowadays"], ["B", "The administrator has to manually declare destination network addresses into the routing table and the appropriate directions to these destinations"], ["C", "Routers interact with each other by a fixed protocol, exchange information by messages with static structure"], ["D", "None of above is true"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which of the following is the true statement about static routing?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'a5fb743041cbcc32428f624c428b156c6a07b5bf9a1a6c5238bc0e42b7a210e7', 1262, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (690, 143, 11, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which of the following is true about configuring a static route on a Cisco router?", "question_type": "one_choice", "correct_answer": "1", "combined_options": "ip route 10.1.3.0 255.255.255.0 10.1.130.253;ip route 10.1.3.0 ethernet 0/0;ip route 10.1.3.0 /24 10.1.130.253;ip route 10.1.3.0 /24 ethernet 0/0"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "ip route 10.1.3.0 255.255.255.0 10.1.130.253"], ["B", "ip route 10.1.3.0 ethernet 0/0"], ["C", "ip route 10.1.3.0 /24 10.1.130.253"], ["D", "ip route 10.1.3.0 /24 ethernet 0/0"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which of the following is true about configuring a static route on a Cisco router?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '00e57d140bc6b5fd2859f51e87b77b76914d45fbb774abe18ce372c6428e53de', 1263, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (691, 143, 12, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which of the following are true about the shortcoming of static routing? (Choose two answers)", "question_type": "multi_choice", "correct_answer": "3;4", "combined_options": "Static routing technique is too sophisticated for understanding and configuring;Static routing is a proprietary technique and could only config on Cisco router;Static routing is not adaptive to almost changes on network topology;Static routing is not appropriate for large network topologies"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "Static routing technique is too sophisticated for understanding and configuring"], ["B", "Static routing is a proprietary technique and could only config on Cisco router"], ["C", "Static routing is not adaptive to almost changes on network topology"], ["D", "Static routing is not appropriate for large network topologies"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which of the following are true about the shortcoming of static routing? (Choose two answers)", "question_type": "multiple", "correct_answer": ["C", "D"]}', 'imported', NULL, NULL, '8b0432107fbf94dfc95b194f60848f66a042f9b3b5a1ab51bbd2ef13d6d08033', 1264, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
