INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (708, 143, 29, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "What are the most considerable shortcoming of STP? (Choose two answers)", "question_type": "multi_choice", "correct_answer": "1;5", "combined_options": "Only supports redundancy, does not support load – balancing;The algorithym is not stable, sometimes malfunctioning;Can not run on switches which trunking together;Can run only on Cisco switches;Very slow convergence"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "Only supports redundancy, does not support load – balancing"], ["B", "The algorithym is not stable, sometimes malfunctioning"], ["C", "Can not run on switches which trunking together"], ["D", "Can run only on Cisco switches"], ["E", "Very slow convergence"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "What are the most considerable shortcoming of STP? (Choose two answers)", "question_type": "multiple", "correct_answer": ["A", "E"]}', 'imported', NULL, NULL, 'e3349766e723021d874376d818da4d2af74381f035274caa1bc43069bd72af0a', 1281, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
