INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (710, 143, 31, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which statement below is not true about Etherchannel?", "question_type": "one_choice", "correct_answer": "3", "combined_options": "The component physical interfaces of an Etherchannel must be consistent about many parameters;Etherchannel is a good HA solution;Etherchannel technique allows to bundle Giga Ethernet interfaces with Fast Ethernet interfaces, but does not allow to bundle Fast Ethernet interfaces with Ethernet interfaces;The load sharing among physical interfaces of an Etherchannel link could be perform based on parameters such as Source MAC, Destination MAC, Source IP, Destination IP, Source Port, Destination Port."}', '{"tags": "ccna_online", "topic": null, "options": [["A", "The component physical interfaces of an Etherchannel must be consistent about many parameters"], ["B", "Etherchannel is a good HA solution"], ["C", "Etherchannel technique allows to bundle Giga Ethernet interfaces with Fast Ethernet interfaces, but does not allow to bundle Fast Ethernet interfaces with Ethernet interfaces"], ["D", "The load sharing among physical interfaces of an Etherchannel link could be perform based on parameters such as Source MAC, Destination MAC, Source IP, Destination IP, Source Port, Destination Port."]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which statement below is not true about Etherchannel?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'bdf47a164580dbff220be616b58679b342e5ef413881fa968568a4b7f65861c5', 1283, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (711, 143, 32, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which of the following are the methods for interVLAN routing? (Choose two answers)", "question_type": "multi_choice", "correct_answer": "2;4", "combined_options": "Static routing;Router on a Stick;Spanning Tree Protocol;Layer 3 switch with SVIs;OSPF"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "Static routing"], ["B", "Router on a Stick"], ["C", "Spanning Tree Protocol"], ["D", "Layer 3 switch with SVIs"], ["E", "OSPF"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which of the following are the methods for interVLAN routing? (Choose two answers)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'imported', NULL, NULL, 'b06c56f897d591ecdc9be800469cd7e271249f3877bc63444b75b1d8df3943e4', 1284, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (712, 143, 33, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which of the following access – list commands matches all packets sent from hosts in subnet 172.16.4.0/23?", "question_type": "one_choice", "correct_answer": "2", "combined_options": "access-list 1 permit 172.16.0.5 0.0.255.0;access-list 1 permit 172.16.4.0 0.0.1.255;access-list 1 permit 172.16.5.0;access-list 1 permit 172.16.5.0 0.0.0.127"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "access-list 1 permit 172.16.0.5 0.0.255.0"], ["B", "access-list 1 permit 172.16.4.0 0.0.1.255"], ["C", "access-list 1 permit 172.16.5.0"], ["D", "access-list 1 permit 172.16.5.0 0.0.0.127"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which of the following access – list commands matches all packets sent from hosts in subnet 172.16.4.0/23?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '5da8d49e07817167b34f497bbdb1298bdbadbcbed5711d7952e3fafeb853d02b', 1285, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (713, 143, 34, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which of the following access – list commands permits packet from subnet 10.1.1.0/27 going to web – server whose IP address is 10.255.1.2?", "question_type": "one_choice", "correct_answer": "3", "combined_options": "access-list 100 permit tcp 10.1.1.0 255.255.255.225 host 10.255.1.2 eq 80;access-list 100 permit udp 10.1.1.0 0.0.0.31 host 10.255.1.2 eq 80;access-list 100 permit tcp 10.1.1.0 0.0.0.31 host 10.255.1.2 eq 80;access-list 100 permit tcp 10.1.1.0 0.0.0.31 host 10.255.1.2 eq 53"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "access-list 100 permit tcp 10.1.1.0 255.255.255.225 host 10.255.1.2 eq 80"], ["B", "access-list 100 permit udp 10.1.1.0 0.0.0.31 host 10.255.1.2 eq 80"], ["C", "access-list 100 permit tcp 10.1.1.0 0.0.0.31 host 10.255.1.2 eq 80"], ["D", "access-list 100 permit tcp 10.1.1.0 0.0.0.31 host 10.255.1.2 eq 53"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which of the following access – list commands permits packet from subnet 10.1.1.0/27 going to web – server whose IP address is 10.255.1.2?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '58dd1ce88c61acde04dab05fbf7860f03b733081379d04e8514ed05b689443b5', 1286, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (714, 143, 35, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "The administrator wants to public a server in the server farm into the Internet with the Public IP provisioned by the ISP, but the users in the intranet have to access to that server by its Private IP. Which NAT technique will be used for the requirement above?", "question_type": "one_choice", "correct_answer": "1", "combined_options": "One – to – one static NAT;One – to – one dynamic NAT;Many – to – one: NAT overload with IP address of outside interface;Many – to – one: NAT overload with pool"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "One – to – one static NAT"], ["B", "One – to – one dynamic NAT"], ["C", "Many – to – one: NAT overload with IP address of outside interface"], ["D", "Many – to – one: NAT overload with pool"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "The administrator wants to public a server in the server farm into the Internet with the Public IP provisioned by the ISP, but the users in the intranet have to access to that server by its Private IP. Which NAT technique will be used for the requirement above?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'd9129f0008920c72a9e3ade834e989f084dcc4a9bcc159c0a15ede1cb60cb731', 1287, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (715, 143, 36, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which NAT technique below is appropriate for the Internet access of normal users?", "question_type": "one_choice", "correct_answer": "3", "combined_options": "One – to – one static NAT;One – to – one dynamic NAT;Many – to – one: NAT overload with IP address of outside interface;None of above is true"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "One – to – one static NAT"], ["B", "One – to – one dynamic NAT"], ["C", "Many – to – one: NAT overload with IP address of outside interface"], ["D", "None of above is true"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which NAT technique below is appropriate for the Internet access of normal users?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '78a754455c32609f0405945dc1d03a2f42ce77750940cdd3146e8564c90ce723', 1288, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (716, 143, 37, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which of the following are the steps to config NAT on a Cisco router? (Choose two answers)", "question_type": "multi_choice", "correct_answer": "4;5", "combined_options": "Config OSPF routing process;Config DHCP server;Config default route;Config one of NAT technique with command begin with “ip nat inside source…”;Config inside interfaces and outside interface"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "Config OSPF routing process"], ["B", "Config DHCP server"], ["C", "Config default route"], ["D", "Config one of NAT technique with command begin with “ip nat inside source...”"], ["E", "Config inside interfaces and outside interface"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which of the following are the steps to config NAT on a Cisco router? (Choose two answers)", "question_type": "multiple", "correct_answer": ["D", "E"]}', 'imported', NULL, NULL, 'a2d18dac5f03baa8d4c119cb1634ad0419e0362b625a67c4476c016acd177eab', 1289, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (717, 143, 38, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "Which of the following is the WAN connection that operates as a Layer 3 VPN?", "question_type": "one_choice", "correct_answer": "4", "combined_options": "Metro Ethernet;PPP;PPPoE;MPLS VPN"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "Metro Ethernet"], ["B", "PPP"], ["C", "PPPoE"], ["D", "MPLS VPN"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which of the following is the WAN connection that operates as a Layer 3 VPN?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '7715b746e2bcd29bdce1c0cc59773e544813c135e67cc55f2b439c6d8bd20258', 1290, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (718, 143, 39, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "What is the correct order of operations for the DHCP for IPv4 process?", "question_type": "one_choice", "correct_answer": "4", "combined_options": "Offer, Request, ACK, Discover;Discover, Request, ACK, Offer;Request, Offer, Discover, ACK;Discover, Offer, Request, ACK"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "Offer, Request, ACK, Discover"], ["B", "Discover, Request, ACK, Offer"], ["C", "Request, Offer, Discover, ACK"], ["D", "Discover, Offer, Request, ACK"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "What is the correct order of operations for the DHCP for IPv4 process?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '2d07ebc424264afe3e8d73ae65b95f207d36e20dab9246fe3472bc474dd9a738', 1291, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (787, 145, 11, 'examtopics_html', '{"vote_a": 11, "vote_b": 10, "vote_c": 1, "option_a": "The BGP session with peer 10.127.0.75 is established.", "option_b": "External BGP (EBGP) exchanges routing information.", "option_c": "The router 100.64.3.1 has the parameter bfd set to enable.", "option_d": "The neighbors displayed are linked to a local router with the neighbor-range set to a value of 4.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which shows the output of a BGP summary. What two conclusions can you draw from this BGP summary? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AB", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134377-exam-nse7_efw-72-topic-1-question-10-discussion/", "discussion_count": 22, "external_question_id": "912162"}', '{"tags": null, "topic": null, "options": [["A", "The BGP session with peer 10.127.0.75 is established."], ["B", "External BGP (EBGP) exchanges routing information."], ["C", "The router 100.64.3.1 has the parameter bfd set to enable."], ["D", "The neighbors displayed are linked to a local router with the neighbor-range set to a value of 4."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134377-exam-nse7_efw-72-topic-1-question-10-discussion/", "discussion_count": 22, "vote_distribution": {"A": 11, "B": 10, "C": 1}, "external_question_id": "912162"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows the output of a BGP summary. What two conclusions can you draw from this BGP summary? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "B"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '3992dd976e40a801ad28f88ece85a8b1b42f69ec8996a36beb995d6e072e7239', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (719, 143, 40, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "When the DHCP server is located at a different subnet with the client subnet, what have to do so the client can get its IP configuration from the DHCP server?", "question_type": "one_choice", "correct_answer": "3", "combined_options": "Config DHCP client on the gateway router;Config a secondary DHCP server on the gateway router;Config DHCP Relay Agent on the gateway router;We have not to do any thing"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "Config DHCP client on the gateway router"], ["B", "Config a secondary DHCP server on the gateway router"], ["C", "Config DHCP Relay Agent on the gateway router"], ["D", "We have not to do any thing"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "When the DHCP server is located at a different subnet with the client subnet, what have to do so the client can get its IP configuration from the DHCP server?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'ad444a0221794099e593b822fd30923ba858f806bbae785ca6bfd4f9bf1a1340', 1292, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (720, 143, 41, 'Trang tính1', '{"tags": "ccna_online", "reference": null, "explanation": null, "question_text": "What are the steps we need to config on the edge router to allow users in the intranet can access the Internet? (Choose tws answers)", "question_type": "multi_choice", "correct_answer": "1;3", "combined_options": "Config a default – route on the edge router and config the routing protocol to propagate that default route to other routers in the intranet;Reset the router;Config NAT on the edge router;Config DHCP server on the edge router;Config interVLAN routing on the edge router"}', '{"tags": "ccna_online", "topic": null, "options": [["A", "Config a default – route on the edge router and config the routing protocol to propagate that default route to other routers in the intranet"], ["B", "Reset the router"], ["C", "Config NAT on the edge router"], ["D", "Config DHCP server on the edge router"], ["E", "Config interVLAN routing on the edge router"]], "reference": null, "difficulty": "medium", "explanation": null, "question_text": "What are the steps we need to config on the edge router to allow users in the intranet can access the Internet? (Choose tws answers)", "question_type": "multiple", "correct_answer": ["A", "C"]}', 'imported', NULL, NULL, 'e43919da83dea26f5776ccbc78ca4ad11cb261a7cb67ecfc56004911d9ed7516', 1293, '2026-05-04 15:49:15.088949+00', '2026-05-04 15:49:15.171206+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (973, 146, 140, 'qblock_pdf', '{"option_a": "Create an Amazon EventBridge custom event bus. Create an archive on the custom event bus. Create a rule to send the custom events to the Lambda function.", "option_b": "Create an archive on the Amazon EventBridge default event bus. Use pattern matching to record the custom events. Create a rule to send the custom events to the Lambda function.", "option_c": "Create an archive on the Amazon EventBridge default event bus. Create an EventBridge pipe to ingest the custom events and to save the custom events in the archive. Create a rule to send the custom events to the Lambda function.", "option_d": "Create a log group in Amazon CloudWatch Logs. Create an Amazon EventBridge rule to send the custom events to the Lambda function and to the log group.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "A custom EventBridge event bus is the correct choice for handling application-specific events.\nYou can define an archive on that custom event bus to record and later replay events by event\ntype or timestamp. Creating an EventBridge rule to send events to a Lambda function ensures\nreal-time processing while maintaining full replay capability, making this the most flexible and\noperationally efficient solution.", "question_text": "A CloudOps engineer needs to build an event infrastructure for a set of custom application- specific events. The events must be sent to an AWS Lambda function for processing. The CloudOps engineer must record the events to replay later by event type or event time. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0139"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon EventBridge custom event bus. Create an archive on the custom event bus. Create a rule to send the custom events to the Lambda function."], ["B", "Create an archive on the Amazon EventBridge default event bus. Use pattern matching to record the custom events. Create a rule to send the custom events to the Lambda function."], ["C", "Create an archive on the Amazon EventBridge default event bus. Create an EventBridge pipe to ingest the custom events and to save the custom events in the archive. Create a rule to send the custom events to the Lambda function."], ["D", "Create a log group in Amazon CloudWatch Logs. Create an Amazon EventBridge rule to send the custom events to the Lambda function and to the log group."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0139"}, "reference": null, "difficulty": "medium", "explanation": "A custom EventBridge event bus is the correct choice for handling application-specific events.\nYou can define an archive on that custom event bus to record and later replay events by event\ntype or timestamp. Creating an EventBridge rule to send events to a Lambda function ensures\nreal-time processing while maintaining full replay capability, making this the most flexible and\noperationally efficient solution.", "question_text": "A CloudOps engineer needs to build an event infrastructure for a set of custom application- specific events. The events must be sent to an AWS Lambda function for processing. The CloudOps engineer must record the events to replay later by event type or event time. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'e490aef5d8609b1d122cd3638127c0db5aa7d3ecaddb8c56f1878653a80e9130', 1487, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (901, 146, 68, 'qblock_pdf', '{"option_a": "Activate all of the AWS generated cost allocation tags for the account.", "option_b": "Apply user-defined tags to the instances through Tag Editor. Activate these tags for cost allocation.", "option_c": "Schedule an AWS Lambda function to run the AWS Pricing Calculator for EC2 usage on a recurring schedule.", "option_d": "Use the AWS Trusted Advisor dashboard to export EC2 cost reports.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Cost allocation tags enable you to categorize and track costs by department or any other\norganizational dimension. AWS supports two tag types: AWS-generated tags and user-defined\ntags. To map costs to departments, user-defined cost allocation tags must be created and\nactivated for cost reporting, and then associated with the EC2 instances. This allows Cost\nExplorer and related billing reports to group and filter costs by the department identifiers defined\nby the organization.", "question_text": "A company runs a large number of Amazon EC2 instances for internal departments. The company needs to track the costs of its existing AWS resources by department. What should a SysOps administrator do to meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0067"}', '{"tags": null, "topic": null, "options": [["A", "Activate all of the AWS generated cost allocation tags for the account."], ["B", "Apply user-defined tags to the instances through Tag Editor. Activate these tags for cost allocation."], ["C", "Schedule an AWS Lambda function to run the AWS Pricing Calculator for EC2 usage on a recurring schedule."], ["D", "Use the AWS Trusted Advisor dashboard to export EC2 cost reports."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0067"}, "reference": null, "difficulty": "medium", "explanation": "Cost allocation tags enable you to categorize and track costs by department or any other\norganizational dimension. AWS supports two tag types: AWS-generated tags and user-defined\ntags. To map costs to departments, user-defined cost allocation tags must be created and\nactivated for cost reporting, and then associated with the EC2 instances. This allows Cost\nExplorer and related billing reports to group and filter costs by the department identifiers defined\nby the organization.", "question_text": "A company runs a large number of Amazon EC2 instances for internal departments. The company needs to track the costs of its existing AWS resources by department. What should a SysOps administrator do to meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '4623075f2ae55d46ce3c5490d9d8029b9f00dda9d84d930634defc36e3e7bb88', 1417, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (912, 146, 79, 'qblock_pdf', '{"option_a": "Create an additional CloudWatch agent configuration filo to capture the DHCP logs. Use the AWS Systems Manager Run Command to restart the CloudWatch agent on each EC2 instance with the append-config option to apply the additional configuration file.", "option_b": "Log in to each EC2 instance with administrator rights. Create a PowerShell script to push the needed baseline log files and DHCP log files to CloudWatch.", "option_c": "Run the CloudWatch agent configuration file wizard on each EC2 instance. Verify that the baseline log files are included and add the DHCP log files during the wizard creation process.", "option_d": "Run the CloudWatch agent configuration file wizard on each EC2 instance and select the advanced detail level. This will capture the operating system log files.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The most operationally efficient approach is to avoid manual reconfiguration or login to each\ninstance. By using AWS Systems Manager Run Command with the append-config option, you\ncan centrally deploy and apply an additional CloudWatch agent configuration file to selected\ninstances. This method scales easily, ensures consistency, and requires no manual intervention\non each EC2 instance.", "question_text": "An environment consists of 100 Amazon EC2 Windows instances. The Amazon CloudWatch agent is deployed and running on all EC2 instances with a baseline configuration file to capture log files. There is a new requirement to capture the DHCP log files that exist on 50 of the instances. What is the MOST operationally efficient way to meet this new requirement?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0078"}', '{"tags": null, "topic": null, "options": [["A", "Create an additional CloudWatch agent configuration filo to capture the DHCP logs. Use the AWS Systems Manager Run Command to restart the CloudWatch agent on each EC2 instance with the append-config option to apply the additional configuration file."], ["B", "Log in to each EC2 instance with administrator rights. Create a PowerShell script to push the needed baseline log files and DHCP log files to CloudWatch."], ["C", "Run the CloudWatch agent configuration file wizard on each EC2 instance. Verify that the baseline log files are included and add the DHCP log files during the wizard creation process."], ["D", "Run the CloudWatch agent configuration file wizard on each EC2 instance and select the advanced detail level. This will capture the operating system log files."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0078"}, "reference": null, "difficulty": "medium", "explanation": "The most operationally efficient approach is to avoid manual reconfiguration or login to each\ninstance. By using AWS Systems Manager Run Command with the append-config option, you\ncan centrally deploy and apply an additional CloudWatch agent configuration file to selected\ninstances. This method scales easily, ensures consistency, and requires no manual intervention\non each EC2 instance.", "question_text": "An environment consists of 100 Amazon EC2 Windows instances. The Amazon CloudWatch agent is deployed and running on all EC2 instances with a baseline configuration file to capture log files. There is a new requirement to capture the DHCP log files that exist on 50 of the instances. What is the MOST operationally efficient way to meet this new requirement?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '7d26f9acea75550e8cf5e1ae3afa0a5c25fa0bcea1df07cb08ac6f3a1c7a2487', 1428, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (848, 146, 15, 'qblock_pdf', '{"option_a": "Migrate the EC2 instance to a compute optimized instance by using AWS VM Import/Export.", "option_b": "Enable hibernation on the EC2 instance. Change the instance type to a compute optimized instance. Disable hibernation on the EC2 instance.", "option_c": "Stop the EC2 instance. Change the instance type to a compute optimized instance. Start the EC2 instance.", "option_d": "Change the instance type to a compute optimized instance while the EC2 instance is running.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "As described in the AWS Cloud Operations and EC2 Management documentation, changing an\ninstance type (e.g., from T3 to C5) requires that the instance be stopped first. Once stopped, the\nengineer can modify the instance type through the AWS Management Console, CLI, or API, then\nstart the instance again to apply changes.\nThis process preserves the root volume, networking configuration, and data, making it an\noperationally safe and efficient way to upgrade to a different instance family.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nChanging the instance type while running (Option D) is unsupported. VM Import/Export (Option A)\nis for external VM migration. Hibernation (Option B) does not apply to type changes.\nThus, Option C is correct -- stopping the instance, changing its type, and restarting it meets AWS\nbest practices.", "question_text": "A company''s Amazon EC2 instance with high CPU utilization is a t3.large instance running a test web app. The company determines the app would run better on a compute-optimized large instance. What should the CloudOps engineer do?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0014"}', '{"tags": null, "topic": null, "options": [["A", "Migrate the EC2 instance to a compute optimized instance by using AWS VM Import/Export."], ["B", "Enable hibernation on the EC2 instance. Change the instance type to a compute optimized instance. Disable hibernation on the EC2 instance."], ["C", "Stop the EC2 instance. Change the instance type to a compute optimized instance. Start the EC2 instance."], ["D", "Change the instance type to a compute optimized instance while the EC2 instance is running."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0014"}, "reference": null, "difficulty": "medium", "explanation": "As described in the AWS Cloud Operations and EC2 Management documentation, changing an\ninstance type (e.g., from T3 to C5) requires that the instance be stopped first. Once stopped, the\nengineer can modify the instance type through the AWS Management Console, CLI, or API, then\nstart the instance again to apply changes.\nThis process preserves the root volume, networking configuration, and data, making it an\noperationally safe and efficient way to upgrade to a different instance family.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nChanging the instance type while running (Option D) is unsupported. VM Import/Export (Option A)\nis for external VM migration. Hibernation (Option B) does not apply to type changes.\nThus, Option C is correct -- stopping the instance, changing its type, and restarting it meets AWS\nbest practices.", "question_text": "A company''s Amazon EC2 instance with high CPU utilization is a t3.large instance running a test web app. The company determines the app would run better on a compute-optimized large instance. What should the CloudOps engineer do?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '88d9d85b477029b6104ff5e913533a39887ec8a8642987611ebe03cb6c99126b', 1364, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (767, 144, 48, 'examtopics_html', '{"vote_c": 5, "vote_d": 5, "option_a": "CLI scripts must start with #!.", "option_b": "Static routes can be added using only TCL scripts.", "option_c": "Incomplete commands can cause CLI scripts to fail.", "option_d": "The commands that start with the # sign did not run.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which contains a CLI script configuration on FortiManager. An administrator configured the CLI script on FortiManager, but the script failed to apply any changes to the managed device after being executed. What are two reasons why the script did not make any changes to the managed device? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "CD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141530-exam-nse7_efw-72-topic-1-question-47-discussion/", "discussion_count": 10, "external_question_id": "921127"}', '{"tags": null, "topic": null, "options": [["A", "CLI scripts must start with #!."], ["B", "Static routes can be added using only TCL scripts."], ["C", "Incomplete commands can cause CLI scripts to fail."], ["D", "The commands that start with the # sign did not run."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141530-exam-nse7_efw-72-topic-1-question-47-discussion/", "discussion_count": 10, "vote_distribution": {"C": 5, "D": 5}, "external_question_id": "921127"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a CLI script configuration on FortiManager. An administrator configured the CLI script on FortiManager, but the script failed to apply any changes to the managed device after being executed. What are two reasons why the script did not make any changes to the managed device? (Choose two.)", "question_type": "multiple", "correct_answer": ["C", "D"]}', 'imported', NULL, NULL, '3e8754dc18e3bcb9989edc4a5b10b07ccc8329b0bd703a6ef786f7226774ff27', 1340, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (721, 144, 2, 'examtopics_html', '{"vote_a": 11, "option_a": "The TCL procedure run_cmd has not been created.", "option_b": "The TCL script must start with #include.", "option_c": "There is no corresponding #! to signify the end of the script.", "option_d": "The TCL procedure lacks the required loop statements to iterate through the changes.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which contains a TCL script configuration on FortiManager. An administrator has configured the TCL script on FortiManager, but the TCL script failed to apply any changes to the managed device after being run. Why did the TCL script fail to make any changes to the managed device?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134367-exam-nse7_efw-72-topic-1-question-1-discussion/", "discussion_count": 11, "external_question_id": "912153"}', '{"tags": null, "topic": null, "options": [["A", "The TCL procedure run_cmd has not been created."], ["B", "The TCL script must start with #include."], ["C", "There is no corresponding #! to signify the end of the script."], ["D", "The TCL procedure lacks the required loop statements to iterate through the changes."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134367-exam-nse7_efw-72-topic-1-question-1-discussion/", "discussion_count": 11, "vote_distribution": {"A": 11}, "external_question_id": "912153"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a TCL script configuration on FortiManager. An administrator has configured the TCL script on FortiManager, but the TCL script failed to apply any changes to the managed device after being run. Why did the TCL script fail to make any changes to the managed device?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '2fcc235b3cbc721397ef456ed5116635393243857904e32a4ccef71e6ef32f7c', 1294, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (722, 144, 3, 'examtopics_html', '{"vote_a": 23, "option_a": "fec-ingress and fsc-egrsss", "option_b": "dpd and dpd-retryinterval", "option_c": "fragmentation and fragmentation-mtu", "option_d": "keepalive and keylive", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "You want to improve reliability over a lossy IPSec tunnel. Which combination of IPSec phase 1 parameters should you configure?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134368-exam-nse7_efw-72-topic-1-question-2-discussion/", "discussion_count": 23, "external_question_id": "912154"}', '{"tags": null, "topic": null, "options": [["A", "fec-ingress and fsc-egrsss"], ["B", "dpd and dpd-retryinterval"], ["C", "fragmentation and fragmentation-mtu"], ["D", "keepalive and keylive"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134368-exam-nse7_efw-72-topic-1-question-2-discussion/", "discussion_count": 23, "vote_distribution": {"A": 23}, "external_question_id": "912154"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "You want to improve reliability over a lossy IPSec tunnel. Which combination of IPSec phase 1 parameters should you configure?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '43a6e3c7452d878a3338cd50e4222c88399ce301fab4ce3b4ccc3c2b4f70e4bc', 1295, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (723, 144, 4, 'examtopics_html', '{"vote_b": 13, "vote_d": 13, "option_a": "When run on the Device Database, changes are applied directly to the managed FortiGate device.", "option_b": "When run on the Remote FortiGate directly, administrators do not have the option to review the changes prior to installation.", "option_c": "When run on the All FortiGate in ADOM, changes are automatically installed without the creation of a new revision history.", "option_d": "When run on the Policy Package, ADOM database, you must use the installation wizard to apply the changes to the managed FortiGate device.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "How are bulk configuration changes made using FortiManager CLI scripts? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134369-exam-nse7_efw-72-topic-1-question-3-discussion/", "discussion_count": 26, "external_question_id": "912155"}', '{"tags": null, "topic": null, "options": [["A", "When run on the Device Database, changes are applied directly to the managed FortiGate device."], ["B", "When run on the Remote FortiGate directly, administrators do not have the option to review the changes prior to installation."], ["C", "When run on the All FortiGate in ADOM, changes are automatically installed without the creation of a new revision history."], ["D", "When run on the Policy Package, ADOM database, you must use the installation wizard to apply the changes to the managed FortiGate device."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134369-exam-nse7_efw-72-topic-1-question-3-discussion/", "discussion_count": 26, "vote_distribution": {"B": 13, "D": 13}, "external_question_id": "912155"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "How are bulk configuration changes made using FortiManager CLI scripts? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'imported', NULL, NULL, 'cddc667d8e7de63e5c99da495945ab969cca8224b8eba24dcf5562da624b40fd', 1296, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (724, 144, 5, 'examtopics_html', '{"vote_a": 1, "vote_c": 24, "option_a": "Only NPs are disabled", "option_b": "Only CPs are disabled", "option_c": "NPs and CPs are enabled", "option_d": "NPs and CPs are disabled", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which contains a partial configuration of the global system. What can you conclude from this output?", "source_format": "examtopics_html", "correct_answer": "C", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134370-exam-nse7_efw-72-topic-1-question-4-discussion/", "discussion_count": 25, "external_question_id": "912156"}', '{"tags": null, "topic": null, "options": [["A", "Only NPs are disabled"], ["B", "Only CPs are disabled"], ["C", "NPs and CPs are enabled"], ["D", "NPs and CPs are disabled"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134370-exam-nse7_efw-72-topic-1-question-4-discussion/", "discussion_count": 25, "vote_distribution": {"A": 1, "C": 24}, "external_question_id": "912156"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a partial configuration of the global system. What can you conclude from this output?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '892180f3777e2087acceb427a8cb0392aabef4c7544a160fb1de293bb184426a', 1297, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (725, 144, 6, 'examtopics_html', '{"vote_b": 8, "vote_c": 31, "vote_d": 2, "option_a": "You have read-only access.", "option_b": "Another user is editing the Finance address object in workspace mode.", "option_c": "FortiGate joined the Security Fabric and the Finance address object was configured on the root FortiGate.", "option_d": "FortiGate is registered on FortiManager.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibits, which show the configurations of two address objects from the same FortiGate. Engineering address object - Finance address object - Why can you modify the Engineering address object, but not the Finance address object?", "source_format": "examtopics_html", "correct_answer": "C", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134371-exam-nse7_efw-72-topic-1-question-5-discussion/", "discussion_count": 41, "external_question_id": "912157"}', '{"tags": null, "topic": null, "options": [["A", "You have read-only access."], ["B", "Another user is editing the Finance address object in workspace mode."], ["C", "FortiGate joined the Security Fabric and the Finance address object was configured on the root FortiGate."], ["D", "FortiGate is registered on FortiManager."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134371-exam-nse7_efw-72-topic-1-question-5-discussion/", "discussion_count": 41, "vote_distribution": {"B": 8, "C": 31, "D": 2}, "external_question_id": "912157"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibits, which show the configurations of two address objects from the same FortiGate. Engineering address object - Finance address object - Why can you modify the Engineering address object, but not the Finance address object?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '639aae9f23b5321b54d05cec6b5978d37ba31e5de6dfbc618765c03b543cbb26', 1298, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (726, 144, 7, 'examtopics_html', '{"vote_b": 15, "vote_c": 11, "vote_d": 4, "option_a": "It applies common settings in an OSPF area", "option_b": "You can apply it in Internal BGP (IBGP) and External BGP (EBGP)", "option_c": "You can configure it on the GUI", "option_d": "It is combined with the neighbor-range parameter", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Which two statements about the neighbor-group command are true? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BC", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134372-exam-nse7_efw-72-topic-1-question-6-discussion/", "discussion_count": 30, "external_question_id": "912158"}', '{"tags": null, "topic": null, "options": [["A", "It applies common settings in an OSPF area"], ["B", "You can apply it in Internal BGP (IBGP) and External BGP (EBGP)"], ["C", "You can configure it on the GUI"], ["D", "It is combined with the neighbor-range parameter"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134372-exam-nse7_efw-72-topic-1-question-6-discussion/", "discussion_count": 30, "vote_distribution": {"B": 15, "C": 11, "D": 4}, "external_question_id": "912158"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which two statements about the neighbor-group command are true? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "C"]}', 'imported', NULL, NULL, '56eb99d4f25dc01403e960b625f52e8603e8ed84362329202859c4b12f896132', 1299, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
