tion_id": "912164"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "What are two functions of automation stitches? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "D"]}', 'imported', NULL, NULL, '32bbd4cbf87bd45f66e4da0a600b73028d849d0e9cc0729261b1760f20781443', 1305, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
