INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (739, 144, 20, 'examtopics_html', '{"vote_a": 7, "vote_c": 9, "option_a": "The metadata format is $<metadata_variable_name>.", "option_b": "You create them on FortiGate.", "option_c": "They can be used as variables in scripts.", "option_d": "They apply only to non-firewall objects.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Which two statements about metadata variables are true? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AC", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134826-exam-nse7_efw-72-topic-1-question-19-discussion/", "discussion_count": 16, "external_question_id": "912171"}', '{"tags": null, "topic": null, "options": [["A", "The metadata format is $."], ["B", "You create them on FortiGate."], ["C", "They can be used as variables in scripts."], ["D", "They apply only to non-firewall objects."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134826-exam-nse7_efw-72-topic-1-question-19-discussion/", "discussion_count": 16, "vote_distribution": {"A": 7, "C": 9}, "external_question_id": "912171"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which two statements about metadata variables are true? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "C"]}', 'imported', NULL, NULL, 'f711d23026f4fcee13e1a76280adc75895d7d91ee47f24bfbcb7ea362323ff1a', 1312, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (740, 144, 21, 'examtopics_html', '{"vote_a": 11, "vote_b": 1, "option_a": "Configure the hub as a route reflector", "option_b": "Configure auto-discovery-sender on the hub", "option_c": "Add a prefix list to the hub that permits routes to be shared between the spokes", "option_d": "Enable route redistribution under config router bgp", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibits, which contain the network topology and BGP configuration for a hub. Exhibit A. Exhibit B. An administrator is trying to configure ADVPN with a hub and spoke VPN setup using iBGP. All the VPNs are up and connected to the hub. The hub is receiving route information from both spokes over iBGP; however the spokes are not receiving route information from each other. What change must the administrator make to the hub BGP configuration so that the routes learned from one spoke are forwarded to the other spoke?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134707-exam-nse7_efw-72-topic-1-question-20-discussion/", "discussion_count": 12, "external_question_id": "912172"}', '{"tags": null, "topic": null, "options": [["A", "Configure the hub as a route reflector"], ["B", "Configure auto-discovery-sender on the hub"], ["C", "Add a prefix list to the hub that permits routes to be shared between the spokes"], ["D", "Enable route redistribution under config router bgp"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134707-exam-nse7_efw-72-topic-1-question-20-discussion/", "discussion_count": 12, "vote_distribution": {"A": 11, "B": 1}, "external_question_id": "912172"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibits, which contain the network topology and BGP configuration for a hub. Exhibit A. Exhibit B. An administrator is trying to configure ADVPN with a hub and spoke VPN setup using iBGP. All the VPNs are up and connected to the hub. The hub is receiving route information from both spokes over iBGP; however the spokes are not receiving route information from each other. What change must the administrator make to the hub BGP configuration so that the routes learned from one spoke are forwarded to the other spoke?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'a8e7f95c35fd2b33b4d60c093f81f357f11a4fed70d32d7024f818cb50f3106a', 1313, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (741, 144, 22, 'examtopics_html', '{"vote_d": 14, "option_a": "FortiGate creates separate virtual interfaces for each dial-up client", "option_b": "The VPN should use the dynamic routing protocol to exchange routing information through the tunnels", "option_c": "Dead peer detection is disabled", "option_d": "The routing table shows a single IPSec virtual interface", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which contains a partial VPN configuration. What can you conclude from this configuration?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134738-exam-nse7_efw-72-topic-1-question-21-discussion/", "discussion_count": 14, "external_question_id": "912173"}', '{"tags": null, "topic": null, "options": [["A", "FortiGate creates separate virtual interfaces for each dial-up client"], ["B", "The VPN should use the dynamic routing protocol to exchange routing information through the tunnels"], ["C", "Dead peer detection is disabled"], ["D", "The routing table shows a single IPSec virtual interface"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134738-exam-nse7_efw-72-topic-1-question-21-discussion/", "discussion_count": 14, "vote_distribution": {"D": 14}, "external_question_id": "912173"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a partial VPN configuration. What can you conclude from this configuration?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '33f9b404f18c51b869a1ad3e62d2eaa609cd9025c988945880bdbb684fe23b1e', 1314, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00'