INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (742, 144, 23, 'examtopics_html', '{"vote_a": 6, "vote_c": 6, "option_a": "The interfaces of the OSPF routers match the MTU value that is configured as 1500.", "option_b": "NGFW-1 is the designated router.", "option_c": "The port3 network has more than one OSPF router.", "option_d": "The OSPF routers are in the area ID of 0.0.0.1.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit which shows information about an OSPF interface. What two conclusions can you draw from this command output? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AC", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134834-exam-nse7_efw-72-topic-1-question-22-discussion/", "discussion_count": 12, "external_question_id": "912174"}', '{"tags": null, "topic": null, "options": [["A", "The interfaces of the OSPF routers match the MTU value that is configured as 1500."], ["B", "NGFW-1 is the designated router."], ["C", "The port3 network has more than one OSPF router."], ["D", "The OSPF routers are in the area ID of 0.0.0.1."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134834-exam-nse7_efw-72-topic-1-question-22-discussion/", "discussion_count": 12, "vote_distribution": {"A": 6, "C": 6}, "external_question_id": "912174"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit which shows information about an OSPF interface. What two conclusions can you draw from this command output? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "C"]}', 'imported', NULL, NULL, 'b7bc7aaba89aafe24b6a1e66ed9095d256243ac1dc88be689afbc671d8b88c50', 1315, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (743, 144, 24, 'examtopics_html', '{"vote_b": 3, "vote_c": 11, "vote_d": 8, "option_a": "It detects only two-way failures.", "option_b": "The two routers must be connected to the same subnet.", "option_c": "It allows failure detection in less than one second.", "option_d": "It is supported for neighbors over multiple hops.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Which two statements about the BFD parameter in BGP are true? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "CD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134837-exam-nse7_efw-72-topic-1-question-23-discussion/", "discussion_count": 22, "external_question_id": "912175"}', '{"tags": null, "topic": null, "options": [["A", "It detects only two-way failures."], ["B", "The two routers must be connected to the same subnet."], ["C", "It allows failure detection in less than one second."], ["D", "It is supported for neighbors over multiple hops."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134837-exam-nse7_efw-72-topic-1-question-23-discussion/", "discussion_count": 22, "vote_distribution": {"B": 3, "C": 11, "D": 8}, "external_question_id": "912175"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which two statements about the BFD parameter in BGP are true? (Choose two.)", "question_type": "multiple", "correct_answer": ["C", "D"]}', 'imported', NULL, NULL, '1a2d583faa60745dddf9821f041f7acc648904ab0641fa2d0fd0d43c2f3f82e1', 1316, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (744, 144, 25, 'examtopics_html', '{"vote_b": 9, "vote_d": 6, "option_a": "Refresh the device status using the Device Manager so that FortiGate populates the IPSec interfaces.", "option_b": "Install the VPN community and gateway configuration on the FortiGate devices so that the VPN interfaces appear on the Policy Objects on FortiManager.", "option_c": "Configure the phase 1 settings in the VPN community that you didn’t initially configure. FortiGate automatically generates the interfaces after you configure the required settings.", "option_d": "Create interface mappings for the IPsec VPN interfaces before you use them in a policy.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "You created a VPN community using VPN Manager on FortiManager. You also added gateways to the VPN community. Now you are trying to create firewall policies to permit traffic over the tunnel; however, the VPN interfaces do not appear as available options. What step must you take to resolve this issue?", "source_format": "examtopics_html", "correct_answer": "B", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134839-exam-nse7_efw-72-topic-1-question-24-discussion/", "discussion_count": 15, "external_question_id": "912176"}', '{"tags": null, "topic": null, "options": [["A", "Refresh the device status using the Device Manager so that FortiGate populates the IPSec interfaces."], ["B", "Install the VPN community and gateway configuration on the FortiGate devices so that the VPN interfaces appear on the Policy Objects on FortiManager."], ["C", "Configure the phase 1 settings in the VPN community that you didn’t initially configure. FortiGate automatically generates the interfaces after you configure the required settings."], ["D", "Create interface mappings for the IPsec VPN interfaces before you use them in a policy."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134839-exam-nse7_efw-72-topic-1-question-24-discussion/", "discussion_count": 15, "vote_distribution": {"B": 9, "D": 6}, "external_question_id": "912176"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "You created a VPN community using VPN Manager on FortiManager. You also added gateways to the VPN community. Now you are trying to create firewall policies to permit traffic over the tunnel; however, the VPN interfaces do not appear as available options. What step must you take to resolve this issue?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'a489365fc3c0daf11f3db87833e1a8118946429ece2aed82af3a5f7765f9a5c6', 1317, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
