INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (747, 144, 28, 'examtopics_html', '{"vote_c": 7, "option_a": "Specify SSH in the Service field.", "option_b": "Select an application control profile corresponding to SSH in the Security Profiles section.", "option_c": "Include SSH in the Application field.", "option_d": "Configure port 22 in the Protocol Options field.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which contains a partial policy configuration. Which setting must you configure to allow SSH?", "source_format": "examtopics_html", "correct_answer": "C", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134757-exam-nse7_efw-72-topic-1-question-27-discussion/", "discussion_count": 7, "external_question_id": "912179"}', '{"tags": null, "topic": null, "options": [["A", "Specify SSH in the Service field."], ["B", "Select an application control profile corresponding to SSH in the Security Profiles section."], ["C", "Include SSH in the Application field."], ["D", "Configure port 22 in the Protocol Options field."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134757-exam-nse7_efw-72-topic-1-question-27-discussion/", "discussion_count": 7, "vote_distribution": {"C": 7}, "external_question_id": "912179"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a partial policy configuration. Which setting must you configure to allow SSH?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'c26b3545c54b58d80e64501e060a485924697ed1b3892cbfe237c73e7f2ffecb', 1320, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (748, 144, 29, 'examtopics_html', '{"vote_b": 12, "vote_d": 4, "option_a": "FortiGate uses the first entry listed in the SAN field in the server certificate", "option_b": "FortiGate uses the CN information from the Subject field in the server certificate", "option_c": "FortiGate uses the SNI from the user''s web browser.", "option_d": "FortiGate closes the connection because this represents an invalid SSL/TLS configuration", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which shows an SSL certification inspection configuration. Which action does FortiGate take if the server name indication (SNI) does not match either the common name (CN) or any of the subject alternative names (SAN) in the server certificate?", "source_format": "examtopics_html", "correct_answer": "B", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134482-exam-nse7_efw-72-topic-1-question-28-discussion/", "discussion_count": 16, "external_question_id": "912180"}', '{"tags": null, "topic": null, "options": [["A", "FortiGate uses the first entry listed in the SAN field in the server certificate"], ["B", "FortiGate uses the CN information from the Subject field in the server certificate"], ["C", "FortiGate uses the SNI from the user''s web browser."], ["D", "FortiGate closes the connection because this represents an invalid SSL/TLS configuration"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134482-exam-nse7_efw-72-topic-1-question-28-discussion/", "discussion_count": 16, "vote_distribution": {"B": 12, "D": 4}, "external_question_id": "912180"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows an SSL certification inspection configuration. Which action does FortiGate take if the server name indication (SNI) does not match either the common name (CN) or any of the subject alternative names (SAN) in the server certificate?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '4e1c46f374c02c4be84f02b6f7c7ac479c6f3d7692460bb70d8a2599ead81db3', 1321, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (749, 144, 30, 'examtopics_html', '{"vote_d": 11, "option_a": "Neighbors maintain communication with the restarting router.", "option_b": "The restarting router sends gratuitous ARP for 30 seconds.", "option_c": "FortiGate restarts if the topology changes.", "option_d": "The router sends grace LSAs before it restarts.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which contains a partial OSPF configuration. What can you conclude from this output?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134485-exam-nse7_efw-72-topic-1-question-29-discussion/", "discussion_count": 11, "external_question_id": "912181"}', '{"tags": null, "topic": null, "options": [["A", "Neighbors maintain communication with the restarting router."], ["B", "The restarting router sends gratuitous ARP for 30 seconds."], ["C", "FortiGate restarts if the topology changes."], ["D", "The router sends grace LSAs before it restarts."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134485-exam-nse7_efw-72-topic-1-question-29-discussion/", "discussion_count": 11, "vote_distribution": {"D": 11}, "external_question_id": "912181"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a partial OSPF configuration. What can you conclude from this output?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'fedf1597fd4b17f093d6b8216f1d7809cca0608f05d695bc16d9fb099491509b', 1322, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (750, 144, 31, 'examtopics_html', '{"vote_a": 10, "vote_c": 1, "vote_d": 9, "option_a": "set neighbor-group advpn", "option_b": "set route-reflector-client enable", "option_c": "set prefix 10.1.0 255.255.254.0", "option_d": "set prefix 172.16.1.0 255.255.255.0", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which contains an ADVPN network diagram and a partial BGP configuration. Network diagram - Partial BGP configuration - Which two parameters should you configure in config neighbor-range? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134486-exam-nse7_efw-72-topic-1-question-30-discussion/", "discussion_count": 20, "external_question_id": "912182"}', '{"tags": null, "topic": null, "options": [["A", "set neighbor-group advpn"], ["B", "set route-reflector-client enable"], ["C", "set prefix 10.1.0 255.255.254.0"], ["D", "set prefix 172.16.1.0 255.255.255.0"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134486-exam-nse7_efw-72-topic-1-question-30-discussion/", "discussion_count": 20, "vote_distribution": {"A": 10, "C": 1, "D": 9}, "external_question_id": "912182"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains an ADVPN network diagram and a partial BGP configuration. Network diagram - Partial BGP configuration - Which two parameters should you configure in config neighbor-range? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "D"]}', 'imported', NULL, NULL, '2eb1e762b7dc25e4330a497f94c70afefa2084e4c0886f9ace7b1b077e9e26dd', 1323, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (751, 144, 32, 'examtopics_html', '{"vote_d": 7, "option_a": "distribute-list-in", "option_b": "rfc1583-compatible", "option_c": "restart-on-topology-change", "option_d": "bfd", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "You want to have faster detection for OSPF. Which parameter should you enable on both connected FortiGate devices?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134842-exam-nse7_efw-72-topic-1-question-31-discussion/", "discussion_count": 7, "external_question_id": "912183"}', '{"tags": null, "topic": null, "options": [["A", "distribute-list-in"], ["B", "rfc1583-compatible"], ["C", "restart-on-topology-change"], ["D", "bfd"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134842-exam-nse7_efw-72-topic-1-question-31-discussion/", "discussion_count": 7, "vote_distribution": {"D": 7}, "external_question_id": "912183"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "You want to have faster detection for OSPF. Which parameter should you enable on both connected FortiGate devices?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '6254c220674a800fc4db5d04043abbd1bafab8233048705e1365dea4821a0a75', 1324, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (752, 144, 33, 'examtopics_html', '{"vote_b": 8, "option_a": "You must change the AS number to match the remote peer.", "option_b": "BGP is attempting to establish a TCP connection with the BGP peer.", "option_c": "The bfd configuration is set to enable.", "option_d": "The routers are in the same area ID of 0.0.0.0.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which provides information on BGP neighbors. What can you conclude from this command output?", "source_format": "examtopics_html", "correct_answer": "B", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134843-exam-nse7_efw-72-topic-1-question-32-discussion/", "discussion_count": 8, "external_question_id": "912184"}', '{"tags": null, "topic": null, "options": [["A", "You must change the AS number to match the remote peer."], ["B", "BGP is attempting to establish a TCP connection with the BGP peer."], ["C", "The bfd configuration is set to enable."], ["D", "The routers are in the same area ID of 0.0.0.0."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134843-exam-nse7_efw-72-topic-1-question-32-discussion/", "discussion_count": 8, "vote_distribution": {"B": 8}, "external_question_id": "912184"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which provides information on BGP neighbors. What can you conclude from this command output?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '7e2cd81e79789251d357230267575c400fc8a0889823c5b5b0bb4e31f5c1418b', 1325, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (753, 144, 34, 'examtopics_html', '{"vote_b": 12, "vote_c": 1, "vote_d": 13, "option_a": "The hub adds routes based on IKE negotiations.", "option_b": "You must configure phase 2 quick mode selectors to 0.0.0.0 0.0.0.0.", "option_c": "All FortiGate devices must be in the same autonomous system (AS).", "option_d": "You must disable add-route in the hub.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Which two statements about ADVPN are true? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134708-exam-nse7_efw-72-topic-1-question-33-discussion/", "discussion_count": 26, "external_question_id": "912185"}', '{"tags": null, "topic": null, "options": [["A", "The hub adds routes based on IKE negotiations."], ["B", "You must configure phase 2 quick mode selectors to 0.0.0.0 0.0.0.0."], ["C", "All FortiGate devices must be in the same autonomous system (AS)."], ["D", "You must disable add-route in the hub."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134708-exam-nse7_efw-72-topic-1-question-33-discussion/", "discussion_count": 26, "vote_distribution": {"B": 12, "C": 1, "D": 13}, "external_question_id": "912185"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which two statements about ADVPN are true? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'imported', NULL, NULL, 'cd79a49e99d5500e72cd8e567e826efcc7bdf90d70cedfaa5c969cfb883c035d', 1326, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (754, 144, 35, 'examtopics_html', '{"vote_a": 10, "option_a": "The NP checks the session key or IPSec SA.", "option_b": "The NP provides IPS signature matching.", "option_c": "You can disable the NP for each firewall policy using the command np-acceleration set to loose.", "option_d": "For TCP traffic, FortiGate CPU offloads the first packets of SYN/ACK and ACK of the three-way handshake to NP.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Which statement about network processor (NP) offloading is true?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134710-exam-nse7_efw-72-topic-1-question-34-discussion/", "discussion_count": 10, "external_question_id": "912186"}', '{"tags": null, "topic": null, "options": [["A", "The NP checks the session key or IPSec SA."], ["B", "The NP provides IPS signature matching."], ["C", "You can disable the NP for each firewall policy using the command np-acceleration set to loose."], ["D", "For TCP traffic, FortiGate CPU offloads the first packets of SYN/ACK and ACK of the three-way handshake to NP."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134710-exam-nse7_efw-72-topic-1-question-34-discussion/", "discussion_count": 10, "vote_distribution": {"A": 10}, "external_question_id": "912186"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which statement about network processor (NP) offloading is true?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '7cc807fcbfb353b477ae1e2fe62d3faa383dedfb68540eb72738019a5080b766', 1327, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (755, 144, 36, 'examtopics_html', '{"vote_b": 9, "option_a": "udp is not a protocol option.", "option_b": "fortiguard-anycast is set to enable.", "option_c": "You do not have the corresponding write access.", "option_d": "FortiManager provides FortiGuard.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which shows an error in system fortiguard configuration. What is the reason you cannot set the protocol to udp in config system fortiguard?", "source_format": "examtopics_html", "correct_answer": "B", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134711-exam-nse7_efw-72-topic-1-question-35-discussion/", "discussion_count": 9, "external_question_id": "912187"}', '{"tags": null, "topic": null, "options": [["A", "udp is not a protocol option."], ["B", "fortiguard-anycast is set to enable."], ["C", "You do not have the corresponding write access."], ["D", "FortiManager provides FortiGuard."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134711-exam-nse7_efw-72-topic-1-question-35-discussion/", "discussion_count": 9, "vote_distribution": {"B": 9}, "external_question_id": "912187"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows an error in system fortiguard configuration. What is the reason you cannot set the protocol to udp in config system fortiguard?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '35135f17c6f679af084cb014f7e121d47ebf5eb2636f1d08bccfc647d277b4df', 1328, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (756, 144, 37, 'examtopics_html', '{"vote_c": 1, "option_a": "Secondary virtual MAC port1 then physical MAC port1", "option_b": "Secondary virtual MAC port1", "option_c": "Secondary physical MAC port1", "option_d": "Secondary physical MAC port1 then virtual MAC port2", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which contains an active-active load balancing scenario. During the traffic flow, the primary FortiGate forwards the SYN packet to the secondary FortiGate. What is the destination MAC address or addresses when packets are forwarded from the primary FortiGate to the secondary FortiGate?", "source_format": "examtopics_html", "correct_answer": "C", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141448-exam-nse7_efw-72-topic-1-question-36-discussion/", "discussion_count": 1, "external_question_id": "921116"}', '{"tags": null, "topic": null, "options": [["A", "Secondary virtual MAC port1 then physical MAC port1"], ["B", "Secondary virtual MAC port1"], ["C", "Secondary physical MAC port1"], ["D", "Secondary physical MAC port1 then virtual MAC port2"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141448-exam-nse7_efw-72-topic-1-question-36-discussion/", "discussion_count": 1, "vote_distribution": {"C": 1}, "external_question_id": "921116"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains an active-active load balancing scenario. During the traffic flow, the primary FortiGate forwards the SYN packet to the secondary FortiGate. What is the destination MAC address or addresses when packets are forwarded from the primary FortiGate to the secondary FortiGate?", "question_type": "single