INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (786, 145, 10, 'examtopics_html', '{"vote_a": 23, "option_a": "Configure set link-failed-signal enable under config system ha on both cluster members", "option_b": "Configure set send-garp-on-failover enable under config system ha on both cluster members.", "option_c": "Configure remote link monitoring to detect an issue in the forwarding path.", "option_d": "Verify that the speed and duplex settings match between the FortiGate interfaces and the connected switch ports.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "An administrator has configured two FortiGate devices for an HA cluster. While testing HA failover, the administrator notices that some of the switches in the network continue to send traffic to the former primary device. What can the administrator do to fix this problem?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134376-exam-nse7_efw-72-topic-1-question-9-discussion/", "discussion_count": 23, "external_question_id": "912161"}', '{"tags": null, "topic": null, "options": [["A", "Configure set link-failed-signal enable under config system ha on both cluster members"], ["B", "Configure set send-garp-on-failover enable under config system ha on both cluster members."], ["C", "Configure remote link monitoring to detect an issue in the forwarding path."], ["D", "Verify that the speed and duplex settings match between the FortiGate interfaces and the connected switch ports."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134376-exam-nse7_efw-72-topic-1-question-9-discussion/", "discussion_count": 23, "vote_distribution": {"A": 23}, "external_question_id": "912161"}, "reference": null, "difficulty": "mediu