INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (766, 144, 47, 'examtopics_html', '{"vote_a": 13, "vote_c": 23, "vote_d": 22, "option_a": "The downstream FortiGate has fabric-object-unification set to local.", "option_b": "The root FortiGate has configuration-sync set to enable.", "option_c": "The address object on the root FortiGate has fabric-object set to disable.", "option_d": "The downstream FortiGate has configuration-sync set to local.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "You configured an address object on the root FortiGate in a Security Fabric. This object is not synchronized with a downstream device. Which two reasons could be the cause? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "CD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141458-exam-nse7_efw-72-topic-1-question-46-discussion/", "discussion_count": 58, "external_question_id": "921126"}', '{"tags": null, "topic": null, "options": [["A", "The downstream FortiGate has fabric-object-unification set to local."], ["B", "The root FortiGate has configuration-sync set to enable."], ["C", "The address object on the root FortiGate has fabric-object set to disable."], ["D", "The downstream FortiGate has configuration-sync set to local."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141458-exam-nse7_efw-72-topic-1-question-46-discussion/", "discussion_count": 58, "vote_distribution": {"A": 13, "C": 23, "D": 22}, "external_question_id": "921126"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "You configured an address object on the root FortiGate in a Security Fabric. This object is not synchronized with a downstream device. Which two reasons could be the cause? (Choose two.)", "question_typ