INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (770, 144, 51, 'examtopics_html', '{"vote_d": 7, "option_a": "F-SBID ( --name “detect_eicar”; --protocol udp; --service ssl; --flow from_client; --pattern “www.eicar.org”; --no_case; --context host;)", "option_b": "F-SBID ( --name “eicar”; --protocol udp; --flow from_server; --pattern “eicar”; --context host;)", "option_c": "F-SBID ( --name “detect_eicar”; --protocol tcp; --service dns; --flow from_server; --pattern “eicar”; --no_case;)", "option_d": "F-SBID ( --name “eicar”; --protocol tcp; --service HTTP; --flow from_client; --pattern “www.eicar.org”; --no_case; --context host;)", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "You want to block access to the website www.eicar.org using a custom IPS signature. Which custom IPS signature should you configure?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141533-exam-nse7_efw-72-topic-1-question-50-discussion/", "discussion_count": 7, "external_question_id": "921130"}', '{"tags": null, "topic": null, "options": [["A", "F-SBID ( --name “detect_eicar”; --protocol udp; --service ssl; --flow from_client; --pattern “www.eicar.org”; --no_case; --context host;)"], ["B", "F-SBID ( --name “eicar”; --protocol udp; --flow from_server; --pattern “eicar”; --context host;)"], ["C", "F-SBID ( --name “detect_eicar”; --protocol tcp; --service dns; --flow from_server; --pattern “eicar”; --no_case;)"], ["D", "F-SBID ( --name “eicar”; --protocol tcp; --service HTTP; --flow from_client; --pattern “www.eicar.org”; --no_case; --context host;)"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141533-exam-nse7_efw-72-topic-1-question-50-discussion/", "discussion_count": 7, "vote_distribution"