INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (772, 144, 53, 'examtopics_html', '{"vote_a": 7, "option_a": "Enable AD-VPN in IPsec phase 1", "option_b": "Configure IP addresses on IPsec virtual interfaces", "option_c": "Set protected network to all", "option_d": "Disable add-route on hub", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Which ADVPN configuration must be configured using a script on FortiManager, when using VPN Manager to manage FortiGate VPN tunnels?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141536-exam-nse7_efw-72-topic-1-question-52-discussion/", "discussion_count": 7, "external_question_id": "921132"}', '{"tags": null, "topic": null, "options": [["A", "Enable AD-VPN in IPsec phase 1"], ["B", "Configure IP addresses on IPsec virtual interfaces"], ["C", "Set protected network to all"], ["D", "Disable add-route on hub"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141536-exam-nse7_efw-72-topic-1-question-52-discussion/", "discussion_count": 7, "vote_distribution": {"A": 7}, "external_question_id": "921132"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which ADVPN configuration must be configured using a script on FortiManager, when using VPN Manager to manage FortiGate VPN tunnels?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '2cd9f62871c1abb1ce96919be0a8a2fbc40ee2a2598a44e6f2a47d7137462df1', 1345, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (773, 144, 54, 'examtopics_html', '{"vote_b": 4, "vote_c": 4, "option_a": "The VRRP domain uses the physical MAC address of the primary FortiGate.", "option_b": "On failover, new primary device uses the same MAC address as the old primary.", "option_c": "10.1.5.254 is the default gateway of the internal network.", "option_d": "By default, FortiGate-B is the primary virtual router.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which contains the partial interface configuration of two FortiGate devices. Which two conclusions can you draw from this configuration? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BC", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141462-exam-nse7_efw-72-topic-1-question-53-discussion/", "discussion_count": 8, "external_question_id": "921133"}', '{"tags": null, "topic": null, "options": [["A", "The VRRP domain uses the physical MAC address of the primary FortiGate."], ["B", "On failover, new primary device uses the same MAC address as the old primary."], ["C", "10.1.5.254 is the default gateway of the internal network."], ["D", "By default, FortiGate-B is the primary virtual router."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141462-exam-nse7_efw-72-topic-1-question-53-discussion/", "discussion_count": 8, "vote_distribution": {"B": 4, "C": 4}, "external_question_id": "921133"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains the partial interface configuration of two FortiGate devices. Which two conclusions can you draw from this configuration? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "C"]}', 'imported', NULL, NULL, '18ec47394312e50ca655f1e1d58a694ab78b4fa8844df505dab07b6f314fafe4', 1346, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (774, 144, 55, 'examtopics_html', '{"vote_c": 5, "vote_d": 5, "option_a": "It supports the XAuth protocol.", "option_b": "Phase 1 includes main mode.", "option_c": "It exchanges a minimum of four messages to establish a secure tunnel.", "option_d": "It supports the extensible authentication protocol (EAP).", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Which two statements about IKE version 2 are true? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "CD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141463-exam-nse7_efw-72-topic-1-question-54-discussion/", "discussion_count": 10, "external_question_id": "921134"}', '{"tags": null, "topic": null, "options": [["A", "It supports the XAuth protocol."], ["B", "Phase 1 includes main mode."], ["C", "It exchanges a minimum of four messages to establish a secure tunnel."], ["D", "It supports the extensible authentication protocol (EAP)."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141463-exam-nse7_efw-72-topic-1-question-54-discussion/", "discussion_count": 10, "vote_distribution": {"C": 5, "D": 5}, "external_question_id": "921134"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which two statements about IKE version 2 are true? (Choose two.)", "question_type": "multiple", "correct_answer": ["C", "D"]}', 'imported', NULL, NULL, '5ac6af1bdf0f27c33353928d404a453986a0b59a3d5657b0ecbf82ca41759d5a', 1347, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
