INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (776, 144, 57, 'examtopics_html', '{"vote_b": 7, "vote_d": 7, "option_a": "Configure a route-map-out.", "option_b": "Disable Redistribute Connected.", "option_c": "Configure a distribute-list-out.", "option_d": "Remove the 10.1.10.0 prefix from the OSPF network.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Refer to the exhibit, which shows a routing table. What two options can you configure in OSPF to block the advertisement of the 10.1.10.0 prefix? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141539-exam-nse7_efw-72-topic-1-question-56-discussion/", "discussion_count": 14, "external_question_id": "921136"}', '{"tags": null, "topic": null, "options": [["A", "Configure a route-map-out."], ["B", "Disable Redistribute Connected."], ["C", "Configure a distribute-list-out."], ["D", "Remove the 10.1.10.0 prefix from the OSPF network."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141539-exam-nse7_efw-72-topic-1-question-56-discussion/", "discussion_count": 14, "vote_distribution": {"B": 7, "D": 7}, "external_question_id": "921136"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows a routing table. What two options can you configure in OSPF to block the advertisement of the 10.1.10.0 prefix? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'imported', NULL, NULL, 'bb417e29d9ea97a629b283ee7b6c2f5927cb54cb28d04758a70bad79a11a66d9', 1349, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (777, 144, 58, 'examtopics_html', '{"vote_a": 4, "vote_c": 4, "option_a": "auto-discovery-receiver must be set to enable on the spokes.", "option_b": "Spoke-to-spoke traffic never goes through the hub.", "option_c": "It supports NAT for on-demand tunnels.", "option_d": "Routing is configured by enabling add-advpn-route.", "source_url": "/srv/exam-platform/uploads/imports/144.html", "question_text": "Which two statements about ADVPN are true? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AC", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141540-exam-nse7_efw-72-topic-1-question-57-discussion/", "discussion_count": 8, "external_question_id": "921137"}', '{"tags": null, "topic": null, "options": [["A", "auto-discovery-receiver must be set to enable on the spokes."], ["B", "Spoke-to-spoke traffic never goes through the hub."], ["C", "It supports NAT for on-demand tunnels."], ["D", "Routing is configured by enabling add-advpn-route."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141540-exam-nse7_efw-72-topic-1-question-57-discussion/", "discussion_count": 8, "vote_distribution": {"A": 4, "C": 4}, "external_question_id": "921137"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which two statements about ADVPN are true? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "C"]}', 'imported', NULL, NULL, '13ba19493f9d6e64b44538e58a4984e2cc6562e63073e603739922be4a1600f9', 1350, '2026-05-04 15:49:15.316442+00', '2026-05-04 15:49:15.600068+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (778, 145, 2, 'examtopics_html', '{"vote_a": 11, "option_a": "The TCL procedure run_cmd has not been created.", "option_b": "The TCL script must start with #include.", "option_c": "There is no corresponding #! to signify the end of the script.", "option_d": "The TCL procedure lacks the required loop statements to iterate through the changes.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which contains a TCL script configuration on FortiManager. An administrator has configured the TCL script on FortiManager, but the TCL script failed to apply any changes to the managed device after being run. Why did the TCL script fail to make any changes to the managed device?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134367-exam-nse7_efw-72-topic-1-question-1-discussion/", "discussion_count": 11, "external_question_id": "912153"}', '{"tags": null, "topic": null, "options": [["A", "The TCL procedure run_cmd has not been created."], ["B", "The TCL script must start with #include."], ["C", "There is no corresponding #! to signify the end of the script."], ["D", "The TCL procedure lacks the required loop statements to iterate through the changes."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134367-exam-nse7_efw-72-topic-1-question-1-discussion/", "discussion_count": 11, "vote_distribution": {"A": 11}, "external_question_id": "912153"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a TCL script configuration on FortiManager. An administrator has configured the TCL script on FortiManager, but the TCL script failed to apply any changes to the managed device after being run. Why did the TCL script fail to make any changes to the managed device?", "question_type": "single", "correct_answer": ["A"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '2fcc235b3cbc721397ef456ed5116635393243857904e32a4ccef71e6ef32f7c', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
