INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (780, 145, 4, 'examtopics_html', '{"vote_b": 13, "vote_d": 13, "option_a": "When run on the Device Database, changes are applied directly to the managed FortiGate device.", "option_b": "When run on the Remote FortiGate directly, administrators do not have the option to review the changes prior to installation.", "option_c": "When run on the All FortiGate in ADOM, changes are automatically installed without the creation of a new revision history.", "option_d": "When run on the Policy Package, ADOM database, you must use the installation wizard to apply the changes to the managed FortiGate device.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "How are bulk configuration changes made using FortiManager CLI scripts? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134369-exam-nse7_efw-72-topic-1-question-3-discussion/", "discussion_count": 26, "external_question_id": "912155"}', '{"tags": null, "topic": null, "options": [["A", "When run on the Device Database, changes are applied directly to the managed FortiGate device."], ["B", "When run on the Remote FortiGate directly, administrators do not have the option to review the changes prior to installation."], ["C", "When run on the All FortiGate in ADOM, changes are automatically installed without the creation of a new revision history."], ["D", "When run on the Policy Package, ADOM database, you must use the installation wizard to apply the changes to the managed FortiGate device."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134369-exam-nse7_efw-72-topic-1-question-3-discussion/", "discussion_count": 26, "vote_distribution": {"B": 13, "D": 13}, "externa