INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (782, 145, 6, 'examtopics_html', '{"vote_b": 8, "vote_c": 31, "vote_d": 2, "option_a": "You have read-only access.", "option_b": "Another user is editing the Finance address object in workspace mode.", "option_c": "FortiGate joined the Security Fabric and the Finance address object was configured on the root FortiGate.", "option_d": "FortiGate is registered on FortiManager.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibits, which show the configurations of two address objects from the same FortiGate. Engineering address object - Finance address object - Why can you modify the Engineering address object, but not the Finance address object?", "source_format": "examtopics_html", "correct_answer": "C", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134371-exam-nse7_efw-72-topic-1-question-5-discussion/", "discussion_count": 41, "external_question_id": "912157"}', '{"tags": null, "topic": null, "options": [["A", "You have read-only access."], ["B", "Another user is editing the Finance address object in workspace mode."], ["C", "FortiGate joined the Security Fabric and the Finance address object was configured on the root FortiGate."], ["D", "FortiGate is registered on FortiManager."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134371-exam-nse7_efw-72-topic-1-question-5-discussion/", "discussion_count": 41, "vote_distribution": {"B": 8, "C": 31, "D": 2}, "external_question_id": "912157"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibits, which show the configurations of two address objects from the same FortiGate. Engineering address object - Finance address object - Why can you modify the Engineering add