INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (789, 145, 13, 'examtopics_html', '{"vote_a": 8, "vote_d": 8, "option_a": "Automation stitches can be created to run diagnostic commands and email the results when CPU or memory usage exceeds specified thresholds.", "option_b": "An automation stitch configured to execute actions in parallel can be set to insert a specific delay between actions.", "option_c": "Automation stitches can be configured on any FortiGate device in a Security Fabric environment.", "option_d": "An automation stitch configured to execute actions sequentially can take parameters from previous actions as input for the current action.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "What are two functions of automation stitches? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134380-exam-nse7_efw-72-topic-1-question-12-discussion/", "discussion_count": 16, "external_question_id": "912164"}', '{"tags": null, "topic": null, "options": [["A", "Automation stitches can be created to run diagnostic commands and email the results when CPU or memory usage exceeds specified thresholds."], ["B", "An automation stitch configured to execute actions in parallel can be set to insert a specific delay between actions."], ["C", "Automation stitches can be configured on any FortiGate device in a Security Fabric environment."], ["D", "An automation stitch configured to execute actions sequentially can take parameters from previous actions as input for the current action."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134380-exam-nse7_efw-72-topic-1-question-12-discussion/", "discussion_count": 16, "vote_distribution": {"A": 8, "D": 8}, "external_question_id": "912164"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "What are two functions of automation stitches? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '32bbd4cbf87bd45f66e4da0a600b73028d849d0e9cc0729261b1760f20781443', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
