INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (792, 145, 16, 'examtopics_html', '{"vote_a": 5, "vote_d": 22, "option_a": "To have only configuration synchronization in layer 3", "option_b": "To load balance both sessions and configuration synchronization between layer 2 and 3", "option_c": "To have both sessions and configuration synchronization in layer 3", "option_d": "To have both sessions and configuration synchronization in layer 2", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit which shows two configured FortiGate devices and peering over FGSP. The main link directly connects the two FortiGate devices and is configured using the set session-syn-dev <interface> command. What is the primary reason to configure the main link?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134402-exam-nse7_efw-72-topic-1-question-15-discussion/", "discussion_count": 27, "external_question_id": "912167"}', '{"tags": null, "topic": null, "options": [["A", "To have only configuration synchronization in layer 3"], ["B", "To load balance both sessions and configuration synchronization between layer 2 and 3"], ["C", "To have both sessions and configuration synchronization in layer 3"], ["D", "To have both sessions and configuration synchronization in layer 2"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134402-exam-nse7_efw-72-topic-1-question-15-discussion/", "discussion_count": 27, "vote_distribution": {"A": 5, "D": 22}, "external_question_id": "912167"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit which shows two configured FortiGate devices and peering over FGSP. The main link directly connects the two FortiGate devices and is configured using the set session-syn-dev command. What is the primary reason to configure the main link?", "question_type": "single", "correct_answer": ["D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '7bb8fc36b14f8788a4acc776db2bcc75279899bc915c888c2f1d15590c5701ac', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
