INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (797, 145, 21, 'examtopics_html', '{"vote_a": 11, "vote_b": 1, "option_a": "Configure the hub as a route reflector", "option_b": "Configure auto-discovery-sender on the hub", "option_c": "Add a prefix list to the hub that permits routes to be shared between the spokes", "option_d": "Enable route redistribution under config router bgp", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibits, which contain the network topology and BGP configuration for a hub. Exhibit A. Exhibit B. An administrator is trying to configure ADVPN with a hub and spoke VPN setup using iBGP. All the VPNs are up and connected to the hub. The hub is receiving route information from both spokes over iBGP; however the spokes are not receiving route information from each other. What change must the administrator make to the hub BGP configuration so that the routes learned from one spoke are forwarded to the other spoke?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134707-exam-nse7_efw-72-topic-1-question-20-discussion/", "discussion_count": 12, "external_question_id": "912172"}', '{"tags": null, "topic": null, "options": [["A", "Configure the hub as a route reflector"], ["B", "Configure auto-discovery-sender on the hub"], ["C", "Add a prefix list to the hub that permits routes to be shared between the spokes"], ["D", "Enable route redistribution under config router bgp"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134707-exam-nse7_efw-72-topic-1-question-20-discussion/", "discussion_count": 12, "vote_distribution": {"A": 11, "B": 1}, "external_question_id": "912172"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibits, which contain the network topology and BGP configuration for a hub. Exhibit A. Exhibit B. An administrator is trying to configure ADVPN with a hub and spoke VPN setup using iBGP. All the VPNs are up and connected to the hub. The hub is receiving route information from both spokes over iBGP; however the spokes are not receiving route information from each other. What change must the administrator make to the hub BGP configuration so that the routes learned from one spoke are forwarded to the other spoke?", "question_type": "single", "correct_answer": ["A"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', 'a8e7f95c35fd2b33b4d60c093f81f357f11a4fed70d32d7024f818cb50f3106a', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (798, 145, 22, 'examtopics_html', '{"vote_d": 14, "option_a": "FortiGate creates separate virtual interfaces for each dial-up client", "option_b": "The VPN should use the dynamic routing protocol to exchange routing information through the tunnels", "option_c": "Dead peer detection is disabled", "option_d": "The routing table shows a single IPSec virtual interface", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which contains a partial VPN configuration. What can you conclude from this configuration?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134738-exam-nse7_efw-72-topic-1-question-21-discussion/", "discussion_count": 14, "external_question_id": "912173"}', '{"tags": null, "topic": null, "options": [["A", "FortiGate creates separate virtual interfaces for each dial-up client"], ["B", "The VPN should use the dynamic routing protocol to exchange routing information through the tunnels"], ["C", "Dead peer detection is disabled"], ["D", "The routing table shows a single IPSec virtual interface"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134738-exam-nse7_efw-72-topic-1-question-21-discussion/", "discussion_count": 14, "vote_distribution": {"D": 14}, "external_question_id": "912173"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a partial VPN configuration. What can you conclude from this configuration?", "question_type": "single", "correct_answer": ["D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '33f9b404f18c51b869a1ad3e62d2eaa609cd9025c988945880bdbb684fe23b1e', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (799, 145, 23, 'examtopics_html', '{"vote_a": 6, "vote_c": 6, "option_a": "The interfaces of the OSPF routers match the MTU value that is configured as 1500.", "option_b": "NGFW-1 is the designated router.", "option_c": "The port3 network has more than one OSPF router.", "option_d": "The OSPF routers are in the area ID of 0.0.0.1.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit which shows information about an OSPF interface. What two conclusions can you draw from this command output? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AC", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134834-exam-nse7_efw-72-topic-1-question-22-discussion/", "discussion_count": 12, "external_question_id": "912174"}', '{"tags": null, "topic": null, "options": [["A", "The interfaces of the OSPF routers match the MTU value that is configured as 1500."], ["B", "NGFW-1 is the designated router."], ["C", "The port3 network has more than one OSPF router."], ["D", "The OSPF routers are in the area ID of 0.0.0.1."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134834-exam-nse7_efw-72-topic-1-question-22-discussion/", "discussion_count": 12, "vote_distribution": {"A": 6, "C": 6}, "external_question_id": "912174"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit which shows information about an OSPF interface. What two conclusions can you draw from this command output? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "C"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', 'b7bc7aaba89aafe24b6a1e66ed9095d256243ac1dc88be689afbc671d8b88c50', NULL, '2026-05-04 15:49:15.9