INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (803, 145, 27, 'examtopics_html', '{"vote_d": 12, "option_a": "Only the DR receives link state information from non-DR routers.", "option_b": "Non-DR and non-BDR routers form full adjacencies to DR only.", "option_c": "FortiGate first checks the OSPF ID to elect a DR.", "option_d": "Non-DR and non-BDR routers send link state updates and acknowledgements to 224.0.0.6.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Which statement about the designated router (DR) and backup designated router (BDR) in an OSPF multi-access network is true?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134481-exam-nse7_efw-72-topic-1-question-26-discussion/", "discussion_count": 12, "external_question_id": "912178"}', '{"tags": null, "topic": null, "options": [["A", "Only the DR receives link state information from non-DR routers."], ["B", "Non-DR and non-BDR routers form full adjacencies to DR only."], ["C", "FortiGate first checks the OSPF ID to elect a DR."], ["D", "Non-DR and non-BDR routers send link state updates and acknowledgements to 224.0.0.6."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134481-exam-nse7_efw-72-topic-1-question-26-discussion/", "discussion_count": 12, "vote_distribution": {"D": 12}, "external_question_id": "912178"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which statement about the designated router (DR) and backup designated router (BDR) in an OSPF multi-access network is true?", "question_type": "single", "correct_answer": ["D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', 'ef57bca851999b5f450020ba415616ebed1e87a261ec776819b6c88367af96