INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (804, 145, 28, 'examtopics_html', '{"vote_c": 7, "option_a": "Specify SSH in the Service field.", "option_b": "Select an application control profile corresponding to SSH in the Security Profiles section.", "option_c": "Include SSH in the Application field.", "option_d": "Configure port 22 in the Protocol Options field.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which contains a partial policy configuration. Which setting must you configure to allow SSH?", "source_format": "examtopics_html", "correct_answer": "C", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134757-exam-nse7_efw-72-topic-1-question-27-discussion/", "discussion_count": 7, "external_question_id": "912179"}', '{"tags": null, "topic": null, "options": [["A", "Specify SSH in the Service field."], ["B", "Select an application control profile corresponding to SSH in the Security Profiles section."], ["C", "Include SSH in the Application field."], ["D", "Configure port 22 in the Protocol Options field."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134757-exam-nse7_efw-72-topic-1-question-27-discussion/", "discussion_count": 7, "vote_distribution": {"C": 7}, "external_question_id": "912179"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a partial policy configuration. Which setting must you configure to allow SSH?", "question_type": "single", "correct_answer": ["C"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', 'c26b3545c54b58d80e64501e060a485924697ed1b3892cbfe237c73e7f2ffecb', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (805, 145, 29, 'examtopics_html', '{"vote_b": 12, "vote_d": 4, "option_a": "FortiGate uses the first entry listed in the SAN field in the server certificate", "option_b": "FortiGate uses the CN information from the Subject field in the server certificate", "option_c": "FortiGate uses the SNI from the user''s web browser.", "option_d": "FortiGate closes the connection because this represents an invalid SSL/TLS configuration", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which shows an SSL certification inspection configuration. Which action does FortiGate take if the server name indication (SNI) does not match either the common name (CN) or any of the subject alternative names (SAN) in the server certificate?", "source_format": "examtopics_html", "correct_answer": "B", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134482-exam-nse7_efw-72-topic-1-question-28-discussion/", "discussion_count": 16, "external_question_id": "912180"}', '{"tags": null, "topic": null, "options": [["A", "FortiGate uses the first entry listed in the SAN field in the server certificate"], ["B", "FortiGate uses the CN information from the Subject field in the server certificate"], ["C", "FortiGate uses the SNI from the user''s web browser."], ["D", "FortiGate closes the connection because this represents an invalid SSL/TLS configuration"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134482-exam-nse7_efw-72-topic-1-question-28-discussion/", "discussion_count": 16, "vote_distribution": {"B": 12, "D": 4}, "external_question_id": "912180"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows an SSL certification inspection configuration. Which action does FortiGate take if the server name indication (SNI) does not match either the common name (CN) or any of the subject alternative names (SAN) in the server certificate?", "question_type": "single", "correct_answer": ["B"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '4e1c46f374c02c4be84f02b6f7c7ac479c6f3d7692460bb70d8a2599ead81db3', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (806, 145, 30, 'examtopics_html', '{"vote_d": 11, "option_a": "Neighbors maintain communication with the restarting router.", "option_b": "The restarting router sends gratuitous ARP for 30 seconds.", "option_c": "FortiGate restarts if the topology changes.", "option_d": "The router sends grace LSAs before it restarts.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which contains a partial OSPF configuration. What can you conclude from this output?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134485-exam-nse7_efw-72-topic-1-question-29-discussion/", "discussion_count": 11, "external_question_id": "912181"}', '{"tags": null, "topic": null, "options": [["A", "Neighbors maintain communication with the restarting router."], ["B", "The restarting router sends gratuitous ARP for 30 seconds."], ["C", "FortiGate restarts if the topology changes."], ["D", "The router sends grace LSAs before it restarts."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134485-exam-nse7_efw-72-topic-1-question-29-discussion/", "discussion_count": 11, "vote_distribution": {"D": 11}, "external_question_id": "912181"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a partial OSPF configuration. What can you conclude from this output?", "question_type": "single", "correct_answer": ["D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', 'fedf1597fd4b17f093d6b8216f1d7809cca0608f05d695bc16d9fb099491509b', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (807, 145, 31, 'examtopics_html', '{"vote_a": 10, "vote_c": 1, "vote_d": 9, "option_a": "set neighbor-group advpn", "option_b": "set route-reflector-client enable", "option_c": "set prefix 10.1.0 255.255.254.0", "option_d": "set prefix 172.16.1.0 255.255.255.0", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which contains an ADVPN network diagram and a partial BGP configuration. Network diagram - Partial BGP configuration - Which two parameters should you configure in config neighbor-range? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134486-exam-nse7_efw-72-topic-1-question-30-discussion/", "discussion_count": 20, "external_question_id": "912182"}', '{"tags": null, "topic": null, "options": [["A", "set neighbor-group advpn"], ["B", "set route-reflector-client enable"], ["C", "set prefix 10.1.0 255.255.254.0"], ["D", "set prefix 172.16.1.0 255.255.255.0"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134486-exam-nse7_efw-72-topic-1-question-30-discussion/", "discussion_count": 20, "vote_distribution": {"A": 10, "C": 1, "D": 9}, "external_question_id": "912182"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains an ADVPN network diagram and a partial BGP configuration. Network diagram - Partial BGP configuration - Which two parameters should you configure in config neighbor-range? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '2eb1e762b7dc25e4330a497f94c70afefa2084e4c0886f9ace7b1b077e9e26dd', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
