INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (809, 145, 33, 'examtopics_html', '{"vote_b": 8, "option_a": "You must change the AS number to match the remote peer.", "option_b": "BGP is attempting to establish a TCP connection with the BGP peer.", "option_c": "The bfd configuration is set to enable.", "option_d": "The routers are in the same area ID of 0.0.0.0.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which provides information on BGP neighbors. What can you conclude from this command output?", "source_format": "examtopics_html", "correct_answer": "B", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134843-exam-nse7_efw-72-topic-1-question-32-discussion/", "discussion_count": 8, "external_question_id": "912184"}', '{"tags": null, "topic": null, "options": [["A", "You must change the AS number to match the remote peer."], ["B", "BGP is attempting to establish a TCP connection with the BGP peer."], ["C", "The bfd configuration is set to enable."], ["D", "The routers are in the same area ID of 0.0.0.0."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134843-exam-nse7_efw-72-topic-1-question-32-discussion/", "discussion_count": 8, "vote_distribution": {"B": 8}, "external_question_id": "912184"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which provides information on BGP neighbors. What can you conclude from this command output?", "question_type": "single", "correct_answer": ["B"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '7e2cd81e79789251d357230267575c400fc8a0889823c5b5b0bb4e31f5c1418b', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (810, 145, 34, 'examtopics_html', '{"vote_b": 12, "vote_c": 1, "vote_d": 13, "option_a": "The hub adds routes based on IKE negotiations.", "option_b": "You must configure phase 2 quick mode selectors to 0.0.0.0 0.0.0.0.", "option_c": "All FortiGate devices must be in the same autonomous system (AS).", "option_d": "You must disable add-route in the hub.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Which two statements about ADVPN are true? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134708-exam-nse7_efw-72-topic-1-question-33-discussion/", "discussion_count": 26, "external_question_id": "912185"}', '{"tags": null, "topic": null, "options": [["A", "The hub adds routes based on IKE negotiations."], ["B", "You must configure phase 2 quick mode selectors to 0.0.0.0 0.0.0.0."], ["C", "All FortiGate devices must be in the same autonomous system (AS)."], ["D", "You must disable add-route in the hub."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134708-exam-nse7_efw-72-topic-1-question-33-discussion/", "discussion_count": 26, "vote_distribution": {"B": 12, "C": 1, "D": 13}, "external_question_id": "912185"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which two statements about ADVPN are true? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', 'cd79a49e99d5500e72cd8e567e826efcc7bdf90d70cedfaa5c969cfb883c035d', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (811, 145, 35, 'examtopics_html', '{"vote_a": 10, "option_a": "The NP checks the session key or IPSec SA.", "option_b": "The NP provides IPS signature matching.", "option_c": "You can disable the NP for each firewall policy using the command np-acceleration set to loose.", "option_d": "For TCP traffic, FortiGate CPU offloads the first packets of SYN/ACK and ACK of the three-way handshake to NP.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Which statement about network processor (NP) offloading is true?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134710-exam-nse7_efw-72-topic-1-question-34-discussion/", "discussion_count": 10, "external_question_id": "912186"}', '{"tags": null, "topic": null, "options": [["A", "The NP checks the session key or IPSec SA."], ["B", "The NP provides IPS signature matching."], ["C", "You can disable the NP for each firewall policy using the command np-acceleration set to loose."], ["D", "For TCP traffic, FortiGate CPU offloads the first packets of SYN/ACK and ACK of the three-way handshake to NP."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134710-exam-nse7_efw-72-topic-1-question-34-discussion/", "discussion_count": 10, "vote_distribution": {"A": 10}, "external_question_id": "912186"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which statement about network processor (NP) offloading is true?", "question_type": "single", "correct_answer": ["A"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '7cc807fcbfb353b477ae1e2fe62d3faa383dedfb68540eb72738019a5080b766', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (812, 145, 36, 'examtopics_html', '{"vote_b": 9, "option_a": "udp is not a protocol option.", "option_b": "fortiguard-anycast is set to enable.", "option_c": "You do not have the corresponding write access.", "option_d": "FortiManager provides FortiGuard.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which shows an error in system fortiguard configuration. What is the reason you cannot set the protocol to udp in config system fortiguard?", "source_format": "examtopics_html", "correct_answer": "B", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134711-exam-nse7_efw-72-topic-1-question-35-discussion/", "discussion_count": 9, "external_question_id": "912187"}', '{"tags": null, "topic": null, "options": [["A", "udp is not a protocol option."], ["B", "fortiguard-anycast is set to enable."], ["C", "You do not have the corresponding write access."], ["D", "FortiManager provides FortiGuard."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/134711-exam-nse7_efw-72-topic-1-question-35-discussion/", "discussion_count": 9, "vote_distribution": {"B": 9}, "external_question_id": "912187"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows an error in system fortiguard configuration. What is the reason you cannot set the protocol to udp in config system fortiguard?", "question_type": "single", "correct_answer": ["B"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '35135f17c6f679af084cb014f7e121d47ebf5eb2636f1d08bccfc647d277b4df', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (813, 145, 37, 'examtopics_html', '{"vote_c": 1, "option_a": "Secondary virtual MAC port1 then physical MAC port1", "option_b": "Secondary virtual MAC port1", "option_c": "Secondary physical MAC port1", "option_d": "Secondary physical MAC port1 then virtual MAC port2", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which contains an active-active load balancing scenario. During the traffic flow, the primary FortiGate forwards the SYN packet to the secondary FortiGate. What is the destination MAC address or addresses when packets are forwarded from the primary FortiGate to the secondary FortiGate?", "source_format": "examtopics_html", "correct_answer": "C", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141448-exam-nse7_efw-72-topic-1-question-36-discussion/", "discussion_count": 1, "external_question_id": "921116"}', '{"tags": null, "topic": null, "options": [["A", "Secondary virtual MAC port1 then physical MAC port1"], ["B", "Secondary virtual MAC port1"], ["C", "Secondary physical MAC port1"], ["D", "Secondary physical MAC port1 then virtual MAC port2"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141448-exam-nse7_efw-72-topic-1-question-36-discussion/", "discussion_count": 1, "vote_distribution": {"C": 1}, "external_question_id": "921116"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains an active-active load balancing scenario. During the traffic flow, the primary FortiGate forwards the SYN packet to the secondary FortiGate. What is the destination MAC address or addresses when packets are forwarded from the primary FortiGate to the secondary FortiGate?", "question_type": "single", "correct_answer": ["C"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '856553b7cde85dc19c87cd2b29c5a165eee2befba6f898623bea7de507916ffa', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
