INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (815, 145, 39, 'examtopics_html', '{"vote_a": 6, "vote_d": 6, "option_a": "It can be configured as an update server, a rating server, or both.", "option_b": "It caches available firmware updates for unmanaged devices.", "option_c": "It supports rating requests from non-FortiGate devices.", "option_d": "It provides VM license validation services.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "In which two ways does FortiManager function when it is deployed as a local FDS? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141504-exam-nse7_efw-72-topic-1-question-38-discussion/", "discussion_count": 12, "external_question_id": "921118"}', '{"tags": null, "topic": null, "options": [["A", "It can be configured as an update server, a rating server, or both."], ["B", "It caches available firmware updates for unmanaged devices."], ["C", "It supports rating requests from non-FortiGate devices."], ["D", "It provides VM license validation services."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141504-exam-nse7_efw-72-topic-1-question-38-discussion/", "discussion_count": 12, "vote_distribution": {"A": 6, "D": 6}, "external_question_id": "921118"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "In which two ways does FortiManager function when it is deployed as a local FDS? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '60a1f59186dbd4ead7c394f68a79b2fb7ff0f7baa8dfd009da7859cd3760e711', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (816, 145, 40, 'examtopics_html', '{"vote_a": 5, "option_a": "The access is blocked, based on the URL Filter configuration.", "option_b": "The access is blocked, based on the Content Filter configuration.", "option_c": "The access is allowed, based on the FortiGuard Category Based Filter configuration.", "option_d": "The access is blocked if the local or the public FortiGuard server does not reply.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which shows a partial web filter profile configuration. What can you conclude from this configuration about access to www.facebook.com, which is categorized as Social Networking?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141505-exam-nse7_efw-72-topic-1-question-39-discussion/", "discussion_count": 5, "external_question_id": "921119"}', '{"tags": null, "topic": null, "options": [["A", "The access is blocked, based on the URL Filter configuration."], ["B", "The access is blocked, based on the Content Filter configuration."], ["C", "The access is allowed, based on the FortiGuard Category Based Filter configuration."], ["D", "The access is blocked if the local or the public FortiGuard server does not reply."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141505-exam-nse7_efw-72-topic-1-question-39-discussion/", "discussion_count": 5, "vote_distribution": {"A": 5}, "external_question_id": "921119"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows a partial web filter profile configuration. What can you conclude from this configuration about access to www.facebook.com, which is categorized as Social Networking?", "question_type": "single", "correct_answer": ["A"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '59b654c594efe2e92a288d0c59422a4d1883c885653f7af39c7134d391561fb5', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (817, 145, 41, 'examtopics_html', '{"vote_d": 11, "option_a": "Shortcut forward", "option_b": "Shortcut reply", "option_c": "Shortcut query", "option_d": "Shortcut offer", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which shows an ADVPN network. The client behind Spoke-1 generates traffic to the device located behind Spoke-2. Which first message does the hub send to Spoke-1 to bring up the dynamic tunnel?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141453-exam-nse7_efw-72-topic-1-question-40-discussion/", "discussion_count": 11, "external_question_id": "921120"}', '{"tags": null, "topic": null, "options": [["A", "Shortcut forward"], ["B", "Shortcut reply"], ["C", "Shortcut query"], ["D", "Shortcut offer"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141453-exam-nse7_efw-72-topic-1-question-40-discussion/", "discussion_count": 11, "vote_distribution": {"D": 11}, "external_question_id": "921120"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows an ADVPN network. The client behind Spoke-1 generates traffic to the device located behind Spoke-2. Which first message does the hub send to Spoke-1 to bring up the dynamic tunnel?", "question_type": "single", "correct_answer": ["D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '3f7f67b61929ad237184d34f75777ee005aa43bb6fe970c61e859965e6a55b6d', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
