INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (824, 145, 48, 'examtopics_html', '{"vote_c": 5, "vote_d": 5, "option_a": "CLI scripts must start with #!.", "option_b": "Static routes can be added using only TCL scripts.", "option_c": "Incomplete commands can cause CLI scripts to fail.", "option_d": "The commands that start with the # sign did not run.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which contains a CLI script configuration on FortiManager. An administrator configured the CLI script on FortiManager, but the script failed to apply any changes to the managed device after being executed. What are two reasons why the script did not make any changes to the managed device? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "CD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141530-exam-nse7_efw-72-topic-1-question-47-discussion/", "discussion_count": 10, "external_question_id": "921127"}', '{"tags": null, "topic": null, "options": [["A", "CLI scripts must start with #!."], ["B", "Static routes can be added using only TCL scripts."], ["C", "Incomplete commands can cause CLI scripts to fail."], ["D", "The commands that start with the # sign did not run."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141530-exam-nse7_efw-72-topic-1-question-47-discussion/", "discussion_count": 10, "vote_distribution": {"C": 5, "D": 5}, "external_question_id": "921127"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains a CLI script configuration on FortiManager. An administrator configured the CLI script on FortiManager, but the script failed to apply any changes to the managed device after being executed. What are two reasons why the script did not make any changes to the managed device? (Choose two.)", "question_type": "multiple", "correct_answer": ["C", "D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '3e8754dc18e3bcb9989edc4a5b10b07ccc8329b0bd703a6ef786f7226774ff27', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (825, 145, 49, 'examtopics_html', '{"vote_a": 2, "vote_b": 8, "option_a": "The administrator can look up the hex value of 34 in the second command output.", "option_b": "The administrator must convert the first two digits of the Domain hex value to a decimal value.", "option_c": "The administrator must convert the first three digits of the IP hex value to binary.", "option_d": "The administrator must add both the Domain and IPhex values of 34 to get the category number.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which shows the output from the webfilter fortiguard cache dump and webfilter categories commands. Using the output, how can an administrator determine the category of the training.fortinet.com website?", "source_format": "examtopics_html", "correct_answer": "B", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141531-exam-nse7_efw-72-topic-1-question-48-discussion/", "discussion_count": 10, "external_question_id": "921128"}', '{"tags": null, "topic": null, "options": [["A", "The administrator can look up the hex value of 34 in the second command output."], ["B", "The administrator must convert the first two digits of the Domain hex value to a decimal value."], ["C", "The administrator must convert the first three digits of the IP hex value to binary."], ["D", "The administrator must add both the Domain and IPhex values of 34 to get the category number."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141531-exam-nse7_efw-72-topic-1-question-48-discussion/", "discussion_count": 10, "vote_distribution": {"A": 2, "B": 8}, "external_question_id": "921128"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows the output from the webfilter fortiguard cache dump and webfilter categories commands. Using the output, how can an administrator determine the category of the training.fortinet.com website?", "question_type": "single", "correct_answer": ["B"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '5e5a25ca2239a6cee15f31b7f02a02e077957450800145c40dc4400d9614a057', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (826, 145, 50, 'examtopics_html', '{"vote_b": 11, "vote_c": 11, "option_a": "set auto-discovery-receiver enable", "option_b": "set auto-discovery-sender enable", "option_c": "set ike-version 2", "option_d": "set auto-discovery-forwarder enable", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which contains the partial ADVPN configuration of a spoke. Which two parameters must you configure on the corresponding single hub? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BC", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141532-exam-nse7_efw-72-topic-1-question-49-discussion/", "discussion_count": 22, "external_question_id": "921129"}', '{"tags": null, "topic": null, "options": [["A", "set auto-discovery-receiver enable"], ["B", "set auto-discovery-sender enable"], ["C", "set ike-version 2"], ["D", "set auto-discovery-forwarder enable"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141532-exam-nse7_efw-72-topic-1-question-49-discussion/", "discussion_count": 22, "vote_distribution": {"B": 11, "C": 11}, "external_question_id": "921129"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains the partial ADVPN configuration of a spoke. Which two parameters must you configure on the corresponding single hub? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "C"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '985fa72f2f7cda7a6307cb86f5afec1c41cdea1afe2bc51b11e2560df65fb44f', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (827, 145, 51, 'examtopics_html', '{"vote_d": 7, "option_a": "F-SBID ( --name “detect_eicar”; --protocol udp; --service ssl; --flow from_client; --pattern “www.eicar.org”; --no_case; --context host;)", "option_b": "F-SBID ( --name “eicar”; --protocol udp; --flow from_server; --pattern “eicar”; --context host;)", "option_c": "F-SBID ( --name “detect_eicar”; --protocol tcp; --service dns; --flow from_server; --pattern “eicar”; --no_case;)", "option_d": "F-SBID ( --name “eicar”; --protocol tcp; --service HTTP; --flow from_client; --pattern “www.eicar.org”; --no_case; --context host;)", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "You want to block access to the website www.eicar.org using a custom IPS signature. Which custom IPS signature should you configure?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141533-exam-nse7_efw-72-topic-1-question-50-discussion/", "discussion_count": 7, "external_question_id": "921130"}', '{"tags": null, "topic": null, "options": [["A", "F-SBID ( --name “detect_eicar”; --protocol udp; --service ssl; --flow from_client; --pattern “www.eicar.org”; --no_case; --context host;)"], ["B", "F-SBID ( --name “eicar”; --protocol udp; --flow from_server; --pattern “eicar”; --context host;)"], ["C", "F-SBID ( --name “detect_eicar”; --protocol tcp; --service dns; --flow from_server; --pattern “eicar”; --no_case;)"], ["D", "F-SBID ( --name “eicar”; --protocol tcp; --service HTTP; --flow from_client; --pattern “www.eicar.org”; --no_case; --context host;)"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141533-exam-nse7_efw-72-topic-1-question-50-discussion/", "discussion_count": 7, "vote_distribution": {"D": 7}, "external_question_id": "921130"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "You want to block access to the website www.eicar.org using a custom IPS signature. Which custom IPS signature should you configure?", "question_type": "single", "correct_answer": ["D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '0ca95702efcd3fc970eea513f576c963fb2db9c84f5c3b084497fe4547f60213', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (828, 145, 52, 'examtopics_html', '{"vote_d": 8, "option_a": "Set net-device to enable.", "option_b": "Set route-overlap to allow.", "option_c": "Set single-source to enable.", "option_d": "Set route-overlap to either use-new or use-old.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which shows a network diagram. Which IPSec phase 2 configuration should you implement so that only one remote site is connected at any time?", "source_format": "examtopics_html", "correct_answer": "D", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141535-exam-nse7_efw-72-topic-1-question-51-discussion/", "discussion_count": 8, "external_question_id": "921131"}', '{"tags": null, "topic": null, "options": [["A", "Set net-device to enable."], ["B", "Set route-overlap to allow."], ["C", "Set single-source to enable."], ["D", "Set route-overlap to either use-new or use-old."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141535-exam-nse7_efw-72-topic-1-question-51-discussion/", "discussion_count": 8, "vote_distribution": {"D": 8}, "external_question_id": "921131"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows a network diagram. Which IPSec phase 2 configuration should you implement so that only one remote site is connected at any time?", "question_type": "single", "correct_answer": ["D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '5137b8cfe3fc9f07bbabe2cca5bf3c7faf0028d222c1914affb9ccccaef859b9', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (829, 145, 53, 'examtopics_html', '{"vote_a": 7, "option_a": "Enable AD-VPN in IPsec phase 1", "option_b": "Configure IP addresses on IPsec virtual interfaces", "option_c": "Set protected network to all", "option_d": "Disable add-route on hub", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Which ADVPN configuration must be configured using a script on FortiManager, when using VPN Manager to manage FortiGate VPN tunnels?", "source_format": "examtopics_html", "correct_answer": "A", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141536-exam-nse7_efw-72-topic-1-question-52-discussion/", "discussion_count": 7, "external_question_id": "921132"}', '{"tags": null, "topic": null, "options": [["A", "Enable AD-VPN in IPsec phase 1"], ["B", "Configure IP addresses on IPsec virtual interfaces"], ["C", "Set protected network to all"], ["D", "Disable add-route on hub"]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141536-exam-nse7_efw-72-topic-1-question-52-discussion/", "discussion_count": 7, "vote_distribution": {"A": 7}, "external_question_id": "921132"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which ADVPN configuration must be configured using a script on FortiManager, when using VPN Manager to manage FortiGate VPN tunnels?", "question_type": "single", "correct_answer": ["A"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '2cd9f62871c1abb1ce96919be0a8a2fbc40ee2a2598a44e6f2a47d7137462df1', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (830, 145, 54, 'examtopics_html', '{"vote_b": 4, "vote_c": 4, "option_a": "The VRRP domain uses the physical MAC address of the primary FortiGate.", "option_b": "On failover, new primary device uses the same MAC address as the old primary.", "option_c": "10.1.5.254 is the default gateway of the internal network.", "option_d": "By default, FortiGate-B is the primary virtual router.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which contains the partial interface configuration of two FortiGate devices. Which two conclusions can you draw from this configuration? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BC", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141462-exam-nse7_efw-72-topic-1-question-53-discussion/", "discussion_count": 8, "external_question_id": "921133"}', '{"tags": null, "topic": null, "options": [["A", "The VRRP domain uses the physical MAC address of the primary FortiGate."], ["B", "On failover, new primary device uses the same MAC address as the old primary."], ["C", "10.1.5.254 is the default gateway of the internal network."], ["D", "By default, FortiGate-B is the primary virtual router."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141462-exam-nse7_efw-72-topic-1-question-53-discussion/", "discussion_count": 8, "vote_distribution": {"B": 4, "C": 4}, "external_question_id": "921133"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which contains the partial interface configuration of two FortiGate devices. Which two conclusions can you draw from this configuration? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "C"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '18ec47394312e50ca655f1e1d58a694ab78b4fa8844df505dab07b6f314fafe4', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (831, 145, 55, 'examtopics_html', '{"vote_c": 5, "vote_d": 5, "option_a": "It supports the XAuth protocol.", "option_b": "Phase 1 includes main mode.", "option_c": "It exchanges a minimum of four messages to establish a secure tunnel.", "option_d": "It supports the extensible authentication protocol (EAP).", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Which two statements about IKE version 2 are true? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "CD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141463-exam-nse7_efw-72-topic-1-question-54-discussion/", "discussion_count": 10, "external_question_id": "921134"}', '{"tags": null, "topic": null, "options": [["A", "It supports the XAuth protocol."], ["B", "Phase 1 includes main mode."], ["C", "It exchanges a minimum of four messages to establish a secure tunnel."], ["D", "It supports the extensible authentication protocol (EAP)."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141463-exam-nse7_efw-72-topic-1-question-54-discussion/", "discussion_count": 10, "vote_distribution": {"C": 5, "D": 5}, "external_question_id": "921134"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which two statements about IKE version 2 are true? (Choose two.)", "question_type": "multiple", "correct_answer": ["C", "D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '5ac6af1bdf0f27c33353928d404a453986a0b59a3d5657b0ecbf82ca41759d5a', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (832, 145, 56, 'examtopics_html', '{"vote_b": 7, "vote_c": 2, "option_a": "Only the root FortiGate.", "option_b": "Each FortiGate in the Security Fabric.", "option_c": "The FortiGate devices performing network address translation (NAT) or unified threat management (UTM), if configured.", "option_d": "Only the last FortiGate that handled a session in the Security Fabric.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Which FortiGate in a Security Fabric sends logs to FortiAnalyzer?", "source_format": "examtopics_html", "correct_answer": "B", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141538-exam-nse7_efw-72-topic-1-question-55-discussion/", "discussion_count": 9, "external_question_id": "921135"}', '{"tags": null, "topic": null, "options": [["A", "Only the root FortiGate."], ["B", "Each FortiGate in the Security Fabric."], ["C", "The FortiGate devices performing network address translation (NAT) or unified threat management (UTM), if configured."], ["D", "Only the last FortiGate that handled a session in the Security Fabric."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141538-exam-nse7_efw-72-topic-1-question-55-discussion/", "discussion_count": 9, "vote_distribution": {"B": 7, "C": 2}, "external_question_id": "921135"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which FortiGate in a Security Fabric sends logs to FortiAnalyzer?", "question_type": "single", "correct_answer": ["B"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '7b3c849e916660a8a5fc6025446ad379ae17354a34ed785cee9cdf1d8ca4e15b', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (833, 145, 57, 'examtopics_html', '{"vote_b": 7, "vote_d": 7, "option_a": "Configure a route-map-out.", "option_b": "Disable Redistribute Connected.", "option_c": "Configure a distribute-list-out.", "option_d": "Remove the 10.1.10.0 prefix from the OSPF network.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Refer to the exhibit, which shows a routing table. What two options can you configure in OSPF to block the advertisement of the 10.1.10.0 prefix? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "BD", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141539-exam-nse7_efw-72-topic-1-question-56-discussion/", "discussion_count": 14, "external_question_id": "921136"}', '{"tags": null, "topic": null, "options": [["A", "Configure a route-map-out."], ["B", "Disable Redistribute Connected."], ["C", "Configure a distribute-list-out."], ["D", "Remove the 10.1.10.0 prefix from the OSPF network."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141539-exam-nse7_efw-72-topic-1-question-56-discussion/", "discussion_count": 14, "vote_distribution": {"B": 7, "D": 7}, "external_question_id": "921136"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Refer to the exhibit, which shows a routing table. What two options can you configure in OSPF to block the advertisement of the 10.1.10.0 prefix? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', 'bb417e29d9ea97a629b283ee7b6c2f5927cb54cb28d04758a70bad79a11a66d9', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (834, 145, 58, 'examtopics_html', '{"vote_a": 4, "vote_c": 4, "option_a": "auto-discovery-receiver must be set to enable on the spokes.", "option_b": "Spoke-to-spoke traffic never goes through the hub.", "option_c": "It supports NAT for on-demand tunnels.", "option_d": "Routing is configured by enabling add-advpn-route.", "source_url": "/srv/exam-platform/uploads/imports/145.html", "question_text": "Which two statements about ADVPN are true? (Choose two.)", "source_format": "examtopics_html", "correct_answer": "AC", "discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141540-exam-nse7_efw-72-topic-1-question-57-discussion/", "discussion_count": 8, "external_question_id": "921137"}', '{"tags": null, "topic": null, "options": [["A", "auto-discovery-receiver must be set to enable on the spokes."], ["B", "Spoke-to-spoke traffic never goes through the hub."], ["C", "It supports NAT for on-demand tunnels."], ["D", "Routing is configured by enabling add-advpn-route."]], "community": {"discussion_url": "https://www.examtopics.com/discussions/fortinet/view/141540-exam-nse7_efw-72-topic-1-question-57-discussion/", "discussion_count": 8, "vote_distribution": {"A": 4, "C": 4}, "external_question_id": "921137"}, "reference": null, "difficulty": "medium", "explanation": null, "question_text": "Which two statements about ADVPN are true? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "C"]}', 'duplicate', NULL, 'duplicate of an existing question in this exam', '13ba19493f9d6e64b44538e58a4984e2cc6562e63073e603739922be4a1600f9', NULL, '2026-05-04 15:49:15.938125+00', '2026-05-04 15:49:15.938125+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (876, 146, 43, 'qblock_pdf', '{"option_a": "Implement a pilot light architecture that provides real-time data replication in the second Region. Configure Amazon Route 53 health checks and automated DNS failover.", "option_b": "Implement a warm standby architecture that provides regular data replication in a second Region. Configure Amazon Route 53 health checks and automated DNS failover.", "option_c": "Implement an active-active architecture that provides real-time data replication across two Regions. Use Amazon Route 53 health checks and a weighted routing policy.", "option_d": "Implement a custom script to generate a regular backup of the data and store it in an S3 bucket that is in a second Region. Use the backup to launch the application in the second Region in the event of a workload failure.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The active-active multi-Region architecture provides the lowest possible RTO and RPO among all\ndisaster recovery strategies. In this approach, workloads are deployed and actively running in\nmultiple AWS Regions simultaneously. All data is continuously replicated in real time between\nRegions using fully managed replication services, ensuring zero data loss (zero RPO).\nBecause both Regions are active and capable of handling requests, failover between them is\ninstantaneous, meeting the RTO of less than 10 minutes. Amazon Route 53 is used with\nweighted or latency-based routing policies and health checks to automatically route traffic away\nfrom an impaired Region to the healthy Region without manual intervention.\nPilot Light Architecture maintains only a minimal copy of the environment in the secondary\nRegion. It requires time to scale up infrastructure during a disaster, resulting in longer RTO and\npotential data loss (non-zero RPO).\nWarm Standby Architecture keeps partially running infrastructure in the secondary Region.\nAlthough faster than pilot light, it still requires scaling and synchronization, resulting in higher\nRTO and RPO compared to active-active.\nBackup and Restore (option D) relies on periodic backups and restores data when needed. This\napproach has the highest RTO and RPO, unsuitable for mission-critical workloads demanding\nhigh availability and zero data loss.\nTherefore, based on AWS-recommended disaster recovery strategies outlined in the AWS Cloud\nOperations and Disaster Recovery Guide, the Active-Active Multi-Region architecture (Option C)\nis the only approach that guarantees RTO <10 minutes and RPO = 0, achieving continuous\navailability and business continuity across Regions.", "question_text": "A global company runs a critical primary workload in the us-east-1 Region. The company wants to ensure business continuity with minimal downtime in case of a workload failure. The company wants to replicate the workload to a second AWS Region. A CloudOps engineer needs a solution that achieves a recovery time objective (RTO) of less than 10 minutes and a zero recovery point objective (RPO) to meet service level agreements. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0042"}', '{"tags": null, "topic": null, "options": [["A", "Implement a pilot light architecture that provides real-time data replication in the second Region. Configure Amazon Route 53 health checks and automated DNS failover."], ["B", "Implement a warm standby architecture that provides regular data replication in a second Region. Configure Amazon Route 53 health checks and automated DNS failover."], ["C", "Implement an active-active architecture that provides real-time data replication across two Regions. Use Amazon Route 53 health checks and a weighted routing policy."], ["D", "Implement a custom script to generate a regular backup of the data and store it in an S3 bucket that is in a second Region. Use the backup to launch the application in the second Region in the event of a workload failure."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0042"}, "reference": null, "difficulty": "medium", "explanation": "The active-active multi-Region architecture provides the lowest possible RTO and RPO among all\ndisaster recovery strategies. In this approach, workloads are deployed and actively running in\nmultiple AWS Regions simultaneously. All data is continuously replicated in real time between\nRegions using fully managed replication services, ensuring zero data loss (zero RPO).\nBecause both Regions are active and capable of handling requests, failover between them is\ninstantaneous, meeting the RTO of less than 10 minutes. Amazon Route 53 is used with\nweighted or latency-based routing policies and health checks to automatically route traffic away\nfrom an impaired Region to the healthy Region without manual intervention.\nPilot Light Architecture maintains only a minimal copy of the environment in the secondary\nRegion. It requires time to scale up infrastructure during a disaster, resulting in longer RTO and\npotential data loss (non-zero RPO).\nWarm Standby Architecture keeps partially running infrastructure in the secondary Region.\nAlthough faster than pilot light, it still requires scaling and synchronization, resulting in higher\nRTO and RPO compared to active-active.\nBackup and Restore (option D) relies on periodic backups and restores data when needed. This\napproach has the highest RTO and RPO, unsuitable for mission-critical workloads demanding\nhigh availability and zero data loss.\nTherefore, based on AWS-recommended disaster recovery strategies outlined in the AWS Cloud\nOperations and Disaster Recovery Guide, the Active-Active Multi-Region architecture (Option C)\nis the only approach that guarantees RTO &lt;10 minutes and RPO = 0, achieving continuous\navailability and business continuity across Regions.", "question_text": "A global company runs a critical primary workload in the us-east-1 Region. The company wants to ensure business continuity with minimal downtime in case of a workload failure. The company wants to replicate the workload to a second AWS Region. A CloudOps engineer needs a solution that achieves a recovery time objective (RTO) of less than 10 minutes and a zero recovery point objective (RPO) to meet service level agreements. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '336efa4d05e083cfb24af490a0878715a9783c50baf3660c2bd8dbbaaab6096d', 1392, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (942, 146, 109, 'qblock_pdf', '{"option_a": "Replace ElastiCache (Redis OSS) with ElastiCache (Memcached).", "option_b": "Create an Amazon EventBridge rule to initiate a backup every hour. Restore the backup when necessary.", "option_c": "Create a read replica in a second Availability Zone. Enable Multi-AZ for the ElastiCache (Redis OSS) replication group.", "option_d": "Enable automatic backups. Restore the backups when necessary.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Enabling Multi-AZ with automatic failover for ElastiCache for Redis provides high availability and\nthe lowest possible RTO, as Redis automatically promotes a replica to primary if the primary node\nfails. This ensures near-instant recovery without manual intervention, unlike backup-based\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nsolutions, which involve downtime and manual restores.", "question_text": "A company uses Amazon ElastiCache (Redis OSS) to cache application data. A CloudOps engineer must implement a solution to increase the resilience of the cache. The solution also must minimize the recovery time objective (RTO). Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0108"}', '{"tags": null, "topic": null, "options": [["A", "Replace ElastiCache (Redis OSS) with ElastiCache (Memcached)."], ["B", "Create an Amazon EventBridge rule to initiate a backup every hour. Restore the backup when necessary."], ["C", "Create a read replica in a second Availability Zone. Enable Multi-AZ for the ElastiCache (Redis OSS) replication group."], ["D", "Enable automatic backups. Restore the backups when necessary."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0108"}, "reference": null, "difficulty": "medium", "explanation": "Enabling Multi-AZ with automatic failover for ElastiCache for Redis provides high availability and\nthe lowest possible RTO, as Redis automatically promotes a replica to primary if the primary node\nfails. This ensures near-instant recovery without manual intervention, unlike backup-based\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nsolutions, which involve downtime and manual restores.", "question_text": "A company uses Amazon ElastiCache (Redis OSS) to cache application data. A CloudOps engineer must implement a solution to increase the resilience of the cache. The solution also must minimize the recovery time objective (RTO). Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'duplicate', NULL, 'duplicate of row 40 earlier in this import', '99f7e4f46e17a1d2ed98a2669dad5f035ffd5aff380db37f19ed0835551f4d59', NULL, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:16.257521+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (961, 146, 128, 'qblock_pdf', '{"option_a": "An A record", "option_b": "An AAAA record", "option_c": "An alias record", "option_d": "A CNAME record", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "To route traffic from example.com to an Application Load Balancer (ALB), you must use an alias\nrecord in Amazon Route 53. Alias records are a Route 53–specific extension of DNS that allows\nmapping a domain name directly to AWS resources such as ALBs, CloudFront distributions, and\nS3 websites. Unlike a CNAME record, an alias record works at the zone apex (e.g.,\nexample.com) and does not incur extra DNS lookup charges.", "question_text": "A company has a microservice that runs on a set of Amazon EC2 instances. The EC2 instances run behind an Application Load Balancer (ALB). A CloudOps engineer must use Amazon Route 53 to create a record that maps the ALB URL to example.com. Which type of record will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0127"}', '{"tags": null, "topic": null, "options": [["A", "An A record"], ["B", "An AAAA record"], ["C", "An alias record"], ["D", "A CNAME record"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0127"}, "reference": null, "difficulty": "medium", "explanation": "To route traffic from example.com to an Application Load Balancer (ALB), you must use an alias\nrecord in Amazon Route 53. Alias records are a Route 53–specific extension of DNS that allows\nmapping a domain name directly to AWS resources such as ALBs, CloudFront distributions, and\nS3 websites. Unlike a CNAME record, an alias record works at the zone apex (e.g.,\nexample.com) and does not incur extra DNS lookup charges.", "question_text": "A company has a microservice that runs on a set of Amazon EC2 instances. The EC2 instances run behind an Application Load Balancer (ALB). A CloudOps engineer must use Amazon Route 53 to create a record that maps the ALB URL to example.com. Which type of record will meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'duplicate', NULL, 'duplicate of row 35 earlier in this import', '886de6d114c3d536888feb930fca701b5028aaeb0a5ea4f087a635d420c5aa03', NULL, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:16.257521+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (859, 146, 26, 'qblock_pdf', '{"option_a": "Grant administrators access to the AWS Key Management Service (AWS KMS) key used to encrypt the log files.", "option_b": "Enable CloudTrail log file integrity validation when the trail is created or updated.", "option_c": "Turn on Amazon S3 server access logging for the bucket storing the log files.", "option_d": "Configure the S3 bucket to replicate the log files to another bucket.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "CloudTrail can produce digest files and sign log files to detect tampering. Enabling log file\nintegrity validation ensures that any modification or deletion of delivered log files can be detected\nby verification against the digests and signatures, providing verifiable evidence of tampering or\nnon-tampering for each log file. This is the standard mechanism used to assure SysOps that logs\nhave not been altered after delivery.", "question_text": "A company is using AWS CloudTrail and wants to ensure that SysOps administrators can easily verify that the log files have not been deleted or changed. Which action should a SysOps administrator take to meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0025"}', '{"tags": null, "topic": null, "options": [["A", "Grant administrators access to the AWS Key Management Service (AWS KMS) key used to encrypt the log files."], ["B", "Enable CloudTrail log file integrity validation when the trail is created or updated."], ["C", "Turn on Amazon S3 server access logging for the bucket storing the log files."], ["D", "Configure the S3 bucket to replicate the log files to another bucket."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0025"}, "reference": null, "difficulty": "medium", "explanation": "CloudTrail can produce digest files and sign log files to detect tampering. Enabling log file\nintegrity validation ensures that any modification or deletion of delivered log files can be detected\nby verification against the digests and signatures, providing verifiable evidence of tampering or\nnon-tampering for each log file. This is the standard mechanism used to assure SysOps that logs\nhave not been altered after delivery.", "question_text": "A company is using AWS CloudTrail and wants to ensure that SysOps administrators can easily verify that the log files have not been deleted or changed. Which action should a SysOps administrator take to meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'de6dbaf19e36058bf8e632a4f2894aa5670ae0dc8213808119ac2067fca25fc8', 1375, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (879, 146, 46, 'qblock_pdf', '{"option_a": "Create a CloudWatch alarm that monitors AWS CloudTrail events for the EC2 instance.", "option_b": "Create a CloudWatch alarm that monitors CloudWatch metrics for EC2 instance CPU utilization.", "option_c": "Create an Amazon Simple Notification Service (Amazon SNS) topic to monitor CloudWatch metrics for EC2 instance CPU utilization.", "option_d": "Create a recurring assessment check on the EC2 instance by using Amazon Inspector to detect deviations in CPU utilization.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The user''s symptom is 100% CPU utilization during unresponsiveness, and CloudWatch monitors\nCPUUtilization metrics by default (with optional detailed monitoring). Setting a CloudWatch alarm\non CPU utilization provides real-time detection of high CPU and can trigger automated actions or\nnotifications to respond quickly. This is the standard, scalable way to monitor and alert on CPU\npressure for EC2 instances.", "question_text": "A company hosts a web application on an Amazon EC2 instance. Users report that the web application is occasionally unresponsive. Amazon CloudWatch metrics indicate that the CPU utilization is 100% during these times. A SysOps administrator must implement a solution to monitor for this issue. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0045"}', '{"tags": null, "topic": null, "options": [["A", "Create a CloudWatch alarm that monitors AWS CloudTrail events for the EC2 instance."], ["B", "Create a CloudWatch alarm that monitors CloudWatch metrics for EC2 instance CPU utilization."], ["C", "Create an Amazon Simple Notification Service (Amazon SNS) topic to monitor CloudWatch metrics for EC2 instance CPU utilization."], ["D", "Create a recurring assessment check on the EC2 instance by using Amazon Inspector to detect deviations in CPU utilization."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0045"}, "reference": null, "difficulty": "medium", "explanation": "The user''s symptom is 100% CPU utilization during unresponsiveness, and CloudWatch monitors\nCPUUtilization metrics by default (with optional detailed monitoring). Setting a CloudWatch alarm\non CPU utilization provides real-time detection of high CPU and can trigger automated actions or\nnotifications to respond quickly. This is the standard, scalable way to monitor and alert on CPU\npressure for EC2 instances.", "question_text": "A company hosts a web application on an Amazon EC2 instance. Users report that the web application is occasionally unresponsive. Amazon CloudWatch metrics indicate that the CPU utilization is 100% during these times. A SysOps administrator must implement a solution to monitor for this issue. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '1daa1efc9bae665091cdee208972a6cdae117d25682f3a3b3116d9e03dc0c53e', 1395, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (835, 146, 2, 'qblock_pdf', '{"option_a": "Use AWS CloudTrail to log API events from generative AI workloads. Store the events in CloudTrail Lake. Use SQL-like queries to generate reports.", "option_b": "Use Amazon CloudWatch to capture generative AI application logs. Stream the logs to Amazon OpenSearch Service. Use an OpenSearch dashboard visualization to generate reports.", "option_c": "Use Amazon CloudWatch to log API events from generative AI workloads. Send the events to an Amazon S3 bucket. Use Amazon Athena queries to generate reports.", "option_d": "Use AWS CloudTrail to capture generative AI application logs. Stream the logs to Amazon Managed Service for Apache Flink. Use SQL queries to generate reports.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "As per AWS Cloud Operations, Bedrock, and Governance documentation, AWS CloudTrail is the\nauthoritative service for capturing API activity and audit trails across AWS accounts. For Amazon\nBedrock, CloudTrail records all user-initiated API calls, including interactions with agents,\nknowledge bases, and generative AI model parameters.\nUsing CloudTrail Lake, organizations can store, query, and analyze CloudTrail events directly\nwithout needing to export data. CloudTrail Lake supports SQL-like queries for generating audit\nand compliance reports, enabling the company to retrieve information such as user identity, API\nusage, timestamp, model or agent ID, and invocation parameters.\nIn contrast, CloudWatch focuses on operational metrics and log streaming, not API-level identity\ndata. OpenSearch or Flink would add unnecessary complexity and cost for this use case.\nThus, the AWS-recommended CloudOps best practice is to leverage CloudTrail with CloudTrail\nLake to maintain auditable, queryable API activity for Bedrock workloads, fulfilling governance\nand compliance requirements.", "question_text": "A medical research company uses an Amazon Bedrock powered AI assistant with agents and knowledge bases to provide physicians quick access to medical study protocols. The company needs to generate audit reports that contain user identities, usage data for Bedrock agents, access data for knowledge bases, and interaction parameters. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0001"}', '{"tags": null, "topic": null, "options": [["A", "Use AWS CloudTrail to log API events from generative AI workloads. Store the events in CloudTrail Lake. Use SQL-like queries to generate reports."], ["B", "Use Amazon CloudWatch to capture generative AI application logs. Stream the logs to Amazon OpenSearch Service. Use an OpenSearch dashboard visualization to generate reports."], ["C", "Use Amazon CloudWatch to log API events from generative AI workloads. Send the events to an Amazon S3 bucket. Use Amazon Athena queries to generate reports."], ["D", "Use AWS CloudTrail to capture generative AI application logs. Stream the logs to Amazon Managed Service for Apache Flink. Use SQL queries to generate reports."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0001"}, "reference": null, "difficulty": "medium", "explanation": "As per AWS Cloud Operations, Bedrock, and Governance documentation, AWS CloudTrail is the\nauthoritative service for capturing API activity and audit trails across AWS accounts. For Amazon\nBedrock, CloudTrail records all user-initiated API calls, including interactions with agents,\nknowledge bases, and generative AI model parameters.\nUsing CloudTrail Lake, organizations can store, query, and analyze CloudTrail events directly\nwithout needing to export data. CloudTrail Lake supports SQL-like queries for generating audit\nand compliance reports, enabling the company to retrieve information such as user identity, API\nusage, timestamp, model or agent ID, and invocation parameters.\nIn contrast, CloudWatch focuses on operational metrics and log streaming, not API-level identity\ndata. OpenSearch or Flink would add unnecessary complexity and cost for this use case.\nThus, the AWS-recommended CloudOps best practice is to leverage CloudTrail with CloudTrail\nLake to maintain auditable, queryable API activity for Bedrock workloads, fulfilling governance\nand compliance requirements.", "question_text": "A medical research company uses an Amazon Bedrock powered AI assistant with agents and knowledge bases to provide physicians quick access to medical study protocols. The company needs to generate audit reports that contain user identities, usage data for Bedrock agents, access data for knowledge bases, and interaction parameters. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '067ae263f13392b6606acae02e0398ef2bc37dfc7bfba4fd3bd197cd32ea73bd', 1351, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (836, 146, 3, 'qblock_pdf', '{"option_a": "Create a custom AWS Lambda function to evaluate and remediate all DynamoDB tables. Create an Amazon EventBridge scheduled rule to invoke the Lambda function.", "option_b": "Create a custom AWS Lambda function to evaluate and remediate all DynamoDB tables. Create an AWS Config custom rule to invoke the Lambda function.", "option_c": "Use the required-tags AWS Config managed rule to evaluate all DynamoDB tables for the appropriate tags. Configure an automatic remediation action that uses an AWS Systems Manager Automation custom runbook.", "option_d": "Create an Amazon EventBridge managed rule to evaluate all DynamoDB tables for the appropriate tags. Configure the EventBridge rule to run an AWS Systems Manager Automation custom runbook for remediation. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations, Governance, and Compliance documentation, AWS\nConfig provides managed rules that automatically evaluate resource configurations for\ncompliance. The \"required-tags\" managed rule allows CloudOps teams to specify mandatory tags\n(e.g., Environment, Owner, CostCenter) and automatically detect non-compliant resources such\nas DynamoDB tables.\nFurthermore, AWS Config supports automatic remediation through AWS Systems Manager\nAutomation runbooks, enabling correction actions (for example, adding missing tags) without\nmanual intervention. This automation minimizes operational overhead and ensures continuous\ncompliance across multiple accounts.\nUsing a custom Lambda function (Options A or B) introduces unnecessary management\ncomplexity, while EventBridge rules alone (Option D) do not provide resource compliance\ntracking or historical visibility.\nTherefore, Option C provides the most efficient, fully managed, and compliant CloudOps solution.", "question_text": "A company needs to enforce tagging requirements for Amazon DynamoDB tables in its AWS accounts. A CloudOps engineer must implement a solution to identify and remediate all DynamoDB tables that do not have the appropriate tags. Which solution will meet these requirements with the LEAST operational overhead?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0002"}', '{"tags": null, "topic": null, "options": [["A", "Create a custom AWS Lambda function to evaluate and remediate all DynamoDB tables. Create an Amazon EventBridge scheduled rule to invoke the Lambda function."], ["B", "Create a custom AWS Lambda function to evaluate and remediate all DynamoDB tables. Create an AWS Config custom rule to invoke the Lambda function."], ["C", "Use the required-tags AWS Config managed rule to evaluate all DynamoDB tables for the appropriate tags. Configure an automatic remediation action that uses an AWS Systems Manager Automation custom runbook."], ["D", "Create an Amazon EventBridge managed rule to evaluate all DynamoDB tables for the appropriate tags. Configure the EventBridge rule to run an AWS Systems Manager Automation custom runbook for remediation. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0002"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations, Governance, and Compliance documentation, AWS\nConfig provides managed rules that automatically evaluate resource configurations for\ncompliance. The \"required-tags\" managed rule allows CloudOps teams to specify mandatory tags\n(e.g., Environment, Owner, CostCenter) and automatically detect non-compliant resources such\nas DynamoDB tables.\nFurthermore, AWS Config supports automatic remediation through AWS Systems Manager\nAutomation runbooks, enabling correction actions (for example, adding missing tags) without\nmanual intervention. This automation minimizes operational overhead and ensures continuous\ncompliance across multiple accounts.\nUsing a custom Lambda function (Options A or B) introduces unnecessary management\ncomplexity, while EventBridge rules alone (Option D) do not provide resource compliance\ntracking or historical visibility.\nTherefore, Option C provides the most efficient, fully managed, and compliant CloudOps solution.", "question_text": "A company needs to enforce tagging requirements for Amazon DynamoDB tables in its AWS accounts. A CloudOps engineer must implement a solution to identify and remediate all DynamoDB tables that do not have the appropriate tags. Which solution will meet these requirements with the LEAST operational overhead?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '19e276b58e8e9e19bbde290fe1f25ba818039aff43bd6681fb34f3a7fef05497', 1352, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (837, 146, 4, 'qblock_pdf', '{"option_a": "Create an IAM role that has a policy that allows s3:list* and s3:get* permissions. Assign the role to the EC2 instance. Assign a company employee to download requested PDF files to the EC2 instance and deliver the files to website users. Create an AWS Lambda function to periodically delete local files.", "option_b": "Create an Amazon CloudFront distribution that uses an origin access control (OAC) that points to the S3 bucket. Apply a bucket policy to the bucket to allow connections from the CloudFront distribution. Assign a company employee to provide a download URL that contains the distribution URL and the object path to users when users request PDF files.", "option_c": "Change the S3 bucket permissions to allow public access on the source S3 bucket. Assign a company employee to provide a PDF file URL to users when users request the PDF files.", "option_d": "Deploy an EC2 instance that has an IAM instance profile to a public subnet. Use a signed URL from the EC2 instance to provide temporary access to the S3 bucket for website users.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Per the AWS Cloud Operations, Networking, and Security documentation, the best practice for\nserving private S3 content securely to end users is to use Amazon CloudFront with Origin Access\nControl (OAC).\nOAC enables CloudFront to access S3 buckets privately, even when Block Public Access\nsettings are enabled at the account level. This allows content to be delivered globally and\nsecurely without making the S3 bucket public. The bucket policy explicitly allows access only from\nthe CloudFront distribution, ensuring that users can retrieve PDF files only via CloudFront URLs.\nThis configuration offers:\nAutomatic scalability through CloudFront caching,\nImproved security via private access control,\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nMinimal administration effort with fully managed services.\nOther options require manual handling or make the bucket public, violating AWS security best\npractices.\nTherefore, Option B--using CloudFront with Origin Access Control and a restrictive bucket policy--\nprovides the most secure, efficient, and low-maintenance CloudOps solution.", "question_text": "A company''s website runs on an Amazon EC2 Linux instance. The website needs to serve PDF files from an Amazon S3 bucket. All public access to the S3 bucket is blocked at the account level. The company needs to allow website users to download the PDF files. Which solution will meet these requirements with the LEAST administrative effort?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0003"}', '{"tags": null, "topic": null, "options": [["A", "Create an IAM role that has a policy that allows s3:list* and s3:get* permissions. Assign the role to the EC2 instance. Assign a company employee to download requested PDF files to the EC2 instance and deliver the files to website users. Create an AWS Lambda function to periodically delete local files."], ["B", "Create an Amazon CloudFront distribution that uses an origin access control (OAC) that points to the S3 bucket. Apply a bucket policy to the bucket to allow connections from the CloudFront distribution. Assign a company employee to provide a download URL that contains the distribution URL and the object path to users when users request PDF files."], ["C", "Change the S3 bucket permissions to allow public access on the source S3 bucket. Assign a company employee to provide a PDF file URL to users when users request the PDF files."], ["D", "Deploy an EC2 instance that has an IAM instance profile to a public subnet. Use a signed URL from the EC2 instance to provide temporary access to the S3 bucket for website users."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0003"}, "reference": null, "difficulty": "medium", "explanation": "Per the AWS Cloud Operations, Networking, and Security documentation, the best practice for\nserving private S3 content securely to end users is to use Amazon CloudFront with Origin Access\nControl (OAC).\nOAC enables CloudFront to access S3 buckets privately, even when Block Public Access\nsettings are enabled at the account level. This allows content to be delivered globally and\nsecurely without making the S3 bucket public. The bucket policy explicitly allows access only from\nthe CloudFront distribution, ensuring that users can retrieve PDF files only via CloudFront URLs.\nThis configuration offers:\nAutomatic scalability through CloudFront caching,\nImproved security via private access control,\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nMinimal administration effort with fully managed services.\nOther options require manual handling or make the bucket public, violating AWS security best\npractices.\nTherefore, Option B--using CloudFront with Origin Access Control and a restrictive bucket policy--\nprovides the most secure, efficient, and low-maintenance CloudOps solution.", "question_text": "A company''s website runs on an Amazon EC2 Linux instance. The website needs to serve PDF files from an Amazon S3 bucket. All public access to the S3 bucket is blocked at the account level. The company needs to allow website users to download the PDF files. Which solution will meet these requirements with the LEAST administrative effort?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'bfc72d07e565e464d0f491a73e564acef879d5d24345d1175829918bc657b737', 1353, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (838, 146, 5, 'qblock_pdf', '{"option_a": "Configure Amazon S3 Cross-Region Replication (CRR). Use Amazon S3 live replication to replicate existing objects.", "option_b": "Configure Amazon S3 Cross-Region Replication (CRR). Use S3 Batch Replication to replicate existing objects.", "option_c": "Configure Amazon S3 Cross-Region Replication (CRR). Use S3 Replication Time Control (S3 RTC) to replicate existing objects.", "option_d": "Use S3 Lifecycle rules to move objects to the destination bucket in a second Region.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Per the AWS Cloud Operations and S3 Data Management documentation, Cross-Region\nReplication (CRR) automatically replicates new objects between S3 buckets across Regions.\nHowever, CRR alone does not retroactively replicate existing objects created before replication\nconfiguration. To include such objects, AWS introduced S3 Batch Replication.\nS3 Batch Replication scans the source bucket and replicates all existing objects that were not\ncopied previously. Additionally, it can retry failed replication tasks automatically, ensuring\nregulatory compliance for complete dataset replication.\nS3 Replication Time Control (S3 RTC) guarantees predictable replication times for new objects\nonly-- it does not cover previously stored data. S3 Lifecycle rules (Option D) move or transition\nobjects between storage classes or buckets, but not in a replication context.\nTherefore, the correct solution is to use S3 Cross-Region Replication (CRR) combined with S3\nBatch Replication to ensure all current and future data is synchronized across Regions with retry\ncapability.", "question_text": "A financial services company stores customer images in an Amazon S3 bucket in the us-east-1 Region. To comply with regulations, the company must ensure that all existing objects are replicated to an S3 bucket in a second AWS Region. If an object replication fails, the company must be able to retry replication for the object. What solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0004"}', '{"tags": null, "topic": null, "options": [["A", "Configure Amazon S3 Cross-Region Replication (CRR). Use Amazon S3 live replication to replicate existing objects."], ["B", "Configure Amazon S3 Cross-Region Replication (CRR). Use S3 Batch Replication to replicate existing objects."], ["C", "Configure Amazon S3 Cross-Region Replication (CRR). Use S3 Replication Time Control (S3 RTC) to replicate existing objects."], ["D", "Use S3 Lifecycle rules to move objects to the destination bucket in a second Region."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0004"}, "reference": null, "difficulty": "medium", "explanation": "Per the AWS Cloud Operations and S3 Data Management documentation, Cross-Region\nReplication (CRR) automatically replicates new objects between S3 buckets across Regions.\nHowever, CRR alone does not retroactively replicate existing objects created before replication\nconfiguration. To include such objects, AWS introduced S3 Batch Replication.\nS3 Batch Replication scans the source bucket and replicates all existing objects that were not\ncopied previously. Additionally, it can retry failed replication tasks automatically, ensuring\nregulatory compliance for complete dataset replication.\nS3 Replication Time Control (S3 RTC) guarantees predictable replication times for new objects\nonly-- it does not cover previously stored data. S3 Lifecycle rules (Option D) move or transition\nobjects between storage classes or buckets, but not in a replication context.\nTherefore, the correct solution is to use S3 Cross-Region Replication (CRR) combined with S3\nBatch Replication to ensure all current and future data is synchronized across Regions with retry\ncapability.", "question_text": "A financial services company stores customer images in an Amazon S3 bucket in the us-east-1 Region. To comply with regulations, the company must ensure that all existing objects are replicated to an S3 bucket in a second AWS Region. If an object replication fails, the company must be able to retry replication for the object. What solution will meet these requirements?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '84e70a7fb1a0ff40a1b61e1a1f3cea899cbaefb87fcafbe13b86811e3c8b486c', 1354, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (839, 146, 6, 'qblock_pdf', '{"option_a": "Create a NAT gateway in the public subnet. Create a route from the private subnet to the NAT gateway. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_b": "Create a NAT gateway in the public subnet. Create a route from the public subnet to the NAT gateway.", "option_c": "Create a NAT gateway in the private subnet. Create a route from the public subnet to the NAT gateway.", "option_d": "Create a NAT gateway in the private subnet. Create a route from the private subnet to the NAT gateway.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Networking documentation, instances in a private\nsubnet do not have a direct route to the internet gateway and thus require a NAT gateway for\noutbound internet access.\nThe correct configuration is to create a NAT gateway in the public subnet, associate an Elastic IP\naddress, and then update the private subnet''s route table to send all 0.0.0.0/0 traffic to the NAT\ngateway. This enables instances in the private subnet to initiate outbound connections while\nkeeping inbound traffic blocked for security.\nPlacing the NAT gateway inside the private subnet (Options C or D) prevents connectivity\nbecause it would not have a route to the internet gateway. Configuring routes from the public\nsubnet to the NAT gateway (Option B) does not serve private subnet traffic.\nHence, Option A follows AWS best practices for enabling secure, managed, outbound-only\ninternet access from private resources.", "question_text": "A CloudOps engineer has created a VPC that contains a public subnet and a private subnet. Amazon EC2 instances that were launched in the private subnet cannot access the internet. The default network ACL is active on all subnets in the VPC, and all security groups allow outbound traffic. Which solution will provide the EC2 instances in the private subnet with access to the internet?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0005"}', '{"tags": null, "topic": null, "options": [["A", "Create a NAT gateway in the public subnet. Create a route from the private subnet to the NAT gateway. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["B", "Create a NAT gateway in the public subnet. Create a route from the public subnet to the NAT gateway."], ["C", "Create a NAT gateway in the private subnet. Create a route from the public subnet to the NAT gateway."], ["D", "Create a NAT gateway in the private subnet. Create a route from the private subnet to the NAT gateway."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0005"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Networking documentation, instances in a private\nsubnet do not have a direct route to the internet gateway and thus require a NAT gateway for\noutbound internet access.\nThe correct configuration is to create a NAT gateway in the public subnet, associate an Elastic IP\naddress, and then update the private subnet''s route table to send all 0.0.0.0/0 traffic to the NAT\ngateway. This enables instances in the private subnet to initiate outbound connections while\nkeeping inbound traffic blocked for security.\nPlacing the NAT gateway inside the private subnet (Options C or D) prevents connectivity\nbecause it would not have a route to the internet gateway. Configuring routes from the public\nsubnet to the NAT gateway (Option B) does not serve private subnet traffic.\nHence, Option A follows AWS best practices for enabling secure, managed, outbound-only\ninternet access from private resources.", "question_text": "A CloudOps engineer has created a VPC that contains a public subnet and a private subnet. Amazon EC2 instances that were launched in the private subnet cannot access the internet. The default network ACL is active on all subnets in the VPC, and all security groups allow outbound traffic. Which solution will provide the EC2 instances in the private subnet with access to the internet?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '0fda0c998835e4861e940a018611edf4ff65f5478aa453d91f1b00e4436fd601', 1355, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (840, 146, 7, 'qblock_pdf', '{"option_a": "Create a user data script that sends an email message through a smart host connector. Include the architecture team''s email address in the user data script as the recipient. Ensure that all new EC2 instances include the user data script as part of a standardized build process.", "option_b": "Create an Amazon Simple Notification Service (Amazon SNS) topic and a subscription that uses the email protocol. Enter the architecture team''s email address as the subscriber. Create an Amazon EventBridge rule that reacts when EC2 instances are launched. Specify the SNS topic as the rule''s target.", "option_c": "Create an Amazon Simple Queue Service (Amazon SQS) queue and a subscription that uses the email protocol. Enter the architecture team''s email address as the subscriber. Create an Amazon EventBridge rule that reacts when EC2 instances are launched. Specify the SQS queue as the rule''s target.", "option_d": "Create an Amazon Simple Notification Service (Amazon SNS) topic. Configure AWS Systems Manager to publish EC2 events to the SNS topic. Create an AWS Lambda function to poll the SNS topic. Configure the Lambda function to send any messages to the architecture team''s email address.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "As per the AWS Cloud Operations and Event Monitoring documentation, the most efficient\nmethod for event-driven notification is to use Amazon EventBridge to detect specific EC2 API\nevents and trigger a Simple Notification Service (SNS) alert.\nEventBridge continuously monitors AWS service events, including RunInstances, which signals\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nthe creation of new EC2 instances. When such an event occurs, EventBridge sends it to an SNS\ntopic, which then immediately emails subscribed recipients -- in this case, the architecture team.\nThis combination provides real-time, serverless notifications with minimal management. SQS\n(Option C) is designed for queue-based processing, not direct user alerts. User data scripts\n(Option A) and custom polling with Lambda (Option D) introduce unnecessary operational\ncomplexity and latency.\nHence, Option B is the correct and AWS-recommended CloudOps design for immediate launch\nnotifications.", "question_text": "A company''s architecture team must receive immediate email notifications whenever new Amazon EC2 instances are launched in the company''s main AWS production account. What should a CloudOps engineer do to meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0006"}', '{"tags": null, "topic": null, "options": [["A", "Create a user data script that sends an email message through a smart host connector. Include the architecture team''s email address in the user data script as the recipient. Ensure that all new EC2 instances include the user data script as part of a standardized build process."], ["B", "Create an Amazon Simple Notification Service (Amazon SNS) topic and a subscription that uses the email protocol. Enter the architecture team''s email address as the subscriber. Create an Amazon EventBridge rule that reacts when EC2 instances are launched. Specify the SNS topic as the rule''s target."], ["C", "Create an Amazon Simple Queue Service (Amazon SQS) queue and a subscription that uses the email protocol. Enter the architecture team''s email address as the subscriber. Create an Amazon EventBridge rule that reacts when EC2 instances are launched. Specify the SQS queue as the rule''s target."], ["D", "Create an Amazon Simple Notification Service (Amazon SNS) topic. Configure AWS Systems Manager to publish EC2 events to the SNS topic. Create an AWS Lambda function to poll the SNS topic. Configure the Lambda function to send any messages to the architecture team''s email address."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0006"}, "reference": null, "difficulty": "medium", "explanation": "As per the AWS Cloud Operations and Event Monitoring documentation, the most efficient\nmethod for event-driven notification is to use Amazon EventBridge to detect specific EC2 API\nevents and trigger a Simple Notification Service (SNS) alert.\nEventBridge continuously monitors AWS service events, including RunInstances, which signals\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nthe creation of new EC2 instances. When such an event occurs, EventBridge sends it to an SNS\ntopic, which then immediately emails subscribed recipients -- in this case, the architecture team.\nThis combination provides real-time, serverless notifications with minimal management. SQS\n(Option C) is designed for queue-based processing, not direct user alerts. User data scripts\n(Option A) and custom polling with Lambda (Option D) introduce unnecessary operational\ncomplexity and latency.\nHence, Option B is the correct and AWS-recommended CloudOps design for immediate launch\nnotifications.", "question_text": "A company''s architecture team must receive immediate email notifications whenever new Amazon EC2 instances are launched in the company''s main AWS production account. What should a CloudOps engineer do to meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '965911a00c3ed70cfc1e593eae4bc1cf524a49f4a5a2c7203e29bef34e37c78e', 1356, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (841, 146, 8, 'qblock_pdf', '{"option_a": "Use the Aurora Backtrack feature to rewind the database to a specified time, 2 hours in the past.", "option_b": "Perform a point-in-time recovery on the existing database to restore the database to a specified point in time, 2 hours in the past.", "option_c": "Perform a point-in-time recovery and create a new database to restore the database to a specified point in time, 2 hours in the past. Reconfigure the application to use a new database endpoint.", "option_d": "Create a new Aurora cluster. Choose the Restore data from S3 bucket option. Choose log files up to the failure time 2 hours in the past.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "In the AWS Cloud Operations and Aurora documentation, when data loss occurs due to human\nerror such as dropped tables, Point-in-Time Recovery (PITR) is the recommended method for\nrestoration. PITR creates a new Aurora cluster restored to a specific time before the failure.\nThe restored cluster has a new endpoint that must be reconfigured in the application to resume\nnormal operations. AWS does not support performing PITR directly on an existing production\ndatabase because that would overwrite current data.\nAurora Backtrack (Option A) applies only to Aurora MySQL, not PostgreSQL. Option B is\nincorrect because PITR cannot be executed in place. Option D refers to an import process from\nS3, which is unrelated to time-based recovery.\nHence, Option C is correct and follows the AWS CloudOps standard recovery pattern for\nPostgreSQL workloads.", "question_text": "A company runs an application on Amazon EC2 that connects to an Amazon Aurora PostgreSQL database. A developer accidentally drops a table from the database, causing application errors. Two hours later, a CloudOps engineer needs to recover the data and make the application functional again. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0007"}', '{"tags": null, "topic": null, "options": [["A", "Use the Aurora Backtrack feature to rewind the database to a specified time, 2 hours in the past."], ["B", "Perform a point-in-time recovery on the existing database to restore the database to a specified point in time, 2 hours in the past."], ["C", "Perform a point-in-time recovery and create a new database to restore the database to a specified point in time, 2 hours in the past. Reconfigure the application to use a new database endpoint."], ["D", "Create a new Aurora cluster. Choose the Restore data from S3 bucket option. Choose log files up to the failure time 2 hours in the past."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0007"}, "reference": null, "difficulty": "medium", "explanation": "In the AWS Cloud Operations and Aurora documentation, when data loss occurs due to human\nerror such as dropped tables, Point-in-Time Recovery (PITR) is the recommended method for\nrestoration. PITR creates a new Aurora cluster restored to a specific time before the failure.\nThe restored cluster has a new endpoint that must be reconfigured in the application to resume\nnormal operations. AWS does not support performing PITR directly on an existing production\ndatabase because that would overwrite current data.\nAurora Backtrack (Option A) applies only to Aurora MySQL, not PostgreSQL. Option B is\nincorrect because PITR cannot be executed in place. Option D refers to an import process from\nS3, which is unrelated to time-based recovery.\nHence, Option C is correct and follows the AWS CloudOps standard recovery pattern for\nPostgreSQL workloads.", "question_text": "A company runs an application on Amazon EC2 that connects to an Amazon Aurora PostgreSQL database. A developer accidentally drops a table from the database, causing application errors. Two hours later, a CloudOps engineer needs to recover the data and make the application functional again. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '09a8ffe891ff2285ee52d9696f576a001c33a0166a8dd4c8d8326f11f68ad1d7', 1357, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (842, 146, 9, 'qblock_pdf', '{"option_a": "Create an Aurora Replica. Promote the replica to replace the primary DB instance.", "option_b": "Create an AWS Lambda function to restore an automatic backup to the existing DB cluster.", "option_c": "Use backtracking to rewind the existing DB cluster to the desired recovery point.", "option_d": "Use point-in-time recovery to restore the existing DB cluster to the desired recovery point.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "As documented in AWS Cloud Operations and Database Recovery, Aurora Backtrack allows you\nto rewind the existing database cluster to a chosen point in time without creating a new cluster.\nThis feature supports fine-grained rollback for accidental data changes, making it ideal for\nscenarios like table deletions or logical corruption.\nBacktracking maintains continuous transaction logs and permits rewinding within a configurable\nwindow (up to 72 hours). It does not require creating a new cluster or endpoint, and it preserves\nthe same production environment, fulfilling the operational requirement for in-place recovery.\nIn contrast, Point-in-Time Recovery (Option D) always creates a new cluster, while replica\npromotion (Option A) and Lambda restoration (Option B) are unrelated to immediate rollback\noperations.\nTherefore, Option C, using Aurora Backtrack, best meets the requirement for same-cluster\nrestoration and minimal downtime.", "question_text": "A company is using an Amazon Aurora MySQL DB cluster that has point-in-time recovery, backtracking, and automatic backup enabled. A CloudOps engineer needs to roll back the DB cluster to a specific recovery point within the previous 72 hours. Restores must be completed in the same production DB cluster. Which solution will meet these requirements? Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0008"}', '{"tags": null, "topic": null, "options": [["A", "Create an Aurora Replica. Promote the replica to replace the primary DB instance."], ["B", "Create an AWS Lambda function to restore an automatic backup to the existing DB cluster."], ["C", "Use backtracking to rewind the existing DB cluster to the desired recovery point."], ["D", "Use point-in-time recovery to restore the existing DB cluster to the desired recovery point."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0008"}, "reference": null, "difficulty": "medium", "explanation": "As documented in AWS Cloud Operations and Database Recovery, Aurora Backtrack allows you\nto rewind the existing database cluster to a chosen point in time without creating a new cluster.\nThis feature supports fine-grained rollback for accidental data changes, making it ideal for\nscenarios like table deletions or logical corruption.\nBacktracking maintains continuous transaction logs and permits rewinding within a configurable\nwindow (up to 72 hours). It does not require creating a new cluster or endpoint, and it preserves\nthe same production environment, fulfilling the operational requirement for in-place recovery.\nIn contrast, Point-in-Time Recovery (Option D) always creates a new cluster, while replica\npromotion (Option A) and Lambda restoration (Option B) are unrelated to immediate rollback\noperations.\nTherefore, Option C, using Aurora Backtrack, best meets the requirement for same-cluster\nrestoration and minimal downtime.", "question_text": "A company is using an Amazon Aurora MySQL DB cluster that has point-in-time recovery, backtracking, and automatic backup enabled. A CloudOps engineer needs to roll back the DB cluster to a specific recovery point within the previous 72 hours. Restores must be completed in the same production DB cluster. Which solution will meet these requirements? Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'd37313010c078f146b3f2456819582914a1d03ef866073e83fb6648637c0063b', 1358, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (843, 146, 10, 'qblock_pdf', '{"option_a": "Deploy and configure the Amazon CloudWatch agent on the EC2 instances to log to a CloudWatch log group. Create a metric filter on the target CloudWatch log group. Create a CloudWatch alarm that publishes to an Amazon Simple Notification Service (Amazon SNS) topic that has an email subscription.", "option_b": "Create a cron job on the EC2 instances to identify errors and push the errors to an Amazon CloudWatch metric filter. Configure the filter to publish to an Amazon Simple Notification Service (Amazon SNS) topic that has an SMS subscription.", "option_c": "Deploy an AWS Lambda function that pushes the errors directly to Amazon CloudWatch Logs. Configure the Lambda function to run every time the log file is updated on disk.", "option_d": "Create an Auto Scaling lifecycle hook that invokes an EC2-based script to identify errors. Configure the script to push the error messages to an Amazon CloudWatch log group when the EC2 instances scale in. Create a CloudWatch alarm that publishes to an Amazon Simple Notification Service (Amazon SNS) topic that has an email subscription when the number of error messages exceeds a threshold.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Monitoring documentation specifies that the Amazon\nCloudWatch Agent is the recommended tool for collecting system and application logs from EC2\ninstances. The agent pushes these logs into a centralized CloudWatch Logs group, providing\ndurable storage and real-time monitoring.\nOnce the logs are centralized, a CloudWatch Metric Filter can be configured to search for specific\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nerror keywords (for example, \"ERROR\" or \"FAILURE\"). This filter transforms matching log entries\ninto custom metrics. From there, a CloudWatch Alarm can monitor the metric threshold and\npublish notifications to an Amazon SNS topic, which can send email or SMS alerts to subscribed\nrecipients.\nThis combination provides a fully automated, managed, and serverless solution for log\naggregation and error alerting. It eliminates the need for manual cron jobs (Option B), custom\nscripts (Option D), or Lambda-based log streaming (Option C).", "question_text": "An application runs on Amazon EC2 instances that are in an Auto Scaling group. A CloudOps engineer needs to implement a solution that provides a central storage location for errors that the application logs to disk. The solution must also provide an alert when the application logs an error. What should the CloudOps engineer do to meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0009"}', '{"tags": null, "topic": null, "options": [["A", "Deploy and configure the Amazon CloudWatch agent on the EC2 instances to log to a CloudWatch log group. Create a metric filter on the target CloudWatch log group. Create a CloudWatch alarm that publishes to an Amazon Simple Notification Service (Amazon SNS) topic that has an email subscription."], ["B", "Create a cron job on the EC2 instances to identify errors and push the errors to an Amazon CloudWatch metric filter. Configure the filter to publish to an Amazon Simple Notification Service (Amazon SNS) topic that has an SMS subscription."], ["C", "Deploy an AWS Lambda function that pushes the errors directly to Amazon CloudWatch Logs. Configure the Lambda function to run every time the log file is updated on disk."], ["D", "Create an Auto Scaling lifecycle hook that invokes an EC2-based script to identify errors. Configure the script to push the error messages to an Amazon CloudWatch log group when the EC2 instances scale in. Create a CloudWatch alarm that publishes to an Amazon Simple Notification Service (Amazon SNS) topic that has an email subscription when the number of error messages exceeds a threshold."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0009"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Monitoring documentation specifies that the Amazon\nCloudWatch Agent is the recommended tool for collecting system and application logs from EC2\ninstances. The agent pushes these logs into a centralized CloudWatch Logs group, providing\ndurable storage and real-time monitoring.\nOnce the logs are centralized, a CloudWatch Metric Filter can be configured to search for specific\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nerror keywords (for example, \"ERROR\" or \"FAILURE\"). This filter transforms matching log entries\ninto custom metrics. From there, a CloudWatch Alarm can monitor the metric threshold and\npublish notifications to an Amazon SNS topic, which can send email or SMS alerts to subscribed\nrecipients.\nThis combination provides a fully automated, managed, and serverless solution for log\naggregation and error alerting. It eliminates the need for manual cron jobs (Option B), custom\nscripts (Option D), or Lambda-based log streaming (Option C).", "question_text": "An application runs on Amazon EC2 instances that are in an Auto Scaling group. A CloudOps engineer needs to implement a solution that provides a central storage location for errors that the application logs to disk. The solution must also provide an alert when the application logs an error. What should the CloudOps engineer do to meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'de9cbf3dc905d5c51b23548099ff7e2d87fbcaa956e24498241f07274c56c38b', 1359, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (844, 146, 11, 'qblock_pdf', '{"option_a": "Add an inbound rule for port 22 in the security group associated with the Ubuntu instance.", "option_b": "Assign the AmazonSSMManagedInstanceCore managed policy to the EC2 instance profile for the Ubuntu instance.", "option_c": "Configure the SSM Agent to log in with a user name of \"ubuntu\".", "option_d": "Generate a new key pair, configure Session Manager to use this new key pair, and provide the private key to the users.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to AWS Cloud Operations and Systems Manager documentation, Session Manager\nrequires that each managed instance be associated with an IAM instance profile that grants\nSystems Manager core permissions. The required permissions are provided by the\nAmazonSSMManagedInstanceCore AWS-managed policy.\nIf this policy is missing or misconfigured, the Systems Manager Agent (SSM Agent) cannot\ncommunicate with the Systems Manager service, causing connection failures even if the agent is\ninstalled and running. This explains why other instances work--those instances likely have the\ncorrect IAM role attached.\nEnabling port 22 (Option A) violates the company''s security policy, while configuring user names\n(Option C) and key pairs (Option D) are irrelevant because Session Manager operates over\nsecure API channels, not SSH keys.\nTherefore, the correct resolution is to attach or update the instance profile with the\nAmazonSSMManagedInstanceCore policy, restoring Session Manager connectivity.", "question_text": "A company''s security policy prohibits connecting to Amazon EC2 instances through SSH and RDP. Instead, staff must use AWS Systems Manager Session Manager. Users report they cannot connect to one Ubuntu instance, even though they can connect to others. What should a CloudOps engineer do to resolve this issue?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0010"}', '{"tags": null, "topic": null, "options": [["A", "Add an inbound rule for port 22 in the security group associated with the Ubuntu instance."], ["B", "Assign the AmazonSSMManagedInstanceCore managed policy to the EC2 instance profile for the Ubuntu instance."], ["C", "Configure the SSM Agent to log in with a user name of \"ubuntu\"."], ["D", "Generate a new key pair, configure Session Manager to use this new key pair, and provide the private key to the users."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0010"}, "reference": null, "difficulty": "medium", "explanation": "According to AWS Cloud Operations and Systems Manager documentation, Session Manager\nrequires that each managed instance be associated with an IAM instance profile that grants\nSystems Manager core permissions. The required permissions are provided by the\nAmazonSSMManagedInstanceCore AWS-managed policy.\nIf this policy is missing or misconfigured, the Systems Manager Agent (SSM Agent) cannot\ncommunicate with the Systems Manager service, causing connection failures even if the agent is\ninstalled and running. This explains why other instances work--those instances likely have the\ncorrect IAM role attached.\nEnabling port 22 (Option A) violates the company''s security policy, while configuring user names\n(Option C) and key pairs (Option D) are irrelevant because Session Manager operates over\nsecure API channels, not SSH keys.\nTherefore, the correct resolution is to attach or update the instance profile with the\nAmazonSSMManagedInstanceCore policy, restoring Session Manager connectivity.", "question_text": "A company''s security policy prohibits connecting to Amazon EC2 instances through SSH and RDP. Instead, staff must use AWS Systems Manager Session Manager. Users report they cannot connect to one Ubuntu instance, even though they can connect to others. What should a CloudOps engineer do to resolve this issue?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'f059a96c096d0fc9e3203f770424e64d559989ec4ae0e19393191467cf1f160b', 1360, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (845, 146, 12, 'qblock_pdf', '{"option_a": "Deploy AWS Shield Advanced in front of the ALB. Enable SQL injection filtering.", "option_b": "Deploy AWS Shield Standard in front of the ALB. Enable SQL injection filtering.", "option_c": "Deploy a vulnerability scanner on each EC2 instance. Continuously scan the application code.", "option_d": "Deploy AWS WAF in front of the ALB. Subscribe to an AWS Managed Rule for SQL injection Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com filtering.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Security documentation confirms that AWS WAF (Web\nApplication Firewall) is designed to protect web applications from application-layer threats,\nincluding SQL injection, cross-site scripting (XSS), and other OWASP Top 10 vulnerabilities.\nWhen integrated with an Application Load Balancer, AWS WAF inspects incoming traffic using\nrule groups. The AWS Managed Rules for SQL Injection Protection provide preconfigured,\ncontinuously updated filters that detect and block malicious SQL patterns.\nAWS Shield (Standard or Advanced) defends against DDoS attacks, not application-layer SQL\nattacks, and vulnerability scanners (Option C) only detect, not prevent, exploitation.\nThus, Option D provides the correct, managed, and automated protection aligned with AWS best\npractices.", "question_text": "A company deploys an application on Amazon EC2 instances in an Auto Scaling group behind an Application Load Balancer (ALB). The company wants to protect the application from SQL injection attacks. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0011"}', '{"tags": null, "topic": null, "options": [["A", "Deploy AWS Shield Advanced in front of the ALB. Enable SQL injection filtering."], ["B", "Deploy AWS Shield Standard in front of the ALB. Enable SQL injection filtering."], ["C", "Deploy a vulnerability scanner on each EC2 instance. Continuously scan the application code."], ["D", "Deploy AWS WAF in front of the ALB. Subscribe to an AWS Managed Rule for SQL injection Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com filtering."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0011"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Security documentation confirms that AWS WAF (Web\nApplication Firewall) is designed to protect web applications from application-layer threats,\nincluding SQL injection, cross-site scripting (XSS), and other OWASP Top 10 vulnerabilities.\nWhen integrated with an Application Load Balancer, AWS WAF inspects incoming traffic using\nrule groups. The AWS Managed Rules for SQL Injection Protection provide preconfigured,\ncontinuously updated filters that detect and block malicious SQL patterns.\nAWS Shield (Standard or Advanced) defends against DDoS attacks, not application-layer SQL\nattacks, and vulnerability scanners (Option C) only detect, not prevent, exploitation.\nThus, Option D provides the correct, managed, and automated protection aligned with AWS best\npractices.", "question_text": "A company deploys an application on Amazon EC2 instances in an Auto Scaling group behind an Application Load Balancer (ALB). The company wants to protect the application from SQL injection attacks. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'c6d1dae1b40276cac3e8c8504d0a8deda9d7f234b997073329a18a826caf4ea8', 1361, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (846, 146, 13, 'qblock_pdf', '{"option_a": "Use Amazon Athena to query the Amazon CloudWatch logs that are associated with the Lambda function.", "option_b": "Use Amazon Athena to query the AWS CloudTrail logs that are associated with the Lambda function.", "option_c": "Use Amazon CloudWatch Logs Insights to query the associated Lambda function logs.", "option_d": "adds unnecessary operational complexity. Thus, Option C provides the most efficient and native AWS CloudOps approach for rapid Lambda error analysis.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Monitoring documentation states that Amazon CloudWatch Logs\nInsights provides a purpose-built query engine for analyzing and visualizing log data directly\nwithin CloudWatch. For Lambda, all invocation results (including errors) are automatically logged\nto CloudWatch Logs.\nBy querying these logs with CloudWatch Logs Insights, the CloudOps engineer can efficiently\ncount the number of \"ERROR\" or \"Exception\" occurrences over the past 7 days using simple\nSQL-like commands. This method is serverless, cost-efficient, and real-time.\nAthena (Options A and B) would require exporting data to Amazon S3, and OpenSearch (Option", "question_text": "An AWS Lambda function is intermittently failing several times a day. A CloudOps engineer must find out how often this error occurred in the last 7 days. Which action will meet this requirement in the MOST operationally efficient manner?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0012"}', '{"tags": null, "topic": null, "options": [["A", "Use Amazon Athena to query the Amazon CloudWatch logs that are associated with the Lambda function."], ["B", "Use Amazon Athena to query the AWS CloudTrail logs that are associated with the Lambda function."], ["C", "Use Amazon CloudWatch Logs Insights to query the associated Lambda function logs."], ["D", "adds unnecessary operational complexity. Thus, Option C provides the most efficient and native AWS CloudOps approach for rapid Lambda error analysis."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0012"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Monitoring documentation states that Amazon CloudWatch Logs\nInsights provides a purpose-built query engine for analyzing and visualizing log data directly\nwithin CloudWatch. For Lambda, all invocation results (including errors) are automatically logged\nto CloudWatch Logs.\nBy querying these logs with CloudWatch Logs Insights, the CloudOps engineer can efficiently\ncount the number of \"ERROR\" or \"Exception\" occurrences over the past 7 days using simple\nSQL-like commands. This method is serverless, cost-efficient, and real-time.\nAthena (Options A and B) would require exporting data to Amazon S3, and OpenSearch (Option", "question_text": "An AWS Lambda function is intermittently failing several times a day. A CloudOps engineer must find out how often this error occurred in the last 7 days. Which action will meet this requirement in the MOST operationally efficient manner?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '821a521b6478bb482ecc4b623493e0e574a331e674d7e1b1a527e3777f79cf6c', 1362, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (847, 146, 14, 'qblock_pdf', '{"option_a": "Configure an IAM policy that denies the s3:DeleteObject action for all users. Three months after an object is written, remove the policy.", "option_b": "Enable S3 Object Lock on a new S3 bucket in compliance mode. Place all backups in the new S3 bucket with a retention period of 3 months.", "option_c": "Enable S3 Versioning on the existing S3 bucket. Configure S3 Lifecycle rules to protect the backups.", "option_d": "Enable S3 Object Lock on a new S3 bucket in governance mode. Place all backups in the new S3 bucket with a retention period of 3 months.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Per the AWS Cloud Operations and Data Protection documentation, S3 Object Lock enforces\nwrite- once-read-many (WORM) protection on objects for a defined retention period.\nThere are two modes:\nCompliance mode: Even the root user cannot delete or modify objects during the retention period.\nGovernance mode: Privileged users with special permissions can override lock settings.\nFor regulatory or audit requirements that prohibit deletion, Compliance mode is the correct\nchoice. When configured with a 3-month retention period, all backup objects are protected from\ndeletion until expiration, ensuring compliance with data retention mandates.\nVersioning (Option C) alone does not prevent deletion. IAM-based restrictions (Option A) lack\ntime-based enforcement and require manual intervention. Governance mode (Option D) is less\nstrict and unsuitable for regulatory retention.\nThus, Option B is the correct CloudOps solution for immutable S3 backups.", "question_text": "A company is storing backups in an Amazon S3 bucket. These backups must not be deleted for at least 3 months after creation. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com What should the CloudOps engineer do?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0013"}', '{"tags": null, "topic": null, "options": [["A", "Configure an IAM policy that denies the s3:DeleteObject action for all users. Three months after an object is written, remove the policy."], ["B", "Enable S3 Object Lock on a new S3 bucket in compliance mode. Place all backups in the new S3 bucket with a retention period of 3 months."], ["C", "Enable S3 Versioning on the existing S3 bucket. Configure S3 Lifecycle rules to protect the backups."], ["D", "Enable S3 Object Lock on a new S3 bucket in governance mode. Place all backups in the new S3 bucket with a retention period of 3 months."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0013"}, "reference": null, "difficulty": "medium", "explanation": "Per the AWS Cloud Operations and Data Protection documentation, S3 Object Lock enforces\nwrite- once-read-many (WORM) protection on objects for a defined retention period.\nThere are two modes:\nCompliance mode: Even the root user cannot delete or modify objects during the retention period.\nGovernance mode: Privileged users with special permissions can override lock settings.\nFor regulatory or audit requirements that prohibit deletion, Compliance mode is the correct\nchoice. When configured with a 3-month retention period, all backup objects are protected from\ndeletion until expiration, ensuring compliance with data retention mandates.\nVersioning (Option C) alone does not prevent deletion. IAM-based restrictions (Option A) lack\ntime-based enforcement and require manual intervention. Governance mode (Option D) is less\nstrict and unsuitable for regulatory retention.\nThus, Option B is the correct CloudOps solution for immutable S3 backups.", "question_text": "A company is storing backups in an Amazon S3 bucket. These backups must not be deleted for at least 3 months after creation. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com What should the CloudOps engineer do?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'e6d9de8b474ec1b1f40dd200b1a682afa3f49c219e318bbaaed0a8d71b495f2c', 1363, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (849, 146, 16, 'qblock_pdf', '{"option_a": "Enable organizational view in AWS Health.", "option_b": "Configure the Health Dashboard in each account to forward events to a central AWS CloudTrail log.", "option_c": "Create an AWS Lambda function to query the AWS Health API and write all events to an Amazon DynamoDB table.", "option_d": "Use the AWS Health API to write events to an Amazon DynamoDB table.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Governance documentation defines that enabling Organizational\nView in AWS Health allows the management account in AWS Organizations to view and\naggregate health events from all member accounts.\nThis feature provides a single-pane-of-glass view of service health issues, account-specific\nevents, and planned maintenance across the organization -- without requiring additional\nautomation or data pipelines.\nAlternative options (B, C, and D) require custom integration and ongoing maintenance. CloudTrail\ndoes not natively forward AWS Health events, and custom Lambda or DynamoDB approaches\nincrease complexity.\nTherefore, Option A -- enabling the Organizational View feature in AWS Health -- is the most\noperationally efficient and AWS-recommended solution.", "question_text": "A company''s CloudOps engineer monitors multiple AWS accounts in an organization and checks each account''s AWS Health Dashboard. After adding 10 new accounts, the engineer wants to consolidate health alerts from all accounts. Which solution meets this requirement with the least operational effort?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0015"}', '{"tags": null, "topic": null, "options": [["A", "Enable organizational view in AWS Health."], ["B", "Configure the Health Dashboard in each account to forward events to a central AWS CloudTrail log."], ["C", "Create an AWS Lambda function to query the AWS Health API and write all events to an Amazon DynamoDB table."], ["D", "Use the AWS Health API to write events to an Amazon DynamoDB table."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0015"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Governance documentation defines that enabling Organizational\nView in AWS Health allows the management account in AWS Organizations to view and\naggregate health events from all member accounts.\nThis feature provides a single-pane-of-glass view of service health issues, account-specific\nevents, and planned maintenance across the organization -- without requiring additional\nautomation or data pipelines.\nAlternative options (B, C, and D) require custom integration and ongoing maintenance. CloudTrail\ndoes not natively forward AWS Health events, and custom Lambda or DynamoDB approaches\nincrease complexity.\nTherefore, Option A -- enabling the Organizational View feature in AWS Health -- is the most\noperationally efficient and AWS-recommended solution.", "question_text": "A company''s CloudOps engineer monitors multiple AWS accounts in an organization and checks each account''s AWS Health Dashboard. After adding 10 new accounts, the engineer wants to consolidate health alerts from all accounts. Which solution meets this requirement with the least operational effort?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '744747e6dfa42dbecc728100165315936929b8eff56f42fad931bd67031b54b3', 1365, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (850, 146, 17, 'qblock_pdf', '{"option_a": "A copy of the IAM Identity Center SAML metadata", "option_b": "The IdP metadata, including the public X.509 certificate", "option_c": "The IP address of the IdP", "option_d": "Root access to the management account", "option_e": "Administrative permissions to the member accounts of the organization Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Identity Management documentation, when\nconfiguring federation between IAM Identity Center (formerly AWS SSO) and an external SAML\n2.0 identity provider, two key prerequisites are required:\nThe IAM Identity Center SAML metadata file -- This is uploaded to the external IdP to establish\ntrust, define SAML endpoints, and enable identity federation.\nThe IdP metadata (including the public X.509 certificate) -- This information is imported into IAM\nIdentity Center to validate authentication assertions and encryption signatures.\nIAM Identity Center and the IdP exchange this metadata to mutually establish secure,\nbidirectional federation.\nNetwork-level details such as IP addresses (Option C) are unnecessary. Root access (Option D)\nor permissions to member accounts (Option E) are not required; only Control Tower or IAM\nadministrative permissions in the management account are needed for setup.\nThus, the correct answer is A and B -- the SAML metadata from both sides is required for\nfederation.", "question_text": "A company that uses AWS Organizations recently implemented AWS Control Tower. The company now needs to centralize identity management. A CloudOps engineer must federate AWS IAM Identity Center with an external SAML 2.0 identity provider (IdP) to centrally manage access to all AWS accounts and cloud applications. Which prerequisites must the CloudOps engineer have so that the CloudOps engineer can connect to the external IdP? (Select TWO.)", "source_format": "qblock_pdf", "correct_answer": "AB", "external_question_id": "Q0016"}', '{"tags": null, "topic": null, "options": [["A", "A copy of the IAM Identity Center SAML metadata"], ["B", "The IdP metadata, including the public X.509 certificate"], ["C", "The IP address of the IdP"], ["D", "Root access to the management account"], ["E", "Administrative permissions to the member accounts of the organization Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0016"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Identity Management documentation, when\nconfiguring federation between IAM Identity Center (formerly AWS SSO) and an external SAML\n2.0 identity provider, two key prerequisites are required:\nThe IAM Identity Center SAML metadata file -- This is uploaded to the external IdP to establish\ntrust, define SAML endpoints, and enable identity federation.\nThe IdP metadata (including the public X.509 certificate) -- This information is imported into IAM\nIdentity Center to validate authentication assertions and encryption signatures.\nIAM Identity Center and the IdP exchange this metadata to mutually establish secure,\nbidirectional federation.\nNetwork-level details such as IP addresses (Option C) are unnecessary. Root access (Option D)\nor permissions to member accounts (Option E) are not required; only Control Tower or IAM\nadministrative permissions in the management account are needed for setup.\nThus, the correct answer is A and B -- the SAML metadata from both sides is required for\nfederation.", "question_text": "A company that uses AWS Organizations recently implemented AWS Control Tower. The company now needs to centralize identity management. A CloudOps engineer must federate AWS IAM Identity Center with an external SAML 2.0 identity provider (IdP) to centrally manage access to all AWS accounts and cloud applications. Which prerequisites must the CloudOps engineer have so that the CloudOps engineer can connect to the external IdP? (Select TWO.)", "question_type": "multiple", "correct_answer": ["A", "B"]}', 'imported', NULL, NULL, '6c58c2aedca7a7bba3d334feadac1e880c92547cd8b154205e046ccbf4c2a5c4', 1366, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (851, 146, 18, 'qblock_pdf', '{"option_a": "Configure the existing EventBridge event to stop the EC2 instances that have the exposed port.", "option_b": "Create a cron job for the FTP server to invoke an AWS Lambda function. Configure the Lambda function to modify the security group of the identified EC2 instances and to remove the instances that allow public access.", "option_c": "Create a cron job for the FTP server that invokes an AWS Lambda function. Configure the Lambda function to modify the server to use SFTP instead of FTP.", "option_d": "Configure the existing EventBridge event to invoke an AWS Lambda function. Configure the function to remove the security group rule that allows public access.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Per the AWS Cloud Operations and Security Automation documentation, Security Hub integrates\nwith Amazon EventBridge to publish findings in real time. These events can trigger automated\nresponses using AWS Lambda functions or AWS Systems Manager Automation runbooks.\nIn this scenario, the correct CloudOps approach is to configure the existing EventBridge rule to\ninvoke a Lambda function that inspects the event payload, identifies the affected security group,\nand removes the offending inbound rule (e.g., port 21 open to 0.0.0.0/0).\nThis event-driven remediation provides continuous compliance and eliminates manual\nintervention. Cron jobs (Options B and C) contradict event-driven design and add operational\noverhead. Stopping instances (Option A) doesn''t address the root cause -- the insecure security\ngroup.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nThus, Option D aligns with AWS best practices for automated security remediation through\nEventBridge and Lambda.", "question_text": "A company hosts an FTP server on EC2 instances. AWS Security Hub sends findings to Amazon EventBridge when the FTP port becomes publicly exposed in attached security groups. A CloudOps engineer needs an automated, event-driven remediation solution to remove public access from security groups. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0017"}', '{"tags": null, "topic": null, "options": [["A", "Configure the existing EventBridge event to stop the EC2 instances that have the exposed port."], ["B", "Create a cron job for the FTP server to invoke an AWS Lambda function. Configure the Lambda function to modify the security group of the identified EC2 instances and to remove the instances that allow public access."], ["C", "Create a cron job for the FTP server that invokes an AWS Lambda function. Configure the Lambda function to modify the server to use SFTP instead of FTP."], ["D", "Configure the existing EventBridge event to invoke an AWS Lambda function. Configure the function to remove the security group rule that allows public access."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0017"}, "reference": null, "difficulty": "medium", "explanation": "Per the AWS Cloud Operations and Security Automation documentation, Security Hub integrates\nwith Amazon EventBridge to publish findings in real time. These events can trigger automated\nresponses using AWS Lambda functions or AWS Systems Manager Automation runbooks.\nIn this scenario, the correct CloudOps approach is to configure the existing EventBridge rule to\ninvoke a Lambda function that inspects the event payload, identifies the affected security group,\nand removes the offending inbound rule (e.g., port 21 open to 0.0.0.0/0).\nThis event-driven remediation provides continuous compliance and eliminates manual\nintervention. Cron jobs (Options B and C) contradict event-driven design and add operational\noverhead. Stopping instances (Option A) doesn''t address the root cause -- the insecure security\ngroup.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nThus, Option D aligns with AWS best practices for automated security remediation through\nEventBridge and Lambda.", "question_text": "A company hosts an FTP server on EC2 instances. AWS Security Hub sends findings to Amazon EventBridge when the FTP port becomes publicly exposed in attached security groups. A CloudOps engineer needs an automated, event-driven remediation solution to remove public access from security groups. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'd8b34a6c1b1c653a5c8a6d8d93f8b18cde3391899f3cd65ea1ff0568b600f1dc', 1367, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (852, 146, 19, 'qblock_pdf', '{"option_a": "Modify the DB instance to be a Multi-AZ DB instance deployment.", "option_b": "Add a read replica in the same Availability Zone where the DB instance is deployed.", "option_c": "Add the DB instance to an Auto Scaling group that has a minimum capacity of 2 and a desired capacity of 2.", "option_d": "Use RDS Proxy to configure a proxy in front of the DB instance.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Database Reliability documentation, Amazon RDS\nMulti- AZ deployments provide high availability and automatic failover by maintaining a\nsynchronous standby replica in a different Availability Zone.\nIn the event of instance failure, planned maintenance, or Availability Zone outage, Amazon RDS\nautomatically promotes the standby to primary with minimal downtime (typically less than 60\nseconds). The failover is transparent to applications because the DB endpoint remains the same.\nBy contrast, read replicas (Option B) are asynchronous and do not provide automated failover.\nAuto Scaling (Option C) applies to EC2, not RDS. RDS Proxy (Option D) improves connection\nmanagement but does not add redundancy.\nThus, Option A -- converting the RDS instance into a Multi-AZ deployment -- delivers the required\nhigh availability and business continuity with minimal operational effort.", "question_text": "A company has an application running on EC2 that stores data in an Amazon RDS for MySQL Single- AZ DB instance. The application requires both read and write operations, and the company needs failover capability with minimal downtime. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0018"}', '{"tags": null, "topic": null, "options": [["A", "Modify the DB instance to be a Multi-AZ DB instance deployment."], ["B", "Add a read replica in the same Availability Zone where the DB instance is deployed."], ["C", "Add the DB instance to an Auto Scaling group that has a minimum capacity of 2 and a desired capacity of 2."], ["D", "Use RDS Proxy to configure a proxy in front of the DB instance."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0018"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Database Reliability documentation, Amazon RDS\nMulti- AZ deployments provide high availability and automatic failover by maintaining a\nsynchronous standby replica in a different Availability Zone.\nIn the event of instance failure, planned maintenance, or Availability Zone outage, Amazon RDS\nautomatically promotes the standby to primary with minimal downtime (typically less than 60\nseconds). The failover is transparent to applications because the DB endpoint remains the same.\nBy contrast, read replicas (Option B) are asynchronous and do not provide automated failover.\nAuto Scaling (Option C) applies to EC2, not RDS. RDS Proxy (Option D) improves connection\nmanagement but does not add redundancy.\nThus, Option A -- converting the RDS instance into a Multi-AZ deployment -- delivers the required\nhigh availability and business continuity with minimal operational effort.", "question_text": "A company has an application running on EC2 that stores data in an Amazon RDS for MySQL Single- AZ DB instance. The application requires both read and write operations, and the company needs failover capability with minimal downtime. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'cc4902c1ed33b06565a74aae005302c533ec0ef91d75b2e167a4f6981a7c292e', 1368, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (853, 146, 20, 'qblock_pdf', '{"option_a": "Add a DependsOn attribute to the custom resource. Specify the EC2 instance in the DependsOn attribute.", "option_b": "Update the custom resource''s service token to point to a valid Lambda function.", "option_c": "Update the Lambda function to use the cfn-response module to send a response to the custom resource.", "option_d": "Use the Fn::If intrinsic function to check for the EC2 instance before the custom resource runs.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Infrastructure-as-Code documentation specifies that when using\nAWS CloudFormation, resources are created in parallel by default unless explicitly ordered using\nDependsOn.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nIf a custom resource (Lambda) depends on another resource (like an EC2 instance) to exist\nbefore execution, a DependsOn attribute must be added to enforce creation order. This ensures\nthe EC2 instance is launched and available before the custom resource executes its automation\nlogic.\nUpdating the service token (Option B) doesn''t affect order of execution. The cfn-response module\n(Option C) handles callback communication but not sequencing. Fn::If (Option D) is for\nconditional creation, not dependency control.\nTherefore, Option A is correct -- adding a DependsOn attribute guarantees that CloudFormation\nprovisions the EC2 instance before executing the Lambda custom resource.", "question_text": "A company has an AWS CloudFormation template that includes an AWS::EC2::Instance resource and a custom resource (Lambda function). The Lambda function fails because it runs before the EC2 instance is launched. Which solution will resolve this issue?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0019"}', '{"tags": null, "topic": null, "options": [["A", "Add a DependsOn attribute to the custom resource. Specify the EC2 instance in the DependsOn attribute."], ["B", "Update the custom resource''s service token to point to a valid Lambda function."], ["C", "Update the Lambda function to use the cfn-response module to send a response to the custom resource."], ["D", "Use the Fn::If intrinsic function to check for the EC2 instance before the custom resource runs."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0019"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Infrastructure-as-Code documentation specifies that when using\nAWS CloudFormation, resources are created in parallel by default unless explicitly ordered using\nDependsOn.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nIf a custom resource (Lambda) depends on another resource (like an EC2 instance) to exist\nbefore execution, a DependsOn attribute must be added to enforce creation order. This ensures\nthe EC2 instance is launched and available before the custom resource executes its automation\nlogic.\nUpdating the service token (Option B) doesn''t affect order of execution. The cfn-response module\n(Option C) handles callback communication but not sequencing. Fn::If (Option D) is for\nconditional creation, not dependency control.\nTherefore, Option A is correct -- adding a DependsOn attribute guarantees that CloudFormation\nprovisions the EC2 instance before executing the Lambda custom resource.", "question_text": "A company has an AWS CloudFormation template that includes an AWS::EC2::Instance resource and a custom resource (Lambda function). The Lambda function fails because it runs before the EC2 instance is launched. Which solution will resolve this issue?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'b72bd937551da91fd517dfe4f0b73131e5848728831a78221ae2d8d462f58b51', 1369, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (854, 146, 21, 'qblock_pdf', '{"option_a": "Define and use a new custom Amazon CloudWatch metric based on the SQS ApproximateNumberOfMessagesDelayed metric in the target tracking policy.", "option_b": "Define and use Amazon CloudWatch metric math to calculate the SQS queue backlog for each instance in the target tracking policy.", "option_c": "Define and use step scaling by specifying a ChangeInCapacity value for the EC2 instances.", "option_d": "Define and use simple scaling by specifying a ChangeInCapacity value for the EC2 instances.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Auto Scaling documentation, scaling applications\nthat consume Amazon SQS messages should be driven by queue backlog per instance, not by\ngeneral system metrics such as network traffic or CPU.\nThe correct approach is to calculate a custom metric using CloudWatch metric math that divides\nthe SQS metric ApproximateNumberOfMessagesVisible by the number of active EC2 instances\nin the Auto Scaling group. This \"backlog per instance\" value represents the average number of\nmessages waiting to be processed by each instance.\nThen, the CloudOps engineer can create a target tracking policy that automatically scales out or\nin based on maintaining a desired backlog threshold. This approach ensures dynamic, workload-\ndriven scaling behavior that reacts in near real time to message volume.\nStep and simple scaling (Options C and D) require manual thresholds and do not automatically\nbalance the load per instance.\nThus, Option B--using CloudWatch metric math to define queue backlog per instance for target\ntracking--is the most effective and AWS-recommended CloudOps practice.", "question_text": "A company uses an Amazon Simple Queue Service (Amazon SQS) queue and Amazon EC2 instances in an Auto Scaling group with target tracking for a web application. The company collects the ASGAverageNetworkIn metric but notices that instances do not scale fast enough during peak traffic. There are a large number of SQS messages accumulating in the queue. A CloudOps engineer must reduce the number of SQS messages during peak periods. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0020"}', '{"tags": null, "topic": null, "options": [["A", "Define and use a new custom Amazon CloudWatch metric based on the SQS ApproximateNumberOfMessagesDelayed metric in the target tracking policy."], ["B", "Define and use Amazon CloudWatch metric math to calculate the SQS queue backlog for each instance in the target tracking policy."], ["C", "Define and use step scaling by specifying a ChangeInCapacity value for the EC2 instances."], ["D", "Define and use simple scaling by specifying a ChangeInCapacity value for the EC2 instances."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0020"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Auto Scaling documentation, scaling applications\nthat consume Amazon SQS messages should be driven by queue backlog per instance, not by\ngeneral system metrics such as network traffic or CPU.\nThe correct approach is to calculate a custom metric using CloudWatch metric math that divides\nthe SQS metric ApproximateNumberOfMessagesVisible by the number of active EC2 instances\nin the Auto Scaling group. This \"backlog per instance\" value represents the average number of\nmessages waiting to be processed by each instance.\nThen, the CloudOps engineer can create a target tracking policy that automatically scales out or\nin based on maintaining a desired backlog threshold. This approach ensures dynamic, workload-\ndriven scaling behavior that reacts in near real time to message volume.\nStep and simple scaling (Options C and D) require manual thresholds and do not automatically\nbalance the load per instance.\nThus, Option B--using CloudWatch metric math to define queue backlog per instance for target\ntracking--is the most effective and AWS-recommended CloudOps practice.", "question_text": "A company uses an Amazon Simple Queue Service (Amazon SQS) queue and Amazon EC2 instances in an Auto Scaling group with target tracking for a web application. The company collects the ASGAverageNetworkIn metric but notices that instances do not scale fast enough during peak traffic. There are a large number of SQS messages accumulating in the queue. A CloudOps engineer must reduce the number of SQS messages during peak periods. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'b0e75db92ac27f15dbbe8c168cca6465ed2a4e98f95dfa900aa58f9e05c72cf0', 1370, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (855, 146, 22, 'qblock_pdf', '{"option_a": "Add a product from the imported portfolio to a local portfolio.", "option_b": "Add new products to the imported portfolio.", "option_c": "Change the launch role for the products contained in the imported portfolio.", "option_d": ". The source (owner) account retains full administrative control over products, launch roles, and lifecycle policies. This model aligns with AWS CloudOps principles of centralized governance with distributed self- service deployment across multiple accounts. Thus, Option A is correct--imported portfolios allow the recipient to add products to a local portfolio but not alter the shared configuration.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Per the AWS Cloud Operations and Service Catalog documentation, when a portfolio is shared\nacross AWS accounts, the recipient account imports the shared portfolio.\nThe recipient CloudOps engineer cannot modify the original products or their configurations but\ncan:\nAdd products from the imported portfolio into their local portfolios for deployment,\nControl end-user access in the recipient account, and Manage local constraints or permissions.\nHowever, the recipient cannot edit, delete, or reconfigure the shared products (Options B, C, and", "question_text": "A CloudOps engineer has created an AWS Service Catalog portfolio and shared it with a second Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com AWS account in the company, managed by a different CloudOps engineer. Which action can the CloudOps engineer in the second account perform?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0021"}', '{"tags": null, "topic": null, "options": [["A", "Add a product from the imported portfolio to a local portfolio."], ["B", "Add new products to the imported portfolio."], ["C", "Change the launch role for the products contained in the imported portfolio."], ["D", ". The source (owner) account retains full administrative control over products, launch roles, and lifecycle policies. This model aligns with AWS CloudOps principles of centralized governance with distributed self- service deployment across multiple accounts. Thus, Option A is correct--imported portfolios allow the recipient to add products to a local portfolio but not alter the shared configuration."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0021"}, "reference": null, "difficulty": "medium", "explanation": "Per the AWS Cloud Operations and Service Catalog documentation, when a portfolio is shared\nacross AWS accounts, the recipient account imports the shared portfolio.\nThe recipient CloudOps engineer cannot modify the original products or their configurations but\ncan:\nAdd products from the imported portfolio into their local portfolios for deployment,\nControl end-user access in the recipient account, and Manage local constraints or permissions.\nHowever, the recipient cannot edit, delete, or reconfigure the shared products (Options B, C, and", "question_text": "A CloudOps engineer has created an AWS Service Catalog portfolio and shared it with a second Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com AWS account in the company, managed by a different CloudOps engineer. Which action can the CloudOps engineer in the second account perform?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '993514077c0354e3717f6b66b7e841fba5f87df349fae38c2f5cd478387967ed', 1371, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (856, 146, 23, 'qblock_pdf', '{"option_a": "Set the routing algorithm of the target group to least outstanding requests.", "option_b": "Turn on anomaly mitigation for the target group.", "option_c": "Turn off the cross-zone load balancing attribute of the target group.", "option_d": "Increase the deregistration delay attribute of the target group.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Elastic Load Balancing documentation, Application\nLoad Balancer (ALB) supports multiple routing algorithms to distribute requests among targets:\nRound robin (default)\nLeast outstanding requests (LOR)\nWeighted random\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nWhen applications require session affinity, AWS recommends using \"least outstanding requests\"\nas the load balancing algorithm because it reduces latency, distributes load evenly, and ensures\nconsistent target responsiveness during high traffic.\nUsing weighted random routing with sticky sessions can cause sessions to be routed\ninconsistently if one target''s capacity fluctuates, leading to session mismatches and application\nerrors -- especially when user sessions rely on instance-specific state.\nDisabling cross-zone balancing (Option C) or adjusting deregistration delay (Option D) does not\naddress routing inconsistency. Anomaly mitigation (Option B) protects against target performance\ndegradation, not sticky-session misrouting.\nTherefore, the correct solution is Option A -- changing the target group''s routing algorithm to least\noutstanding requests ensures smoother, predictable session handling and resolves random\napplication errors.", "question_text": "A company is migrating a legacy application to AWS. The application runs on EC2 instances across multiple Availability Zones behind an Application Load Balancer (ALB). The target group routing algorithm is set to weighted random, and the application requires session affinity (sticky sessions). After deployment, users report random application errors that were not present before migration, even though target health checks are passing. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0022"}', '{"tags": null, "topic": null, "options": [["A", "Set the routing algorithm of the target group to least outstanding requests."], ["B", "Turn on anomaly mitigation for the target group."], ["C", "Turn off the cross-zone load balancing attribute of the target group."], ["D", "Increase the deregistration delay attribute of the target group."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0022"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Elastic Load Balancing documentation, Application\nLoad Balancer (ALB) supports multiple routing algorithms to distribute requests among targets:\nRound robin (default)\nLeast outstanding requests (LOR)\nWeighted random\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nWhen applications require session affinity, AWS recommends using \"least outstanding requests\"\nas the load balancing algorithm because it reduces latency, distributes load evenly, and ensures\nconsistent target responsiveness during high traffic.\nUsing weighted random routing with sticky sessions can cause sessions to be routed\ninconsistently if one target''s capacity fluctuates, leading to session mismatches and application\nerrors -- especially when user sessions rely on instance-specific state.\nDisabling cross-zone balancing (Option C) or adjusting deregistration delay (Option D) does not\naddress routing inconsistency. Anomaly mitigation (Option B) protects against target performance\ndegradation, not sticky-session misrouting.\nTherefore, the correct solution is Option A -- changing the target group''s routing algorithm to least\noutstanding requests ensures smoother, predictable session handling and resolves random\napplication errors.", "question_text": "A company is migrating a legacy application to AWS. The application runs on EC2 instances across multiple Availability Zones behind an Application Load Balancer (ALB). The target group routing algorithm is set to weighted random, and the application requires session affinity (sticky sessions). After deployment, users report random application errors that were not present before migration, even though target health checks are passing. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '42288a853d9d1ec437625ca53e14854f2780f700780b00d85f1bdbfaeb13e9fe', 1372, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (857, 146, 24, 'qblock_pdf', '{"option_a": "Create an Amazon EventBridge rule to send all IAM events to an AWS Lambda function for analysis.", "option_b": "Query Amazon EC2 logs by using Amazon CloudWatch Logs Insights for all events initiated with the compromised access key within the suspected timeframe.", "option_c": "Search AWS CloudTrail event history for all events initiated with the compromised access key within the suspected timeframe.", "option_d": "Search VPC Flow Logs for all events initiated with the compromised access key within the suspected timeframe.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Security documentation, AWS CloudTrail is the\nauthoritative service for recording API activity across all AWS services within an account.\nWhen an access key is compromised, CloudTrail logs all API requests made using that key,\nincluding details such as:\nThe user identity (access key ID) that made the request,\nThe service, operation, resource, and timestamp affected, and\nThe source IP address and region of the request.\nBy searching the CloudTrail event history for the specific access key ID, the CloudOps engineer\ncan identify every action performed by that key during the suspected breach window.", "question_text": "A CloudOps engineer must manage the security of an AWS account. Recently, an IAM user''s access key was mistakenly uploaded to a public code repository. The engineer must identify everything that was changed using this compromised key. How should the CloudOps engineer meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0023"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon EventBridge rule to send all IAM events to an AWS Lambda function for analysis."], ["B", "Query Amazon EC2 logs by using Amazon CloudWatch Logs Insights for all events initiated with the compromised access key within the suspected timeframe."], ["C", "Search AWS CloudTrail event history for all events initiated with the compromised access key within the suspected timeframe."], ["D", "Search VPC Flow Logs for all events initiated with the compromised access key within the suspected timeframe."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0023"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Security documentation, AWS CloudTrail is the\nauthoritative service for recording API activity across all AWS services within an account.\nWhen an access key is compromised, CloudTrail logs all API requests made using that key,\nincluding details such as:\nThe user identity (access key ID) that made the request,\nThe service, operation, resource, and timestamp affected, and\nThe source IP address and region of the request.\nBy searching the CloudTrail event history for the specific access key ID, the CloudOps engineer\ncan identify every action performed by that key during the suspected breach window.", "question_text": "A CloudOps engineer must manage the security of an AWS account. Recently, an IAM user''s access key was mistakenly uploaded to a public code repository. The engineer must identify everything that was changed using this compromised key. How should the CloudOps engineer meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '893468a5275d44da71e8a7bdeae74585515213a6eb4a63f5df33fd81ddbeca5c', 1373, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (858, 146, 25, 'qblock_pdf', '{"option_a": "Place all the EC2 instances into a cluster placement group.", "option_b": "Configure and assign two Elastic IP addresses for each EC2 instance.", "option_c": "Configure jumbo frames on all the EC2 instances in the cluster.", "option_d": "increases distance, worsening latency. Hence, Option A -- using a cluster placement group -- delivers the lowest possible network latency and is AWS''s best-practice design for HPC-style clusters.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Compute documentation explains that placement groups control\nhow EC2 instances are physically arranged within AWS data centers to optimize network\nperformance.\nCluster placement groups place instances physically close together within a single Availability\nZone, connected through high-bandwidth, low-latency networking (ideal for tightly coupled, HPC,\nor distributed workloads).\nSpread placement groups distribute instances across distinct racks or Availability Zones for fault\ntolerance, increasing latency.\nPartition placement groups separate instances into partitions for isolation, not latency reduction.\nTherefore, to minimize latency for workloads such as computational clusters, the CloudOps\nengineer should use a cluster placement group. This placement ensures single-digit microsecond\nlatency and enhanced packet rate performance between instances.\nElastic IPs (Option B) do not influence internal networking. Jumbo frames (Option C) can\nmarginally improve throughput but do not reduce propagation latency. Spread placement (Option", "question_text": "A company runs custom statistical analysis software on a cluster of Amazon EC2 instances. The software is highly sensitive to network latency between nodes, although network throughput is not a limitation. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Which solution will minimize network latency?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0024"}', '{"tags": null, "topic": null, "options": [["A", "Place all the EC2 instances into a cluster placement group."], ["B", "Configure and assign two Elastic IP addresses for each EC2 instance."], ["C", "Configure jumbo frames on all the EC2 instances in the cluster."], ["D", "increases distance, worsening latency. Hence, Option A -- using a cluster placement group -- delivers the lowest possible network latency and is AWS''s best-practice design for HPC-style clusters."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0024"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Compute documentation explains that placement groups control\nhow EC2 instances are physically arranged within AWS data centers to optimize network\nperformance.\nCluster placement groups place instances physically close together within a single Availability\nZone, connected through high-bandwidth, low-latency networking (ideal for tightly coupled, HPC,\nor distributed workloads).\nSpread placement groups distribute instances across distinct racks or Availability Zones for fault\ntolerance, increasing latency.\nPartition placement groups separate instances into partitions for isolation, not latency reduction.\nTherefore, to minimize latency for workloads such as computational clusters, the CloudOps\nengineer should use a cluster placement group. This placement ensures single-digit microsecond\nlatency and enhanced packet rate performance between instances.\nElastic IPs (Option B) do not influence internal networking. Jumbo frames (Option C) can\nmarginally improve throughput but do not reduce propagation latency. Spread placement (Option", "question_text": "A company runs custom statistical analysis software on a cluster of Amazon EC2 instances. The software is highly sensitive to network latency between nodes, although network throughput is not a limitation. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Which solution will minimize network latency?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '814afd4eb712e1b633fff1efc7781211299258520d7e277fe8e64edb27b5ec6d', 1374, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (860, 146, 27, 'qblock_pdf', '{"option_a": "For each production EC2 instance, create an Amazon CloudWatch alarm for Status Check Failed: System. Set the alarm action to recover the EC2 instance. Configure the alarm notification to be published to an Amazon Simple Notification Service (Amazon SNS) topic.", "option_b": "On each production EC2 instance, create a script that monitors the system health by sending a heartbeat notification every minute to a central monitoring server. If an EC2 instance fails to send a heartbeat, run a script on the monitoring server to stop and start the EC2 instance and to publish a notification to an Amazon Simple Notification Service (Amazon SNS) topic.", "option_c": "On each production EC2 instance, create a script that sends network pings to a highly available endpoint by way of a cron job. If the script detects a network response timeout, invoke a command to reboot the EC2 instance.", "option_d": "On each production EC2 instance, configure an Amazon CloudWatch agent to collect and send logs to a log group in Amazon CloudWatch Logs. Create a CloudWatch alarm that is based on a metric filter that tracks errors. Configure the alarm to invoke an AWS Lambda function to reboot the EC2 instance and send a notification email.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "EC2 status checks run every minute and expose a System check metric that indicates hardware\nor system-level impairment. CloudWatch alarms can trigger on Status Check Failed: System and\nautomatically recover the instance (or take a defined action) without manual intervention,\nsatisfying both the automatic recovery and alerting requirements. This approach minimizes\nmanual steps and scales across many instances, leveraging built-in AWS health signals and\nstandard notification channels. It is also consistent with AWS guidance on using CloudWatch\nalarms to recover impaired instances and to notify via SNS.", "question_text": "A company runs several production workloads on Amazon EC2 instances. A SysOps administrator discovered that a production EC2 instance failed a system health check. The Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com SysOps administrator recovered the instance manually. The SysOps administrator wants to automate the recovery task of EC2 instances and receive notifications whenever a system health check fails. Detailed monitoring is activated for all of the company''s production EC2 instances. Which of the following is the MOST operationally efficient solution that meets these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0026"}', '{"tags": null, "topic": null, "options": [["A", "For each production EC2 instance, create an Amazon CloudWatch alarm for Status Check Failed: System. Set the alarm action to recover the EC2 instance. Configure the alarm notification to be published to an Amazon Simple Notification Service (Amazon SNS) topic."], ["B", "On each production EC2 instance, create a script that monitors the system health by sending a heartbeat notification every minute to a central monitoring server. If an EC2 instance fails to send a heartbeat, run a script on the monitoring server to stop and start the EC2 instance and to publish a notification to an Amazon Simple Notification Service (Amazon SNS) topic."], ["C", "On each production EC2 instance, create a script that sends network pings to a highly available endpoint by way of a cron job. If the script detects a network response timeout, invoke a command to reboot the EC2 instance."], ["D", "On each production EC2 instance, configure an Amazon CloudWatch agent to collect and send logs to a log group in Amazon CloudWatch Logs. Create a CloudWatch alarm that is based on a metric filter that tracks errors. Configure the alarm to invoke an AWS Lambda function to reboot the EC2 instance and send a notification email."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0026"}, "reference": null, "difficulty": "medium", "explanation": "EC2 status checks run every minute and expose a System check metric that indicates hardware\nor system-level impairment. CloudWatch alarms can trigger on Status Check Failed: System and\nautomatically recover the instance (or take a defined action) without manual intervention,\nsatisfying both the automatic recovery and alerting requirements. This approach minimizes\nmanual steps and scales across many instances, leveraging built-in AWS health signals and\nstandard notification channels. It is also consistent with AWS guidance on using CloudWatch\nalarms to recover impaired instances and to notify via SNS.", "question_text": "A company runs several production workloads on Amazon EC2 instances. A SysOps administrator discovered that a production EC2 instance failed a system health check. The Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com SysOps administrator recovered the instance manually. The SysOps administrator wants to automate the recovery task of EC2 instances and receive notifications whenever a system health check fails. Detailed monitoring is activated for all of the company''s production EC2 instances. Which of the following is the MOST operationally efficient solution that meets these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '846c2f2aa26aa609573fe064f465a7f1790e578480957d30e1275224cd94d817', 1376, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (861, 146, 28, 'qblock_pdf', '{"option_a": "Flush the contents of ElastiCache for Memcached.", "option_b": "Increase the ConnectionOverhead parameter value.", "option_c": "Increase the number of nodes in the cluster.", "option_d": "Increase the size of the nodes in the cluster.", "option_e": "Decrease the number of nodes in the cluster.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "High eviction counts in Memcached occur when the total cache capacity is insufficient for the\nworking set. Increasing the node size provides more memory per node, allowing more data to be\ncached before evictions occur. This directly reduces eviction pressure on a per-node basis.\nAdding more nodes increases overall cluster memory and parallel cache capacity, allowing the\naggregate cache to hold more items concurrently and reducing the likelihood that frequently\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\naccessed data is evicted. This scalability approach is standard practice when facing memory-\nbound eviction issues in ElastiCache Memcached clusters.", "question_text": "A company has an application that uses Amazon ElastiCache for Memcached to cache query responses to improve latency. However, the application''s users are reporting slow response times. A SysOps administrator notices that the Amazon CloudWatch metrics for Memcached evictions are high. Which actions should the SysOps administrator take to fix this issue? (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "CD", "external_question_id": "Q0027"}', '{"tags": null, "topic": null, "options": [["A", "Flush the contents of ElastiCache for Memcached."], ["B", "Increase the ConnectionOverhead parameter value."], ["C", "Increase the number of nodes in the cluster."], ["D", "Increase the size of the nodes in the cluster."], ["E", "Decrease the number of nodes in the cluster."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0027"}, "reference": null, "difficulty": "medium", "explanation": "High eviction counts in Memcached occur when the total cache capacity is insufficient for the\nworking set. Increasing the node size provides more memory per node, allowing more data to be\ncached before evictions occur. This directly reduces eviction pressure on a per-node basis.\nAdding more nodes increases overall cluster memory and parallel cache capacity, allowing the\naggregate cache to hold more items concurrently and reducing the likelihood that frequently\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\naccessed data is evicted. This scalability approach is standard practice when facing memory-\nbound eviction issues in ElastiCache Memcached clusters.", "question_text": "A company has an application that uses Amazon ElastiCache for Memcached to cache query responses to improve latency. However, the application''s users are reporting slow response times. A SysOps administrator notices that the Amazon CloudWatch metrics for Memcached evictions are high. Which actions should the SysOps administrator take to fix this issue? (Choose two.)", "question_type": "multiple", "correct_answer": ["C", "D"]}', 'imported', NULL, NULL, '4a059cb18cd35252aa6fc1c72eede836e5af3ddc3ef1534498dd6b578c48ad23', 1377, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (862, 146, 29, 'qblock_pdf', '{"option_a": "Replace the ALB with a Network Load Balancer.", "option_b": "Add Elastic Load Balancing (ELB) health checks to the Auto Scaling group.", "option_c": "Update the target group configuration on the ALB. Enable session affinity (sticky sessions).", "option_d": "Install the Amazon CloudWatch agent on all instances. Configure the agent to reboot the instances.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "In this scenario, the EC2 instances pass their EC2 status checks, indicating that the operating\nsystem is responsive. However, the application hosted on the instance is failing intermittently,\nreturning HTTP 500 errors. This demonstrates a discrepancy between the instance-level health\nand the application-level health.\nAuto Scaling groups should incorporate Elastic Load Balancing (ELB) health checks instead of\nrelying solely on EC2 status checks. The ELB health check probes the application endpoint (for\nexample, HTTP or HTTPS target group health checks), ensuring that the application itself is\nfunctioning correctly.\nWhen an instance fails an ELB health check, Amazon EC2 Auto Scaling will automatically mark\nthe instance as unhealthy and replace it with a new one, ensuring continuous availability and\nperformance optimization.\n\"Implement monitoring and health checks using ALB and EC2 Auto Scaling integration.\nApplication Load Balancer health checks allow Auto Scaling to terminate and replace instances\nthat fail application-level health checks, ensuring consistent application performance.\"\n\"When you enable the ELB health check type for your Auto Scaling group, Amazon EC2 Auto\nScaling considers both EC2 status checks and Elastic Load Balancing health checks to determine\ninstance health. If an instance fails the ELB health check, it is automatically replaced.\"\nTherefore, the correct answer is B, as it ensures proper application-level monitoring and\nremediation using ALB-integrated ELB health checks--a core CloudOps operational practice for\nproactive incident response and availability assurance.", "question_text": "A company''s ecommerce application is running on Amazon EC2 instances that are behind an Application Load Balancer (ALB). The instances are in an Auto Scaling group. Customers report that the website is occasionally down. When the website is down, it returns an HTTP 500 (server error) status code to customer browsers. The Auto Scaling group''s health check is configured for EC2 status checks, and the instances appear healthy. Which solution will resolve the problem?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0028"}', '{"tags": null, "topic": null, "options": [["A", "Replace the ALB with a Network Load Balancer."], ["B", "Add Elastic Load Balancing (ELB) health checks to the Auto Scaling group."], ["C", "Update the target group configuration on the ALB. Enable session affinity (sticky sessions)."], ["D", "Install the Amazon CloudWatch agent on all instances. Configure the agent to reboot the instances."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0028"}, "reference": null, "difficulty": "medium", "explanation": "In this scenario, the EC2 instances pass their EC2 status checks, indicating that the operating\nsystem is responsive. However, the application hosted on the instance is failing intermittently,\nreturning HTTP 500 errors. This demonstrates a discrepancy between the instance-level health\nand the application-level health.\nAuto Scaling groups should incorporate Elastic Load Balancing (ELB) health checks instead of\nrelying solely on EC2 status checks. The ELB health check probes the application endpoint (for\nexample, HTTP or HTTPS target group health checks), ensuring that the application itself is\nfunctioning correctly.\nWhen an instance fails an ELB health check, Amazon EC2 Auto Scaling will automatically mark\nthe instance as unhealthy and replace it with a new one, ensuring continuous availability and\nperformance optimization.\n\"Implement monitoring and health checks using ALB and EC2 Auto Scaling integration.\nApplication Load Balancer health checks allow Auto Scaling to terminate and replace instances\nthat fail application-level health checks, ensuring consistent application performance.\"\n\"When you enable the ELB health check type for your Auto Scaling group, Amazon EC2 Auto\nScaling considers both EC2 status checks and Elastic Load Balancing health checks to determine\ninstance health. If an instance fails the ELB health check, it is automatically replaced.\"\nTherefore, the correct answer is B, as it ensures proper application-level monitoring and\nremediation using ALB-integrated ELB health checks--a core CloudOps operational practice for\nproactive incident response and availability assurance.", "question_text": "A company''s ecommerce application is running on Amazon EC2 instances that are behind an Application Load Balancer (ALB). The instances are in an Auto Scaling group. Customers report that the website is occasionally down. When the website is down, it returns an HTTP 500 (server error) status code to customer browsers. The Auto Scaling group''s health check is configured for EC2 status checks, and the instances appear healthy. Which solution will resolve the problem?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'fde8cad429484354f1a15e9caaa03f7b45f893ab00bf77e45b856622e877830f', 1378, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (863, 146, 30, 'qblock_pdf', '{"option_a": "Create an Amazon Machine Image (AMI) from a healthy instance. Launch additional instances from the AMI in the same Availability Zone. Add the new instances to the ALB target group.", "option_b": "Increase the size of each instance. Create an Amazon EventBridge rule. Configure the EventBridge rule to restart the instances if they enter a failed state.", "option_c": "Create an Amazon Machine Image (AMI) from a healthy instance. Launch an additional instance from the AMI in the same Availability Zone. Add the new instance to the ALB target group. Create an AWS Lambda function that runs when an instance is unhealthy. Configure the Lambda function to stop and restart the unhealthy instance.", "option_d": "Create an Amazon Machine Image (AMI) from a healthy instance. Create a launch template that uses the AMI. Create an Amazon EC2 Auto Scaling group that is deployed across multiple Availability Zones. Configure the Auto Scaling group to add instances to the ALB target group.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "High availability requires removing single-AZ risk and eliminating manual recovery. The AWS\nReliability best practices state to design for multi-AZ and automatic healing: Auto Scaling \"helps\nmaintain application availability and allows you to automatically add or remove EC2 instances\"\n(AWS Auto Scaling User Guide). The Reliability Pillar recommends to \"distribute workloads\nacross multiple Availability Zones\" and to \"automate recovery from failure\" (AWS Well-Architected\nFramework ?Reliability Pillar). Attaching the Auto Scaling group to an ALB target group enables\nhealth-based replacement: instances failing load balancer health checks are replaced and traffic\nis routed only to healthy targets. Using an AMI in a launch template ensures consistent,\nrepeatable instance configuration (AWS EC2 Launch Templates). Options A and C keep all\ninstances in a single Availability Zone and rely on manual or ad-hoc restarts, which do not meet\nhigh-availability or resiliency goals. Option B only scales vertically and adds a restart rule; it\nneither removes the single-AZ failure domain nor provides automated replacement. Therefore,\ncreating a multi-AZ EC2 Auto Scaling group with a launch template and attaching it to the ALB\ntarget group (Option D) is the CloudOps-aligned solution for resilience and business continuity.", "question_text": "A company hosts a critical legacy application on two Amazon EC2 instances that are in one Availability Zone. The instances run behind an Application Load Balancer (ALB). The company uses Amazon CloudWatch alarms to send Amazon Simple Notification Service (Amazon SNS) notifications when the ALB health checks detect an unhealthy instance. After a notification, the Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com company''s engineers manually restart the unhealthy instance. A CloudOps engineer must configure the application to be highly available and more resilient to failures. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0029"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon Machine Image (AMI) from a healthy instance. Launch additional instances from the AMI in the same Availability Zone. Add the new instances to the ALB target group."], ["B", "Increase the size of each instance. Create an Amazon EventBridge rule. Configure the EventBridge rule to restart the instances if they enter a failed state."], ["C", "Create an Amazon Machine Image (AMI) from a healthy instance. Launch an additional instance from the AMI in the same Availability Zone. Add the new instance to the ALB target group. Create an AWS Lambda function that runs when an instance is unhealthy. Configure the Lambda function to stop and restart the unhealthy instance."], ["D", "Create an Amazon Machine Image (AMI) from a healthy instance. Create a launch template that uses the AMI. Create an Amazon EC2 Auto Scaling group that is deployed across multiple Availability Zones. Configure the Auto Scaling group to add instances to the ALB target group."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0029"}, "reference": null, "difficulty": "medium", "explanation": "High availability requires removing single-AZ risk and eliminating manual recovery. The AWS\nReliability best practices state to design for multi-AZ and automatic healing: Auto Scaling \"helps\nmaintain application availability and allows you to automatically add or remove EC2 instances\"\n(AWS Auto Scaling User Guide). The Reliability Pillar recommends to \"distribute workloads\nacross multiple Availability Zones\" and to \"automate recovery from failure\" (AWS Well-Architected\nFramework ?Reliability Pillar). Attaching the Auto Scaling group to an ALB target group enables\nhealth-based replacement: instances failing load balancer health checks are replaced and traffic\nis routed only to healthy targets. Using an AMI in a launch template ensures consistent,\nrepeatable instance configuration (AWS EC2 Launch Templates). Options A and C keep all\ninstances in a single Availability Zone and rely on manual or ad-hoc restarts, which do not meet\nhigh-availability or resiliency goals. Option B only scales vertically and adds a restart rule; it\nneither removes the single-AZ failure domain nor provides automated replacement. Therefore,\ncreating a multi-AZ EC2 Auto Scaling group with a launch template and attaching it to the ALB\ntarget group (Option D) is the CloudOps-aligned solution for resilience and business continuity.", "question_text": "A company hosts a critical legacy application on two Amazon EC2 instances that are in one Availability Zone. The instances run behind an Application Load Balancer (ALB). The company uses Amazon CloudWatch alarms to send Amazon Simple Notification Service (Amazon SNS) notifications when the ALB health checks detect an unhealthy instance. After a notification, the Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com company''s engineers manually restart the unhealthy instance. A CloudOps engineer must configure the application to be highly available and more resilient to failures. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '976915291663596164d62a27354c2b724a7f33770640fa4db4765880af5741e5', 1379, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (929, 146, 96, 'qblock_pdf', '{"option_a": "Launch a new Amazon EC2 instance. Configure a cron job to use the AWS SDK to send an SNS notification to subscribers every Saturday.", "option_b": "Create a rule in Amazon EventBridge that triggers every Saturday. Configure the rule to publish a notification to an SNS topic.", "option_c": "Create an SNS subscription to a message fanout that sends notifications to subscribers every Saturday.", "option_d": "Use the AWS Step Functions scheduling feature to run a Step Functions step every Saturday. Configure the step to publish a message to an SNS topic.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Amazon EventBridge can natively schedule events using cron expressions. By creating a rule\nthat triggers every Saturday and directly publishes to the SNS topic, the process becomes fully\nautomated with no servers or custom scripts required. This is the most operationally efficient and\ncost-effective approach since it leverages managed services without ongoing maintenance or\ncompute resources.", "question_text": "A company has millions of subscribers. The company''s marketing department wants to automate a process that sends notifications to subscribers every Saturday. The company already has a mechanism that uses Amazon Simple Notification Service (Amazon SNS) to send notifications to subscribers. However, the company has historically sent notifications to subscribers manually A CloudOps engineer needs a solution to automatically send notifications on a schedule. Which solution will meet these requirements in the MOST operationally efficient way?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0095"}', '{"tags": null, "topic": null, "options": [["A", "Launch a new Amazon EC2 instance. Configure a cron job to use the AWS SDK to send an SNS notification to subscribers every Saturday."], ["B", "Create a rule in Amazon EventBridge that triggers every Saturday. Configure the rule to publish a notification to an SNS topic."], ["C", "Create an SNS subscription to a message fanout that sends notifications to subscribers every Saturday."], ["D", "Use the AWS Step Functions scheduling feature to run a Step Functions step every Saturday. Configure the step to publish a message to an SNS topic."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0095"}, "reference": null, "difficulty": "medium", "explanation": "Amazon EventBridge can natively schedule events using cron expressions. By creating a rule\nthat triggers every Saturday and directly publishes to the SNS topic, the process becomes fully\nautomated with no servers or custom scripts required. This is the most operationally efficient and\ncost-effective approach since it leverages managed services without ongoing maintenance or\ncompute resources.", "question_text": "A company has millions of subscribers. The company''s marketing department wants to automate a process that sends notifications to subscribers every Saturday. The company already has a mechanism that uses Amazon Simple Notification Service (Amazon SNS) to send notifications to subscribers. However, the company has historically sent notifications to subscribers manually A CloudOps engineer needs a solution to automatically send notifications on a schedule. Which solution will meet these requirements in the MOST operationally efficient way?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'b89d20acf89af63ecdb8c6fec6aa8b4986bbdea9f3b98192124be2bf66d214ae', 1445, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (864, 146, 31, 'qblock_pdf', '{"option_a": "Create an IAM user with an IAM policy that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues. Embed the IAM user''s credentials in the application''s configuration.", "option_b": "Create an IAM user with an IAM policy that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues. Export the IAM user''s access key and secret access key as environment variables on the EC2 instance.", "option_c": "Create and associate an IAM role that allows EC2 instances to call AWS services. Attach an IAM policy to the role that allows sqs:* permissions to the appropriate queues.", "option_d": "Create and associate an IAM role that allows EC2 instances to call AWS services. Attach an IAM policy to the role that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nThe most secure pattern is to use an IAM role for Amazon EC2 with the minimum required\npermissions. AWS guidance states: \"Use roles for applications that run on Amazon EC2\ninstances\" and \"grant least privilege by allowing only the actions required to perform a task.\" By\nattaching a role to the instance, short-lived credentials are automatically provided through the\ninstance metadata service; this removes the need to create long-term access keys or embed\nsecrets. Granting only sqs:SendMessage, sqs:ReceiveMessage, and sqs:DeleteMessage against\nthe specific SQS queues enforces least privilege and aligns with CloudOps security controls.\nOptions A and B rely on IAM user access keys, which contravene best practices for workloads on\nEC2 and increase credential- management risk. Option C uses a role but grants sqs:*, violating\nleast-privilege principles. Therefore, Option D meets the security requirement with scoped,\ntemporary credentials and precise permissions.", "question_text": "An Amazon EC2 instance is running an application that uses Amazon Simple Queue Service (Amazon SQS) queues. A CloudOps engineer must ensure that the application can read, write, and delete messages from the SQS queues. Which solution will meet these requirements in the MOST secure manner?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0030"}', '{"tags": null, "topic": null, "options": [["A", "Create an IAM user with an IAM policy that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues. Embed the IAM user''s credentials in the application''s configuration."], ["B", "Create an IAM user with an IAM policy that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues. Export the IAM user''s access key and secret access key as environment variables on the EC2 instance."], ["C", "Create and associate an IAM role that allows EC2 instances to call AWS services. Attach an IAM policy to the role that allows sqs:* permissions to the appropriate queues."], ["D", "Create and associate an IAM role that allows EC2 instances to call AWS services. Attach an IAM policy to the role that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0030"}, "reference": null, "difficulty": "medium", "explanation": "Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nThe most secure pattern is to use an IAM role for Amazon EC2 with the minimum required\npermissions. AWS guidance states: \"Use roles for applications that run on Amazon EC2\ninstances\" and \"grant least privilege by allowing only the actions required to perform a task.\" By\nattaching a role to the instance, short-lived credentials are automatically provided through the\ninstance metadata service; this removes the need to create long-term access keys or embed\nsecrets. Granting only sqs:SendMessage, sqs:ReceiveMessage, and sqs:DeleteMessage against\nthe specific SQS queues enforces least privilege and aligns with CloudOps security controls.\nOptions A and B rely on IAM user access keys, which contravene best practices for workloads on\nEC2 and increase credential- management risk. Option C uses a role but grants sqs:*, violating\nleast-privilege principles. Therefore, Option D meets the security requirement with scoped,\ntemporary credentials and precise permissions.", "question_text": "An Amazon EC2 instance is running an application that uses Amazon Simple Queue Service (Amazon SQS) queues. A CloudOps engineer must ensure that the application can read, write, and delete messages from the SQS queues. Which solution will meet these requirements in the MOST secure manner?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'ac9bf11354d2f412dbf242bdbfc117c796581c433754f556fb7e63e989c54eef', 1380, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (865, 146, 32, 'qblock_pdf', '{"option_a": "Create an Amazon S3 bucket. Create an export task from appropriate log groups in CloudWatch. Export the logs to the S3 bucket. Configure an Amazon Macie scan to discover personal data in the S3 bucket. Invoke an AWS Lambda function to move identified personal data to a second S3 bucket. Update the S3 bucket policies to grant only the security team access to both buckets.", "option_b": "Create a customer managed AWS KMS key. Configure the KMS key policy to allow only the security team to perform decrypt operations. Associate the KMS key with the application log group.", "option_c": "Create an Amazon CloudWatch data protection policy for the application log group. Configure data identifiers for the types of personal information that the application logs. Ensure that the security team has permission to call the unmask API operation on the application log group.", "option_d": "Create an OpenSearch domain. Create an AWS Glue workflow that runs a Detect PII transform job and streams the output to the OpenSearch domain. Configure the CloudWatch log group to stream the logs to AWS Glue. Modify the OpenSearch domain access policy to allow only the security team to access the domain.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "CloudWatch Logs data protection provides native redaction/masking of sensitive data at ingestion\nand query. AWS documentation states it can \"detect and protect sensitive data in logs\" using data\nidentifiers, and that authorized users can \"use the unmask action to view the original data.\"\nCreating a data protection policy on the log group masks PII by default for all viewers, satisfying\nthe requirement to redact personal information. Granting only the security team permission to\ninvoke the unmask API operation ensures that unredacted content is restricted. Option B (KMS)\nencrypts at rest but does not redact fields; encryption alone does not prevent plaintext visibility to\nauthorized readers. Options A and D add complexity and latency, move data out of CloudWatch,\nand do not provide default inline redaction/unmask controls in CloudWatch itself. Therefore, the\nCloudOps-aligned, managed solution is to use CloudWatch Logs data protection with appropriate\ndata identifiers and unmask permissions limited to the security team.", "question_text": "A company runs an application that logs user data to an Amazon CloudWatch Logs log group. The company discovers that personal information the application has logged is visible in plain text in the CloudWatch logs. The company needs a solution to redact personal information in the logs by default. Unredacted information must be available only to the company''s security team. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0031"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon S3 bucket. Create an export task from appropriate log groups in CloudWatch. Export the logs to the S3 bucket. Configure an Amazon Macie scan to discover personal data in the S3 bucket. Invoke an AWS Lambda function to move identified personal data to a second S3 bucket. Update the S3 bucket policies to grant only the security team access to both buckets."], ["B", "Create a customer managed AWS KMS key. Configure the KMS key policy to allow only the security team to perform decrypt operations. Associate the KMS key with the application log group."], ["C", "Create an Amazon CloudWatch data protection policy for the application log group. Configure data identifiers for the types of personal information that the application logs. Ensure that the security team has permission to call the unmask API operation on the application log group."], ["D", "Create an OpenSearch domain. Create an AWS Glue workflow that runs a Detect PII transform job and streams the output to the OpenSearch domain. Configure the CloudWatch log group to stream the logs to AWS Glue. Modify the OpenSearch domain access policy to allow only the security team to access the domain."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0031"}, "reference": null, "difficulty": "medium", "explanation": "CloudWatch Logs data protection provides native redaction/masking of sensitive data at ingestion\nand query. AWS documentation states it can \"detect and protect sensitive data in logs\" using data\nidentifiers, and that authorized users can \"use the unmask action to view the original data.\"\nCreating a data protection policy on the log group masks PII by default for all viewers, satisfying\nthe requirement to redact personal information. Granting only the security team permission to\ninvoke the unmask API operation ensures that unredacted content is restricted. Option B (KMS)\nencrypts at rest but does not redact fields; encryption alone does not prevent plaintext visibility to\nauthorized readers. Options A and D add complexity and latency, move data out of CloudWatch,\nand do not provide default inline redaction/unmask controls in CloudWatch itself. Therefore, the\nCloudOps-aligned, managed solution is to use CloudWatch Logs data protection with appropriate\ndata identifiers and unmask permissions limited to the security team.", "question_text": "A company runs an application that logs user data to an Amazon CloudWatch Logs log group. The company discovers that personal information the application has logged is visible in plain text in the CloudWatch logs. The company needs a solution to redact personal information in the logs by default. Unredacted information must be available only to the company''s security team. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'bcee4b8b4c8054f913ab7b244c6fafcd8446e8e7eabc820d8a9b35445b834fb4', 1381, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (866, 146, 33, 'qblock_pdf', '{"option_a": "Create AWS Config rules with remediation actions in each account to detect policy violations. Implement IAM permissions boundaries for the account root users.", "option_b": "Enable AWS Security Hub across the organization. Create custom security standards to enforce the security requirements. Use AWS CloudFormation StackSets to deploy the standards to all the accounts in the organization. Set up Security Hub automated remediation actions.", "option_c": "Use AWS Control Tower for account governance. Configure Region deny controls. Use Service Control Policies (SCPs) to restrict root user access.", "option_d": "Configure AWS Firewall Manager with security policies to meet the security requirements. Use an AWS Config aggregator with organization-wide conformance packs to detect security policy violations.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS CloudOps governance best practices emphasize centralized account management and\npreventive guardrails. AWS Control Tower integrates directly with AWS Organizations and\nprovides \"Region deny controls\" and \"Service Control Policies (SCPs)\" that apply automatically to\nall existing and newly created member accounts. SCPs are organization-wide guardrails that\ndefine the maximum permissions for accounts. They can explicitly deny actions such as\nlaunching EC2 instances in a specific Region, or block root user access.\nTo prevent CloudTrail log deletion, SCPs can also include denies on cloudtrail:DeleteTrail and\ns3:DeleteObject actions targeting the CloudTrail log S3 bucket. These SCPs ensure that no user,\nincluding administrators, can violate the compliance requirements.\n\"Use AWS Control Tower to establish a secure, compliant, multi-account environment with\npreventive guardrails through service control policies and detective controls through AWS\nConfig.\"\nThis approach meets all stated needs: centralized enforcement, automatic propagation to new\naccounts, region-based restrictions, and immutable audit logs. Options A, B, and D either detect\nviolations reactively or lack complete enforcement and automation across future accounts.", "question_text": "Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com A multinational company uses an organization in AWS Organizations to manage over 200 member accounts across multiple AWS Regions. The company must ensure that all AWS resources meet specific security requirements. The company must not deploy any EC2 instances in the ap-southeast-2 Region. The company must completely block root user actions in all member accounts. The company must prevent any user from deleting AWS CloudTrail logs, including administrators. The company requires a centrally managed solution that the company can automatically apply to all existing and future accounts. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0032"}', '{"tags": null, "topic": null, "options": [["A", "Create AWS Config rules with remediation actions in each account to detect policy violations. Implement IAM permissions boundaries for the account root users."], ["B", "Enable AWS Security Hub across the organization. Create custom security standards to enforce the security requirements. Use AWS CloudFormation StackSets to deploy the standards to all the accounts in the organization. Set up Security Hub automated remediation actions."], ["C", "Use AWS Control Tower for account governance. Configure Region deny controls. Use Service Control Policies (SCPs) to restrict root user access."], ["D", "Configure AWS Firewall Manager with security policies to meet the security requirements. Use an AWS Config aggregator with organization-wide conformance packs to detect security policy violations."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0032"}, "reference": null, "difficulty": "medium", "explanation": "AWS CloudOps governance best practices emphasize centralized account management and\npreventive guardrails. AWS Control Tower integrates directly with AWS Organizations and\nprovides \"Region deny controls\" and \"Service Control Policies (SCPs)\" that apply automatically to\nall existing and newly created member accounts. SCPs are organization-wide guardrails that\ndefine the maximum permissions for accounts. They can explicitly deny actions such as\nlaunching EC2 instances in a specific Region, or block root user access.\nTo prevent CloudTrail log deletion, SCPs can also include denies on cloudtrail:DeleteTrail and\ns3:DeleteObject actions targeting the CloudTrail log S3 bucket. These SCPs ensure that no user,\nincluding administrators, can violate the compliance requirements.\n\"Use AWS Control Tower to establish a secure, compliant, multi-account environment with\npreventive guardrails through service control policies and detective controls through AWS\nConfig.\"\nThis approach meets all stated needs: centralized enforcement, automatic propagation to new\naccounts, region-based restrictions, and immutable audit logs. Options A, B, and D either detect\nviolations reactively or lack complete enforcement and automation across future accounts.", "question_text": "Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com A multinational company uses an organization in AWS Organizations to manage over 200 member accounts across multiple AWS Regions. The company must ensure that all AWS resources meet specific security requirements. The company must not deploy any EC2 instances in the ap-southeast-2 Region. The company must completely block root user actions in all member accounts. The company must prevent any user from deleting AWS CloudTrail logs, including administrators. The company requires a centrally managed solution that the company can automatically apply to all existing and future accounts. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '6e74805588ce0a02efa0127f76f11b86822c0fc9b217596bc5a62c6a82f8254e', 1382, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (867, 146, 34, 'qblock_pdf', '{"option_a": "Create a service control policy (SCP) in the organization to add the new IAM roles to each account.", "option_b": "Deploy an AWS CloudFormation change set to the organization with a template to create the new IAM roles.", "option_c": "Use AWS CloudFormation StackSets to deploy a template to each account to create the new IAM roles. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_d": "Use AWS Config to create an organization rule to add the new IAM roles to each account.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "StackSets enables you to create, update, or delete CloudFormation stacks across multiple AWS\naccounts and regions from a single administrator account, which is ideal for applying identical\nIAM role configurations across all accounts in an organization. This approach minimizes manual\neffort, ensures consistency, and scales with the number of accounts. It is the recommended\npattern for cross-account resource provisioning within AWS Organizations.", "question_text": "A company uses AWS Organizations to create and manage many AWS accounts. The company wants to deploy new IAM roles in each account. Which action should the SysOps administrator take to deploy the new roles in each of the organization''s accounts?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0033"}', '{"tags": null, "topic": null, "options": [["A", "Create a service control policy (SCP) in the organization to add the new IAM roles to each account."], ["B", "Deploy an AWS CloudFormation change set to the organization with a template to create the new IAM roles."], ["C", "Use AWS CloudFormation StackSets to deploy a template to each account to create the new IAM roles. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["D", "Use AWS Config to create an organization rule to add the new IAM roles to each account."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0033"}, "reference": null, "difficulty": "medium", "explanation": "StackSets enables you to create, update, or delete CloudFormation stacks across multiple AWS\naccounts and regions from a single administrator account, which is ideal for applying identical\nIAM role configurations across all accounts in an organization. This approach minimizes manual\neffort, ensures consistency, and scales with the number of accounts. It is the recommended\npattern for cross-account resource provisioning within AWS Organizations.", "question_text": "A company uses AWS Organizations to create and manage many AWS accounts. The company wants to deploy new IAM roles in each account. Which action should the SysOps administrator take to deploy the new roles in each of the organization''s accounts?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '6cf26e3c7f57ff392e3281e401dc35650f7717d2c01fef45ac0eb033938ce593', 1383, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (868, 146, 35, 'qblock_pdf', '{"option_a": "An A record", "option_b": "An AAAA record", "option_c": "An alias record", "option_d": "A CNAME record", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "An alias record is the recommended Route 53 record type to map domain names (e.g.,\nexample.com) to AWS-managed resources such as an Application Load Balancer. Alias records\nare extension types of A or AAAA records that support AWS resources directly, providing\nautomatic DNS integration and no additional query costs.\n\"Use alias records to map your domain or subdomain to an AWS resource such as an Application\nLoad Balancer, CloudFront distribution, or S3 website endpoint.\"\nA and AAAA records are used for static IP addresses, not load balancers. CNAME records\ncannot be used at the root domain (e.g., example.com). Thus, Option C is correct as it meets\nCloudOps networking best practices for scalable, managed DNS resolution to ALBs.", "question_text": "A company has a microservice that runs on a set of Amazon EC2 instances. The EC2 instances run behind an Application Load Balancer (ALB). A CloudOps engineer must use Amazon Route 53 to create a record that maps the ALB URL to example.com. Which type of record will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0034"}', '{"tags": null, "topic": null, "options": [["A", "An A record"], ["B", "An AAAA record"], ["C", "An alias record"], ["D", "A CNAME record"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0034"}, "reference": null, "difficulty": "medium", "explanation": "An alias record is the recommended Route 53 record type to map domain names (e.g.,\nexample.com) to AWS-managed resources such as an Application Load Balancer. Alias records\nare extension types of A or AAAA records that support AWS resources directly, providing\nautomatic DNS integration and no additional query costs.\n\"Use alias records to map your domain or subdomain to an AWS resource such as an Application\nLoad Balancer, CloudFront distribution, or S3 website endpoint.\"\nA and AAAA records are used for static IP addresses, not load balancers. CNAME records\ncannot be used at the root domain (e.g., example.com). Thus, Option C is correct as it meets\nCloudOps networking best practices for scalable, managed DNS resolution to ALBs.", "question_text": "A company has a microservice that runs on a set of Amazon EC2 instances. The EC2 instances run behind an Application Load Balancer (ALB). A CloudOps engineer must use Amazon Route 53 to create a record that maps the ALB URL to example.com. Which type of record will meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '886de6d114c3d536888feb930fca701b5028aaeb0a5ea4f087a635d420c5aa03', 1384, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (869, 146, 36, 'qblock_pdf', '{"option_a": "The security group of the EC2 instances has no Allow rule for the traffic from the NLB. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_b": "The security group of the NLB has no Allow rule for the traffic from the on-premises environment.", "option_c": "The ACL of the on-premises environment does not allow traffic to the AWS environment.", "option_d": "The network ACL that is associated with the subnet does not allow outbound traffic for the ephemeral port range.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "VPC Flow Logs show the request arriving and being ACCEPTed on dstport 8080 and the\ncorresponding response being REJECTed on the return path to the client''s ephemeral port\n(59003). AWS networking guidance states that security groups are stateful (return traffic is\nautomatically allowed) while network ACLs are stateless and require explicit inbound and\noutbound rules for both directions. CloudOps operational guidance for VPC networking further\nnotes that when you allow an inbound request (for example, TCP 8080) through a subnet''s\nnetwork ACL, you must also allow the outbound ephemeral port range (typically 1024?5535) for\nthe response traffic; otherwise, the return packets are dropped and appear as REJECT in flow\nlogs. The observed pattern--request accepted to 8080, response rejected to 59003--matches a\nmissing outbound ephemeral-range allow on the subnet''s NACL. Therefore, the cause is the\nsubnet NACL, not security groups or on-premises ACLs. The remediation is to add an outbound\nALLOW rule on the NACL for the appropriate ephemeral TCP port range back to the on-premises\nCIDR (and the corresponding inbound rule if asymmetric).", "question_text": "Application A runs on Amazon EC2 instances behind a Network Load Balancer (NLB). The EC2 instances are in an Auto Scaling group and are in the same subnet that is associated with the NLB. Other applications from an on-premises environment cannot communicate with Application A on port 8080. To troubleshoot the issue, a CloudOps engineer analyzes the flow logs. The flow logs include the following records: ACCEPT from 192.168.0.13:59003    172.31.16.139:8080 REJECT from 172.31.16.139:8080    192.168.0.13:59003 What is the reason for the rejected traffic?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0035"}', '{"tags": null, "topic": null, "options": [["A", "The security group of the EC2 instances has no Allow rule for the traffic from the NLB. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["B", "The security group of the NLB has no Allow rule for the traffic from the on-premises environment."], ["C", "The ACL of the on-premises environment does not allow traffic to the AWS environment."], ["D", "The network ACL that is associated with the subnet does not allow outbound traffic for the ephemeral port range."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0035"}, "reference": null, "difficulty": "medium", "explanation": "VPC Flow Logs show the request arriving and being ACCEPTed on dstport 8080 and the\ncorresponding response being REJECTed on the return path to the client''s ephemeral port\n(59003). AWS networking guidance states that security groups are stateful (return traffic is\nautomatically allowed) while network ACLs are stateless and require explicit inbound and\noutbound rules for both directions. CloudOps operational guidance for VPC networking further\nnotes that when you allow an inbound request (for example, TCP 8080) through a subnet''s\nnetwork ACL, you must also allow the outbound ephemeral port range (typically 1024?5535) for\nthe response traffic; otherwise, the return packets are dropped and appear as REJECT in flow\nlogs. The observed pattern--request accepted to 8080, response rejected to 59003--matches a\nmissing outbound ephemeral-range allow on the subnet''s NACL. Therefore, the cause is the\nsubnet NACL, not security groups or on-premises ACLs. The remediation is to add an outbound\nALLOW rule on the NACL for the appropriate ephemeral TCP port range back to the on-premises\nCIDR (and the corresponding inbound rule if asymmetric).", "question_text": "Application A runs on Amazon EC2 instances behind a Network Load Balancer (NLB). The EC2 instances are in an Auto Scaling group and are in the same subnet that is associated with the NLB. Other applications from an on-premises environment cannot communicate with Application A on port 8080. To troubleshoot the issue, a CloudOps engineer analyzes the flow logs. The flow logs include the following records: ACCEPT from 192.168.0.13:59003 172.31.16.139:8080 REJECT from 172.31.16.139:8080 192.168.0.13:59003 What is the reason for the rejected traffic?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '199f5338272f58c87281f1f6cd9efdc462b069d16ed749390c48cb327f8206c8', 1385, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (870, 146, 37, 'qblock_pdf', '{"option_a": "Configure an Amazon Simple Notification Service (Amazon SNS) topic to invoke the Lambda function when a user uploads a new image to the S3 bucket.", "option_b": "Configure an Amazon CloudWatch alarm to invoke the Lambda function when a user uploads a new image to the S3 bucket.", "option_c": "Configure S3 Event Notifications to invoke the Lambda function when a user uploads a new image to the S3 bucket.", "option_d": "Configure an Amazon Simple Queue Service (Amazon SQS) queue to invoke the Lambda function when a user uploads a new image to the S3 bucket.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Use Amazon S3 Event Notifications with AWS Lambda to trigger image processing on object\ncreation. S3 natively supports invoking Lambda for events such as s3:ObjectCreated:*, providing\na serverless, low-latency pipeline without managing additional services. AWS operational\nguidance states that \"Amazon S3 can directly invoke a Lambda function in response to object-\ncreated events,\" allowing you to pass event metadata (bucket/key) to the function for resizing and\nwriting results back to S3. This approach minimizes operational overhead, scales automatically\nwith upload volume, and integrates with standard retry semantics. SNS or SQS can be added for\nfan-out or buffering patterns, but they are not required when the requirement is simply \"invoke the\nLambda function on upload.\" CloudWatch alarms do not detect individual S3 object uploads and\ncannot directly satisfy per-object triggers. Therefore, configuring S3    Lambda event notifications\nmeets the requirement most directly and aligns with CloudOps best practices for event-driven,\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nserverless automation.", "question_text": "A company runs a website on Amazon EC2 instances. Users can upload images to an Amazon S3 bucket and publish the images to the website. The company wants to deploy a serverless image-processing application that uses an AWS Lambda function to resize the uploaded images. The company''s development team has created the Lambda function. A CloudOps engineer must implement a solution to invoke the Lambda function when users upload new images to the S3 bucket. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0036"}', '{"tags": null, "topic": null, "options": [["A", "Configure an Amazon Simple Notification Service (Amazon SNS) topic to invoke the Lambda function when a user uploads a new image to the S3 bucket."], ["B", "Configure an Amazon CloudWatch alarm to invoke the Lambda function when a user uploads a new image to the S3 bucket."], ["C", "Configure S3 Event Notifications to invoke the Lambda function when a user uploads a new image to the S3 bucket."], ["D", "Configure an Amazon Simple Queue Service (Amazon SQS) queue to invoke the Lambda function when a user uploads a new image to the S3 bucket."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0036"}, "reference": null, "difficulty": "medium", "explanation": "Use Amazon S3 Event Notifications with AWS Lambda to trigger image processing on object\ncreation. S3 natively supports invoking Lambda for events such as s3:ObjectCreated:*, providing\na serverless, low-latency pipeline without managing additional services. AWS operational\nguidance states that \"Amazon S3 can directly invoke a Lambda function in response to object-\ncreated events,\" allowing you to pass event metadata (bucket/key) to the function for resizing and\nwriting results back to S3. This approach minimizes operational overhead, scales automatically\nwith upload volume, and integrates with standard retry semantics. SNS or SQS can be added for\nfan-out or buffering patterns, but they are not required when the requirement is simply \"invoke the\nLambda function on upload.\" CloudWatch alarms do not detect individual S3 object uploads and\ncannot directly satisfy per-object triggers. Therefore, configuring S3 Lambda event notifications\nmeets the requirement most directly and aligns with CloudOps best practices for event-driven,\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nserverless automation.", "question_text": "A company runs a website on Amazon EC2 instances. Users can upload images to an Amazon S3 bucket and publish the images to the website. The company wants to deploy a serverless image-processing application that uses an AWS Lambda function to resize the uploaded images. The company''s development team has created the Lambda function. A CloudOps engineer must implement a solution to invoke the Lambda function when users upload new images to the S3 bucket. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '781fc6f5ecc25a507c0bf320eb33d87697f0a20e62867b73d82847ce1d7ceec2', 1386, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (871, 146, 38, 'qblock_pdf', '{"option_a": "Create an Aurora Replica node. Create an Auto Scaling policy to scale replicas based on CPU utilization. Ensure that all reporting requests use the read-only connection string.", "option_b": "Create a second Aurora MySQL single-node DB cluster in a second Availability Zone. Ensure that all reporting requests use the connection string for this additional node.", "option_c": "Create an AWS Lambda function that caches reporting requests. Ensure that all reporting requests call the Lambda function.", "option_d": "Create a multi-node Amazon ElastiCache cluster. Ensure that all reporting requests use the ElastiCache cluster. Use the database if the data is not in the cache.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Amazon Aurora supports up to 15 Aurora Replicas that share the same storage volume and\nprovide read scaling and improved availability. Official guidance states that replicas \"offload read\ntraffic from the writer\" and that you should direct read-only workloads to the reader endpoint,\nreducing CPU pressure and connection counts on the primary. Aurora also supports Replica Auto\nScaling through Application Auto Scaling policies using metrics such as CPU utilization or\nconnections to add or remove replicas automatically. This design addresses both high CPU and\nmaximum connections by moving reporting traffic to read replicas while keeping a single write\nprimary for OLTP. Option B creates a separate cluster with independent storage, increasing\noperational overhead and data synchronization complexity. Options C and D introduce\napplication-layer caching changes that may not guarantee data freshness or relieve the write\nnode directly. Therefore, adding read replicas and routing reporting to the reader endpoint, with\nauto scaling based on load, is the least intrusive, CloudOps-aligned way to stabilize performance.", "question_text": "A company hosts a production MySQL database on an Amazon Aurora single-node DB cluster. The database is queried heavily for reporting purposes. The DB cluster is experiencing periods of performance degradation because of high CPU utilization and maximum connections errors. A CloudOps engineer needs to improve the stability of the database. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0037"}', '{"tags": null, "topic": null, "options": [["A", "Create an Aurora Replica node. Create an Auto Scaling policy to scale replicas based on CPU utilization. Ensure that all reporting requests use the read-only connection string."], ["B", "Create a second Aurora MySQL single-node DB cluster in a second Availability Zone. Ensure that all reporting requests use the connection string for this additional node."], ["C", "Create an AWS Lambda function that caches reporting requests. Ensure that all reporting requests call the Lambda function."], ["D", "Create a multi-node Amazon ElastiCache cluster. Ensure that all reporting requests use the ElastiCache cluster. Use the database if the data is not in the cache."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0037"}, "reference": null, "difficulty": "medium", "explanation": "Amazon Aurora supports up to 15 Aurora Replicas that share the same storage volume and\nprovide read scaling and improved availability. Official guidance states that replicas \"offload read\ntraffic from the writer\" and that you should direct read-only workloads to the reader endpoint,\nreducing CPU pressure and connection counts on the primary. Aurora also supports Replica Auto\nScaling through Application Auto Scaling policies using metrics such as CPU utilization or\nconnections to add or remove replicas automatically. This design addresses both high CPU and\nmaximum connections by moving reporting traffic to read replicas while keeping a single write\nprimary for OLTP. Option B creates a separate cluster with independent storage, increasing\noperational overhead and data synchronization complexity. Options C and D introduce\napplication-layer caching changes that may not guarantee data freshness or relieve the write\nnode directly. Therefore, adding read replicas and routing reporting to the reader endpoint, with\nauto scaling based on load, is the least intrusive, CloudOps-aligned way to stabilize performance.", "question_text": "A company hosts a production MySQL database on an Amazon Aurora single-node DB cluster. The database is queried heavily for reporting purposes. The DB cluster is experiencing periods of performance degradation because of high CPU utilization and maximum connections errors. A CloudOps engineer needs to improve the stability of the database. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'ffc52cd5fa50643bd6643d7806a4d2ebb878b8b0aaf15fb71a5fa42729cf3da6', 1387, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (872, 146, 39, 'qblock_pdf', '{"option_a": "The Auto Scaling group will launch an additional EC2 instance every time the RequestCountPerTarget metric exceeds the predefined limit.", "option_b": "The Auto Scaling group will launch one EC2 instance and will wait for the default cooldown period before launching another instance.", "option_c": "The Auto Scaling group will send an alert to the ALB to rebalance the traffic and not add new EC2 instances until the load is normalized.", "option_d": "The Auto Scaling group will try to distribute the traffic among all EC2 instances before launching another instance.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nWith simple scaling policies, an Auto Scaling group performs one scaling activity when the alarm\ncondition is met, then observes a default cooldown period (300 seconds) before another scaling\nactivity of the same type can begin. CloudOps guidance explains that cooldown prevents rapid\nsuccessive scale-outs by allowing time for the newly launched instance(s) to register with the load\nbalancer and impact the metric. Even if the alarm breaches multiple times during the cooldown\nwindow, the group waits until the cooldown completes before evaluating and acting again. In this\ncase, although RequestCountPerTarget exceeded the threshold twice within 180 seconds, the\ngroup will launch a single instance and then wait for cooldown before any additional scale-out can\noccur. Options A, C, and D do not reflect the behavior of simple scaling with cooldowns; A\ndescribes step/target-tracking-like behavior, and C/D are not Auto Scaling mechanics.", "question_text": "A CloudOps engineer configures an application to run on Amazon EC2 instances behind an Application Load Balancer (ALB) in a simple scaling Auto Scaling group with the default settings. The Auto Scaling group is configured to use the RequestCountPerTarget metric for scaling. The CloudOps engineer notices that the RequestCountPerTarget metric exceeded the specified limit twice in 180 seconds. How will the number of EC2 instances in this Auto Scaling group be affected in this scenario?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0038"}', '{"tags": null, "topic": null, "options": [["A", "The Auto Scaling group will launch an additional EC2 instance every time the RequestCountPerTarget metric exceeds the predefined limit."], ["B", "The Auto Scaling group will launch one EC2 instance and will wait for the default cooldown period before launching another instance."], ["C", "The Auto Scaling group will send an alert to the ALB to rebalance the traffic and not add new EC2 instances until the load is normalized."], ["D", "The Auto Scaling group will try to distribute the traffic among all EC2 instances before launching another instance."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0038"}, "reference": null, "difficulty": "medium", "explanation": "Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nWith simple scaling policies, an Auto Scaling group performs one scaling activity when the alarm\ncondition is met, then observes a default cooldown period (300 seconds) before another scaling\nactivity of the same type can begin. CloudOps guidance explains that cooldown prevents rapid\nsuccessive scale-outs by allowing time for the newly launched instance(s) to register with the load\nbalancer and impact the metric. Even if the alarm breaches multiple times during the cooldown\nwindow, the group waits until the cooldown completes before evaluating and acting again. In this\ncase, although RequestCountPerTarget exceeded the threshold twice within 180 seconds, the\ngroup will launch a single instance and then wait for cooldown before any additional scale-out can\noccur. Options A, C, and D do not reflect the behavior of simple scaling with cooldowns; A\ndescribes step/target-tracking-like behavior, and C/D are not Auto Scaling mechanics.", "question_text": "A CloudOps engineer configures an application to run on Amazon EC2 instances behind an Application Load Balancer (ALB) in a simple scaling Auto Scaling group with the default settings. The Auto Scaling group is configured to use the RequestCountPerTarget metric for scaling. The CloudOps engineer notices that the RequestCountPerTarget metric exceeded the specified limit twice in 180 seconds. How will the number of EC2 instances in this Auto Scaling group be affected in this scenario?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '32dad9cf504d834aa7a3f4acbc20ebebfd400c0c08581110596f4515da7fe5be', 1388, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (880, 146, 47, 'qblock_pdf', '{"option_a": "The EFS mount target has been created in a private subnet.", "option_b": "The IAM role that is associated with the EC2 instances does not allow the efs:MountFileSystem action.", "option_c": "The route tables have not been configured to route traffic to a VPC endpoint for Amazon EFS in the new Availability Zone.", "option_d": "The security group for the mount target does not allow inbound NFS connections from the security group used by the EC2 instances.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "When you add a new EFS mount target in a new Availability Zone, that mount target has its own\nsecurity group. For the EC2 instances in that AZ to mount the file system over NFS, the mount\ntarget’s security group must allow inbound TCP 2049 (NFS) from the EC2 instances’ security\ngroup.\nIf that rule isn’t there, the instances can see the mount target in the same VPC/AZ but can’t\ncomplete the NFS connection, so the mount fails.", "question_text": "A company runs an application on a large fleet of Amazon EC2 instances to process financial transactions. The EC2 instances share data by using an Amazon Elastic File System (Amazon EFS) file system. The company wants to deploy the application to a new Availability Zone and has created new subnets and a mount target in the new Availability Zone. When a SysOps administrator launches Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com new EC2 instances in the new subnets, the EC2 instances are unable to mount the file system. What is a reason for this issue?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0046"}', '{"tags": null, "topic": null, "options": [["A", "The EFS mount target has been created in a private subnet."], ["B", "The IAM role that is associated with the EC2 instances does not allow the efs:MountFileSystem action."], ["C", "The route tables have not been configured to route traffic to a VPC endpoint for Amazon EFS in the new Availability Zone."], ["D", "The security group for the mount target does not allow inbound NFS connections from the security group used by the EC2 instances."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0046"}, "reference": null, "difficulty": "medium", "explanation": "When you add a new EFS mount target in a new Availability Zone, that mount target has its own\nsecurity group. For the EC2 instances in that AZ to mount the file system over NFS, the mount\ntarget’s security group must allow inbound TCP 2049 (NFS) from the EC2 instances’ security\ngroup.\nIf that rule isn’t there, the instances can see the mount target in the same VPC/AZ but can’t\ncomplete the NFS connection, so the mount fails.", "question_text": "A company runs an application on a large fleet of Amazon EC2 instances to process financial transactions. The EC2 instances share data by using an Amazon Elastic File System (Amazon EFS) file system. The company wants to deploy the application to a new Availability Zone and has created new subnets and a mount target in the new Availability Zone. When a SysOps administrator launches Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com new EC2 instances in the new subnets, the EC2 instances are unable to mount the file system. What is a reason for this issue?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '43b7d2e167d859d58027467054f6a06f63ca8a94a7696f838848bb561d50a0c4', 1396, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (873, 146, 40, 'qblock_pdf', '{"option_a": "Replace ElastiCache (Redis OSS) with ElastiCache (Memcached).", "option_b": "Create an Amazon EventBridge rule to initiate a backup every hour. Restore the backup when necessary.", "option_c": "Create a read replica in a second Availability Zone. Enable Multi-AZ for the ElastiCache (Redis OSS) replication group.", "option_d": "Enable automatic backups. Restore the backups when necessary.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "For high availability and fast failover, ElastiCache for Redis supports replication groups with Multi-\nAZ and automatic failover. CloudOps guidance states that a primary node can be paired with one\nor more replicas across multiple Availability Zones; if the primary fails, Redis automatically\npromotes a replica to primary in seconds, thereby minimizing RTO. This architecture maintains in-\nmemory data continuity without waiting for backup restore operations. Backups (Options B and D)\nprovide durability but require restore and re-warm procedures that increase RTO and may impact\napplication latency. Switching engines (Option A) to Memcached does not provide Redis\nreplication/failover semantics and would not inherently improve resilience for this use case.\nTherefore, creating a read replica in a different AZ and enabling Multi-AZ with automatic failover\nis the prescribed CloudOps pattern to increase resilience and achieve the lowest practical RTO\nfor Redis caches.", "question_text": "A company uses Amazon ElastiCache (Redis OSS) to cache application data. A CloudOps engineer must implement a solution to increase the resilience of the cache. The solution also must minimize the recovery time objective (RTO). Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0039"}', '{"tags": null, "topic": null, "options": [["A", "Replace ElastiCache (Redis OSS) with ElastiCache (Memcached)."], ["B", "Create an Amazon EventBridge rule to initiate a backup every hour. Restore the backup when necessary."], ["C", "Create a read replica in a second Availability Zone. Enable Multi-AZ for the ElastiCache (Redis OSS) replication group."], ["D", "Enable automatic backups. Restore the backups when necessary."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0039"}, "reference": null, "difficulty": "medium", "explanation": "For high availability and fast failover, ElastiCache for Redis supports replication groups with Multi-\nAZ and automatic failover. CloudOps guidance states that a primary node can be paired with one\nor more replicas across multiple Availability Zones; if the primary fails, Redis automatically\npromotes a replica to primary in seconds, thereby minimizing RTO. This architecture maintains in-\nmemory data continuity without waiting for backup restore operations. Backups (Options B and D)\nprovide durability but require restore and re-warm procedures that increase RTO and may impact\napplication latency. Switching engines (Option A) to Memcached does not provide Redis\nreplication/failover semantics and would not inherently improve resilience for this use case.\nTherefore, creating a read replica in a different AZ and enabling Multi-AZ with automatic failover\nis the prescribed CloudOps pattern to increase resilience and achieve the lowest practical RTO\nfor Redis caches.", "question_text": "A company uses Amazon ElastiCache (Redis OSS) to cache application data. A CloudOps engineer must implement a solution to increase the resilience of the cache. The solution also must minimize the recovery time objective (RTO). Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '99f7e4f46e17a1d2ed98a2669dad5f035ffd5aff380db37f19ed0835551f4d59', 1389, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (874, 146, 41, 'qblock_pdf', '{"option_a": "Write a script to continue backing up the RDS instance every five minutes.", "option_b": "Create an AWS Lambda function to take a snapshot of the RDS instance, and manually invoke the function before deleting the stack.", "option_c": "Use the Snapshot Deletion Policy in the CloudFormation template definition of the RDS instance.", "option_d": "Create a new CloudFormation template to perform backups of the RDS instance, and run this Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com template before deleting the stack.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS CloudFormation supports the DeletionPolicy attribute to control what happens to a resource\nwhen a stack is deleted. For Amazon RDS DB instances, setting DeletionPolicy: Snapshot\ninstructs CloudFormation to retain a final DB snapshot automatically at stack deletion. CloudOps\nbest practice recommends using this native mechanism for data retention and auditability,\navoiding manual scripts or out-of-band processes. Options A, B, and D introduce operational\noverhead and potential human error. With DeletionPolicy set to Snapshot, the environment can\nbe repeatedly created and torn down while preserving data states for later restoration with\nminimal manual steps. This aligns with IaC principles--declarative, repeatable, and reliable--and\nsupports efficient lifecycle management of ephemeral development stacks.", "question_text": "An AWS CloudFormation template creates an Amazon RDS instance. This template is used to build up development environments as needed and then delete the stack when the environment is no longer required. The RDS-persisted data must be retained for further use, even after the CloudFormation stack is deleted. How can this be achieved in a reliable and efficient way?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0040"}', '{"tags": null, "topic": null, "options": [["A", "Write a script to continue backing up the RDS instance every five minutes."], ["B", "Create an AWS Lambda function to take a snapshot of the RDS instance, and manually invoke the function before deleting the stack."], ["C", "Use the Snapshot Deletion Policy in the CloudFormation template definition of the RDS instance."], ["D", "Create a new CloudFormation template to perform backups of the RDS instance, and run this Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com template before deleting the stack."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0040"}, "reference": null, "difficulty": "medium", "explanation": "AWS CloudFormation supports the DeletionPolicy attribute to control what happens to a resource\nwhen a stack is deleted. For Amazon RDS DB instances, setting DeletionPolicy: Snapshot\ninstructs CloudFormation to retain a final DB snapshot automatically at stack deletion. CloudOps\nbest practice recommends using this native mechanism for data retention and auditability,\navoiding manual scripts or out-of-band processes. Options A, B, and D introduce operational\noverhead and potential human error. With DeletionPolicy set to Snapshot, the environment can\nbe repeatedly created and torn down while preserving data states for later restoration with\nminimal manual steps. This aligns with IaC principles--declarative, repeatable, and reliable--and\nsupports efficient lifecycle management of ephemeral development stacks.", "question_text": "An AWS CloudFormation template creates an Amazon RDS instance. This template is used to build up development environments as needed and then delete the stack when the environment is no longer required. The RDS-persisted data must be retained for further use, even after the CloudFormation stack is deleted. How can this be achieved in a reliable and efficient way?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '3d7f92f81e92a7d062741fa286948f1323104d6f1f1ed3942e1f18fbc2996f4e', 1390, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (875, 146, 42, 'qblock_pdf', '{"option_a": "Create an EC2 Instance Connect endpoint in the private subnet. Update the security group to allow inbound SSH traffic. Create an IAM group for privileged administrators. Assign the PowerUserAccess managed policy to the IAM group.", "option_b": "Create a Systems Manager endpoint in the private subnet. Update the security group to allow SSH traffic from the private network where the Systems Manager endpoint is connected. Create an IAM group for privileged administrators. Assign the PowerUserAccess managed policy to the IAM group.", "option_c": "Create an EC2 Instance Connect endpoint in the public subnet. Update the security group to allow SSH traffic from the private network. Create an IAM group for privileged administrators. Assign the PowerUserAccess managed policy to the IAM group.", "option_d": "Create a Systems Manager endpoint in the public subnet. Create an IAM role that has the AmazonSSMManagedInstanceCore permission for the EC2 instance. Create an IAM group for privileged administrators. Assign the AmazonEC2ReadOnlyAccess IAM policy to the IAM group.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "EC2 Instance Connect Endpoint (EIC Endpoint) enables SSH to instances in private subnets\nwithout public IPs and without needing to traverse the public internet. CloudOps guidance\nexplains that you deploy the endpoint in the same VPC/subnet as the targets, then allow inbound\nSSH on the instance security group from the endpoint''s security group. Access is governed by\nIAM--administrators must have Instance Connect permissions; while the example uses a broad\npolicy, the key mechanism is EIC in the private subnet plus SG rules scoped to the endpoint.\nSystems Manager Session Manager can provide shell access without SSH, but the requirement\nexplicitly states \"connect through SSH,\" making EIC the purpose-built solution. Options B and D\nmisuse Systems Manager for SSH and propose unnecessary SG changes or incorrect endpoint\nplacement; Option C places the endpoint in a public subnet, which is not required for private SSH\naccess. Therefore, creating an EC2 Instance Connect endpoint in the private subnet and\nupdating SGs accordingly meets the requirement while keeping the instance non-internet-\nexposed.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A company has a VPC that contains a public subnet and a private subnet. The company deploys an Amazon EC2 instance that uses an Amazon Linux Amazon Machine Image (AMI) and has the AWS Systems Manager Agent (SSM Agent) installed in the private subnet. The EC2 instance is in a security group that allows only outbound traffic. A CloudOps engineer needs to give a group of privileged administrators the ability to connect to the instance through SSH without exposing the instance to the internet. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0041"}', '{"tags": null, "topic": null, "options": [["A", "Create an EC2 Instance Connect endpoint in the private subnet. Update the security group to allow inbound SSH traffic. Create an IAM group for privileged administrators. Assign the PowerUserAccess managed policy to the IAM group."], ["B", "Create a Systems Manager endpoint in the private subnet. Update the security group to allow SSH traffic from the private network where the Systems Manager endpoint is connected. Create an IAM group for privileged administrators. Assign the PowerUserAccess managed policy to the IAM group."], ["C", "Create an EC2 Instance Connect endpoint in the public subnet. Update the security group to allow SSH traffic from the private network. Create an IAM group for privileged administrators. Assign the PowerUserAccess managed policy to the IAM group."], ["D", "Create a Systems Manager endpoint in the public subnet. Create an IAM role that has the AmazonSSMManagedInstanceCore permission for the EC2 instance. Create an IAM group for privileged administrators. Assign the AmazonEC2ReadOnlyAccess IAM policy to the IAM group."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0041"}, "reference": null, "difficulty": "medium", "explanation": "EC2 Instance Connect Endpoint (EIC Endpoint) enables SSH to instances in private subnets\nwithout public IPs and without needing to traverse the public internet. CloudOps guidance\nexplains that you deploy the endpoint in the same VPC/subnet as the targets, then allow inbound\nSSH on the instance security group from the endpoint''s security group. Access is governed by\nIAM--administrators must have Instance Connect permissions; while the example uses a broad\npolicy, the key mechanism is EIC in the private subnet plus SG rules scoped to the endpoint.\nSystems Manager Session Manager can provide shell access without SSH, but the requirement\nexplicitly states \"connect through SSH,\" making EIC the purpose-built solution. Options B and D\nmisuse Systems Manager for SSH and propose unnecessary SG changes or incorrect endpoint\nplacement; Option C places the endpoint in a public subnet, which is not required for private SSH\naccess. Therefore, creating an EC2 Instance Connect endpoint in the private subnet and\nupdating SGs accordingly meets the requirement while keeping the instance non-internet-\nexposed.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A company has a VPC that contains a public subnet and a private subnet. The company deploys an Amazon EC2 instance that uses an Amazon Linux Amazon Machine Image (AMI) and has the AWS Systems Manager Agent (SSM Agent) installed in the private subnet. The EC2 instance is in a security group that allows only outbound traffic. A CloudOps engineer needs to give a group of privileged administrators the ability to connect to the instance through SSH without exposing the instance to the internet. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '8b960bc3de27a090c91ce67378b0e1d7e1ac0965c80ea05020e3d073060fe01a', 1391, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (877, 146, 44, 'qblock_pdf', '{"option_a": "The missing instances have insufficient historical Amazon CloudWatch metric data for analysis.", "option_b": "Compute Optimizer does not support the instance types of the missing instances.", "option_c": "Compute Optimizer already considers the missing instances to be optimized.", "option_d": "The missing instances are running a Windows operating system.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Compute Optimizer documentation, Compute\nOptimizer provides right-sizing recommendations by analyzing Amazon CloudWatch metrics and\ninstance configuration data. However, AWS explicitly notes that only supported instance types\nare included in Compute Optimizer analyses. If an EC2 instance type is newly released or not yet\nsupported by Compute Optimizer, it will not appear in the Compute Optimizer dashboard until\nofficial support is added.\nThe documentation explains that \"Compute Optimizer analyses only supported resource types\nand instance families. Instances using unsupported or newly launched instance types will not\nappear in the Compute Optimizer console.\" This ensures the service provides accurate\nrecommendations based on sufficient performance history and benchmark data.\nWhile CloudWatch metrics are required for analysis, the complete absence of instances from the\ndashboard -- rather than \"insufficient metric data\" notifications -- indicates unsupported instance\ntypes. Compute Optimizer would normally still display those with limited metrics but would flag\nthem as \"insufficient data,\" not remove them entirely.\nTherefore, the most accurate cause of missing instances in this case is that Compute Optimizer\ndoes not support the newly released instance types, making option B correct.", "question_text": "A CloudOps engineer is using AWS Compute Optimizer to generate recommendations for a fleet of Amazon EC2 instances. Some of the instances use newly released instance types, while other Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com instances use older instance types. After the analysis is complete, the CloudOps engineer notices that some of the EC2 instances are missing from the Compute Optimizer dashboard. What is the likely cause of this issue?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0043"}', '{"tags": null, "topic": null, "options": [["A", "The missing instances have insufficient historical Amazon CloudWatch metric data for analysis."], ["B", "Compute Optimizer does not support the instance types of the missing instances."], ["C", "Compute Optimizer already considers the missing instances to be optimized."], ["D", "The missing instances are running a Windows operating system."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0043"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Compute Optimizer documentation, Compute\nOptimizer provides right-sizing recommendations by analyzing Amazon CloudWatch metrics and\ninstance configuration data. However, AWS explicitly notes that only supported instance types\nare included in Compute Optimizer analyses. If an EC2 instance type is newly released or not yet\nsupported by Compute Optimizer, it will not appear in the Compute Optimizer dashboard until\nofficial support is added.\nThe documentation explains that \"Compute Optimizer analyses only supported resource types\nand instance families. Instances using unsupported or newly launched instance types will not\nappear in the Compute Optimizer console.\" This ensures the service provides accurate\nrecommendations based on sufficient performance history and benchmark data.\nWhile CloudWatch metrics are required for analysis, the complete absence of instances from the\ndashboard -- rather than \"insufficient metric data\" notifications -- indicates unsupported instance\ntypes. Compute Optimizer would normally still display those with limited metrics but would flag\nthem as \"insufficient data,\" not remove them entirely.\nTherefore, the most accurate cause of missing instances in this case is that Compute Optimizer\ndoes not support the newly released instance types, making option B correct.", "question_text": "A CloudOps engineer is using AWS Compute Optimizer to generate recommendations for a fleet of Amazon EC2 instances. Some of the instances use newly released instance types, while other Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com instances use older instance types. After the analysis is complete, the CloudOps engineer notices that some of the EC2 instances are missing from the Compute Optimizer dashboard. What is the likely cause of this issue?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '02007a26bc7c8b0429310870a591fbf35c6a1cea272f72c996427b173c8104cd', 1393, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (878, 146, 45, 'qblock_pdf', '{"option_a": "Interface VPC endpoints for EventBridge are required in the sender accounts and receiver accounts.", "option_b": "The target Lambda function is in a different AWS Region, which is not supported by EventBridge.", "option_c": "The resource-based policy on the target event bus must be modified to allow PutEvents API calls Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com from the sender accounts.", "option_d": "The rule in the receiving account must specify {\"account\": [\"sender-account-id\"]} in its event pattern and must include the receiving account ID.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "When events are sent across AWS accounts -- particularly from multiple accounts in an AWS\nOrganization -- the target event bus in the receiver account must include a resource-based policy\nthat explicitly allows events:PutEvents API calls from the sender accounts or the organization ID.\nEven if the sender accounts have IAM permissions to call PutEvents, the receiving event bus\nmust trust those accounts via a resource policy. Without this configuration, EventBridge\nautomatically rejects incoming cross-account events, and those events never reach the target\nLambda function for processing.\nAWS guidance states that \"Cross-account event delivery requires a resource-based policy on the\nevent bus that grants permissions to the source accounts or organization.\" The policy can include\neither individual AWS account IDs or the organization''s root ID.\nIn this scenario, because the events originate from multiple accounts and there is no resource\npolicy on the target event bus to authorize those sender accounts, the events are not delivered.\nTherefore, the correct cause is C ?the resource-based policy on the target event bus must be\nmodified to allow PutEvents API calls from the sender accounts.", "question_text": "A company uses an organization in AWS Organizations to manage multiple AWS accounts. The company needs to send specific events from all the accounts in the organization to a new receiver account, where an AWS Lambda function will process the events. A CloudOps engineer configures Amazon EventBridge to route events to a target event bus in the us- west-2 Region in the receiver account. The CloudOps engineer creates rules in both the sender and receiver accounts that match the specified events. The rules do not specify an account parameter in the event pattern. IAM roles are created in the sender accounts to allow PutEvents actions on the target event bus. However, the first test events from the us-east-1 Region are not processed by the Lambda function in the receiving account. What is the likely reason the events are not processed?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0044"}', '{"tags": null, "topic": null, "options": [["A", "Interface VPC endpoints for EventBridge are required in the sender accounts and receiver accounts."], ["B", "The target Lambda function is in a different AWS Region, which is not supported by EventBridge."], ["C", "The resource-based policy on the target event bus must be modified to allow PutEvents API calls Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com from the sender accounts."], ["D", "The rule in the receiving account must specify {\"account\": [\"sender-account-id\"]} in its event pattern and must include the receiving account ID."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0044"}, "reference": null, "difficulty": "medium", "explanation": "When events are sent across AWS accounts -- particularly from multiple accounts in an AWS\nOrganization -- the target event bus in the receiver account must include a resource-based policy\nthat explicitly allows events:PutEvents API calls from the sender accounts or the organization ID.\nEven if the sender accounts have IAM permissions to call PutEvents, the receiving event bus\nmust trust those accounts via a resource policy. Without this configuration, EventBridge\nautomatically rejects incoming cross-account events, and those events never reach the target\nLambda function for processing.\nAWS guidance states that \"Cross-account event delivery requires a resource-based policy on the\nevent bus that grants permissions to the source accounts or organization.\" The policy can include\neither individual AWS account IDs or the organization''s root ID.\nIn this scenario, because the events originate from multiple accounts and there is no resource\npolicy on the target event bus to authorize those sender accounts, the events are not delivered.\nTherefore, the correct cause is C ?the resource-based policy on the target event bus must be\nmodified to allow PutEvents API calls from the sender accounts.", "question_text": "A company uses an organization in AWS Organizations to manage multiple AWS accounts. The company needs to send specific events from all the accounts in the organization to a new receiver account, where an AWS Lambda function will process the events. A CloudOps engineer configures Amazon EventBridge to route events to a target event bus in the us- west-2 Region in the receiver account. The CloudOps engineer creates rules in both the sender and receiver accounts that match the specified events. The rules do not specify an account parameter in the event pattern. IAM roles are created in the sender accounts to allow PutEvents actions on the target event bus. However, the first test events from the us-east-1 Region are not processed by the Lambda function in the receiving account. What is the likely reason the events are not processed?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'b054eeda57ca0de7ea33a37c9f63637d4954ba877624fcc72f7cccf1b40a5d76', 1394, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (881, 146, 48, 'qblock_pdf', '{"option_a": "Create a backup plan in AWS Backup. Assign resources by resource ID, selecting all existing EC2 and EFS resources that are running in the account. Edit the backup plan daily to include any new resources. Schedule the backup plan to run every day with a lifecycle policy to expire backups after 30 days.", "option_b": "Create a backup plan in AWS Backup. Assign resources by tags. Ensure that all existing EC2 and EFS resources are tagged correctly. Apply a service control policy (SCP) for the production account OU that prevents instance and file system creation unless the correct tags are applied. Schedule the backup plan to run every day with a lifecycle policy to expire backups after 30 days.", "option_c": "Create a lifecycle policy in Amazon Data Lifecycle Manager (Amazon DLM). Assign all resources by resource ID, selecting all existing EC2 and EFS resources that are running in the account. Edit the lifecycle policy daily to include any new resources. Schedule the lifecycle policy to create snapshots every day with a retention period of 30 days.", "option_d": "Create a lifecycle policy in Amazon Data Lifecycle Manager (Amazon DLM). Assign all resources by tags. Ensure that all existing EC2 and EFS resources are tagged correctly. Apply a service control policy (SCP) that prevents resource creation unless the correct tags are applied. Schedule the lifecycle policy to create snapshots every day with a retention period of 30 days.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Backup supports both EC2 and EFS natively. (Amazon DLM does not support EFS backups\n— that rules out C and D right away.)\nUsing tags instead of listing individual resource IDs means you don’t have to edit the plan every\ntime someone launches a new instance or creates a new file system.\nAdding an SCP that enforces tagging at creation guarantees that all future resources are\nautomatically included in backups.\nYou can set the plan to run daily and expire after 30 days — exactly what’s required.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "The company uses AWS Organizations to manage its accounts. For the production account, a SysOps administrator must ensure that all data is backed up daily for all current and future Amazon EC2 instances and Amazon Elastic File System (Amazon EFS) file systems. Backups must be retained for 30 days. Which solution will meet these requirements with the LEAST amount of effort?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0047"}', '{"tags": null, "topic": null, "options": [["A", "Create a backup plan in AWS Backup. Assign resources by resource ID, selecting all existing EC2 and EFS resources that are running in the account. Edit the backup plan daily to include any new resources. Schedule the backup plan to run every day with a lifecycle policy to expire backups after 30 days."], ["B", "Create a backup plan in AWS Backup. Assign resources by tags. Ensure that all existing EC2 and EFS resources are tagged correctly. Apply a service control policy (SCP) for the production account OU that prevents instance and file system creation unless the correct tags are applied. Schedule the backup plan to run every day with a lifecycle policy to expire backups after 30 days."], ["C", "Create a lifecycle policy in Amazon Data Lifecycle Manager (Amazon DLM). Assign all resources by resource ID, selecting all existing EC2 and EFS resources that are running in the account. Edit the lifecycle policy daily to include any new resources. Schedule the lifecycle policy to create snapshots every day with a retention period of 30 days."], ["D", "Create a lifecycle policy in Amazon Data Lifecycle Manager (Amazon DLM). Assign all resources by tags. Ensure that all existing EC2 and EFS resources are tagged correctly. Apply a service control policy (SCP) that prevents resource creation unless the correct tags are applied. Schedule the lifecycle policy to create snapshots every day with a retention period of 30 days."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0047"}, "reference": null, "difficulty": "medium", "explanation": "AWS Backup supports both EC2 and EFS natively. (Amazon DLM does not support EFS backups\n— that rules out C and D right away.)\nUsing tags instead of listing individual resource IDs means you don’t have to edit the plan every\ntime someone launches a new instance or creates a new file system.\nAdding an SCP that enforces tagging at creation guarantees that all future resources are\nautomatically included in backups.\nYou can set the plan to run daily and expire after 30 days — exactly what’s required.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "The company uses AWS Organizations to manage its accounts. For the production account, a SysOps administrator must ensure that all data is backed up daily for all current and future Amazon EC2 instances and Amazon Elastic File System (Amazon EFS) file systems. Backups must be retained for 30 days. Which solution will meet these requirements with the LEAST amount of effort?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '864795258717fba3bb2de0e5a55bae9163c329e5391df2318a821afce2cd0322', 1397, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (882, 146, 49, 'qblock_pdf', '{"option_a": "Attach an Elastic IP address to the Lambda function and configure a route to the internet gateway of the VPC.", "option_b": "Connect the Lambda function to a private subnet that has a route to the virtual private gateway of the VPC.", "option_c": "Connect the Lambda function to a public subnet that has a route to the internet gateway of the VPC.", "option_d": "Connect the Lambda function to a private subnet that has a route to a NAT gateway deployed in a public subnet of the VPC.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Lambda functions configured to run in a VPC require network egress to reach the internet for\nexternal APIs. A private subnet with a default route to a NAT gateway provides outbound internet\naccess for the Lambda without exposing the Lambda’s resources to inbound internet traffic. This\nsetup preserves the security of the VPC while enabling internet access for external API calls. The\nNAT gateway handles outbound connections on behalf of resources in the private subnet,\nensuring stable and scalable access.", "question_text": "A company needs to ensure that an AWS Lambda function can access resources in a VPC in the company''s account. The Lambda function requires access to third-party APIs that can be accessed only over the internet. Which action should a SysOps administrator take to meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0048"}', '{"tags": null, "topic": null, "options": [["A", "Attach an Elastic IP address to the Lambda function and configure a route to the internet gateway of the VPC."], ["B", "Connect the Lambda function to a private subnet that has a route to the virtual private gateway of the VPC."], ["C", "Connect the Lambda function to a public subnet that has a route to the internet gateway of the VPC."], ["D", "Connect the Lambda function to a private subnet that has a route to a NAT gateway deployed in a public subnet of the VPC."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0048"}, "reference": null, "difficulty": "medium", "explanation": "Lambda functions configured to run in a VPC require network egress to reach the internet for\nexternal APIs. A private subnet with a default route to a NAT gateway provides outbound internet\naccess for the Lambda without exposing the Lambda’s resources to inbound internet traffic. This\nsetup preserves the security of the VPC while enabling internet access for external API calls. The\nNAT gateway handles outbound connections on behalf of resources in the private subnet,\nensuring stable and scalable access.", "question_text": "A company needs to ensure that an AWS Lambda function can access resources in a VPC in the company''s account. The Lambda function requires access to third-party APIs that can be accessed only over the internet. Which action should a SysOps administrator take to meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '3decfc1e109c5be4324be57340fcb76632ca675ee43ba64112cff0a4302854ec', 1398, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (883, 146, 50, 'qblock_pdf', '{"option_a": "Use the AWS CLI to print all security group rules for review.", "option_b": "Review AWS Trusted Advisor findings in an organizational view for the Security Groups ?Specific Ports Unrestricted check.", "option_c": "Create an AWS Lambda function to gather security group rules from all accounts. Aggregate the findings in an Amazon S3 bucket.", "option_d": "Enable Amazon Inspector in each account. Run an automated workload discovery job.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to AWS Cloud Operations and Governance documentation, AWS Trusted Advisor\nprovides automated checks for security group rules across all accounts, including identifying ports\nopen to 0.0.0.0/0.\nWhen viewed in organizational mode, Trusted Advisor integrates with AWS Organizations,\nallowing administrators to access organization-wide security findings from a central management\naccount. This approach requires no custom code, additional infrastructure, or manual inspection,\nproviding immediate visibility and the lowest operational overhead.\nAWS CLI scripts (Option A) or Lambda automation (Option C) introduce additional maintenance,\nand Amazon Inspector (Option D) is focused on instance-level vulnerabilities, not network access\nrules.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nTherefore, Option B is the AWS-recommended CloudOps best practice for centralized and low-\neffort open-port auditing.", "question_text": "A company uses AWS Organizations to manage multiple AWS accounts. A CloudOps engineer must identify all IPv4 ports open to 0.0.0.0/0 across the organization''s accounts. Which solution will meet this requirement with the LEAST operational effort?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0049"}', '{"tags": null, "topic": null, "options": [["A", "Use the AWS CLI to print all security group rules for review."], ["B", "Review AWS Trusted Advisor findings in an organizational view for the Security Groups ?Specific Ports Unrestricted check."], ["C", "Create an AWS Lambda function to gather security group rules from all accounts. Aggregate the findings in an Amazon S3 bucket."], ["D", "Enable Amazon Inspector in each account. Run an automated workload discovery job."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0049"}, "reference": null, "difficulty": "medium", "explanation": "According to AWS Cloud Operations and Governance documentation, AWS Trusted Advisor\nprovides automated checks for security group rules across all accounts, including identifying ports\nopen to 0.0.0.0/0.\nWhen viewed in organizational mode, Trusted Advisor integrates with AWS Organizations,\nallowing administrators to access organization-wide security findings from a central management\naccount. This approach requires no custom code, additional infrastructure, or manual inspection,\nproviding immediate visibility and the lowest operational overhead.\nAWS CLI scripts (Option A) or Lambda automation (Option C) introduce additional maintenance,\nand Amazon Inspector (Option D) is focused on instance-level vulnerabilities, not network access\nrules.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nTherefore, Option B is the AWS-recommended CloudOps best practice for centralized and low-\neffort open-port auditing.", "question_text": "A company uses AWS Organizations to manage multiple AWS accounts. A CloudOps engineer must identify all IPv4 ports open to 0.0.0.0/0 across the organization''s accounts. Which solution will meet this requirement with the LEAST operational effort?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '89b56ab38da02d966f962b879420e8b0b9da0c3d4b82cc97e8ace036771a6967', 1399, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (884, 146, 51, 'qblock_pdf', '{"option_a": "The Expires header has been set to 3 hours.", "option_b": "Cached assets are not expiring in the edge location.", "option_c": "Cache invalidation is missing in the CloudFront configuration.", "option_d": "Cache-duration settings conflict with each other.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "As per the AWS Cloud Operations and Content Delivery documentation, CloudFront determines\ncache behavior by evaluating both origin headers (e.g., Cache-Control and Expires) and\ndistribution- level TTL settings.\nWhen Cache-Control max-age conflicts with the Maximum TTL configured in CloudFront, the\nshorter TTL value takes precedence. This results in CloudFront caching content for only 5\nminutes instead of 1 hour, despite the origin headers suggesting a longer duration.\nAWS documentation explicitly states: \"When both origin cache headers and CloudFront TTL\nsettings are defined, CloudFront uses the most restrictive caching period.\" This mismatch causes\nthe perceived performance drop, as CloudFront frequently revalidates content.\nTherefore, Option D is correct -- cache-duration settings conflict with each other, leading to\nunexpected caching behavior.", "question_text": "A company hosts a static website in an Amazon S3 bucket, accessed globally via Amazon CloudFront. The Cache-Control max-age header is set to 1 hour, and Maximum TTL is set to 5 minutes. The CloudOps engineer observes that CloudFront is not caching objects for the expected duration. What is the reason for this issue?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0050"}', '{"tags": null, "topic": null, "options": [["A", "The Expires header has been set to 3 hours."], ["B", "Cached assets are not expiring in the edge location."], ["C", "Cache invalidation is missing in the CloudFront configuration."], ["D", "Cache-duration settings conflict with each other."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0050"}, "reference": null, "difficulty": "medium", "explanation": "As per the AWS Cloud Operations and Content Delivery documentation, CloudFront determines\ncache behavior by evaluating both origin headers (e.g., Cache-Control and Expires) and\ndistribution- level TTL settings.\nWhen Cache-Control max-age conflicts with the Maximum TTL configured in CloudFront, the\nshorter TTL value takes precedence. This results in CloudFront caching content for only 5\nminutes instead of 1 hour, despite the origin headers suggesting a longer duration.\nAWS documentation explicitly states: \"When both origin cache headers and CloudFront TTL\nsettings are defined, CloudFront uses the most restrictive caching period.\" This mismatch causes\nthe perceived performance drop, as CloudFront frequently revalidates content.\nTherefore, Option D is correct -- cache-duration settings conflict with each other, leading to\nunexpected caching behavior.", "question_text": "A company hosts a static website in an Amazon S3 bucket, accessed globally via Amazon CloudFront. The Cache-Control max-age header is set to 1 hour, and Maximum TTL is set to 5 minutes. The CloudOps engineer observes that CloudFront is not caching objects for the expected duration. What is the reason for this issue?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'd490f10811778b1d8bd105ec42076a65cd34db91ffc0e3d94f1f80bdfccffa6a', 1400, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (885, 146, 52, 'qblock_pdf', '{"option_a": "Configure the AWS Config rule to identify noncompliant security groups. Configure the rule to use the AWS-PublishSNSNotification AWS Systems Manager Automation runbook to send notifications about noncompliant resources.", "option_b": "Configure the AWS Config rule to identify noncompliant security groups. Configure the rule to use the AWS-DisableIncomingSSHOnPort22 AWS Systems Manager Automation runbook to remediate noncompliant resources.", "option_c": "Make an AWS Config API call to search for noncompliant security groups. Disable SSH access for noncompliant security groups by using a Deny rule.", "option_d": "Configure the AWS Config rule to identify noncompliant security groups. Manually update each Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com noncompliant security group to remove the Allow rule.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Governance documentation specifies that AWS Config can be\npaired with AWS Systems Manager Automation runbooks for automatic remediation of\nnoncompliant resources.\nFor SSH restrictions, the restricted-ssh managed rule detects any security group allowing\ninbound traffic on port 22. To automatically remediate these findings, AWS provides the AWS-\nDisableIncomingSSHOnPort22 runbook. This runbook programmatically removes inbound rules\nthat allow port 22 traffic from affected security groups.\nThis approach achieves continuous compliance with minimal human intervention. By contrast,\nsending notifications (Option A) does not enforce remediation, API-based scripts (Option C) add\noperational overhead, and manual remediation (Option D) violates automation best practices.\nTherefore, the most efficient CloudOps solution is Option B, using AWS Config with the AWS-\nDisableIncomingSSHOnPort22 automation runbook for automatic, scalable enforcement.", "question_text": "A company runs applications on Amazon EC2 instances. The company wants to ensure that SSH ports on the EC2 instances are never open. The company has enabled AWS Config and has set up the restricted-ssh AWS managed rule. A CloudOps engineer must implement a solution to remediate SSH port access for noncompliant security groups. What should the engineer do to meet this requirement with the MOST operational efficiency?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0051"}', '{"tags": null, "topic": null, "options": [["A", "Configure the AWS Config rule to identify noncompliant security groups. Configure the rule to use the AWS-PublishSNSNotification AWS Systems Manager Automation runbook to send notifications about noncompliant resources."], ["B", "Configure the AWS Config rule to identify noncompliant security groups. Configure the rule to use the AWS-DisableIncomingSSHOnPort22 AWS Systems Manager Automation runbook to remediate noncompliant resources."], ["C", "Make an AWS Config API call to search for noncompliant security groups. Disable SSH access for noncompliant security groups by using a Deny rule."], ["D", "Configure the AWS Config rule to identify noncompliant security groups. Manually update each Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com noncompliant security group to remove the Allow rule."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0051"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Governance documentation specifies that AWS Config can be\npaired with AWS Systems Manager Automation runbooks for automatic remediation of\nnoncompliant resources.\nFor SSH restrictions, the restricted-ssh managed rule detects any security group allowing\ninbound traffic on port 22. To automatically remediate these findings, AWS provides the AWS-\nDisableIncomingSSHOnPort22 runbook. This runbook programmatically removes inbound rules\nthat allow port 22 traffic from affected security groups.\nThis approach achieves continuous compliance with minimal human intervention. By contrast,\nsending notifications (Option A) does not enforce remediation, API-based scripts (Option C) add\noperational overhead, and manual remediation (Option D) violates automation best practices.\nTherefore, the most efficient CloudOps solution is Option B, using AWS Config with the AWS-\nDisableIncomingSSHOnPort22 automation runbook for automatic, scalable enforcement.", "question_text": "A company runs applications on Amazon EC2 instances. The company wants to ensure that SSH ports on the EC2 instances are never open. The company has enabled AWS Config and has set up the restricted-ssh AWS managed rule. A CloudOps engineer must implement a solution to remediate SSH port access for noncompliant security groups. What should the engineer do to meet this requirement with the MOST operational efficiency?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '63f1822360232b9bb0e32adff8b22e8c24c1e6f31763f2f99769269fb79e4b18', 1401, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (886, 146, 53, 'qblock_pdf', '{"option_a": "Create an inbound rule in the security group to allow HTTPS traffic on port 443 from the private subnet.", "option_b": "Create an inbound rule in the security group to allow SSH traffic on port 22 from the private subnet.", "option_c": "Create an IAM instance profile that allows AWS Systems Manager Session Manager to access the EC2 instance. Associate the instance profile with the instance.", "option_d": "Recreate the EC2 instance. Associate an SSH key pair with the instance.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and EC2 Connectivity documentation, EC2 Instance\nConnect Endpoint allows access to instances without internet exposure or open SSH ports.\nHowever, for successful connectivity, the EC2 instance must have Systems Manager permissions\nthrough an IAM instance profile.\nIf no IAM instance profile is attached, the instance cannot establish a control channel with the\nSystems Manager service, and EC2 Instance Connect cannot authenticate the session.\nOpening port 22 (Option B) is unnecessary and contradicts the private subnet design. HTTPS\nrules (Option A) are irrelevant because EC2 Instance Connect communicates through AWS APIs,\nnot direct HTTPS connections. Recreating the instance with a key pair (Option D) bypasses the\nintended keyless connection mechanism.\nTherefore, Option C -- attaching an IAM instance profile with Systems Manager permissions --\nenables secure, private access through EC2 Instance Connect Endpoint.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A CloudOps engineer created a VPC with a private subnet, a security group allowing all outbound traffic, and an endpoint for EC2 Instance Connect in the private subnet. The EC2 instance was launched without an SSH key pair, using the same subnet and security group. However, the engineer cannot connect via EC2 Instance Connect endpoint. How can the CloudOps engineer connect to the instance?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0052"}', '{"tags": null, "topic": null, "options": [["A", "Create an inbound rule in the security group to allow HTTPS traffic on port 443 from the private subnet."], ["B", "Create an inbound rule in the security group to allow SSH traffic on port 22 from the private subnet."], ["C", "Create an IAM instance profile that allows AWS Systems Manager Session Manager to access the EC2 instance. Associate the instance profile with the instance."], ["D", "Recreate the EC2 instance. Associate an SSH key pair with the instance."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0052"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and EC2 Connectivity documentation, EC2 Instance\nConnect Endpoint allows access to instances without internet exposure or open SSH ports.\nHowever, for successful connectivity, the EC2 instance must have Systems Manager permissions\nthrough an IAM instance profile.\nIf no IAM instance profile is attached, the instance cannot establish a control channel with the\nSystems Manager service, and EC2 Instance Connect cannot authenticate the session.\nOpening port 22 (Option B) is unnecessary and contradicts the private subnet design. HTTPS\nrules (Option A) are irrelevant because EC2 Instance Connect communicates through AWS APIs,\nnot direct HTTPS connections. Recreating the instance with a key pair (Option D) bypasses the\nintended keyless connection mechanism.\nTherefore, Option C -- attaching an IAM instance profile with Systems Manager permissions --\nenables secure, private access through EC2 Instance Connect Endpoint.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A CloudOps engineer created a VPC with a private subnet, a security group allowing all outbound traffic, and an endpoint for EC2 Instance Connect in the private subnet. The EC2 instance was launched without an SSH key pair, using the same subnet and security group. However, the engineer cannot connect via EC2 Instance Connect endpoint. How can the CloudOps engineer connect to the instance?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'df07230403b11082a605df1d2163530b24816036794023ec6a5dd6b0a96558f7', 1402, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (887, 146, 54, 'qblock_pdf', '{"option_a": "Create an Amazon CloudFront distribution with the GET HTTP method allowed and the S3 bucket as an origin.", "option_b": "Create an Amazon ElastiCache cluster and enable caching for the S3 bucket.", "option_c": "Set up AWS Global Accelerator and configure it with the S3 bucket.", "option_d": "Enable S3 Transfer Acceleration and use the acceleration endpoint when uploading files.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Storage documentation confirms that S3 Transfer Acceleration is\ndesigned to increase upload speed for objects transferred to S3 buckets over long distances.\nIt uses AWS Global Edge Network and Amazon CloudFront edge locations to route data through\noptimized network paths, reducing latency and achieving higher throughput compared to standard\nS3 uploads.\nAfter enabling Transfer Acceleration on the bucket, users upload files to the accelerated endpoint\n(e.g., bucketname.s3-accelerate.amazonaws.com). This feature requires no changes to\napplication logic besides endpoint modification and provides immediate performance\nimprovement.\nCloudFront (Option A) is for content delivery, not uploads. ElastiCache (Option B) and Global\nAccelerator (Option C) are unrelated to S3 upload performance.\nThus, Option D is correct -- enable S3 Transfer Acceleration for faster, optimized file uploads.", "question_text": "A company needs to upload gigabytes of files daily to Amazon S3 and requires higher throughput and faster upload speeds. Which action should a CloudOps engineer take?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0053"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon CloudFront distribution with the GET HTTP method allowed and the S3 bucket as an origin."], ["B", "Create an Amazon ElastiCache cluster and enable caching for the S3 bucket."], ["C", "Set up AWS Global Accelerator and configure it with the S3 bucket."], ["D", "Enable S3 Transfer Acceleration and use the acceleration endpoint when uploading files."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0053"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Storage documentation confirms that S3 Transfer Acceleration is\ndesigned to increase upload speed for objects transferred to S3 buckets over long distances.\nIt uses AWS Global Edge Network and Amazon CloudFront edge locations to route data through\noptimized network paths, reducing latency and achieving higher throughput compared to standard\nS3 uploads.\nAfter enabling Transfer Acceleration on the bucket, users upload files to the accelerated endpoint\n(e.g., bucketname.s3-accelerate.amazonaws.com). This feature requires no changes to\napplication logic besides endpoint modification and provides immediate performance\nimprovement.\nCloudFront (Option A) is for content delivery, not uploads. ElastiCache (Option B) and Global\nAccelerator (Option C) are unrelated to S3 upload performance.\nThus, Option D is correct -- enable S3 Transfer Acceleration for faster, optimized file uploads.", "question_text": "A company needs to upload gigabytes of files daily to Amazon S3 and requires higher throughput and faster upload speeds. Which action should a CloudOps engineer take?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '792e348dbb897e1aa333a3495af97328cbaee1adc416fdb62cf691a07b9dca8c', 1403, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (888, 146, 55, 'qblock_pdf', '{"option_a": "Add another node to the ElastiCache cluster.", "option_b": "Increase the ElastiCache TTL value.", "option_c": "Decrease the ElastiCache TTL value.", "option_d": "Migrate to a new ElastiCache cluster with larger nodes.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and ElastiCache documentation, cache evictions occur\nwhen the cache runs out of memory and must remove items to make space for new data.\nTo reduce evictions and retain frequently accessed items, AWS recommends increasing the total\navailable memory -- either by scaling up to larger node types or scaling out by adding\nshards/nodes. Migrating to a cluster with larger nodes is the simplest and most efficient solution\nbecause it immediately expands capacity without architectural changes.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nAdjusting TTL (Options B and C) controls expiration timing, not memory allocation. Adding a\nsingle node (Option A) may help, but redistributing data requires resharding, introducing more\ncomplexity.\nThus, Option D provides the lowest operational overhead and ensures high cache hit rates by\nincreasing total cache memory.", "question_text": "An ecommerce company uses Amazon ElastiCache (Redis OSS) for caching product queries. The CloudOps engineer observes a large number of cache evictions in Amazon CloudWatch metrics and needs to reduce evictions while retaining popular data in cache. Which solution meets these requirements with the least operational overhead?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0054"}', '{"tags": null, "topic": null, "options": [["A", "Add another node to the ElastiCache cluster."], ["B", "Increase the ElastiCache TTL value."], ["C", "Decrease the ElastiCache TTL value."], ["D", "Migrate to a new ElastiCache cluster with larger nodes."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0054"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and ElastiCache documentation, cache evictions occur\nwhen the cache runs out of memory and must remove items to make space for new data.\nTo reduce evictions and retain frequently accessed items, AWS recommends increasing the total\navailable memory -- either by scaling up to larger node types or scaling out by adding\nshards/nodes. Migrating to a cluster with larger nodes is the simplest and most efficient solution\nbecause it immediately expands capacity without architectural changes.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nAdjusting TTL (Options B and C) controls expiration timing, not memory allocation. Adding a\nsingle node (Option A) may help, but redistributing data requires resharding, introducing more\ncomplexity.\nThus, Option D provides the lowest operational overhead and ensures high cache hit rates by\nincreasing total cache memory.", "question_text": "An ecommerce company uses Amazon ElastiCache (Redis OSS) for caching product queries. The CloudOps engineer observes a large number of cache evictions in Amazon CloudWatch metrics and needs to reduce evictions while retaining popular data in cache. Which solution meets these requirements with the least operational overhead?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '871816b06c01db0b1121d9f68152f50a39e0721adfbdfa71a70df2f9a2d3e48c', 1404, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (889, 146, 56, 'qblock_pdf', '{"option_a": "Add an inbound rule to the database''s security group. Reference 111122223333/sg-1234abcd as the source.", "option_b": "Add an inbound rule to the database''s security group. Reference pcx-b04deed9/sg-1234abcd as the source.", "option_c": "Add an inbound rule to the database''s security group. Reference sg-1234abcd as the source.", "option_d": "Add an inbound rule to the database''s security group. Reference 444455556666/sg-1234abcd as the source.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to AWS Cloud Operations and VPC Networking documentation, when VPCs are\npeered, security groups can reference peer account security groups directly to restrict traffic\nbetween them.\nThis feature allows specifying the security group ID (sg-1234abcd) from the source account\n(111122223333) in the target database''s security group inbound rule. AWS automatically\nvalidates that the VPCs are connected through an existing VPC peering connection and that\nmutual permissions are properly configured.\nYou do not prefix the security group ID with the account or peering connection (Options A and B),\nand using the destination account ID (Option D) is incorrect because it represents the database\nside, not the source.\nHence, the correct configuration is Option C, which references the application servers'' security\ngroup directly for precise, least-privilege access control.", "question_text": "A company''s application servers in AWS account 111122223333 use a security group sg- 1234abcd. They need to access a database hosted in account 444455556666. The VPCs are connected using a VPC peering connection (pcx-b04deed9). A CloudOps engineer must configure the database''s security group to allow new connections only from the application servers. What should the engineer do?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0055"}', '{"tags": null, "topic": null, "options": [["A", "Add an inbound rule to the database''s security group. Reference 111122223333/sg-1234abcd as the source."], ["B", "Add an inbound rule to the database''s security group. Reference pcx-b04deed9/sg-1234abcd as the source."], ["C", "Add an inbound rule to the database''s security group. Reference sg-1234abcd as the source."], ["D", "Add an inbound rule to the database''s security group. Reference 444455556666/sg-1234abcd as the source."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0055"}, "reference": null, "difficulty": "medium", "explanation": "According to AWS Cloud Operations and VPC Networking documentation, when VPCs are\npeered, security groups can reference peer account security groups directly to restrict traffic\nbetween them.\nThis feature allows specifying the security group ID (sg-1234abcd) from the source account\n(111122223333) in the target database''s security group inbound rule. AWS automatically\nvalidates that the VPCs are connected through an existing VPC peering connection and that\nmutual permissions are properly configured.\nYou do not prefix the security group ID with the account or peering connection (Options A and B),\nand using the destination account ID (Option D) is incorrect because it represents the database\nside, not the source.\nHence, the correct configuration is Option C, which references the application servers'' security\ngroup directly for precise, least-privilege access control.", "question_text": "A company''s application servers in AWS account 111122223333 use a security group sg- 1234abcd. They need to access a database hosted in account 444455556666. The VPCs are connected using a VPC peering connection (pcx-b04deed9). A CloudOps engineer must configure the database''s security group to allow new connections only from the application servers. What should the engineer do?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '29a514e271def42eec3a2f0a7a43293d0cdd11f8697def6590719f93a9c2305a', 1405, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (890, 146, 57, 'qblock_pdf', '{"option_a": "Use Amazon Detective to continuously find and uninstall unauthorized modules from the Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com instances.", "option_b": "Use Amazon GuardDuty to create and deploy an Amazon Machine Image (AMI) that includes only the approved modules.", "option_c": "Use AWS Systems Manager Run Command to install the approved modules on all running instances during an in-place update.", "option_d": "Use EC2 Image Builder to create and test an Amazon Machine Image (AMI) that includes only the approved modules. Update the deployment workflow to use the new AMI.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Deployment documentation, EC2 Image Builder is\nthe AWS-managed service for automating the creation, maintenance, validation, and deployment\nof secure and compliant Amazon Machine Images (AMIs).\nIt allows CloudOps teams to define image pipelines that include only approved software modules\nand configuration scripts. EC2 Image Builder automatically tests and verifies these AMIs for\ncompliance before deployment.\nThis process ensures configuration consistency, eliminates manual installation errors, and\nsimplifies ongoing patch management. The service integrates with AWS Systems Manager,\nAmazon Inspector, and AWS CloudFormation for end-to-end automation.\nAmazon Detective and GuardDuty (Options A & B) are security monitoring tools, not image\nmanagement solutions.\nRun Command (Option C) applies ad-hoc updates but does not create standard, reusable AMIs.\nTherefore, Option D is correct--EC2 Image Builder provides the most operationally efficient and\ncompliant way to create an approved baseline AMI for future deployments.", "question_text": "A company''s developers manually install software modules on Amazon EC2 instances to deploy new versions of a service. A security audit finds that instances contain inconsistent and unapproved modules. A CloudOps engineer must create a new instance image that contains only approved software. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0056"}', '{"tags": null, "topic": null, "options": [["A", "Use Amazon Detective to continuously find and uninstall unauthorized modules from the Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com instances."], ["B", "Use Amazon GuardDuty to create and deploy an Amazon Machine Image (AMI) that includes only the approved modules."], ["C", "Use AWS Systems Manager Run Command to install the approved modules on all running instances during an in-place update."], ["D", "Use EC2 Image Builder to create and test an Amazon Machine Image (AMI) that includes only the approved modules. Update the deployment workflow to use the new AMI."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0056"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Deployment documentation, EC2 Image Builder is\nthe AWS-managed service for automating the creation, maintenance, validation, and deployment\nof secure and compliant Amazon Machine Images (AMIs).\nIt allows CloudOps teams to define image pipelines that include only approved software modules\nand configuration scripts. EC2 Image Builder automatically tests and verifies these AMIs for\ncompliance before deployment.\nThis process ensures configuration consistency, eliminates manual installation errors, and\nsimplifies ongoing patch management. The service integrates with AWS Systems Manager,\nAmazon Inspector, and AWS CloudFormation for end-to-end automation.\nAmazon Detective and GuardDuty (Options A &amp; B) are security monitoring tools, not image\nmanagement solutions.\nRun Command (Option C) applies ad-hoc updates but does not create standard, reusable AMIs.\nTherefore, Option D is correct--EC2 Image Builder provides the most operationally efficient and\ncompliant way to create an approved baseline AMI for future deployments.", "question_text": "A company''s developers manually install software modules on Amazon EC2 instances to deploy new versions of a service. A security audit finds that instances contain inconsistent and unapproved modules. A CloudOps engineer must create a new instance image that contains only approved software. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'ccdd4e1d42849b6e16932e1774244cc06aa1283213cbe85f2a899cd761f0c622', 1406, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (891, 146, 58, 'qblock_pdf', '{"option_a": "Launch a new Amazon EC2 instance. Configure a cron job to use the AWS SDK to send an SNS notification to subscribers every Saturday.", "option_b": "Create a rule in Amazon EventBridge that triggers every Saturday. Configure the rule to publish a notification to an SNS topic.", "option_c": "Create an SNS subscription to a message fanout that sends notifications to subscribers every Saturday.", "option_d": "Use AWS Step Functions scheduling to run a step every Saturday. Configure the step to publish a message to an SNS topic.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Per the AWS Cloud Operations and Event Management documentation, Amazon EventBridge\nprovides native scheduling capabilities that can trigger events at defined intervals--such as\nweekly, daily, or cron-based schedules.\nCreating an EventBridge rule that runs every Saturday and publishes a message to an SNS topic\nfully automates the notification process without maintaining servers or manual jobs. This\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\napproach is serverless, highly reliable, and fully managed by AWS.\nEC2 cron jobs (Option A) require instance management, patching, and cost overhead.\nSNS subscriptions (Option C) handle message delivery, not scheduling.\nStep Functions (Option D) are designed for complex workflows, not simple scheduled triggers.\nThus, Option B provides the most operationally efficient CloudOps solution by integrating\nEventBridge scheduled events with SNS topics for automated, recurring notifications.", "question_text": "A company with millions of subscribers needs to automatically send notifications every Saturday. The company already uses Amazon SNS to send messages but has historically sent them manually. Which solution will meet these requirements in the MOST operationally efficient way?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0057"}', '{"tags": null, "topic": null, "options": [["A", "Launch a new Amazon EC2 instance. Configure a cron job to use the AWS SDK to send an SNS notification to subscribers every Saturday."], ["B", "Create a rule in Amazon EventBridge that triggers every Saturday. Configure the rule to publish a notification to an SNS topic."], ["C", "Create an SNS subscription to a message fanout that sends notifications to subscribers every Saturday."], ["D", "Use AWS Step Functions scheduling to run a step every Saturday. Configure the step to publish a message to an SNS topic."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0057"}, "reference": null, "difficulty": "medium", "explanation": "Per the AWS Cloud Operations and Event Management documentation, Amazon EventBridge\nprovides native scheduling capabilities that can trigger events at defined intervals--such as\nweekly, daily, or cron-based schedules.\nCreating an EventBridge rule that runs every Saturday and publishes a message to an SNS topic\nfully automates the notification process without maintaining servers or manual jobs. This\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\napproach is serverless, highly reliable, and fully managed by AWS.\nEC2 cron jobs (Option A) require instance management, patching, and cost overhead.\nSNS subscriptions (Option C) handle message delivery, not scheduling.\nStep Functions (Option D) are designed for complex workflows, not simple scheduled triggers.\nThus, Option B provides the most operationally efficient CloudOps solution by integrating\nEventBridge scheduled events with SNS topics for automated, recurring notifications.", "question_text": "A company with millions of subscribers needs to automatically send notifications every Saturday. The company already uses Amazon SNS to send messages but has historically sent them manually. Which solution will meet these requirements in the MOST operationally efficient way?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '94582dc5314ee46c400176a1f6f02bc8e865f72449f66f8621494ee34214f24d', 1407, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (892, 146, 59, 'qblock_pdf', '{"option_a": "Configure the CloudFront distribution to add a custom Cache-Control header to requests for content from the S3 bucket.", "option_b": "Modify the distribution settings to specify the protocol as HTTPS only.", "option_c": "do not directly refresh outdated cache content.", "option_d": "Create a CloudFront invalidation. Thus, Option D -- issuing a CloudFront invalidation -- ensures users receive the latest website content immediately after deployment.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Content Delivery documentation explains that Amazon\nCloudFront caches objects in edge locations for a defined time based on TTL settings or origin\nheaders. When new content is deployed to the S3 origin, previously cached versions remain in\nedge caches until they expire.\nTo immediately serve the new version, CloudOps engineers must initiate a CloudFront\ninvalidation, which removes cached objects from all edge locations. This forces CloudFront to\nfetch the latest version from the origin (S3).\nInvalidations can target individual objects (e.g., /index.html) or wildcard paths (e.g., /*) and are the\nAWS-recommended approach for dynamic content refresh after static site updates.\nChanging headers (Option A), enforcing HTTPS (Option B), or applying caching policies (Option", "question_text": "A company hosts a static website in Amazon S3 behind an Amazon CloudFront distribution. When new versions are deployed, users sometimes do not see updated content immediately. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0058"}', '{"tags": null, "topic": null, "options": [["A", "Configure the CloudFront distribution to add a custom Cache-Control header to requests for content from the S3 bucket."], ["B", "Modify the distribution settings to specify the protocol as HTTPS only."], ["C", "do not directly refresh outdated cache content."], ["D", "Create a CloudFront invalidation. Thus, Option D -- issuing a CloudFront invalidation -- ensures users receive the latest website content immediately after deployment."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0058"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Content Delivery documentation explains that Amazon\nCloudFront caches objects in edge locations for a defined time based on TTL settings or origin\nheaders. When new content is deployed to the S3 origin, previously cached versions remain in\nedge caches until they expire.\nTo immediately serve the new version, CloudOps engineers must initiate a CloudFront\ninvalidation, which removes cached objects from all edge locations. This forces CloudFront to\nfetch the latest version from the origin (S3).\nInvalidations can target individual objects (e.g., /index.html) or wildcard paths (e.g., /*) and are the\nAWS-recommended approach for dynamic content refresh after static site updates.\nChanging headers (Option A), enforcing HTTPS (Option B), or applying caching policies (Option", "question_text": "A company hosts a static website in Amazon S3 behind an Amazon CloudFront distribution. When new versions are deployed, users sometimes do not see updated content immediately. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '6c206678573cc41bc9265b044c832822b4abce55ed3b1f9a992e8aef5ad8b50b', 1408, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (893, 146, 60, 'qblock_pdf', '{"option_a": "com.amazonaws.eu-west-1.ssm", "option_b": "com.amazonaws.eu-west-1.ec2messages", "option_c": "com.amazonaws.eu-west-1.ec2", "option_d": "com.amazonaws.eu-west-1.ssmmessages Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_e": "com.amazonaws.eu-west-1.s3", "option_f": "com.amazonaws.eu-west-1.states", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Systems Manager documentation states that to use Session\nManager privately within a VPC (without internet access), three interface VPC endpoints must be\nconfigured:\ncom.amazonaws.<region>.ssm ?enables Systems Manager core API communication.\ncom.amazonaws.<region>.ec2messages ?allows the agent to send and receive messages\nbetween EC2 and Systems Manager.\ncom.amazonaws.<region>.ssmmessages ?enables real-time interactive communication for\nSession Manager connections.\nThese endpoints ensure secure, private connectivity over the AWS network, eliminating the need\nfor public internet routing.\nEndpoints for S3, Step Functions, or EC2 API (Options C, E, F) are not required for Session\nManager functionality.\nThus, the correct combination is A, B, and D, aligning with AWS CloudOps best practices for\nsecure, private Systems Manager access.", "question_text": "A company uses AWS Systems Manager Session Manager to manage EC2 instances in the eu- west-1 Region. The company wants private connectivity using VPC endpoints. Which VPC endpoints are required to meet these requirements? (Select THREE.)", "source_format": "qblock_pdf", "correct_answer": "ABD", "external_question_id": "Q0059"}', '{"tags": null, "topic": null, "options": [["A", "com.amazonaws.eu-west-1.ssm"], ["B", "com.amazonaws.eu-west-1.ec2messages"], ["C", "com.amazonaws.eu-west-1.ec2"], ["D", "com.amazonaws.eu-west-1.ssmmessages Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["E", "com.amazonaws.eu-west-1.s3"], ["F", "com.amazonaws.eu-west-1.states"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0059"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Systems Manager documentation states that to use Session\nManager privately within a VPC (without internet access), three interface VPC endpoints must be\nconfigured:\ncom.amazonaws..ssm ?enables Systems Manager core API communication.\ncom.amazonaws..ec2messages ?allows the agent to send and receive messages\nbetween EC2 and Systems Manager.\ncom.amazonaws..ssmmessages ?enables real-time interactive communication for\nSession Manager connections.\nThese endpoints ensure secure, private connectivity over the AWS network, eliminating the need\nfor public internet routing.\nEndpoints for S3, Step Functions, or EC2 API (Options C, E, F) are not required for Session\nManager functionality.\nThus, the correct combination is A, B, and D, aligning with AWS CloudOps best practices for\nsecure, private Systems Manager access.", "question_text": "A company uses AWS Systems Manager Session Manager to manage EC2 instances in the eu- west-1 Region. The company wants private connectivity using VPC endpoints. Which VPC endpoints are required to meet these requirements? (Select THREE.)", "question_type": "multiple", "correct_answer": ["A", "B", "D"]}', 'imported', NULL, NULL, 'ba03cb6003a96b83dead4d9fb60e4dca778084dea598dd33ab74b2e62af8124f', 1409, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (894, 146, 61, 'qblock_pdf', '{"option_a": "Adjust the minimum capacity of the Auto Scaling group to the size required to meet the increased demand during the 2-hour period.", "option_b": "Adjust the launch template that is associated with the Auto Scaling group to be more sensitive to increases in user traffic.", "option_c": "Create a scheduled scaling action to scale out the number of EC2 instances shortly before the increase in user traffic occurs.", "option_d": "Manually add a few more EC2 instances to the Auto Scaling group to support the increase in user traffic. Enable instance scale-in protection on the Auto Scaling group.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Compute documentation, when workloads exhibit\npredictable traffic patterns, the best practice is to use scheduled scaling for Amazon EC2 Auto\nScaling groups.\nWith scheduled scaling, administrators can predefine the desired capacity of an Auto Scaling\ngroup to increase before anticipated demand (in this case, before the 2-hour peak) and scale\nback down afterward. This ensures that sufficient compute capacity is provisioned proactively,\navoiding performance degradation while maintaining cost efficiency.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nAWS notes: \"Scheduled actions enable scaling your Auto Scaling group at predictable times,\nallowing you to pre-warm instances before demand spikes.\"\nManual scaling (Option D) adds operational overhead. Adjusting launch templates (Option B)\ndoesn''t affect scaling behavior, and permanently increasing minimum capacity (Option A) wastes\nresources outside of peak hours.\nThus, Option C provides an automated, cost-effective, and operationally efficient CloudOps\nsolution.", "question_text": "A company runs an application on Amazon EC2 instances behind an Elastic Load Balancer (ELB) in an Auto Scaling group. The application performs well except during a 2-hour period of daily peak traffic, when performance slows. A CloudOps engineer must resolve this issue with minimal operational effort. What should the engineer do?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0060"}', '{"tags": null, "topic": null, "options": [["A", "Adjust the minimum capacity of the Auto Scaling group to the size required to meet the increased demand during the 2-hour period."], ["B", "Adjust the launch template that is associated with the Auto Scaling group to be more sensitive to increases in user traffic."], ["C", "Create a scheduled scaling action to scale out the number of EC2 instances shortly before the increase in user traffic occurs."], ["D", "Manually add a few more EC2 instances to the Auto Scaling group to support the increase in user traffic. Enable instance scale-in protection on the Auto Scaling group."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0060"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Compute documentation, when workloads exhibit\npredictable traffic patterns, the best practice is to use scheduled scaling for Amazon EC2 Auto\nScaling groups.\nWith scheduled scaling, administrators can predefine the desired capacity of an Auto Scaling\ngroup to increase before anticipated demand (in this case, before the 2-hour peak) and scale\nback down afterward. This ensures that sufficient compute capacity is provisioned proactively,\navoiding performance degradation while maintaining cost efficiency.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nAWS notes: \"Scheduled actions enable scaling your Auto Scaling group at predictable times,\nallowing you to pre-warm instances before demand spikes.\"\nManual scaling (Option D) adds operational overhead. Adjusting launch templates (Option B)\ndoesn''t affect scaling behavior, and permanently increasing minimum capacity (Option A) wastes\nresources outside of peak hours.\nThus, Option C provides an automated, cost-effective, and operationally efficient CloudOps\nsolution.", "question_text": "A company runs an application on Amazon EC2 instances behind an Elastic Load Balancer (ELB) in an Auto Scaling group. The application performs well except during a 2-hour period of daily peak traffic, when performance slows. A CloudOps engineer must resolve this issue with minimal operational effort. What should the engineer do?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '5503efc56a03ec8165ecd77c49d5298eda9700c3651413a8ba30015cbcb514d2', 1410, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (895, 146, 62, 'qblock_pdf', '{"option_a": "Configure a home AWS Region in Systems Manager Quick Setup in the organization''s management account. Deploy the Systems Manager Default Host Management Configuration Quick Setup from the management account.", "option_b": "Configure a home AWS Region in Systems Manager Quick Setup in the organization''s management account. Create a Systems Manager Run Command that attaches the AmazonSSMServiceRolePolicy IAM policy to every IAM role that the EC2 instances use. Invoke the command in every account in the organization.", "option_c": "Create an AWS CloudFormation stack set that contains a Systems Manager parameter to define the Default Host Management Configuration role. Use the organization''s management account to deploy the stack set to every account in the organization.", "option_d": "Create an AWS CloudFormation stack set that contains an EC2 instance profile with the AmazonSSMManagedEC2InstanceDefaultPolicy IAM policy attached. Use the organization''s management account to deploy the stack set to every account in the organization.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS CloudOps automation best practices recommend using AWS Systems Manager Quick\nSetup for organization-wide management and configuration of EC2 instances. The Default Host\nManagement Configuration Quick Setup automatically enables Systems Manager capabilities\nsuch as Patch Manager, Inventory, Session Manager, and Automation across all managed\ninstances within the organization.\nWhen deployed from the management account, Quick Setup automatically integrates with AWS\nOrganizations to propagate configuration and permissions to existing and future accounts. This\nmeets the requirement for organization-wide management with no manual configuration or SSH\naccess.\n\"You can use Quick Setup in the management account of an organization in AWS Organizations\nto configure Systems Manager capabilities for all accounts and Regions. Quick Setup\nautomatically keeps configurations up to date.\"\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nOptions B, C, and D require custom deployments or manual IAM updates, lacking centralized\nautomation. Therefore, Option A fully satisfies CloudOps standards for automated provisioning\nand ongoing management of EC2 instances across an organization.", "question_text": "A company''s AWS accounts are in an organization in AWS Organizations. The organization has all features enabled. The accounts use Amazon EC2 instances to host applications. The company manages the EC2 instances manually by using the AWS Management Console. The company applies updates to the EC2 instances by using an SSH connection to each EC2 instance. The company needs a solution that uses AWS Systems Manager to manage all the organization''s current and future EC2 instances. The latest version of Systems Manager Agent (SSM Agent) is running on the EC2 instances. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0061"}', '{"tags": null, "topic": null, "options": [["A", "Configure a home AWS Region in Systems Manager Quick Setup in the organization''s management account. Deploy the Systems Manager Default Host Management Configuration Quick Setup from the management account."], ["B", "Configure a home AWS Region in Systems Manager Quick Setup in the organization''s management account. Create a Systems Manager Run Command that attaches the AmazonSSMServiceRolePolicy IAM policy to every IAM role that the EC2 instances use. Invoke the command in every account in the organization."], ["C", "Create an AWS CloudFormation stack set that contains a Systems Manager parameter to define the Default Host Management Configuration role. Use the organization''s management account to deploy the stack set to every account in the organization."], ["D", "Create an AWS CloudFormation stack set that contains an EC2 instance profile with the AmazonSSMManagedEC2InstanceDefaultPolicy IAM policy attached. Use the organization''s management account to deploy the stack set to every account in the organization."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0061"}, "reference": null, "difficulty": "medium", "explanation": "AWS CloudOps automation best practices recommend using AWS Systems Manager Quick\nSetup for organization-wide management and configuration of EC2 instances. The Default Host\nManagement Configuration Quick Setup automatically enables Systems Manager capabilities\nsuch as Patch Manager, Inventory, Session Manager, and Automation across all managed\ninstances within the organization.\nWhen deployed from the management account, Quick Setup automatically integrates with AWS\nOrganizations to propagate configuration and permissions to existing and future accounts. This\nmeets the requirement for organization-wide management with no manual configuration or SSH\naccess.\n\"You can use Quick Setup in the management account of an organization in AWS Organizations\nto configure Systems Manager capabilities for all accounts and Regions. Quick Setup\nautomatically keeps configurations up to date.\"\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nOptions B, C, and D require custom deployments or manual IAM updates, lacking centralized\nautomation. Therefore, Option A fully satisfies CloudOps standards for automated provisioning\nand ongoing management of EC2 instances across an organization.", "question_text": "A company''s AWS accounts are in an organization in AWS Organizations. The organization has all features enabled. The accounts use Amazon EC2 instances to host applications. The company manages the EC2 instances manually by using the AWS Management Console. The company applies updates to the EC2 instances by using an SSH connection to each EC2 instance. The company needs a solution that uses AWS Systems Manager to manage all the organization''s current and future EC2 instances. The latest version of Systems Manager Agent (SSM Agent) is running on the EC2 instances. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '943433cadcf417823a19c96586c948fd8b0d68a0028c645bd62ee80da22bf164', 1411, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (896, 146, 63, 'qblock_pdf', '{"option_a": "Create a script by using the AWS CLI to run the aws cloudformation put-dashboard command with the name of the dashboard. Run the command each time a new CloudFormation stack is created.", "option_b": "Export the existing CloudWatch dashboard as JSON. Update the CloudFormation template to define an AWS::CloudWatch::Dashboard resource. Include the exported JSON in the resource''s DashboardBody property.", "option_c": "Update the CloudFormation template to define an AWS::CloudWatch::Dashboard resource. Use the intrinsic Ref function to reference the ID of the existing CloudWatch dashboard.", "option_d": "Update the CloudFormation template to define an AWS::CloudWatch::Dashboard resource. Specify the name of the existing dashboard in the DashboardName property.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to CloudOps automation and monitoring best practices, CloudWatch dashboards\nshould be provisioned as infrastructure-as-code (IaC) resources using AWS CloudFormation to\nensure consistency, repeatability, and version control. AWS CloudFormation supports the\nAWS::CloudWatch::Dashboard resource, where the DashboardBody property accepts a JSON\nobject describing widgets, metrics, and layout.\nBy exporting the existing dashboard configuration as JSON and embedding it into the\nCloudFormation template, every deployment of the application automatically creates its\ncorresponding dashboard. This method aligns with the CloudOps requirement for automated\ndeployment and operational visibility within the same stack lifecycle.\n\"Use the AWS::CloudWatch::Dashboard resource to create a dashboard from your template. You\ncan include the same JSON you use to define a dashboard in the console.\"\nOption A requires manual execution. Options C and D incorrectly reference or reuse existing\ndashboards, failing to produce unique, deployment-specific dashboards.", "question_text": "A CloudOps engineer creates an AWS CloudFormation template to define an application stack that can be deployed in multiple AWS Regions. The CloudOps engineer also creates an Amazon CloudWatch dashboard by using the AWS Management Console. Each deployment of the application requires its own CloudWatch dashboard. How can the CloudOps engineer automate the creation of the CloudWatch dashboard each time the application is deployed?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0062"}', '{"tags": null, "topic": null, "options": [["A", "Create a script by using the AWS CLI to run the aws cloudformation put-dashboard command with the name of the dashboard. Run the command each time a new CloudFormation stack is created."], ["B", "Export the existing CloudWatch dashboard as JSON. Update the CloudFormation template to define an AWS::CloudWatch::Dashboard resource. Include the exported JSON in the resource''s DashboardBody property."], ["C", "Update the CloudFormation template to define an AWS::CloudWatch::Dashboard resource. Use the intrinsic Ref function to reference the ID of the existing CloudWatch dashboard."], ["D", "Update the CloudFormation template to define an AWS::CloudWatch::Dashboard resource. Specify the name of the existing dashboard in the DashboardName property."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0062"}, "reference": null, "difficulty": "medium", "explanation": "According to CloudOps automation and monitoring best practices, CloudWatch dashboards\nshould be provisioned as infrastructure-as-code (IaC) resources using AWS CloudFormation to\nensure consistency, repeatability, and version control. AWS CloudFormation supports the\nAWS::CloudWatch::Dashboard resource, where the DashboardBody property accepts a JSON\nobject describing widgets, metrics, and layout.\nBy exporting the existing dashboard configuration as JSON and embedding it into the\nCloudFormation template, every deployment of the application automatically creates its\ncorresponding dashboard. This method aligns with the CloudOps requirement for automated\ndeployment and operational visibility within the same stack lifecycle.\n\"Use the AWS::CloudWatch::Dashboard resource to create a dashboard from your template. You\ncan include the same JSON you use to define a dashboard in the console.\"\nOption A requires manual execution. Options C and D incorrectly reference or reuse existing\ndashboards, failing to produce unique, deployment-specific dashboards.", "question_text": "A CloudOps engineer creates an AWS CloudFormation template to define an application stack that can be deployed in multiple AWS Regions. The CloudOps engineer also creates an Amazon CloudWatch dashboard by using the AWS Management Console. Each deployment of the application requires its own CloudWatch dashboard. How can the CloudOps engineer automate the creation of the CloudWatch dashboard each time the application is deployed?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '60885cd0bcd68b80a4e6c44fd2b31e17db8ba5d91850d21b9bd94bf6d9b9d753', 1412, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (897, 146, 64, 'qblock_pdf', '{"option_a": "Use Organizations tag policies to enforce mandatory tagging on all resources. Enable cost Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com allocation tags in the AWS Billing and Cost Management console.", "option_b": "Configure AWS CloudTrail events to invoke an AWS Lambda function to detect untagged resources and to automatically assign tags based on predefined rules.", "option_c": "Use AWS Config to evaluate tagging compliance. Use AWS Budgets to apply tags for cost allocation.", "option_d": "Use AWS Service Catalog to provision only pre-tagged resources. Use AWS Trusted Advisor to enforce tagging across the organization.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Tagging is essential for governance, cost management, and automation in CloudOps operations.\nThe AWS Organizations tag policies feature allows centralized definition and enforcement of\nrequired tag keys and accepted values across all accounts in an organization. According to the\nAWS CloudOps study guide under Deployment, Provisioning, and Automation, tag policies\nenable automatic validation of tags, ensuring consistency with minimal manual overhead.\nOnce tagging consistency is enforced, enabling cost allocation tags in the AWS Billing and Cost\nManagement console allows accurate cost distribution per business unit.\n\"Use AWS Organizations tag policies to standardize tags across accounts. You can activate cost\nallocation tags in the Billing console to track and allocate costs.\"\nOption B introduces unnecessary complexity with Lambda automation. Option C detects but does\nnot enforce tagging. Option D limits flexibility to Service Catalog resources only. Therefore,\nOption A provides a centrally managed, automated, and low-overhead solution that meets\nCloudOps tagging and cost-tracking requirements.", "question_text": "A CloudOps engineer needs to ensure that AWS resources across multiple AWS accounts are tagged consistently. The company uses an organization in AWS Organizations to centrally manage the accounts. The company wants to implement cost allocation tags to accurately track the costs that are allocated to each business unit. Which solution will meet these requirements with the LEAST operational overhead?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0063"}', '{"tags": null, "topic": null, "options": [["A", "Use Organizations tag policies to enforce mandatory tagging on all resources. Enable cost Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com allocation tags in the AWS Billing and Cost Management console."], ["B", "Configure AWS CloudTrail events to invoke an AWS Lambda function to detect untagged resources and to automatically assign tags based on predefined rules."], ["C", "Use AWS Config to evaluate tagging compliance. Use AWS Budgets to apply tags for cost allocation."], ["D", "Use AWS Service Catalog to provision only pre-tagged resources. Use AWS Trusted Advisor to enforce tagging across the organization."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0063"}, "reference": null, "difficulty": "medium", "explanation": "Tagging is essential for governance, cost management, and automation in CloudOps operations.\nThe AWS Organizations tag policies feature allows centralized definition and enforcement of\nrequired tag keys and accepted values across all accounts in an organization. According to the\nAWS CloudOps study guide under Deployment, Provisioning, and Automation, tag policies\nenable automatic validation of tags, ensuring consistency with minimal manual overhead.\nOnce tagging consistency is enforced, enabling cost allocation tags in the AWS Billing and Cost\nManagement console allows accurate cost distribution per business unit.\n\"Use AWS Organizations tag policies to standardize tags across accounts. You can activate cost\nallocation tags in the Billing console to track and allocate costs.\"\nOption B introduces unnecessary complexity with Lambda automation. Option C detects but does\nnot enforce tagging. Option D limits flexibility to Service Catalog resources only. Therefore,\nOption A provides a centrally managed, automated, and low-overhead solution that meets\nCloudOps tagging and cost-tracking requirements.", "question_text": "A CloudOps engineer needs to ensure that AWS resources across multiple AWS accounts are tagged consistently. The company uses an organization in AWS Organizations to centrally manage the accounts. The company wants to implement cost allocation tags to accurately track the costs that are allocated to each business unit. Which solution will meet these requirements with the LEAST operational overhead?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '0a57b2d1dfecebd9c7c737d90fcebdd253746b45408d1841db3f86da4254b7b7', 1413, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (898, 146, 65, 'qblock_pdf', '{"option_a": "Extend the file system with operating system-level tools to use the new storage capacity.", "option_b": "Reattach the EBS volume to the EC2 instance.", "option_c": "Reboot the EC2 instance that is attached to the EBS volume.", "option_d": "Take a snapshot of the EBS volume. Replace the original volume with a volume that is created from the snapshot.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "When an Amazon EBS volume is resized, the new storage capacity is immediately available to\nthe attached EC2 instance. However, EBS does not automatically extend the file system. The\nCloudOps engineer must manually extend the file system within the operating system to utilize\nthe additional space.\n\"After you increase the size of an EBS volume, use file system璼pecific tools to extend the file\nsystem so that the operating system can use the new storage capacity.\"\nOn Windows instances, this can be achieved through Disk Management or diskpart commands.\nOn Linux systems, utilities such as growpart and resize2fs are used.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nOptions B and C do not modify file system metadata and are ineffective. Option D unnecessarily\nreplaces the volume, which adds risk and downtime. Thus, Option A aligns with the Monitoring\nand Performance Optimization practices of AWS CloudOps by properly extending the file system\nto recognize the new capacity.", "question_text": "A user working in the Amazon EC2 console increased the size of an Amazon Elastic Block Store (Amazon EBS) volume attached to an Amazon EC2 Windows instance. The change is not reflected in the file system. What should a CloudOps engineer do to resolve this issue?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0064"}', '{"tags": null, "topic": null, "options": [["A", "Extend the file system with operating system-level tools to use the new storage capacity."], ["B", "Reattach the EBS volume to the EC2 instance."], ["C", "Reboot the EC2 instance that is attached to the EBS volume."], ["D", "Take a snapshot of the EBS volume. Replace the original volume with a volume that is created from the snapshot."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0064"}, "reference": null, "difficulty": "medium", "explanation": "When an Amazon EBS volume is resized, the new storage capacity is immediately available to\nthe attached EC2 instance. However, EBS does not automatically extend the file system. The\nCloudOps engineer must manually extend the file system within the operating system to utilize\nthe additional space.\n\"After you increase the size of an EBS volume, use file system璼pecific tools to extend the file\nsystem so that the operating system can use the new storage capacity.\"\nOn Windows instances, this can be achieved through Disk Management or diskpart commands.\nOn Linux systems, utilities such as growpart and resize2fs are used.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nOptions B and C do not modify file system metadata and are ineffective. Option D unnecessarily\nreplaces the volume, which adds risk and downtime. Thus, Option A aligns with the Monitoring\nand Performance Optimization practices of AWS CloudOps by properly extending the file system\nto recognize the new capacity.", "question_text": "A user working in the Amazon EC2 console increased the size of an Amazon Elastic Block Store (Amazon EBS) volume attached to an Amazon EC2 Windows instance. The change is not reflected in the file system. What should a CloudOps engineer do to resolve this issue?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'f00f5dace0782f4b60f8f2d57c388027afc21eec4eba59c9cc8370d27bc52ed9', 1414, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (899, 146, 66, 'qblock_pdf', '{"option_a": "Create an Amazon CloudWatch Contributor Insights rule on the log data.", "option_b": "Create a metric filter on the log data.", "option_c": "Create a subscription filter on the log data.", "option_d": "Create an Amazon CloudWatch Application Insights rule for the workload.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "To analyze and visualize custom statistics such as the p90 latency (90th percentile), a\nCloudWatch metric must be generated from the log data. The correct method is to create a metric\nfilter that extracts the latency value from each log event and publishes it as a CloudWatch metric.\nOnce the metric is published, percentile statistics (p90, p95, etc.) can be displayed in CloudWatch\ndashboards or alarms.\n\"You can use metric filters to extract numerical fields from log events and publish them as metrics\nin CloudWatch. CloudWatch supports percentile statistics such as p90 and p95 for these\nmetrics.\"\nContributor Insights (Option A) is for analyzing frequent contributors, not numeric distributions.\nSubscription filters (Option C) are used for log streaming, and Application Insights (Option D)\nprovides monitoring of application health but not custom p90 statistics. Hence, Option B is the\nCloudOps-aligned, minimal-overhead solution for percentile latency monitoring.", "question_text": "A company has a workload that is sending log data to Amazon CloudWatch Logs. One of the fields includes a measure of application latency. A CloudOps engineer needs to monitor the p90 statistic of this field over time. What should the CloudOps engineer do to meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0065"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon CloudWatch Contributor Insights rule on the log data."], ["B", "Create a metric filter on the log data."], ["C", "Create a subscription filter on the log data."], ["D", "Create an Amazon CloudWatch Application Insights rule for the workload."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0065"}, "reference": null, "difficulty": "medium", "explanation": "To analyze and visualize custom statistics such as the p90 latency (90th percentile), a\nCloudWatch metric must be generated from the log data. The correct method is to create a metric\nfilter that extracts the latency value from each log event and publishes it as a CloudWatch metric.\nOnce the metric is published, percentile statistics (p90, p95, etc.) can be displayed in CloudWatch\ndashboards or alarms.\n\"You can use metric filters to extract numerical fields from log events and publish them as metrics\nin CloudWatch. CloudWatch supports percentile statistics such as p90 and p95 for these\nmetrics.\"\nContributor Insights (Option A) is for analyzing frequent contributors, not numeric distributions.\nSubscription filters (Option C) are used for log streaming, and Application Insights (Option D)\nprovides monitoring of application health but not custom p90 statistics. Hence, Option B is the\nCloudOps-aligned, minimal-overhead solution for percentile latency monitoring.", "question_text": "A company has a workload that is sending log data to Amazon CloudWatch Logs. One of the fields includes a measure of application latency. A CloudOps engineer needs to monitor the p90 statistic of this field over time. What should the CloudOps engineer do to meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'ba7c283d5060e6c7f50b9dfacefa2e0d40fd1ea5ca80561a588f960db7149e2f', 1415, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (900, 146, 67, 'qblock_pdf', '{"option_a": "Create an Amazon CloudWatch alarm for the VolumeIdleTime metric with an action to take a snapshot of the EBS volume.", "option_b": "Create a pipeline in AWS Data Pipeline to take a snapshot of the EBS volume on a recurring schedule.", "option_c": "Create an Amazon Data Lifecycle Manager (Amazon DLM) policy to take a snapshot of the EBS volume on a recurring schedule.", "option_d": "Create an AWS DataSync task to take a snapshot of the EBS volume on a recurring schedule.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Amazon Data Lifecycle Manager (DLM) is the AWS service specifically designed to automate the\ncreation, retention, and deletion of EBS snapshots.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nWith DLM, you can:\n- Automatically create snapshots on a recurring schedule (e.g., daily, hourly).\n- Retain snapshots for a specific number of days.\n- Delete old snapshots automatically to save costs.\n- Ensure consistent and automated backups without manual intervention.\nThis approach fully meets the company’s requirement for a backup strategy for the EBS volume.", "question_text": "A company is running a custom database on an Amazon EC2 instance. The database stores its data on an Amazon Elastic Block Store (Amazon EBS) volume. A SysOps administrator must set up a backup strategy for the EBS volume. What should the SysOps administrator do to meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0066"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon CloudWatch alarm for the VolumeIdleTime metric with an action to take a snapshot of the EBS volume."], ["B", "Create a pipeline in AWS Data Pipeline to take a snapshot of the EBS volume on a recurring schedule."], ["C", "Create an Amazon Data Lifecycle Manager (Amazon DLM) policy to take a snapshot of the EBS volume on a recurring schedule."], ["D", "Create an AWS DataSync task to take a snapshot of the EBS volume on a recurring schedule."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0066"}, "reference": null, "difficulty": "medium", "explanation": "Amazon Data Lifecycle Manager (DLM) is the AWS service specifically designed to automate the\ncreation, retention, and deletion of EBS snapshots.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nWith DLM, you can:\n- Automatically create snapshots on a recurring schedule (e.g., daily, hourly).\n- Retain snapshots for a specific number of days.\n- Delete old snapshots automatically to save costs.\n- Ensure consistent and automated backups without manual intervention.\nThis approach fully meets the company’s requirement for a backup strategy for the EBS volume.", "question_text": "A company is running a custom database on an Amazon EC2 instance. The database stores its data on an Amazon Elastic Block Store (Amazon EBS) volume. A SysOps administrator must set up a backup strategy for the EBS volume. What should the SysOps administrator do to meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'db742e6d326543e8cb963e163629d21491bc88e6317b2866006f14b7b4c4ff25', 1416, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (902, 146, 69, 'qblock_pdf', '{"option_a": "Configure the backup software to use Amazon S3 as the target for the data backups.", "option_b": "Configure the backup software to use Amazon S3 Glacier Flexible Retrieval as the target for the data backups.", "option_c": "Use AWS Storage Gateway, and configure it to use gateway-cached volumes.", "option_d": "Use AWS Storage Gateway, and configure it to use gateway-stored volumes.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The Storage Gateway service enables hybrid cloud backup by presenting local block storage that\nsynchronizes with AWS cloud storage. For scenarios where all data must remain available locally\nwhile still backed up to AWS, the correct mode is gateway-stored volumes.\n\"Use stored volumes if you want to keep all your data locally while asynchronously backing up\npoint-in-time snapshots to Amazon S3 for durable storage.\"\nThese volumes expose an iSCSI interface compatible with POSIX file systems, allowing direct\nuse by on-premises backup software.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nGateway-cached volumes (Option C) store primary data in AWS with limited local cache, violating\nthe \"all data must be available locally\" requirement. Options A and B are object-based storage\nsolutions, not compatible with POSIX or block-based backup applications.\nTherefore, Option D fully satisfies CloudOps reliability and continuity best practices by ensuring\nlocal availability, cloud durability, and POSIX compatibility for backups.", "question_text": "A company is running an application on premises and wants to use AWS for data backup. All of the data must be available locally. The backup application can write only to block-based storage that is compatible with the Portable Operating System Interface (POSIX). Which backup solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0068"}', '{"tags": null, "topic": null, "options": [["A", "Configure the backup software to use Amazon S3 as the target for the data backups."], ["B", "Configure the backup software to use Amazon S3 Glacier Flexible Retrieval as the target for the data backups."], ["C", "Use AWS Storage Gateway, and configure it to use gateway-cached volumes."], ["D", "Use AWS Storage Gateway, and configure it to use gateway-stored volumes."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0068"}, "reference": null, "difficulty": "medium", "explanation": "The Storage Gateway service enables hybrid cloud backup by presenting local block storage that\nsynchronizes with AWS cloud storage. For scenarios where all data must remain available locally\nwhile still backed up to AWS, the correct mode is gateway-stored volumes.\n\"Use stored volumes if you want to keep all your data locally while asynchronously backing up\npoint-in-time snapshots to Amazon S3 for durable storage.\"\nThese volumes expose an iSCSI interface compatible with POSIX file systems, allowing direct\nuse by on-premises backup software.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nGateway-cached volumes (Option C) store primary data in AWS with limited local cache, violating\nthe \"all data must be available locally\" requirement. Options A and B are object-based storage\nsolutions, not compatible with POSIX or block-based backup applications.\nTherefore, Option D fully satisfies CloudOps reliability and continuity best practices by ensuring\nlocal availability, cloud durability, and POSIX compatibility for backups.", "question_text": "A company is running an application on premises and wants to use AWS for data backup. All of the data must be available locally. The backup application can write only to block-based storage that is compatible with the Portable Operating System Interface (POSIX). Which backup solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'ebca2d72f6ccbde4e064cbed970527e4bf3725bb130bfb07ceb63efc48645a5f', 1418, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (903, 146, 70, 'qblock_pdf', '{"option_a": "Attach an IAM policy to the users or groups that require access to the EC2 instances.", "option_b": "Attach an IAM role to control access to the EC2 instances.", "option_c": "Create a placement group for the EC2 instances and add a specific tag.", "option_d": "Create a service account and attach it to the EC2 instances that need to be controlled.", "option_e": "Create an IAM policy that grants access to any EC2 instances with a tag specified in the Condition element.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Systems Manager Session Manager allows secure, auditable instance access without SSH\nkeys or inbound ports. To control access based on instance tags, CloudOps best practices\nrequire two configurations:\nAttach an IAM policy to users or groups granting ssm:StartSession,\nssm:DescribeInstanceInformation, and ssm:DescribeSessions.\nInclude a Condition element in the IAM policy referencing instance tags, such as Condition:\n{\"StringEquals\": {\"ssm:resourceTag/Environment\": \"Production\"}}.\nThis ensures users can start sessions only with instances that have matching tags, providing fine-\ngrained access control.\nAWS CloudOps documentation under Security and Compliance states:\n\"Use IAM policies with resource tags in the Condition element to restrict which managed\ninstances users can access using Session Manager.\"\nOptions B and D incorrectly suggest attaching roles or service accounts that are not relevant to\nuser-level access control. Option C (placement groups) pertains to networking and performance,\nnot access management. Therefore, A and E together provide tag-based, least-privilege access\nas required.", "question_text": "A CloudOps engineer needs to control access to groups of Amazon EC2 instances using AWS Systems Manager Session Manager. Specific tags on the EC2 instances have already been added. Which additional actions should the CloudOps engineer take to control access? (Select TWO.)", "source_format": "qblock_pdf", "correct_answer": "AE", "external_question_id": "Q0069"}', '{"tags": null, "topic": null, "options": [["A", "Attach an IAM policy to the users or groups that require access to the EC2 instances."], ["B", "Attach an IAM role to control access to the EC2 instances."], ["C", "Create a placement group for the EC2 instances and add a specific tag."], ["D", "Create a service account and attach it to the EC2 instances that need to be controlled."], ["E", "Create an IAM policy that grants access to any EC2 instances with a tag specified in the Condition element."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0069"}, "reference": null, "difficulty": "medium", "explanation": "AWS Systems Manager Session Manager allows secure, auditable instance access without SSH\nkeys or inbound ports. To control access based on instance tags, CloudOps best practices\nrequire two configurations:\nAttach an IAM policy to users or groups granting ssm:StartSession,\nssm:DescribeInstanceInformation, and ssm:DescribeSessions.\nInclude a Condition element in the IAM policy referencing instance tags, such as Condition:\n{\"StringEquals\": {\"ssm:resourceTag/Environment\": \"Production\"}}.\nThis ensures users can start sessions only with instances that have matching tags, providing fine-\ngrained access control.\nAWS CloudOps documentation under Security and Compliance states:\n\"Use IAM policies with resource tags in the Condition element to restrict which managed\ninstances users can access using Session Manager.\"\nOptions B and D incorrectly suggest attaching roles or service accounts that are not relevant to\nuser-level access control. Option C (placement groups) pertains to networking and performance,\nnot access management. Therefore, A and E together provide tag-based, least-privilege access\nas required.", "question_text": "A CloudOps engineer needs to control access to groups of Amazon EC2 instances using AWS Systems Manager Session Manager. Specific tags on the EC2 instances have already been added. Which additional actions should the CloudOps engineer take to control access? (Select TWO.)", "question_type": "multiple", "correct_answer": ["A", "E"]}', 'imported', NULL, NULL, 'e79b04bf8b5e4f80c3e6a8e3728e2b2e54098f3bf297a91557ab50f6187209dc', 1419, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (904, 146, 71, 'qblock_pdf', '{"option_a": "Create Amazon CloudWatch alarms that monitor the health of the ALB in each Region. Configure Route 53 DNS failover by using a health check that monitors the alarms.", "option_b": "Create Amazon CloudWatch alarms that monitor the health of the EC2 instances in each Region. Configure Route 53 DNS failover by using a health check that monitors the alarms.", "option_c": "Configure Route 53 DNS failover by using a health check that monitors the private IP address of an EC2 instance in each Region.", "option_d": "Configure Route 53 geoproximity routing. Specify the Regions that are used for the infrastructure.", "option_e": "Configure Route 53 simple routing. Specify the continent, country, and state or province that are used for the infrastructure.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The combination of geoproximity routing and DNS failover health checks provides global low-\nlatency routing with high availability.\nGeoproximity routing in Route 53 routes users to the AWS Region closest to their geographic\nlocation, optimizing latency. For automatic failover, Route 53 health checks can monitor\nCloudWatch alarms tied to the health of the ALB in each Region. When a Region becomes\nunhealthy, Route 53 reroutes traffic to the next available Region automatically.\n\"Use geoproximity routing to direct users to resources based on geographic location, and\nconfigure health checks to provide DNS failover for high availability.\"\nOption B incorrectly monitors EC2 instances directly, which is not efficient at scale. Option C uses\nprivate IPs, which cannot be globally health-checked. Option E (simple routing) does not support\ngeographic or failover routing. Hence, A and D together meet both the proximity and failover\nrequirements.", "question_text": "A global gaming company is preparing to launch a new game on AWS. The game runs in multiple AWS Regions on a fleet of Amazon EC2 instances. The instances are in an Auto Scaling group behind an Application Load Balancer (ALB) in each Region. The company plans to use Amazon Route 53 for DNS services. The DNS configuration must direct users to the Region that is closest to them and must provide automated failover. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Which combination of steps should a CloudOps engineer take to configure Route 53 to meet these requirements? (Select TWO.)", "source_format": "qblock_pdf", "correct_answer": "AD", "external_question_id": "Q0070"}', '{"tags": null, "topic": null, "options": [["A", "Create Amazon CloudWatch alarms that monitor the health of the ALB in each Region. Configure Route 53 DNS failover by using a health check that monitors the alarms."], ["B", "Create Amazon CloudWatch alarms that monitor the health of the EC2 instances in each Region. Configure Route 53 DNS failover by using a health check that monitors the alarms."], ["C", "Configure Route 53 DNS failover by using a health check that monitors the private IP address of an EC2 instance in each Region."], ["D", "Configure Route 53 geoproximity routing. Specify the Regions that are used for the infrastructure."], ["E", "Configure Route 53 simple routing. Specify the continent, country, and state or province that are used for the infrastructure."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0070"}, "reference": null, "difficulty": "medium", "explanation": "The combination of geoproximity routing and DNS failover health checks provides global low-\nlatency routing with high availability.\nGeoproximity routing in Route 53 routes users to the AWS Region closest to their geographic\nlocation, optimizing latency. For automatic failover, Route 53 health checks can monitor\nCloudWatch alarms tied to the health of the ALB in each Region. When a Region becomes\nunhealthy, Route 53 reroutes traffic to the next available Region automatically.\n\"Use geoproximity routing to direct users to resources based on geographic location, and\nconfigure health checks to provide DNS failover for high availability.\"\nOption B incorrectly monitors EC2 instances directly, which is not efficient at scale. Option C uses\nprivate IPs, which cannot be globally health-checked. Option E (simple routing) does not support\ngeographic or failover routing. Hence, A and D together meet both the proximity and failover\nrequirements.", "question_text": "A global gaming company is preparing to launch a new game on AWS. The game runs in multiple AWS Regions on a fleet of Amazon EC2 instances. The instances are in an Auto Scaling group behind an Application Load Balancer (ALB) in each Region. The company plans to use Amazon Route 53 for DNS services. The DNS configuration must direct users to the Region that is closest to them and must provide automated failover. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Which combination of steps should a CloudOps engineer take to configure Route 53 to meet these requirements? (Select TWO.)", "question_type": "multiple", "correct_answer": ["A", "D"]}', 'imported', NULL, NULL, '0440130dc563cac83c9e9eba7ad42c72f724c400d4effa830b91bb9c5d49a496', 1420, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (905, 146, 72, 'qblock_pdf', '{"option_a": "Create an AWS Lambda function to change the RDS master user password. Create an Amazon EventBridge scheduled rule to invoke the Lambda function.", "option_b": "Create a new SecureString parameter in AWS Systems Manager Parameter Store. Encrypt the parameter with an AWS Key Management Service (AWS KMS) key. Configure automatic rotation.", "option_c": "Create a new String parameter in AWS Systems Manager Parameter Store. Configure automatic rotation.", "option_d": "Create a new RDS database secret in AWS Secrets Manager. Apply the secret to the RDS DB instance. Configure automatic rotation.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Secrets Manager natively supports credential management and automatic rotation for\nAmazon RDS master user passwords. When a secret is associated with an RDS instance,\nSecrets Manager automatically updates the password both in the secret and on the database,\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nwithout downtime or manual scripting.\n\"AWS Secrets Manager can automatically rotate the master user password for Amazon RDS\ndatabases. Rotation is fully managed and integrated, requiring no custom code or maintenance.\"\nOption A introduces unnecessary Lambda automation. Option B and C use Parameter Store,\nwhich does not provide direct RDS password rotation. Therefore, Option D achieves secure,\nautomatic credential rotation with least operational effort, fully aligned with CloudOps security\nautomation principles.", "question_text": "A company requires the rotation of administrative credentials for production workloads on a regular basis. A CloudOps engineer must implement this policy for an Amazon RDS DB instance''s master user password. Which solution will meet this requirement with the LEAST operational effort?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0071"}', '{"tags": null, "topic": null, "options": [["A", "Create an AWS Lambda function to change the RDS master user password. Create an Amazon EventBridge scheduled rule to invoke the Lambda function."], ["B", "Create a new SecureString parameter in AWS Systems Manager Parameter Store. Encrypt the parameter with an AWS Key Management Service (AWS KMS) key. Configure automatic rotation."], ["C", "Create a new String parameter in AWS Systems Manager Parameter Store. Configure automatic rotation."], ["D", "Create a new RDS database secret in AWS Secrets Manager. Apply the secret to the RDS DB instance. Configure automatic rotation."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0071"}, "reference": null, "difficulty": "medium", "explanation": "AWS Secrets Manager natively supports credential management and automatic rotation for\nAmazon RDS master user passwords. When a secret is associated with an RDS instance,\nSecrets Manager automatically updates the password both in the secret and on the database,\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nwithout downtime or manual scripting.\n\"AWS Secrets Manager can automatically rotate the master user password for Amazon RDS\ndatabases. Rotation is fully managed and integrated, requiring no custom code or maintenance.\"\nOption A introduces unnecessary Lambda automation. Option B and C use Parameter Store,\nwhich does not provide direct RDS password rotation. Therefore, Option D achieves secure,\nautomatic credential rotation with least operational effort, fully aligned with CloudOps security\nautomation principles.", "question_text": "A company requires the rotation of administrative credentials for production workloads on a regular basis. A CloudOps engineer must implement this policy for an Amazon RDS DB instance''s master user password. Which solution will meet this requirement with the LEAST operational effort?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '719ec807bb649fe584da6de997696566c1c54795346d826db2ef5535febbea62', 1421, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (906, 146, 73, 'qblock_pdf', '{"option_a": "Create an AWS Cost and Usage Report. Analyze the results in Amazon Athena. Configure an alarm to publish a message to an Amazon Simple Notification Service (Amazon SNS) topic when costs reach 75% of the threshold. Subscribe the email distribution list to the topic.", "option_b": "Create an Amazon CloudWatch billing alarm to detect when costs reach 75% of the threshold. Configure the alarm to publish a message to an Amazon Simple Notification Service (Amazon SNS) topic. Subscribe the email distribution list to the topic.", "option_c": "Use AWS Budgets to create a cost budget for data transfer costs. Set an alert at 75% of the budgeted amount. Configure the budget to send a notification to the email distribution list when costs reach 75% of the threshold.", "option_d": "Set up a VPC flow log. Set up a subscription filter to an AWS Lambda function to analyze data transfer. Configure the Lambda function to send a notification to the email distribution list when costs reach 75% of the threshold.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to the AWS Cloud Operations and Cost Management documentation, AWS Budgets is\nthe recommended service to track and alert on cost thresholds across all AWS accounts and\nresources. It allows users to define cost, usage, or reservation budgets, and configure\nnotifications to trigger when usage or cost reaches defined percentages of the budgeted value\n(e.g., 75%, 90%, 100%).\nThe AWS Budgets system integrates natively with Amazon Simple Notification Service (SNS) to\ndeliver alerts to an email distribution list or SNS topic subscribers. AWS Budgets supports\ngranular cost filters, including specific service categories such as data transfer, regions, or linked\naccounts, ensuring precise visibility into inter-Region transfer costs.\nBy contrast, CloudWatch billing alarms (Option B) monitor total account charges only and do not\nallow detailed service-level filtering, such as data transfer between Regions. Cost and Usage\nReports (Option A) are for detailed cost analysis, not real-time alerting, and VPC Flow Logs\n(Option D) capture traffic data, not billing or cost-based metrics.\nThus, using AWS Budgets with a 75% alert threshold best satisfies the operational and\nnotification requirements.", "question_text": "A CloudOps engineer needs to track the costs of data transfer between AWS Regions. The CloudOps engineer must implement a solution to send alerts to an email distribution list when transfer costs reach 75% of a specific threshold. What should the CloudOps engineer do to meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0072"}', '{"tags": null, "topic": null, "options": [["A", "Create an AWS Cost and Usage Report. Analyze the results in Amazon Athena. Configure an alarm to publish a message to an Amazon Simple Notification Service (Amazon SNS) topic when costs reach 75% of the threshold. Subscribe the email distribution list to the topic."], ["B", "Create an Amazon CloudWatch billing alarm to detect when costs reach 75% of the threshold. Configure the alarm to publish a message to an Amazon Simple Notification Service (Amazon SNS) topic. Subscribe the email distribution list to the topic."], ["C", "Use AWS Budgets to create a cost budget for data transfer costs. Set an alert at 75% of the budgeted amount. Configure the budget to send a notification to the email distribution list when costs reach 75% of the threshold."], ["D", "Set up a VPC flow log. Set up a subscription filter to an AWS Lambda function to analyze data transfer. Configure the Lambda function to send a notification to the email distribution list when costs reach 75% of the threshold."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0072"}, "reference": null, "difficulty": "medium", "explanation": "According to the AWS Cloud Operations and Cost Management documentation, AWS Budgets is\nthe recommended service to track and alert on cost thresholds across all AWS accounts and\nresources. It allows users to define cost, usage, or reservation budgets, and configure\nnotifications to trigger when usage or cost reaches defined percentages of the budgeted value\n(e.g., 75%, 90%, 100%).\nThe AWS Budgets system integrates natively with Amazon Simple Notification Service (SNS) to\ndeliver alerts to an email distribution list or SNS topic subscribers. AWS Budgets supports\ngranular cost filters, including specific service categories such as data transfer, regions, or linked\naccounts, ensuring precise visibility into inter-Region transfer costs.\nBy contrast, CloudWatch billing alarms (Option B) monitor total account charges only and do not\nallow detailed service-level filtering, such as data transfer between Regions. Cost and Usage\nReports (Option A) are for detailed cost analysis, not real-time alerting, and VPC Flow Logs\n(Option D) capture traffic data, not billing or cost-based metrics.\nThus, using AWS Budgets with a 75% alert threshold best satisfies the operational and\nnotification requirements.", "question_text": "A CloudOps engineer needs to track the costs of data transfer between AWS Regions. The CloudOps engineer must implement a solution to send alerts to an email distribution list when transfer costs reach 75% of a specific threshold. What should the CloudOps engineer do to meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '5e2e0824b9db5990386f4d702f168aabd81dbcfdb5dee8f2c96fdc5bca57849a', 1422, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (907, 146, 74, 'qblock_pdf', '{"option_a": "Install the Amazon CloudWatch agent on the EC2 instances.", "option_b": "Create an AWS CloudTrail metric filter for the web logs. Configure an alarm for the specific errors.", "option_c": "Create an Amazon CloudWatch metric filter for the web logs. Configure an alarm for the specific errors.", "option_d": "Publish alarm findings to Amazon Simple Email Service (Amazon SES). Invoke an AWS Lambda function to restart the web server software.", "option_e": "Create an Amazon EventBridge rule that responds to the alarm. Configure the rule to invoke an AWS Systems Manager Automation runbook to restart the web server software.", "option_f": "Create an Amazon Simple Notification Service (Amazon SNS) notification that responds to the alarm. Configure the notification to invoke an AWS Systems Manager Automation runbook to restart the web server software.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Per the AWS Cloud Operations, Monitoring, and Automation documentation, the correct workflow\nfor automated operational remediation is:\nAmazon CloudWatch Agent is installed on each EC2 instance (Option A) to collect local log data\nand push it to Amazon CloudWatch Logs.\nA CloudWatch Metric Filter (Option C) is then defined to identify specific error strings or patterns\nwithin those logs (e.g., \"HTTP 5xx\" or \"Service Unavailable\"). When such an event occurs,\nCloudWatch Alarms are triggered.\nUpon alarm activation, Amazon EventBridge rules (Option E) are configured to respond\nautomatically by invoking an AWS Systems Manager Automation runbook, which executes an\naction to restart the web server process on the affected instance via SSM Agent.\nThis approach aligns directly with AWS''s recommended CloudOps remediation pattern, known as\nevent-driven automation, which ensures minimal downtime and eliminates manual intervention.\nOptions involving CloudTrail (B) or SES notifications (D) are incorrect because they are unrelated\nto log-based application monitoring and automated remediation workflows.", "question_text": "A CloudOps engineer needs to set up alerting and remediation for a web application. The Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com application consists of Amazon EC2 instances that have AWS Systems Manager Agent (SSM Agent) installed. Each EC2 instance runs a custom web server. The EC2 instances run behind a load balancer and write logs locally. The CloudOps engineer must implement a solution that restarts the web server software automatically if specific web errors are detected in the logs. Which combination of steps will meet these requirements? (Select THREE.)", "source_format": "qblock_pdf", "correct_answer": "ACE", "external_question_id": "Q0073"}', '{"tags": null, "topic": null, "options": [["A", "Install the Amazon CloudWatch agent on the EC2 instances."], ["B", "Create an AWS CloudTrail metric filter for the web logs. Configure an alarm for the specific errors."], ["C", "Create an Amazon CloudWatch metric filter for the web logs. Configure an alarm for the specific errors."], ["D", "Publish alarm findings to Amazon Simple Email Service (Amazon SES). Invoke an AWS Lambda function to restart the web server software."], ["E", "Create an Amazon EventBridge rule that responds to the alarm. Configure the rule to invoke an AWS Systems Manager Automation runbook to restart the web server software."], ["F", "Create an Amazon Simple Notification Service (Amazon SNS) notification that responds to the alarm. Configure the notification to invoke an AWS Systems Manager Automation runbook to restart the web server software."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0073"}, "reference": null, "difficulty": "medium", "explanation": "Per the AWS Cloud Operations, Monitoring, and Automation documentation, the correct workflow\nfor automated operational remediation is:\nAmazon CloudWatch Agent is installed on each EC2 instance (Option A) to collect local log data\nand push it to Amazon CloudWatch Logs.\nA CloudWatch Metric Filter (Option C) is then defined to identify specific error strings or patterns\nwithin those logs (e.g., \"HTTP 5xx\" or \"Service Unavailable\"). When such an event occurs,\nCloudWatch Alarms are triggered.\nUpon alarm activation, Amazon EventBridge rules (Option E) are configured to respond\nautomatically by invoking an AWS Systems Manager Automation runbook, which executes an\naction to restart the web server process on the affected instance via SSM Agent.\nThis approach aligns directly with AWS''s recommended CloudOps remediation pattern, known as\nevent-driven automation, which ensures minimal downtime and eliminates manual intervention.\nOptions involving CloudTrail (B) or SES notifications (D) are incorrect because they are unrelated\nto log-based application monitoring and automated remediation workflows.", "question_text": "A CloudOps engineer needs to set up alerting and remediation for a web application. The Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com application consists of Amazon EC2 instances that have AWS Systems Manager Agent (SSM Agent) installed. Each EC2 instance runs a custom web server. The EC2 instances run behind a load balancer and write logs locally. The CloudOps engineer must implement a solution that restarts the web server software automatically if specific web errors are detected in the logs. Which combination of steps will meet these requirements? (Select THREE.)", "question_type": "multiple", "correct_answer": ["A", "C", "E"]}', 'imported', NULL, NULL, 'eee048126e76a3c092b9b70fc7004da3d1048efb99c28cab05372af0e46ae40f', 1423, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (908, 146, 75, 'qblock_pdf', '{"option_a": "Use a certificate issued by AWS Certificate Manager (ACM).", "option_b": "Use a certificate issued by a third-party certificate authority (CA).", "option_c": "Configure CloudFront to automatically renew the certificate when the certificate expires.", "option_d": "Configure email validation for the certificate. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_e": "Configure DNS validation for the certificate.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Cloud Operations and Security documentation specifies that for Amazon CloudFront,\nautomatic certificate renewal is only supported for certificates issued by AWS Certificate Manager\n(ACM). When a certificate is managed by ACM and validated through DNS validation, ACM\nautomatically renews the certificate before expiration without requiring manual intervention.\nOption A ensures that the certificate is issued and managed by ACM, enabling full integration with\nCloudFront. Option E (DNS validation) is essential for automation; AWS performs revalidation\nautomatically as long as the DNS validation record remains in place.\nBy contrast, email validation (Option D) requires manual user confirmation upon renewal, which\nprevents automatic renewals. Certificates issued by third-party certificate authorities (Option B)\nare manually managed and must be reimported into ACM after renewal. CloudFront does not\nhave a direct feature (Option C) to renew certificates; it relies on ACM''s lifecycle management.\nThus, combining ACM-issued certificates (A) with DNS validation (E) ensures continuous,\nautomated renewal with no downtime or human action required.", "question_text": "A CloudOps engineer is configuring an Amazon CloudFront distribution to use an SSL/TLS certificate. The CloudOps engineer must ensure automatic certificate renewal. Which combination of steps will meet this requirement? (Select TWO.)", "source_format": "qblock_pdf", "correct_answer": "AE", "external_question_id": "Q0074"}', '{"tags": null, "topic": null, "options": [["A", "Use a certificate issued by AWS Certificate Manager (ACM)."], ["B", "Use a certificate issued by a third-party certificate authority (CA)."], ["C", "Configure CloudFront to automatically renew the certificate when the certificate expires."], ["D", "Configure email validation for the certificate. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["E", "Configure DNS validation for the certificate."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0074"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Cloud Operations and Security documentation specifies that for Amazon CloudFront,\nautomatic certificate renewal is only supported for certificates issued by AWS Certificate Manager\n(ACM). When a certificate is managed by ACM and validated through DNS validation, ACM\nautomatically renews the certificate before expiration without requiring manual intervention.\nOption A ensures that the certificate is issued and managed by ACM, enabling full integration with\nCloudFront. Option E (DNS validation) is essential for automation; AWS performs revalidation\nautomatically as long as the DNS validation record remains in place.\nBy contrast, email validation (Option D) requires manual user confirmation upon renewal, which\nprevents automatic renewals. Certificates issued by third-party certificate authorities (Option B)\nare manually managed and must be reimported into ACM after renewal. CloudFront does not\nhave a direct feature (Option C) to renew certificates; it relies on ACM''s lifecycle management.\nThus, combining ACM-issued certificates (A) with DNS validation (E) ensures continuous,\nautomated renewal with no downtime or human action required.", "question_text": "A CloudOps engineer is configuring an Amazon CloudFront distribution to use an SSL/TLS certificate. The CloudOps engineer must ensure automatic certificate renewal. Which combination of steps will meet this requirement? (Select TWO.)", "question_type": "multiple", "correct_answer": ["A", "E"]}', 'imported', NULL, NULL, '721c1643d798f697658261e7f47b304ef373c2ceb02282ddd9a2a315eed2a8f3', 1424, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (909, 146, 76, 'qblock_pdf', '{"option_a": "Create a Route 53 Resolver inbound endpoint. Attach a security group to the endpoint to allow inbound traffic on TCP/UDP port 53 from the on-premises DNS servers.", "option_b": "Create a Route 53 Resolver inbound endpoint. Attach a security group to the endpoint to allow outbound traffic on TCP/UDP port 53 to the on-premises DNS servers.", "option_c": "Create a Route 53 Resolver outbound endpoint. Attach a security group to the endpoint to allow inbound traffic on TCP/UDP port 53 from the on-premises DNS servers.", "option_d": "Create a Route 53 Resolver outbound endpoint. Attach a security group to the endpoint to allow outbound traffic on TCP/UDP port 53 to the on-premises DNS servers.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "According to AWS Cloud Operations and Networking documentation, Route 53 Resolver inbound\nendpoints allow DNS queries to originate from on-premises DNS servers and resolve private\nhosted zone records in AWS. The inbound endpoint provides DNS resolver IP addresses within\nthe VPC, which the on-premises DNS servers can forward queries to over AWS Direct Connect\nor VPN connections.\nThe inbound endpoint must be associated with a security group that permits inbound traffic on\nTCP and UDP port 53 from the on-premises DNS server IP addresses. This ensures that DNS\nrequests from the on-premises environment reach the VPC Resolver for resolution of private\ndomains like example.com.\nBy contrast, outbound endpoints are used for the opposite direction--resolving external (on-\npremises or internet) DNS names from within AWS VPCs. Therefore, only an inbound endpoint\ncorrectly satisfies the direction of resolution in this scenario.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A company has an on-premises DNS solution and wants to resolve DNS records in an Amazon Route 53 private hosted zone for example.com. The company has set up an AWS Direct Connect connection for network connectivity between the on-premises network and the VPC. A CloudOps engineer must ensure that an on-premises server can query records in the example.com domain. What should the CloudOps engineer do to meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0075"}', '{"tags": null, "topic": null, "options": [["A", "Create a Route 53 Resolver inbound endpoint. Attach a security group to the endpoint to allow inbound traffic on TCP/UDP port 53 from the on-premises DNS servers."], ["B", "Create a Route 53 Resolver inbound endpoint. Attach a security group to the endpoint to allow outbound traffic on TCP/UDP port 53 to the on-premises DNS servers."], ["C", "Create a Route 53 Resolver outbound endpoint. Attach a security group to the endpoint to allow inbound traffic on TCP/UDP port 53 from the on-premises DNS servers."], ["D", "Create a Route 53 Resolver outbound endpoint. Attach a security group to the endpoint to allow outbound traffic on TCP/UDP port 53 to the on-premises DNS servers."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0075"}, "reference": null, "difficulty": "medium", "explanation": "According to AWS Cloud Operations and Networking documentation, Route 53 Resolver inbound\nendpoints allow DNS queries to originate from on-premises DNS servers and resolve private\nhosted zone records in AWS. The inbound endpoint provides DNS resolver IP addresses within\nthe VPC, which the on-premises DNS servers can forward queries to over AWS Direct Connect\nor VPN connections.\nThe inbound endpoint must be associated with a security group that permits inbound traffic on\nTCP and UDP port 53 from the on-premises DNS server IP addresses. This ensures that DNS\nrequests from the on-premises environment reach the VPC Resolver for resolution of private\ndomains like example.com.\nBy contrast, outbound endpoints are used for the opposite direction--resolving external (on-\npremises or internet) DNS names from within AWS VPCs. Therefore, only an inbound endpoint\ncorrectly satisfies the direction of resolution in this scenario.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A company has an on-premises DNS solution and wants to resolve DNS records in an Amazon Route 53 private hosted zone for example.com. The company has set up an AWS Direct Connect connection for network connectivity between the on-premises network and the VPC. A CloudOps engineer must ensure that an on-premises server can query records in the example.com domain. What should the CloudOps engineer do to meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '70bc23e3ff5ba56a4f28d31b77f2a01fc513eb7d4925eb85f9e62dbd525fa2bd', 1425, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (910, 146, 77, 'qblock_pdf', '{"option_a": "The Outputs section of the CloudFormation template was omitted.", "option_b": "The Parameters section of the CloudFormation template was omitted.", "option_c": "The PrivateDnsName cannot be sot from a CloudFormation template.", "option_d": "The VPC was not specified in the CloudFormation template.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "In AWS CloudFormation, the PrivateDnsName property of an AWS::EC2::Instance resource is a\nread-only attribute automatically assigned by AWS when the instance is launched. It cannot be\nmanually specified in the template. Attempting to define it causes stack creation to fail with a\nvalidation error. CloudFormation manages this value based on the subnet and VPC DNS\nconfiguration, so it must be omitted from the template.", "question_text": "A CloudOps engineer is examining the following AWS CloudFormation template: Why will the stack creation fail?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0076"}', '{"tags": null, "topic": null, "options": [["A", "The Outputs section of the CloudFormation template was omitted."], ["B", "The Parameters section of the CloudFormation template was omitted."], ["C", "The PrivateDnsName cannot be sot from a CloudFormation template."], ["D", "The VPC was not specified in the CloudFormation template."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0076"}, "reference": null, "difficulty": "medium", "explanation": "In AWS CloudFormation, the PrivateDnsName property of an AWS::EC2::Instance resource is a\nread-only attribute automatically assigned by AWS when the instance is launched. It cannot be\nmanually specified in the template. Attempting to define it causes stack creation to fail with a\nvalidation error. CloudFormation manages this value based on the subnet and VPC DNS\nconfiguration, so it must be omitted from the template.", "question_text": "A CloudOps engineer is examining the following AWS CloudFormation template: Why will the stack creation fail?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '403b9197b34b8ca3682fca7a3fedd1f2ec346c989f96559f81e6c2cc49d9cb6e', 1426, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (911, 146, 78, 'qblock_pdf', '{"option_a": "It takes at least 30 days to be able to use tags to filter views in Cost Explorer.", "option_b": "The company has not activated the user-defined tags for cost allocation.", "option_c": "The company has not created an AWS Cost and Usage Report.", "option_d": "The company has not created a usage budget in AWS Budgets.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "User-defined (custom) tags must be manually activated as cost allocation tags in the AWS Billing\nand Cost Management console before they can be used for filtering or grouping data in AWS\nCost Explorer or Cost and Usage Reports. After activation, it can take up to 24 hours for the tags\nto appear in Cost Explorer - not 20 or 30 days.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A company applies user-defined tags to resources that are associated with the company''s AWS workloads. Twenty days after applying the tags, the company notices that it cannot use the tags to filter views in the AWS Cost Explorer console. What is the reason for this issue?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0077"}', '{"tags": null, "topic": null, "options": [["A", "It takes at least 30 days to be able to use tags to filter views in Cost Explorer."], ["B", "The company has not activated the user-defined tags for cost allocation."], ["C", "The company has not created an AWS Cost and Usage Report."], ["D", "The company has not created a usage budget in AWS Budgets."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0077"}, "reference": null, "difficulty": "medium", "explanation": "User-defined (custom) tags must be manually activated as cost allocation tags in the AWS Billing\nand Cost Management console before they can be used for filtering or grouping data in AWS\nCost Explorer or Cost and Usage Reports. After activation, it can take up to 24 hours for the tags\nto appear in Cost Explorer - not 20 or 30 days.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A company applies user-defined tags to resources that are associated with the company''s AWS workloads. Twenty days after applying the tags, the company notices that it cannot use the tags to filter views in the AWS Cost Explorer console. What is the reason for this issue?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '5dde4f03c265d455c82f459feb4e195ed453370da867f2c30010b169cd0b2fce', 1427, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (913, 146, 80, 'qblock_pdf', '{"option_a": "Configure an IAM policy that denies the s3:DeleteObject action for all users. Three months after an object is written, remove the policy.", "option_b": "Enable S3 Object Lock on a new S3 bucket in compliance mode. Place all backups in the new S3 bucket with a retention period of 3 months.", "option_c": "Enable S3 Versioning on the existing S3 bucket. Configure S3 Lifecycle rules to protect the backups.", "option_d": "Enable S3 Object Lock on a new S3 bucket in governance mode. Place all backups in the new S3 bucket with a retention period of 3 months.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "S3 Object Lock in compliance mode prevents any user, including the root user, from deleting or\nmodifying objects during the retention period. This guarantees that backups remain undeletable\nfor the required 3 months. Object Lock must be enabled when the bucket is created, and\ncompliance mode ensures regulatory-grade protection.", "question_text": "A company is storing backups in an Amazon S3 bucket. The backups must not be deleted for at least 3 months after the backups are created. What should a CloudOps engineer do to meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0079"}', '{"tags": null, "topic": null, "options": [["A", "Configure an IAM policy that denies the s3:DeleteObject action for all users. Three months after an object is written, remove the policy."], ["B", "Enable S3 Object Lock on a new S3 bucket in compliance mode. Place all backups in the new S3 bucket with a retention period of 3 months."], ["C", "Enable S3 Versioning on the existing S3 bucket. Configure S3 Lifecycle rules to protect the backups."], ["D", "Enable S3 Object Lock on a new S3 bucket in governance mode. Place all backups in the new S3 bucket with a retention period of 3 months."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0079"}, "reference": null, "difficulty": "medium", "explanation": "S3 Object Lock in compliance mode prevents any user, including the root user, from deleting or\nmodifying objects during the retention period. This guarantees that backups remain undeletable\nfor the required 3 months. Object Lock must be enabled when the bucket is created, and\ncompliance mode ensures regulatory-grade protection.", "question_text": "A company is storing backups in an Amazon S3 bucket. The backups must not be deleted for at least 3 months after the backups are created. What should a CloudOps engineer do to meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '122dc46c0907ab109ad0852b553c87b22e2c4cf9c8cc3c1b69f64e1d54f6f62e', 1429, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (914, 146, 81, 'qblock_pdf', '{"option_a": "The IAM policy that is attached to the IAM role for the flow log is missing the logs:CreateLogGroup permission.", "option_b": "The IAM policy that is attached to the IAM role for the flow log is missing the logs:CreateExportTask permission.", "option_c": "The VPC is configured for IPv6 addresses.", "option_d": "The VPC is peered with another VPC in the AWS account", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "To publish VPC flow logs to Amazon CloudWatch Logs, the IAM role used by the flow logs must\nhave permissions such as logs:CreateLogGroup, logs:CreateLogStream, and logs:PutLogEvents.\nIf the logs:CreateLogGroup permission is missing, CloudWatch Logs cannot create or write to the\nlog group, preventing the logs from appearing.", "question_text": "A company''s CloudOps engineer is troubleshooting communication between the components of an application. The company configured VPC flow logs to be published to Amazon CloudWatch Logs However, there are no logs in CloudWatch Logs. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com What could be blocking the VPC flow logs from being published to CloudWatch Logs?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0080"}', '{"tags": null, "topic": null, "options": [["A", "The IAM policy that is attached to the IAM role for the flow log is missing the logs:CreateLogGroup permission."], ["B", "The IAM policy that is attached to the IAM role for the flow log is missing the logs:CreateExportTask permission."], ["C", "The VPC is configured for IPv6 addresses."], ["D", "The VPC is peered with another VPC in the AWS account"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0080"}, "reference": null, "difficulty": "medium", "explanation": "To publish VPC flow logs to Amazon CloudWatch Logs, the IAM role used by the flow logs must\nhave permissions such as logs:CreateLogGroup, logs:CreateLogStream, and logs:PutLogEvents.\nIf the logs:CreateLogGroup permission is missing, CloudWatch Logs cannot create or write to the\nlog group, preventing the logs from appearing.", "question_text": "A company''s CloudOps engineer is troubleshooting communication between the components of an application. The company configured VPC flow logs to be published to Amazon CloudWatch Logs However, there are no logs in CloudWatch Logs. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com What could be blocking the VPC flow logs from being published to CloudWatch Logs?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '542e68f1e895fc19a106b99c00b78d9badc8d73520ca19f7a50bcbed8a8efbf0', 1430, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (915, 146, 82, 'qblock_pdf', '{"option_a": "Set the routing algorithm of the target group to least outstanding requests.", "option_b": "Turn on anomaly mitigation for the target group.", "option_c": "Turn off the cross-zone load balancing attribute of the target group.", "option_d": "Increase the deregistration delay attribute of the target group.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The application requires session affinity (sticky sessions). However, the weighted random routing\nalgorithm for an ALB does not support sticky sessions, so clients are sent to different targets and\nthe stateful legacy app returns random errors. By changing the target group to an algorithm that\nsupports stickiness (such as least outstanding requests), you can then use sticky sessions so all\nrequests in a session go to the same instance, resolving the errors.", "question_text": "A company is migrating a legacy application to AWS. The company manually installs and configures the legacy application on Amazon EC2 instances across multiple Availability Zones. The company sets up an Application Load Balancer (ALB) for the application. The company sets the target group routing algorithm to weighted random. The application requires session affinity. After the company deploys the application, users report random application errors that were not present in the legacy version of the application. The target group health checks do not show any failures. The company must resolve the application errors. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0081"}', '{"tags": null, "topic": null, "options": [["A", "Set the routing algorithm of the target group to least outstanding requests."], ["B", "Turn on anomaly mitigation for the target group."], ["C", "Turn off the cross-zone load balancing attribute of the target group."], ["D", "Increase the deregistration delay attribute of the target group."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0081"}, "reference": null, "difficulty": "medium", "explanation": "The application requires session affinity (sticky sessions). However, the weighted random routing\nalgorithm for an ALB does not support sticky sessions, so clients are sent to different targets and\nthe stateful legacy app returns random errors. By changing the target group to an algorithm that\nsupports stickiness (such as least outstanding requests), you can then use sticky sessions so all\nrequests in a session go to the same instance, resolving the errors.", "question_text": "A company is migrating a legacy application to AWS. The company manually installs and configures the legacy application on Amazon EC2 instances across multiple Availability Zones. The company sets up an Application Load Balancer (ALB) for the application. The company sets the target group routing algorithm to weighted random. The application requires session affinity. After the company deploys the application, users report random application errors that were not present in the legacy version of the application. The target group health checks do not show any failures. The company must resolve the application errors. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'ee68819fd896fcc78e2fd79d61b0d4bb873872ff4f0e960f7ddd1036a0dc2b24', 1431, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (916, 146, 83, 'qblock_pdf', '{"option_a": "Create an Aurora Replica. Promote the replica to replace the primary DB instance.", "option_b": "Create an AWS Lambda function to restore an automatic backup to the existing DB cluster.", "option_c": "Use backtracking to rewind the existing DB cluster to the desired recovery point. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_d": "Use point-in-time recovery to restore the existing DB duster to the desired recovery point.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Aurora MySQL backtracking lets you “rewind” the existing DB cluster to a previous point in time\n(within the configured backtrack window, such as 72 hours) without creating a new cluster. Point-\nin-time recovery and automatic backups create a new cluster, which does not meet the\nrequirement to restore in the same production DB cluster, whereas backtracking does.", "question_text": "A company is using an Amazon Aurora MySQL DB cluster that has point-in-time recovery, backtracking, and automatic backup enabled. A CloudOps engineer needs to be able to roll back the DB cluster to a specific recovery point within the previous 72 hours. Restores must be completed in the same production DB cluster. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0082"}', '{"tags": null, "topic": null, "options": [["A", "Create an Aurora Replica. Promote the replica to replace the primary DB instance."], ["B", "Create an AWS Lambda function to restore an automatic backup to the existing DB cluster."], ["C", "Use backtracking to rewind the existing DB cluster to the desired recovery point. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["D", "Use point-in-time recovery to restore the existing DB duster to the desired recovery point."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0082"}, "reference": null, "difficulty": "medium", "explanation": "Aurora MySQL backtracking lets you “rewind” the existing DB cluster to a previous point in time\n(within the configured backtrack window, such as 72 hours) without creating a new cluster. Point-\nin-time recovery and automatic backups create a new cluster, which does not meet the\nrequirement to restore in the same production DB cluster, whereas backtracking does.", "question_text": "A company is using an Amazon Aurora MySQL DB cluster that has point-in-time recovery, backtracking, and automatic backup enabled. A CloudOps engineer needs to be able to roll back the DB cluster to a specific recovery point within the previous 72 hours. Restores must be completed in the same production DB cluster. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '56ba02ace2f6e5f5a99dd7d32625933ba5b38d5fc1c8cab6ffbb56199a6751f2', 1432, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (922, 146, 89, 'qblock_pdf', '{"option_a": "Create a Systems Manager Distributor package for the third-party agent.", "option_b": "Create a Systems Manager OpsItem that includes the tag value for Windows. Attach the Systems Manager inventory to the OpsItem.", "option_c": "Create an AWS Lambda function. Program the Lambda function to log in to each instance and to Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com install or update the third-party agent as needed.", "option_d": "Create a Systems Manager State Manager association to run the AWS-RunRemoteScript document Populate the details of the third-party agent package.", "option_e": "Create a Systems Manager State Manager association to run the AWS-ConfigureAWSPackage document. Populate the details of the third-party agent package. Specify instance tags based on the appropriate tag value for Windows.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Create a Systems Manager Distributor package for the third-party agent.\nDistributor is the native SSM feature for packaging and distributing software like third-party\nagents, making it easy to manage versions and updates centrally.\nCreate a Systems Manager State Manager association to run the AWS-ConfigureAWSPackage\ndocument. Populate the details of the third-party agent package. Specify instance tags based on\nthe appropriate tag value for Windows.\nState Manager ensures that all tagged Windows EC2 instances continuously have the agent\ninstalled and updated automatically, providing ongoing compliance with minimal operational\neffort.", "question_text": "A company must ensure that all Amazon EC2 Windows instances that are launched in an AWS account have a third-party agent installed. The company uses AWS Systems Manager, and the Windows instances are tagged appropriately. The company must deploy periodic updates to the third-party agent when the updates become available. Which combination of steps will meet these requirements with the LEAST operational effort? (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "AE", "external_question_id": "Q0088"}', '{"tags": null, "topic": null, "options": [["A", "Create a Systems Manager Distributor package for the third-party agent."], ["B", "Create a Systems Manager OpsItem that includes the tag value for Windows. Attach the Systems Manager inventory to the OpsItem."], ["C", "Create an AWS Lambda function. Program the Lambda function to log in to each instance and to Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com install or update the third-party agent as needed."], ["D", "Create a Systems Manager State Manager association to run the AWS-RunRemoteScript document Populate the details of the third-party agent package."], ["E", "Create a Systems Manager State Manager association to run the AWS-ConfigureAWSPackage document. Populate the details of the third-party agent package. Specify instance tags based on the appropriate tag value for Windows."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0088"}, "reference": null, "difficulty": "medium", "explanation": "Create a Systems Manager Distributor package for the third-party agent.\nDistributor is the native SSM feature for packaging and distributing software like third-party\nagents, making it easy to manage versions and updates centrally.\nCreate a Systems Manager State Manager association to run the AWS-ConfigureAWSPackage\ndocument. Populate the details of the third-party agent package. Specify instance tags based on\nthe appropriate tag value for Windows.\nState Manager ensures that all tagged Windows EC2 instances continuously have the agent\ninstalled and updated automatically, providing ongoing compliance with minimal operational\neffort.", "question_text": "A company must ensure that all Amazon EC2 Windows instances that are launched in an AWS account have a third-party agent installed. The company uses AWS Systems Manager, and the Windows instances are tagged appropriately. The company must deploy periodic updates to the third-party agent when the updates become available. Which combination of steps will meet these requirements with the LEAST operational effort? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "E"]}', 'imported', NULL, NULL, 'b41ac029f625f10ba76704e87209aebf6316bf9f079041f6af33e912be1cf69f', 1438, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (917, 146, 84, 'qblock_pdf', '{"option_a": "Set the value of the DisableRollback parameter to False during stack creation.", "option_b": "Set the value of the OnFailure parameter to DO_NOTHING during stack creation.", "option_c": "Specify a rollback configuration that has a rollback trigger of DO_NOTHING during stack creation.", "option_d": "Set the value of the OnFailure parameter to ROLLBACK during stack creation.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "When OnFailure=DO_NOTHING is set in AWS CloudFormation, the stack remains in the\n“CREATE_FAILED” state instead of being automatically rolled back and deleted. This preserves\nany successfully created resources, allowing the CloudOps engineer to investigate and correct\nthe issue without losing existing resources.", "question_text": "A CloudOps engineer is troubleshooting an AWS CloudFormation stack creation that failed. Before the CloudOps engineer can identify the problem, the stack and its resources are deleted. For future deployments, the CloudOps engineer must preserve any resources that CloudFormation successfully created. What should the CloudOps engineer do to meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0083"}', '{"tags": null, "topic": null, "options": [["A", "Set the value of the DisableRollback parameter to False during stack creation."], ["B", "Set the value of the OnFailure parameter to DO_NOTHING during stack creation."], ["C", "Specify a rollback configuration that has a rollback trigger of DO_NOTHING during stack creation."], ["D", "Set the value of the OnFailure parameter to ROLLBACK during stack creation."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0083"}, "reference": null, "difficulty": "medium", "explanation": "When OnFailure=DO_NOTHING is set in AWS CloudFormation, the stack remains in the\n“CREATE_FAILED” state instead of being automatically rolled back and deleted. This preserves\nany successfully created resources, allowing the CloudOps engineer to investigate and correct\nthe issue without losing existing resources.", "question_text": "A CloudOps engineer is troubleshooting an AWS CloudFormation stack creation that failed. Before the CloudOps engineer can identify the problem, the stack and its resources are deleted. For future deployments, the CloudOps engineer must preserve any resources that CloudFormation successfully created. What should the CloudOps engineer do to meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'c6b74696113ac9ea65e6fa9c10a4c40b8e92a65cd166f00aa7139caa7dd441b3', 1433, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (918, 146, 85, 'qblock_pdf', '{"option_a": "Create an Application Load Balancer that has one HTTPS listener on port 80. Attach an SSL/TLS certificate to listener port 80. Create a rule to redirect requests from HTTP to HTTPS.", "option_b": "Create an Application Load Balancer that has one HTTP listener on port 80 and one HTTPS protocol listener on port 443. Attach an SSL/TLS certificate to listener port 443. Create a rule to redirect requests from port 80 to port 443.", "option_c": "Create an Application Load Balancer that has two TCP listeners on port 80 and port 443. Attach an SSL/TLS certificate to listener port 443. Create a rule to redirect requests from port 80 to port 443.", "option_d": "Create a Network Load Balancer that has two TCP listeners on port 80 and port 443. Attach an SSL/TLS certificate to listener port 443. Create a rule to redirect requests from port 80 to port 443.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "An Application Load Balancer (ALB) supports both HTTP and HTTPS listeners. By attaching an\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nACM-managed SSL/TLS certificate to the HTTPS listener on port 443 and configuring a redirect\nrule in the HTTP (port 80) listener to forward traffic to HTTPS, the ALB automatically redirects all\nHTTP requests to HTTPS, meeting both the security and operational requirements.", "question_text": "A company plans to run a public web application on Amazon EC2 instances behind an Elastic Load Balancing (ELB) load balancer. The company’s security team wants to protect the website by using AWS Certificate Manager (ACM) certificates. The load balancer must automatically redirect any HTTP requests to HTTPS. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0084"}', '{"tags": null, "topic": null, "options": [["A", "Create an Application Load Balancer that has one HTTPS listener on port 80. Attach an SSL/TLS certificate to listener port 80. Create a rule to redirect requests from HTTP to HTTPS."], ["B", "Create an Application Load Balancer that has one HTTP listener on port 80 and one HTTPS protocol listener on port 443. Attach an SSL/TLS certificate to listener port 443. Create a rule to redirect requests from port 80 to port 443."], ["C", "Create an Application Load Balancer that has two TCP listeners on port 80 and port 443. Attach an SSL/TLS certificate to listener port 443. Create a rule to redirect requests from port 80 to port 443."], ["D", "Create a Network Load Balancer that has two TCP listeners on port 80 and port 443. Attach an SSL/TLS certificate to listener port 443. Create a rule to redirect requests from port 80 to port 443."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0084"}, "reference": null, "difficulty": "medium", "explanation": "An Application Load Balancer (ALB) supports both HTTP and HTTPS listeners. By attaching an\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nACM-managed SSL/TLS certificate to the HTTPS listener on port 443 and configuring a redirect\nrule in the HTTP (port 80) listener to forward traffic to HTTPS, the ALB automatically redirects all\nHTTP requests to HTTPS, meeting both the security and operational requirements.", "question_text": "A company plans to run a public web application on Amazon EC2 instances behind an Elastic Load Balancing (ELB) load balancer. The company’s security team wants to protect the website by using AWS Certificate Manager (ACM) certificates. The load balancer must automatically redirect any HTTP requests to HTTPS. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '8ce419df836e5dae637947fed906db01c0758ed1ca8b10e3178df9f504973d3d', 1434, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (919, 146, 86, 'qblock_pdf', '{"option_a": "Create an IAM group that has a policy that allows the ec2:RunInstances action when the CostCenter-Project tag is present. Place all IAM users who need access to the application accounts in the IAM group.", "option_b": "Create a service control policy (SCP) that denies the oc2:RunInstances action when the CostCenter-Project tag is missing. Attach the SCP to the application OU.", "option_c": "Create an IAM role that has a policy that allows the oc2:RunInstances action when the CostCenter-Project tag is present. Attach the IAM role to the IAM users that are in the application OU accounts.", "option_d": "Create a service control policy (SCP) that denies the ec2:RunInstances action when the CostCenter-Project tag is missing. Attach the SCP to the root OU.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "To enforce a mandatory tag across multiple accounts in an OU, you use a service control policy.\nAn SCP with a Deny on ec2:RunInstances when the CostCenter-Project tag is not present will\nblock launches of untagged instances in all accounts in that OU, regardless of local IAM policies.\nAttaching it to the application OU ensures the restriction applies only there and not to other OUs\nor the entire organization.", "question_text": "A company uses AWS Organizations to manage a set of AWS accounts. The company has set up organizational units (OUs) in the organization. An application OU supports various applications. A CloudOps engineer must prevent users from launching Amazon EC2 instances that do not have a CostCenter-Project tag into any account in the application OU. The restriction must apply only to accounts in the application OU. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0085"}', '{"tags": null, "topic": null, "options": [["A", "Create an IAM group that has a policy that allows the ec2:RunInstances action when the CostCenter-Project tag is present. Place all IAM users who need access to the application accounts in the IAM group."], ["B", "Create a service control policy (SCP) that denies the oc2:RunInstances action when the CostCenter-Project tag is missing. Attach the SCP to the application OU."], ["C", "Create an IAM role that has a policy that allows the oc2:RunInstances action when the CostCenter-Project tag is present. Attach the IAM role to the IAM users that are in the application OU accounts."], ["D", "Create a service control policy (SCP) that denies the ec2:RunInstances action when the CostCenter-Project tag is missing. Attach the SCP to the root OU."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0085"}, "reference": null, "difficulty": "medium", "explanation": "To enforce a mandatory tag across multiple accounts in an OU, you use a service control policy.\nAn SCP with a Deny on ec2:RunInstances when the CostCenter-Project tag is not present will\nblock launches of untagged instances in all accounts in that OU, regardless of local IAM policies.\nAttaching it to the application OU ensures the restriction applies only there and not to other OUs\nor the entire organization.", "question_text": "A company uses AWS Organizations to manage a set of AWS accounts. The company has set up organizational units (OUs) in the organization. An application OU supports various applications. A CloudOps engineer must prevent users from launching Amazon EC2 instances that do not have a CostCenter-Project tag into any account in the application OU. The restriction must apply only to accounts in the application OU. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '7c4fa9ccf032a5b8d40dfce5e4b4c6622013c09ccbee44d9080fe36e799beab5', 1435, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (920, 146, 87, 'qblock_pdf', '{"option_a": "Use a secondary tag to create 10 batches of 30 instances each. Use a Systems Manager Run Command document to download and install the package. Specify the target as part of the Run Command document by using the secondary tag. Run each batch one time.", "option_b": "Use an AWS Lambda function to automatically run a Systems Manager Run Command document that roads a list of instance IDs that have the user-defined tag. Set reserved concurrency for the Lambda function to 30.", "option_c": "Use a Systems Manager Run Command document to download and install the package. Use rate Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com control to set concurrency to 30. Specify the target by using the user-defined tag as part of the Run Command document.", "option_d": "Use a parallel workflow state in AWS Step Functions to automatically run a Systems Manager Run Command document that reads a list of instance IDs that have the user-defined tag. Set the number of parallel states to 30. Run the Step Functions workflow 10 times.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Systems Manager Run Command supports rate control, where you can set max\nconcurrency (e.g., 30) and target instances by tag. This lets you run the command on all tagged\ninstances while automatically limiting concurrent executions to 30, avoiding repository overload\nand scaling cleanly as the number of instances grows, without extra scripting or manual batching.", "question_text": "A company runs a business application on more than 300 Linux-based instances. Each instance has the AWS Systems Manager Agent (SSM Agent) installed. The company expects the number of instances to grow in the future. All business application instances have the same user-defined tag. A CloudOps engineer wants to run a command on all the business application instances to download and install a package from a private repository. To avoid overwhelming the repository, the CloudOps engineer wants to ensure that no more than 30 downloads occur at one time. Which solution will meet this requirement in the MOST operationally efficient way?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0086"}', '{"tags": null, "topic": null, "options": [["A", "Use a secondary tag to create 10 batches of 30 instances each. Use a Systems Manager Run Command document to download and install the package. Specify the target as part of the Run Command document by using the secondary tag. Run each batch one time."], ["B", "Use an AWS Lambda function to automatically run a Systems Manager Run Command document that roads a list of instance IDs that have the user-defined tag. Set reserved concurrency for the Lambda function to 30."], ["C", "Use a Systems Manager Run Command document to download and install the package. Use rate Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com control to set concurrency to 30. Specify the target by using the user-defined tag as part of the Run Command document."], ["D", "Use a parallel workflow state in AWS Step Functions to automatically run a Systems Manager Run Command document that reads a list of instance IDs that have the user-defined tag. Set the number of parallel states to 30. Run the Step Functions workflow 10 times."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0086"}, "reference": null, "difficulty": "medium", "explanation": "AWS Systems Manager Run Command supports rate control, where you can set max\nconcurrency (e.g., 30) and target instances by tag. This lets you run the command on all tagged\ninstances while automatically limiting concurrent executions to 30, avoiding repository overload\nand scaling cleanly as the number of instances grows, without extra scripting or manual batching.", "question_text": "A company runs a business application on more than 300 Linux-based instances. Each instance has the AWS Systems Manager Agent (SSM Agent) installed. The company expects the number of instances to grow in the future. All business application instances have the same user-defined tag. A CloudOps engineer wants to run a command on all the business application instances to download and install a package from a private repository. To avoid overwhelming the repository, the CloudOps engineer wants to ensure that no more than 30 downloads occur at one time. Which solution will meet this requirement in the MOST operationally efficient way?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '1fde40207244b872d6af0b5ca5b2732868be1ea9dc40b865887509116528642c', 1436, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (921, 146, 88, 'qblock_pdf', '{"option_a": "Add a Route 53 health check for each of the weighted records that received traffic during the recent update.", "option_b": "Increase the weight of Route 53 records in the Region where traffic must go during updates.", "option_c": "Reconfigure all records to use latency-based routing across all Regions uniformly.", "option_d": "Reduce the TTL value for latency-based routing to detect changes more quickly.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "In Route 53 latency-based routing, traffic is routed to the Region with the lowest latency, and\nwithin each Region, weighted records can distribute traffic across multiple endpoints. However, if\nthe weighted records lack individual health checks, Route 53 cannot detect endpoint failures and\ncontinues routing traffic to unhealthy targets. Attaching a Route 53 health check to each weighted\nrecord ensures that only healthy endpoints receive traffic, preventing recurrence of the issue.", "question_text": "A company uses Amazon Route 53 with latency-based routing across multiple AWS Regions to provide resiliency. The company uses Route 53 with latency-based routing to direct traffic to the nearest Region. Within each Region, weighted A records distribute traffic across multiple Availability Zones. During a recent update, some Availability Zone endpoints became unhealthy. Route 53 continued to route traffic to the unhealthy endpoints. The company must prevent this issue from occurring in the future. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0087"}', '{"tags": null, "topic": null, "options": [["A", "Add a Route 53 health check for each of the weighted records that received traffic during the recent update."], ["B", "Increase the weight of Route 53 records in the Region where traffic must go during updates."], ["C", "Reconfigure all records to use latency-based routing across all Regions uniformly."], ["D", "Reduce the TTL value for latency-based routing to detect changes more quickly."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0087"}, "reference": null, "difficulty": "medium", "explanation": "In Route 53 latency-based routing, traffic is routed to the Region with the lowest latency, and\nwithin each Region, weighted records can distribute traffic across multiple endpoints. However, if\nthe weighted records lack individual health checks, Route 53 cannot detect endpoint failures and\ncontinues routing traffic to unhealthy targets. Attaching a Route 53 health check to each weighted\nrecord ensures that only healthy endpoints receive traffic, preventing recurrence of the issue.", "question_text": "A company uses Amazon Route 53 with latency-based routing across multiple AWS Regions to provide resiliency. The company uses Route 53 with latency-based routing to direct traffic to the nearest Region. Within each Region, weighted A records distribute traffic across multiple Availability Zones. During a recent update, some Availability Zone endpoints became unhealthy. Route 53 continued to route traffic to the unhealthy endpoints. The company must prevent this issue from occurring in the future. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'e8777eeca58d6b3840aed0c035503d3f5622bce1b1f3097e5efd68215335bfee', 1437, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (923, 146, 90, 'qblock_pdf', '{"option_a": "Define a patch baseline in Systems Manager Patch Manager. Use a Patch Manager scan to identify the affected instances. Use the Patch Now option in each Region to update the affected instances.", "option_b": "Use AWS Config to identify the affected instances. Define a patch baseline in Systems Manager Patch Manager. Use the Patch Now option in Patch Manager to update the affected instances.", "option_c": "Create an Amazon EventBridge rule to react to Systems Manager Compliance events. Configure the EventBridge rule to run a patch baseline on the affected instances.", "option_d": "Use AWS Config to identify the affected instances. Update the existing EC2 AMIs with the desired patch Manually launch instances from the new AMIs to replace the affected instances in both Regions.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Systems Manager Patch Manager is designed specifically to scan managed instances for\nmissing patches and apply them with minimal operational effort. By defining a patch baseline and\nrunning a Patch Manager scan, you can automatically identify which instances are vulnerable,\nthen use Patch Now (per Region) to patch only the affected instances. This leverages existing\nSSM integration, avoids extra services like AWS Config or manual AMI/instance management,\nand provides the lowest operational overhead.", "question_text": "A company has deployed Amazon EC2 instances from custom Amazon Machine Images (AMIs) in two AWS Regions. The company registered all the instances with AWS Systems Manager. The company discovers that the operating system on some instances has a significant zero-day exploit. However, the company does not know how many instances are affected. A CloudOps engineer must implement a solution to deploy operating system patches for the affected EC2 instances. Which solution will meet this requirement with the LEAST operational overhead?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0089"}', '{"tags": null, "topic": null, "options": [["A", "Define a patch baseline in Systems Manager Patch Manager. Use a Patch Manager scan to identify the affected instances. Use the Patch Now option in each Region to update the affected instances."], ["B", "Use AWS Config to identify the affected instances. Define a patch baseline in Systems Manager Patch Manager. Use the Patch Now option in Patch Manager to update the affected instances."], ["C", "Create an Amazon EventBridge rule to react to Systems Manager Compliance events. Configure the EventBridge rule to run a patch baseline on the affected instances."], ["D", "Use AWS Config to identify the affected instances. Update the existing EC2 AMIs with the desired patch Manually launch instances from the new AMIs to replace the affected instances in both Regions."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0089"}, "reference": null, "difficulty": "medium", "explanation": "AWS Systems Manager Patch Manager is designed specifically to scan managed instances for\nmissing patches and apply them with minimal operational effort. By defining a patch baseline and\nrunning a Patch Manager scan, you can automatically identify which instances are vulnerable,\nthen use Patch Now (per Region) to patch only the affected instances. This leverages existing\nSSM integration, avoids extra services like AWS Config or manual AMI/instance management,\nand provides the lowest operational overhead.", "question_text": "A company has deployed Amazon EC2 instances from custom Amazon Machine Images (AMIs) in two AWS Regions. The company registered all the instances with AWS Systems Manager. The company discovers that the operating system on some instances has a significant zero-day exploit. However, the company does not know how many instances are affected. A CloudOps engineer must implement a solution to deploy operating system patches for the affected EC2 instances. Which solution will meet this requirement with the LEAST operational overhead?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'ec635b2a714fdf0fafb5001365b1f1d05bc7d044a45971d9673ed4647cb64ebc', 1439, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (924, 146, 91, 'qblock_pdf', '{"option_a": "Configure the existing EventBridge event to stop the EC2 instances that have the exposed port.", "option_b": "Create a cron job for the FTP server to invoke an AWS Lambda function. Configure the Lambda function to modify the security group of the identified EC2 instances and to remove the instances that allow public access.", "option_c": "Create a cron job for the FTP server that invokes an AWS Lambda function. Configure the Lambda function to modify the server to use SFTP instead of FTP.", "option_d": "Configure the existing EventBridge event to invoke an AWS Lambda function. Configure the function to remove the security group rule that allows public access.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Security Hub already sends findings to Amazon EventBridge, so the most efficient event-driven\nremediation is to have EventBridge trigger a Lambda function whenever a relevant finding\n(publicly exposed port) occurs. The Lambda function can parse the finding, identify the affected\nsecurity group and port, and remove the 0.0.0.0/0 (or ::/0) rule that exposes the port. This directly\nfixes the root cause (the security group rule) and can be reused for similar exposed-port findings\nwithout manual intervention or periodic jobs.", "question_text": "Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com A company hosts an FTP server on Amazon EC2 instances. In the company’s AWS environment, AWS Security Hub sends findings for the EC2 instances to Amazon EventBridge because the FTP port has become publicly exposed in the security groups that are attached to the instances. A CloudOps engineer wants an automated solution to remediate the Security Hub finding and any similar exposed port findings. The CloudOps engineer wants to use an event-driven approach. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0090"}', '{"tags": null, "topic": null, "options": [["A", "Configure the existing EventBridge event to stop the EC2 instances that have the exposed port."], ["B", "Create a cron job for the FTP server to invoke an AWS Lambda function. Configure the Lambda function to modify the security group of the identified EC2 instances and to remove the instances that allow public access."], ["C", "Create a cron job for the FTP server that invokes an AWS Lambda function. Configure the Lambda function to modify the server to use SFTP instead of FTP."], ["D", "Configure the existing EventBridge event to invoke an AWS Lambda function. Configure the function to remove the security group rule that allows public access."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0090"}, "reference": null, "difficulty": "medium", "explanation": "Security Hub already sends findings to Amazon EventBridge, so the most efficient event-driven\nremediation is to have EventBridge trigger a Lambda function whenever a relevant finding\n(publicly exposed port) occurs. The Lambda function can parse the finding, identify the affected\nsecurity group and port, and remove the 0.0.0.0/0 (or ::/0) rule that exposes the port. This directly\nfixes the root cause (the security group rule) and can be reused for similar exposed-port findings\nwithout manual intervention or periodic jobs.", "question_text": "Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com A company hosts an FTP server on Amazon EC2 instances. In the company’s AWS environment, AWS Security Hub sends findings for the EC2 instances to Amazon EventBridge because the FTP port has become publicly exposed in the security groups that are attached to the instances. A CloudOps engineer wants an automated solution to remediate the Security Hub finding and any similar exposed port findings. The CloudOps engineer wants to use an event-driven approach. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'b9a3db2f2036c39a4b86a585c68fb29962dc541804ed9c1a4374b1e938834647', 1440, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (925, 146, 92, 'qblock_pdf', '{"option_a": "Deploy the instances in a cluster placement group in one Availability Zone.", "option_b": "Deploy the instances in a partition placement group in two Availability Zones.", "option_c": "Deploy the instances in a partition placement group in one Availability Zone.", "option_d": "Deploy the instances in a spread placement group in two Availability Zones.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Cluster placement groups place EC2 instances close together within a single Availability Zone,\nproviding very low network latency and high network throughput, which is ideal for HPC\nworkloads that require fast, high-bandwidth communication between nodes. Partition and spread\ngroups focus on isolation and failure-domain separation, not on maximizing inter-instance\nnetwork performance.", "question_text": "A company plans to migrate several of its high performance computing (HPC) virtual machines (VMs) to Amazon EC2 instances on AWS. A CloudOps engineer must identify a placement group for this deployment. The strategy must minimize network latency and must maximize network throughput between the HPC VMs. Which strategy should the CloudOps engineer choose to meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0091"}', '{"tags": null, "topic": null, "options": [["A", "Deploy the instances in a cluster placement group in one Availability Zone."], ["B", "Deploy the instances in a partition placement group in two Availability Zones."], ["C", "Deploy the instances in a partition placement group in one Availability Zone."], ["D", "Deploy the instances in a spread placement group in two Availability Zones."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0091"}, "reference": null, "difficulty": "medium", "explanation": "Cluster placement groups place EC2 instances close together within a single Availability Zone,\nproviding very low network latency and high network throughput, which is ideal for HPC\nworkloads that require fast, high-bandwidth communication between nodes. Partition and spread\ngroups focus on isolation and failure-domain separation, not on maximizing inter-instance\nnetwork performance.", "question_text": "A company plans to migrate several of its high performance computing (HPC) virtual machines (VMs) to Amazon EC2 instances on AWS. A CloudOps engineer must identify a placement group for this deployment. The strategy must minimize network latency and must maximize network throughput between the HPC VMs. Which strategy should the CloudOps engineer choose to meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '96bee3066ce3a8e05d732678b496f4c405ab9657f6bff32b7a4020c6c802cb53', 1441, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (926, 146, 93, 'qblock_pdf', '{"option_a": "Designate a central security account as the AWS Security Hub administrator account. Create a script that sends an invitation from the Security Hub administrator account and accepts the invitation from the member account. Run the script every time a new account is created. Configure Security Hub to run the CIS AWS Foundations Benchmark scans.", "option_b": "Run the CIS AWS Foundations Benchmark across all accounts by using Amazon Inspector.", "option_c": "Designate a central security account as the Amazon GuardDuty administrator account. Create a script that sends an invitation from the GuardDuty administrator account and accepts the invitation from the member account. Run the script every time a new account is created. Configure GuardDuty to run the CIS AWS Foundations Benchmark scans.", "option_d": "Designate an AWS Security Hub administrator account. Configure new accounts in the organization to automatically become member accounts. Enable CIS AWS Foundations Benchmark scans.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Security Hub natively supports running the CIS AWS Foundations Benchmark across\nmultiple accounts in an organization. By designating a central administrator account and enabling\nautomatic account enrollment, all current and future member accounts are automatically included\nin Security Hub compliance checks. This approach eliminates the need for manual scripting or\naccount invitations, providing the most operationally efficient and scalable solution.", "question_text": "A company manages a set of accounts on AWS by using AWS Organizations. The company''s security team wants to use a native AWS service to regularly scan all AWS accounts against the Center for Internet Security (CIS) AWS Foundations Benchmark. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com What is the MOST operationally efficient way to meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0092"}', '{"tags": null, "topic": null, "options": [["A", "Designate a central security account as the AWS Security Hub administrator account. Create a script that sends an invitation from the Security Hub administrator account and accepts the invitation from the member account. Run the script every time a new account is created. Configure Security Hub to run the CIS AWS Foundations Benchmark scans."], ["B", "Run the CIS AWS Foundations Benchmark across all accounts by using Amazon Inspector."], ["C", "Designate a central security account as the Amazon GuardDuty administrator account. Create a script that sends an invitation from the GuardDuty administrator account and accepts the invitation from the member account. Run the script every time a new account is created. Configure GuardDuty to run the CIS AWS Foundations Benchmark scans."], ["D", "Designate an AWS Security Hub administrator account. Configure new accounts in the organization to automatically become member accounts. Enable CIS AWS Foundations Benchmark scans."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0092"}, "reference": null, "difficulty": "medium", "explanation": "AWS Security Hub natively supports running the CIS AWS Foundations Benchmark across\nmultiple accounts in an organization. By designating a central administrator account and enabling\nautomatic account enrollment, all current and future member accounts are automatically included\nin Security Hub compliance checks. This approach eliminates the need for manual scripting or\naccount invitations, providing the most operationally efficient and scalable solution.", "question_text": "A company manages a set of accounts on AWS by using AWS Organizations. The company''s security team wants to use a native AWS service to regularly scan all AWS accounts against the Center for Internet Security (CIS) AWS Foundations Benchmark. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com What is the MOST operationally efficient way to meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '06489f10f213d3f4f8df6c5e103a71674730d90362177cec73fae39b8f5f3861', 1442, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (927, 146, 94, 'qblock_pdf', '{"option_a": "Use the monitoring graphs in the EC2 console to view metrics for EBS volumes. Review the consumed space against the provisioned space on each volume. Identify any volumes that have low utilization.", "option_b": "Stop the EC2 instances from the EC2 console. Change the EC2 instance type to Amazon EBS- optimized. Start the EC2 instances.", "option_c": "Opt in to AWS Compute Optimizer. Allow sufficient time for metrics to be gathered. Review the Compute Optimizer findings for EBS volumes.", "option_d": "Install the fio tool onto the EC2 instances and create a .cfg file to approximate the required workloads. Use the benchmark results to gauge whether the provisioned EBS volumes are of the most appropriate type.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Compute Optimizer automatically analyzes EBS volume metrics (IOPS, throughput, and\ncapacity) to provide cost optimization recommendations based on actual usage patterns. It\nidentifies overprovisioned volumes and suggests lower-cost volume types without requiring\nmanual benchmarking or instance modifications. This is the most operationally efficient solution\nbecause it is fully managed and requires no manual data collection or analysis.", "question_text": "A company has users that deploy Amazon EC2 instances that have more volume performance capacity than is required. A CloudOps engineer needs to review all Amazon Elastic Block Store (Amazon EBS) volumes that are associated with the instances and create cost optimization recommendations based on IOPS and throughput. What should the CloudOps engineer do to meet these requirements in the MOST operationally efficient way?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0093"}', '{"tags": null, "topic": null, "options": [["A", "Use the monitoring graphs in the EC2 console to view metrics for EBS volumes. Review the consumed space against the provisioned space on each volume. Identify any volumes that have low utilization."], ["B", "Stop the EC2 instances from the EC2 console. Change the EC2 instance type to Amazon EBS- optimized. Start the EC2 instances."], ["C", "Opt in to AWS Compute Optimizer. Allow sufficient time for metrics to be gathered. Review the Compute Optimizer findings for EBS volumes."], ["D", "Install the fio tool onto the EC2 instances and create a .cfg file to approximate the required workloads. Use the benchmark results to gauge whether the provisioned EBS volumes are of the most appropriate type."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0093"}, "reference": null, "difficulty": "medium", "explanation": "AWS Compute Optimizer automatically analyzes EBS volume metrics (IOPS, throughput, and\ncapacity) to provide cost optimization recommendations based on actual usage patterns. It\nidentifies overprovisioned volumes and suggests lower-cost volume types without requiring\nmanual benchmarking or instance modifications. This is the most operationally efficient solution\nbecause it is fully managed and requires no manual data collection or analysis.", "question_text": "A company has users that deploy Amazon EC2 instances that have more volume performance capacity than is required. A CloudOps engineer needs to review all Amazon Elastic Block Store (Amazon EBS) volumes that are associated with the instances and create cost optimization recommendations based on IOPS and throughput. What should the CloudOps engineer do to meet these requirements in the MOST operationally efficient way?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'e5fc33bddcccfa509eb4769017594680cf6ead5773b22fd61b842c118426d79a', 1443, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (928, 146, 95, 'qblock_pdf', '{"option_a": "Use AWS Trusted Advisor to perform a check for S3 buckets that do not have logging enabled. Configure the check to enable logging for S3 buckets that do not have logging enabled.", "option_b": "Configure an S3 bucket policy that requires all current and future S3 buckets to have logging enabled.", "option_c": "Use the s3-bucket-logging-enabled AWS Config managed rule. Add a remediation action that uses an AWS Lambda function to enable logging.", "option_d": "Use the s3-bucket-logging-enabled AWS Config managed rule. Add a remediation action that uses the AWS-ConfigureS3BucketLogging AWS Systems Manager Automation runbook to enable logging.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The AWS Config managed rule s3-bucket-logging-enabled continuously evaluates whether S3\nbuckets have logging enabled. By attaching an automatic remediation action using the AWS-\nConfigureS3BucketLogging Systems Manager Automation runbook, AWS can automatically\nenable logging for any noncompliant bucket. This provides a fully automated and scalable\nsolution that applies to both existing and newly created buckets with minimal operational effort.", "question_text": "A CloudOps engineer must ensure that all of a company''s current and future Amazon S3 buckets Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com have logging enabled. If an S3 bucket does not have logging enabled, an automated process must enable logging for the S3 bucket. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0094"}', '{"tags": null, "topic": null, "options": [["A", "Use AWS Trusted Advisor to perform a check for S3 buckets that do not have logging enabled. Configure the check to enable logging for S3 buckets that do not have logging enabled."], ["B", "Configure an S3 bucket policy that requires all current and future S3 buckets to have logging enabled."], ["C", "Use the s3-bucket-logging-enabled AWS Config managed rule. Add a remediation action that uses an AWS Lambda function to enable logging."], ["D", "Use the s3-bucket-logging-enabled AWS Config managed rule. Add a remediation action that uses the AWS-ConfigureS3BucketLogging AWS Systems Manager Automation runbook to enable logging."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0094"}, "reference": null, "difficulty": "medium", "explanation": "The AWS Config managed rule s3-bucket-logging-enabled continuously evaluates whether S3\nbuckets have logging enabled. By attaching an automatic remediation action using the AWS-\nConfigureS3BucketLogging Systems Manager Automation runbook, AWS can automatically\nenable logging for any noncompliant bucket. This provides a fully automated and scalable\nsolution that applies to both existing and newly created buckets with minimal operational effort.", "question_text": "A CloudOps engineer must ensure that all of a company''s current and future Amazon S3 buckets Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com have logging enabled. If an S3 bucket does not have logging enabled, an automated process must enable logging for the S3 bucket. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '428d40f7dd74d139e07e3d39c75c5ac8a954e89c33795bc6dd4846bedb582643', 1444, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (930, 146, 97, 'qblock_pdf', '{"option_a": "Modify the replication configuration to change object ownership to the destination S3 bucket owner.", "option_b": "Ensure that the replication rule applies to all objects in the source S3 bucket and is not scoped to a single prefix.", "option_c": "Retry the request when the S3 Replication Time Control (S3 RTC) has elapsed.", "option_d": "Verify that the storage class for the replicated objects did not change between the source S3 bucket and the destination S3 bucket.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "In cross-account S3 replication, by default, replicated objects are owned by the source account,\nwhich causes Access Denied errors when the destination account tries to access them. To\nresolve this, you must enable the “change object ownership to destination bucket owner” option\n(using the AccessControlTranslation property in the replication configuration). This ensures the\ndestination account owns the replicated objects and can access them without permission issues.", "question_text": "A CloudOps engineer is responsible for a company’s disaster recovery procedures. The company has a source Amazon S3 bucket in a production account, and it wants to replicate objects from Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com the source to a destination S3 bucket in a nonproduction account. The CloudOps engineer configures S3 cross-Region, cross-account replication to copy the source S3 bucket to the destination S3 bucket. When the CloudOps engineer attempts to access objects in the destination S3 bucket, they receive an Access Denied error. Which solution will resolve this problem?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0096"}', '{"tags": null, "topic": null, "options": [["A", "Modify the replication configuration to change object ownership to the destination S3 bucket owner."], ["B", "Ensure that the replication rule applies to all objects in the source S3 bucket and is not scoped to a single prefix."], ["C", "Retry the request when the S3 Replication Time Control (S3 RTC) has elapsed."], ["D", "Verify that the storage class for the replicated objects did not change between the source S3 bucket and the destination S3 bucket."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0096"}, "reference": null, "difficulty": "medium", "explanation": "In cross-account S3 replication, by default, replicated objects are owned by the source account,\nwhich causes Access Denied errors when the destination account tries to access them. To\nresolve this, you must enable the “change object ownership to destination bucket owner” option\n(using the AccessControlTranslation property in the replication configuration). This ensures the\ndestination account owns the replicated objects and can access them without permission issues.", "question_text": "A CloudOps engineer is responsible for a company’s disaster recovery procedures. The company has a source Amazon S3 bucket in a production account, and it wants to replicate objects from Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com the source to a destination S3 bucket in a nonproduction account. The CloudOps engineer configures S3 cross-Region, cross-account replication to copy the source S3 bucket to the destination S3 bucket. When the CloudOps engineer attempts to access objects in the destination S3 bucket, they receive an Access Denied error. Which solution will resolve this problem?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '9da896a6259640650b2da7ceae117738ae425ef7689dc5e9083b254c717116fd', 1446, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (931, 146, 98, 'qblock_pdf', '{"option_a": "Create an IAM user with an IAM policy that allows the sqs:SendMessage permission, the sqsReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues. Embed the IAM user''s credentials in the application’s configuration.", "option_b": "Create an IAM user with an IAM policy that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues. Export the IAM user''s access key and secret access key as environment variables on the EC2 instance.", "option_c": "Create and associate an IAM role that allows EC2 instances to call AWS services. Attach an IAM policy to the role that allows sqs:* permissions to the appropriate queues.", "option_d": "Create and associate an IAM role that allows EC2 instances to call AWS services. Attach an IAM policy to the role that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The most secure approach is to use an IAM role for EC2 (no long-lived credentials) and grant\nonly the specific SQS actions needed (send, receive, delete) on the required queues. The\ninstance automatically receives temporary credentials via the role, enforcing least privilege and\navoiding hard-coded or environment-stored access keys.", "question_text": "An Amazon EC2 instance is running an application that uses Amazon Simple Queue Service (Amazon SQS) queues. A CloudOps engineer must ensure that the application can read write, and delete messages from the SQS queues. Which solution will meet these requirements in the MOST secure manner?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0097"}', '{"tags": null, "topic": null, "options": [["A", "Create an IAM user with an IAM policy that allows the sqs:SendMessage permission, the sqsReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues. Embed the IAM user''s credentials in the application’s configuration."], ["B", "Create an IAM user with an IAM policy that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues. Export the IAM user''s access key and secret access key as environment variables on the EC2 instance."], ["C", "Create and associate an IAM role that allows EC2 instances to call AWS services. Attach an IAM policy to the role that allows sqs:* permissions to the appropriate queues."], ["D", "Create and associate an IAM role that allows EC2 instances to call AWS services. Attach an IAM policy to the role that allows the sqs:SendMessage permission, the sqs:ReceiveMessage permission, and the sqs:DeleteMessage permission to the appropriate queues."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0097"}, "reference": null, "difficulty": "medium", "explanation": "The most secure approach is to use an IAM role for EC2 (no long-lived credentials) and grant\nonly the specific SQS actions needed (send, receive, delete) on the required queues. The\ninstance automatically receives temporary credentials via the role, enforcing least privilege and\navoiding hard-coded or environment-stored access keys.", "question_text": "An Amazon EC2 instance is running an application that uses Amazon Simple Queue Service (Amazon SQS) queues. A CloudOps engineer must ensure that the application can read write, and delete messages from the SQS queues. Which solution will meet these requirements in the MOST secure manner?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'f93624c4d0adc5c77a1a2892b789e0ce72621ba56a9aa32775ece7ebb669277d', 1447, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (932, 146, 99, 'qblock_pdf', '{"option_a": "Configure AWS Key Management Service (AWS KMS) to automatically rotate the keys for the DB instance. Use RDS Proxy to handle the increases in database connections.", "option_b": "Configure AWS Key Management Service (AWS KMS) to automatically rotate the keys for the DB instance. Use RDS read replicas to handle the increases in database connections.", "option_c": "Configure AWS Secrets Manager to automatically rotate the credentials for the DB instance. Use RDS Proxy to handle the increases in database connections.", "option_d": "Configure AWS Secrets Manager to automatically rotate the credentials for the DB instance. Use RDS read replicas to handle the increases in database connections.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Secrets Manager is designed to store and automatically rotate database credentials,\nmeeting the monthly rotation requirement without code changes.\nRDS Proxy manages database connections and pools them efficiently, protecting the DB instance\nduring sudden spikes in client connections and reducing connection overhead for a write-\nintensive workload.", "question_text": "A CloudOps engineer is designing a solution for an Amazon RDS for PostgreSQL DB instance. Database credentials must be stored and rotated monthly. The applications that connect to the Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com DB instance send write-intensive traffic with variable client connections that sometimes increase significantly in a short period of time. Which solution should a CloudOps engineer choose to meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0098"}', '{"tags": null, "topic": null, "options": [["A", "Configure AWS Key Management Service (AWS KMS) to automatically rotate the keys for the DB instance. Use RDS Proxy to handle the increases in database connections."], ["B", "Configure AWS Key Management Service (AWS KMS) to automatically rotate the keys for the DB instance. Use RDS read replicas to handle the increases in database connections."], ["C", "Configure AWS Secrets Manager to automatically rotate the credentials for the DB instance. Use RDS Proxy to handle the increases in database connections."], ["D", "Configure AWS Secrets Manager to automatically rotate the credentials for the DB instance. Use RDS read replicas to handle the increases in database connections."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0098"}, "reference": null, "difficulty": "medium", "explanation": "AWS Secrets Manager is designed to store and automatically rotate database credentials,\nmeeting the monthly rotation requirement without code changes.\nRDS Proxy manages database connections and pools them efficiently, protecting the DB instance\nduring sudden spikes in client connections and reducing connection overhead for a write-\nintensive workload.", "question_text": "A CloudOps engineer is designing a solution for an Amazon RDS for PostgreSQL DB instance. Database credentials must be stored and rotated monthly. The applications that connect to the Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com DB instance send write-intensive traffic with variable client connections that sometimes increase significantly in a short period of time. Which solution should a CloudOps engineer choose to meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '288c2194e5b657856e8100fc399b1527ff2fa5a319d25e967314f09f7dc6756c', 1448, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (933, 146, 100, 'qblock_pdf', '{"option_a": "Create an Amazon Route 53 private hosted zone. Populate the zone with the hostnames and IP addresses of the hosts in the on-premises data center.", "option_b": "Create an Amazon Route 53 Resolver outbound endpoint. Add the IP addresses of an on- premises DNS server for the domain names that need to be forwarded.", "option_c": "Set up a forwarding rule for reverse DNS queries in Amazon Route 53 Resolver. Set the enableDnsHostnames attribute to true for the VPC.", "option_d": "Add the hostnames and IP addresses for the on-premises hosts to the /etc/hosts file of each EC2 instance.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The Route 53 Resolver outbound endpoint enables DNS queries from resources in a VPC to be\nforwarded to on-premises DNS servers over an existing AWS Direct Connect or VPN connection.\nBy creating forwarding rules that specify which domains should be resolved through the on-\npremises DNS servers, EC2 instances in the VPC can seamlessly resolve internal hostnames\nwithout manual configuration or ongoing maintenance. This is the most scalable and low-\nmaintenance solution.", "question_text": "A company operates compute resources in a VPC and in the company’s on-premises data center. The company already has an AWS Direct Connect connection between the VPC and the on-premises data center. A CloudOps engineer needs to ensure that Amazon EC2 instances in the VPC can resolve DNS names for hosts in the on-premises data center. Which solution will meet this requirement with the LEAST amount of ongoing maintenance?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0099"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon Route 53 private hosted zone. Populate the zone with the hostnames and IP addresses of the hosts in the on-premises data center."], ["B", "Create an Amazon Route 53 Resolver outbound endpoint. Add the IP addresses of an on- premises DNS server for the domain names that need to be forwarded."], ["C", "Set up a forwarding rule for reverse DNS queries in Amazon Route 53 Resolver. Set the enableDnsHostnames attribute to true for the VPC."], ["D", "Add the hostnames and IP addresses for the on-premises hosts to the /etc/hosts file of each EC2 instance."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0099"}, "reference": null, "difficulty": "medium", "explanation": "The Route 53 Resolver outbound endpoint enables DNS queries from resources in a VPC to be\nforwarded to on-premises DNS servers over an existing AWS Direct Connect or VPN connection.\nBy creating forwarding rules that specify which domains should be resolved through the on-\npremises DNS servers, EC2 instances in the VPC can seamlessly resolve internal hostnames\nwithout manual configuration or ongoing maintenance. This is the most scalable and low-\nmaintenance solution.", "question_text": "A company operates compute resources in a VPC and in the company’s on-premises data center. The company already has an AWS Direct Connect connection between the VPC and the on-premises data center. A CloudOps engineer needs to ensure that Amazon EC2 instances in the VPC can resolve DNS names for hosts in the on-premises data center. Which solution will meet this requirement with the LEAST amount of ongoing maintenance?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '77c1bf69fd3e936049ffd39adfd029d938adc7b6ec7c6404139f1da32a7d5b11', 1449, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (934, 146, 101, 'qblock_pdf', '{"option_a": "Create a CloudWatch Logs metric filter that counts the number of times that the web server returns an HTTP 404 response.", "option_b": "Create a CloudWatch Logs subscription filter that counts the number of times that the web server returns an HTTP 404 response.", "option_c": "Create an AWS Lambda function that runs a CloudWatch Logs Insights query that counts the number of 404 codes in the log events during the past hour.", "option_d": "Create a script that runs a CloudWatch Logs Insights query that counts the number of 404 codes in the log events during the past hour.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "A CloudWatch Logs metric filter can automatically scan log events in real time and extract\nspecific patterns - such as HTTP 404 response codes - to publish custom metrics. This provides\ncontinuous, automated monitoring without the need for scheduled queries or external scripts,\nmaking it the most operationally efficient and scalable solution.", "question_text": "A company hosts a web application on an Amazon EC2 instance. The web server logs are published to Amazon CloudWatch Logs. The log events have the same structure and include the HTTP response codes that are associated with the user requests. The company needs to monitor Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com the number of times that the web server returns an HTTP 404 response. What is the MOST operationally efficient solution that meets these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0100"}', '{"tags": null, "topic": null, "options": [["A", "Create a CloudWatch Logs metric filter that counts the number of times that the web server returns an HTTP 404 response."], ["B", "Create a CloudWatch Logs subscription filter that counts the number of times that the web server returns an HTTP 404 response."], ["C", "Create an AWS Lambda function that runs a CloudWatch Logs Insights query that counts the number of 404 codes in the log events during the past hour."], ["D", "Create a script that runs a CloudWatch Logs Insights query that counts the number of 404 codes in the log events during the past hour."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0100"}, "reference": null, "difficulty": "medium", "explanation": "A CloudWatch Logs metric filter can automatically scan log events in real time and extract\nspecific patterns - such as HTTP 404 response codes - to publish custom metrics. This provides\ncontinuous, automated monitoring without the need for scheduled queries or external scripts,\nmaking it the most operationally efficient and scalable solution.", "question_text": "A company hosts a web application on an Amazon EC2 instance. The web server logs are published to Amazon CloudWatch Logs. The log events have the same structure and include the HTTP response codes that are associated with the user requests. The company needs to monitor Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com the number of times that the web server returns an HTTP 404 response. What is the MOST operationally efficient solution that meets these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '1d614ed48c1880964ca03319aa9bd6043caa678b44b6ffa1b681e995a755532b', 1450, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (935, 146, 102, 'qblock_pdf', '{"option_a": "Increase the maximum number of instances in the Auto Scaling group to meet the capacity that is required at peak usage.", "option_b": "Increase the minimum number of instances in the Auto Scaling group to meet the capacity that is required at peak usage.", "option_c": "Update the Auto Scaling group to launch new instances in a second Availability Zone in the same AWS Region.", "option_d": "Update the Auto Scaling group to launch new instances in an Availability Zone in a second AWS Region.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "High availability within AWS is achieved by distributing resources across multiple Availability\nZones in the same Region. By updating the Auto Scaling group to span at least two Availability\nZones, the application can continue serving traffic even if one zone becomes unavailable. This\nconfiguration works seamlessly with the Application Load Balancer, which automatically routes\ntraffic only to healthy instances across those zones.", "question_text": "A company has an internal web application that runs on Amazon EC2 instances behind an Application Load Balancer. The instances run in an Amazon EC2 Auto Scaling group in a single Availability Zone. A CloudOps engineer must make the application highly available. Which action should the CloudOps engineer take to meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0101"}', '{"tags": null, "topic": null, "options": [["A", "Increase the maximum number of instances in the Auto Scaling group to meet the capacity that is required at peak usage."], ["B", "Increase the minimum number of instances in the Auto Scaling group to meet the capacity that is required at peak usage."], ["C", "Update the Auto Scaling group to launch new instances in a second Availability Zone in the same AWS Region."], ["D", "Update the Auto Scaling group to launch new instances in an Availability Zone in a second AWS Region."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0101"}, "reference": null, "difficulty": "medium", "explanation": "High availability within AWS is achieved by distributing resources across multiple Availability\nZones in the same Region. By updating the Auto Scaling group to span at least two Availability\nZones, the application can continue serving traffic even if one zone becomes unavailable. This\nconfiguration works seamlessly with the Application Load Balancer, which automatically routes\ntraffic only to healthy instances across those zones.", "question_text": "A company has an internal web application that runs on Amazon EC2 instances behind an Application Load Balancer. The instances run in an Amazon EC2 Auto Scaling group in a single Availability Zone. A CloudOps engineer must make the application highly available. Which action should the CloudOps engineer take to meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '4db8e144c1029598636eef00b1bd4f7fa99775ffc47724d4c9b7efb4e82c0b19', 1451, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (936, 146, 103, 'qblock_pdf', '{"option_a": "The CloudOps engineer did not create an outbound rule that allows ephemeral port return traffic in the new network ACL.", "option_b": "The CloudOps engineer did not create an outbound rule in the security group that allows HTTP traffic from port 80.", "option_c": "The Elastic IP address assigned to the EC2 instance has changed.", "option_d": "There is an additional network ACL associated with the subnet that includes a rule that denies inbound HTTP traffic from port 80.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Network ACLs are stateless, meaning that return traffic for allowed inbound connections must be\nexplicitly permitted by outbound rules. Although the inbound rule allows HTTP (port 80) from\n0.0.0.0/0, if the outbound rule does not allow ephemeral ports (typically 1024–65535), return\ntraffic from the web server to clients will be blocked, preventing users from accessing the website.", "question_text": "A CloudOps engineer is creating a simple, public-facing website running on Amazon EC2. The CloudOps engineer created the EC2 instance in an existing public subnet and assigned an Elastic IP address to the instance. Next, the CloudOps engineer created and applied a new security group to the instance to allow incoming HTTP traffic from 0.0.0.0/0. Finally, the CloudOps engineer created a new network ACL and applied it to the subnet to allow incoming HTTP traffic from 0.0.0.0/0. However, the website cannot be reached from the internet. What is the cause of this issue? Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0102"}', '{"tags": null, "topic": null, "options": [["A", "The CloudOps engineer did not create an outbound rule that allows ephemeral port return traffic in the new network ACL."], ["B", "The CloudOps engineer did not create an outbound rule in the security group that allows HTTP traffic from port 80."], ["C", "The Elastic IP address assigned to the EC2 instance has changed."], ["D", "There is an additional network ACL associated with the subnet that includes a rule that denies inbound HTTP traffic from port 80."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0102"}, "reference": null, "difficulty": "medium", "explanation": "Network ACLs are stateless, meaning that return traffic for allowed inbound connections must be\nexplicitly permitted by outbound rules. Although the inbound rule allows HTTP (port 80) from\n0.0.0.0/0, if the outbound rule does not allow ephemeral ports (typically 1024–65535), return\ntraffic from the web server to clients will be blocked, preventing users from accessing the website.", "question_text": "A CloudOps engineer is creating a simple, public-facing website running on Amazon EC2. The CloudOps engineer created the EC2 instance in an existing public subnet and assigned an Elastic IP address to the instance. Next, the CloudOps engineer created and applied a new security group to the instance to allow incoming HTTP traffic from 0.0.0.0/0. Finally, the CloudOps engineer created a new network ACL and applied it to the subnet to allow incoming HTTP traffic from 0.0.0.0/0. However, the website cannot be reached from the internet. What is the cause of this issue? Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'bed2b02ef6c695f0f3c28c8cdcedaa5ebeb28ac0fd188b4ab1d1daa46c504383', 1452, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (937, 146, 104, 'qblock_pdf', '{"option_a": "Replace the NAT gateway with a NAT instance that is deployed in the public subnet. Update the private subnet''s route table to use the NAT instance.", "option_b": "Create a VPC endpoint for Systems Manager. Remove routes to the internet through the NAT gateway from the private subnet''s route table.", "option_c": "Attach the AmazonSSMManagedInstanceCore AWS managed policy to the EC2 instance profile that is associated with the instances.", "option_d": "Attach a custom policy that allows all actions to ssm* to the EC2 instance profile that is associated with the instances.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "For EC2 instances to register and appear in AWS Systems Manager (Fleet Manager, Run\nCommand, Patch Manager, etc.), the instance’s IAM instance profile must have the correct\npermissions. The recommended least-privilege policy is AmazonSSMManagedInstanceCore,\nwhich grants SSM Agent the necessary access to Systems Manager, AWS Identity and Access\nManagement, and (optionally) CloudWatch Logs. Without this policy, the agent cannot register\nthe instance, even if network connectivity through a NAT gateway is present.", "question_text": "A company wants to use AWS Systems Manager to manage a large fleet of Amazon EC2 instances. The company hosts the instances in private subnets. The company follows the principle of least privilege to assign access permissions. All private subnets have internet connectivity through a NAT gateway. A CloudOps engineer installs the latest version of the Systems Manager Agent (SSM Agent). However, the EC2 instances do not appear in Systems Manager Fleet Manager. The CloudOps engineer must resolve this issue. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0103"}', '{"tags": null, "topic": null, "options": [["A", "Replace the NAT gateway with a NAT instance that is deployed in the public subnet. Update the private subnet''s route table to use the NAT instance."], ["B", "Create a VPC endpoint for Systems Manager. Remove routes to the internet through the NAT gateway from the private subnet''s route table."], ["C", "Attach the AmazonSSMManagedInstanceCore AWS managed policy to the EC2 instance profile that is associated with the instances."], ["D", "Attach a custom policy that allows all actions to ssm* to the EC2 instance profile that is associated with the instances."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0103"}, "reference": null, "difficulty": "medium", "explanation": "For EC2 instances to register and appear in AWS Systems Manager (Fleet Manager, Run\nCommand, Patch Manager, etc.), the instance’s IAM instance profile must have the correct\npermissions. The recommended least-privilege policy is AmazonSSMManagedInstanceCore,\nwhich grants SSM Agent the necessary access to Systems Manager, AWS Identity and Access\nManagement, and (optionally) CloudWatch Logs. Without this policy, the agent cannot register\nthe instance, even if network connectivity through a NAT gateway is present.", "question_text": "A company wants to use AWS Systems Manager to manage a large fleet of Amazon EC2 instances. The company hosts the instances in private subnets. The company follows the principle of least privilege to assign access permissions. All private subnets have internet connectivity through a NAT gateway. A CloudOps engineer installs the latest version of the Systems Manager Agent (SSM Agent). However, the EC2 instances do not appear in Systems Manager Fleet Manager. The CloudOps engineer must resolve this issue. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'f1efe4b7a70c414e98344468351bca34305141ad11e831d81f1fd73e945baaa8', 1453, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (938, 146, 105, 'qblock_pdf', '{"option_a": "Adjust the Auto Scaling group to scale faster when a high number of messages is in the queue.", "option_b": "Use the Amazon Simple Notification Service (Amazon SNS) fanout feature with Amazon SQS to send the notifications in parallel to all the EC2 instances.", "option_c": "Add an Amazon DynamoDB stream to accelerate the message processing.", "option_d": "Create a queue for alarm notifications and a queue for information notifications. Update the application to collect messages from the alarm notifications queue first.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "By separating alarm and information notifications into two SQS queues, the application can\nalways poll and process the alarm queue first, ensuring high-priority alarm messages are handled\nbefore lower-priority informational ones. This achieves true prioritization with minimal architectural\nchange and without relying on scaling behavior or unrelated services.", "question_text": "A company has an application that collects notifications from thousands of alarm systems. The notifications include alarm notifications and information notifications. The information notifications include the system arming processes, disarming processes, and sensor status. All notifications are kept as messages in an Amazon Simple Queue Service (Amazon SQS) queue. Amazon EC2 instances that are in an Auto Scaling group process the messages. A Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com CloudOps engineer needs to implement a solution that prioritizes alarm notifications over information notifications. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0104"}', '{"tags": null, "topic": null, "options": [["A", "Adjust the Auto Scaling group to scale faster when a high number of messages is in the queue."], ["B", "Use the Amazon Simple Notification Service (Amazon SNS) fanout feature with Amazon SQS to send the notifications in parallel to all the EC2 instances."], ["C", "Add an Amazon DynamoDB stream to accelerate the message processing."], ["D", "Create a queue for alarm notifications and a queue for information notifications. Update the application to collect messages from the alarm notifications queue first."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0104"}, "reference": null, "difficulty": "medium", "explanation": "By separating alarm and information notifications into two SQS queues, the application can\nalways poll and process the alarm queue first, ensuring high-priority alarm messages are handled\nbefore lower-priority informational ones. This achieves true prioritization with minimal architectural\nchange and without relying on scaling behavior or unrelated services.", "question_text": "A company has an application that collects notifications from thousands of alarm systems. The notifications include alarm notifications and information notifications. The information notifications include the system arming processes, disarming processes, and sensor status. All notifications are kept as messages in an Amazon Simple Queue Service (Amazon SQS) queue. Amazon EC2 instances that are in an Auto Scaling group process the messages. A Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com CloudOps engineer needs to implement a solution that prioritizes alarm notifications over information notifications. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '48a84385b27fb7b9b3c59d266bf74b714f8b8e232c1c45691ce435f09d29d5f8', 1454, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (939, 146, 106, 'qblock_pdf', '{"option_a": "Whether at least ono Amazon EC2 instance is in the running state", "option_b": "The AWS Support plan", "option_c": "An AWS Organizations service control policy (SCP)", "option_d": "Whether the AWS account root user has multi-factor authentication (MFA) enabled", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The number and depth of Trusted Advisor checks available depend on the AWS Support plan\nlevel.\nBasic and Developer Support plans only provide a limited set of checks (mainly Service Limits\nand Security).\nBusiness and Enterprise Support plans provide access to the full set of Trusted Advisor checks,\nincluding cost optimization, performance, and fault tolerance.", "question_text": "A company is implementing security and compliance by using AWS Trusted Advisor. The company’s CloudOps team is validating the list of Trusted Advisor checks that it can access. Which factor will affect the quantity of available Trusted Advisor checks?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0105"}', '{"tags": null, "topic": null, "options": [["A", "Whether at least ono Amazon EC2 instance is in the running state"], ["B", "The AWS Support plan"], ["C", "An AWS Organizations service control policy (SCP)"], ["D", "Whether the AWS account root user has multi-factor authentication (MFA) enabled"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0105"}, "reference": null, "difficulty": "medium", "explanation": "The number and depth of Trusted Advisor checks available depend on the AWS Support plan\nlevel.\nBasic and Developer Support plans only provide a limited set of checks (mainly Service Limits\nand Security).\nBusiness and Enterprise Support plans provide access to the full set of Trusted Advisor checks,\nincluding cost optimization, performance, and fault tolerance.", "question_text": "A company is implementing security and compliance by using AWS Trusted Advisor. The company’s CloudOps team is validating the list of Trusted Advisor checks that it can access. Which factor will affect the quantity of available Trusted Advisor checks?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '4aa2f76a60a3b910134fa08f117dc67a2b832fdd4f7a3e1e0d5fc2964c7ef73b', 1455, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (940, 146, 107, 'qblock_pdf', '{"option_a": "Assume the OrganizationAccountAccessRole IAM role from the management account. Deploy the template in each of the accounts.", "option_b": "Create an AWS Lambda function to assume a role in each account. Deploy the template by using the AWS CloudFormation CreateStack API call. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_c": "Create an AWS Lambda function to query for a list of accounts. Deploy the template by using the AWS CloudFormation CreateStack API call.", "option_d": "Use AWS CloudFormation StackSets from the management account to deploy the template in each of the accounts.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS CloudFormation StackSets is purpose-built for deploying CloudFormation templates across\nmultiple AWS accounts and Regions from a central management account. When integrated with\nAWS Organizations, StackSets automatically handles account targeting and stack\nsynchronization with minimal manual effort, providing the lowest operational overhead compared\nto scripting or manual deployment approaches.", "question_text": "A CloudOps engineer has successfully deployed a VPC with an AWS CloudFormation template The CloudOps engineer wants to deploy the same template across multiple accounts that are managed through AWS Organizations. Which solution will meet this requirement with the LEAST operational overhead?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0106"}', '{"tags": null, "topic": null, "options": [["A", "Assume the OrganizationAccountAccessRole IAM role from the management account. Deploy the template in each of the accounts."], ["B", "Create an AWS Lambda function to assume a role in each account. Deploy the template by using the AWS CloudFormation CreateStack API call. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["C", "Create an AWS Lambda function to query for a list of accounts. Deploy the template by using the AWS CloudFormation CreateStack API call."], ["D", "Use AWS CloudFormation StackSets from the management account to deploy the template in each of the accounts."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0106"}, "reference": null, "difficulty": "medium", "explanation": "AWS CloudFormation StackSets is purpose-built for deploying CloudFormation templates across\nmultiple AWS accounts and Regions from a central management account. When integrated with\nAWS Organizations, StackSets automatically handles account targeting and stack\nsynchronization with minimal manual effort, providing the lowest operational overhead compared\nto scripting or manual deployment approaches.", "question_text": "A CloudOps engineer has successfully deployed a VPC with an AWS CloudFormation template The CloudOps engineer wants to deploy the same template across multiple accounts that are managed through AWS Organizations. Which solution will meet this requirement with the LEAST operational overhead?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '16afd65535e25f4ab322056b04b3bf5199743cfb7b336722d57fb900df3570b5', 1456, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (941, 146, 108, 'qblock_pdf', '{"option_a": "A record", "option_b": "Alias record", "option_c": "CNAME record", "option_d": "Pointer (PTR) record", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "A CNAME (Canonical Name) record maps one domain name (e.g., www.company.com) to\nanother domain name (e.g., app.example.com). This allows users to access the application using\nthe company’s custom domain while DNS resolution automatically points to the external\nhostname. Alias records are used for AWS resources like CloudFront or ELB, not external\ndomains.", "question_text": "A company''s application is hosted by an internet provider at app.example.com. The company wants to access the application by using www.company.com, which the company owns and manages with Amazon Route 53. Which Route 53 record should be created to address this?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0107"}', '{"tags": null, "topic": null, "options": [["A", "A record"], ["B", "Alias record"], ["C", "CNAME record"], ["D", "Pointer (PTR) record"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0107"}, "reference": null, "difficulty": "medium", "explanation": "A CNAME (Canonical Name) record maps one domain name (e.g., www.company.com) to\nanother domain name (e.g., app.example.com). This allows users to access the application using\nthe company’s custom domain while DNS resolution automatically points to the external\nhostname. Alias records are used for AWS resources like CloudFront or ELB, not external\ndomains.", "question_text": "A company''s application is hosted by an internet provider at app.example.com. The company wants to access the application by using www.company.com, which the company owns and manages with Amazon Route 53. Which Route 53 record should be created to address this?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '7a397f36bcbd4bea25940fa7cb7a975de9e19a60981b85692abb09f6e70a09db', 1457, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (943, 146, 110, 'qblock_pdf', '{"option_a": "Configure CloudTrail to send email notifications to the CloudOps engineer when CloudTrail detects changes to the IAM policies.", "option_b": "Create an Amazon EventBridge rule to invoke an AWS Lambda function to check the CloudFormation stack for drift. Configure the function to use Amazon Simple Notification Service (Amazon SNS) to notify the CloudOps engineer if the function detects any drift.", "option_c": "Use AWS Identity and Access Management Access Analyzer to generate a policy based on CloudTrail activity for the IAM role that is attached to the IAM policies in the production account. Compare the results to the IAM policies that are in the sandbox account. Send a notification to the CloudOps engineer if the policies are different.", "option_d": "Store the IAM policies as a JSON document in an Amazon S3 bucket. Use an AWS Lambda function to periodically compare the IAM policies with the JSON document that is stored in the S3 bucket.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "CloudFormation drift detection is designed to detect any configuration changes made outside\nCloudFormation (such as manual edits to IAM policies). By wiring CloudTrail → EventBridge →\nLambda → Drift Detection → SNS, you automatically trigger drift checks when relevant changes\noccur and notify the CloudOps engineer if the actual IAM policies differ from the CloudFormation\ntemplate. This leverages managed services and avoids building your own comparison logic,\nproviding the least administrative effort among the options.", "question_text": "A company has multiple AWS accounts. A CloudOps engineer uses a sandbox account to create and verify IAM policies for use in a production account. The CloudOps engineer uses AWS CloudFormation to deploy policies to the sandbox account for testing. When tests pass, the CloudOps engineer deploys the policies to production. The CloudOps engineer has configured AWS CloudTrail in both the sandbox account and the production account. The CloudOps engineer wants to detect any changes to the IAM policies after the policies have been deployed by CloudFormation. The CloudOps engineer must receive notifications for any changes to the policies. Which solution will meet these requirements with the LEAST administrative effort?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0109"}', '{"tags": null, "topic": null, "options": [["A", "Configure CloudTrail to send email notifications to the CloudOps engineer when CloudTrail detects changes to the IAM policies."], ["B", "Create an Amazon EventBridge rule to invoke an AWS Lambda function to check the CloudFormation stack for drift. Configure the function to use Amazon Simple Notification Service (Amazon SNS) to notify the CloudOps engineer if the function detects any drift."], ["C", "Use AWS Identity and Access Management Access Analyzer to generate a policy based on CloudTrail activity for the IAM role that is attached to the IAM policies in the production account. Compare the results to the IAM policies that are in the sandbox account. Send a notification to the CloudOps engineer if the policies are different."], ["D", "Store the IAM policies as a JSON document in an Amazon S3 bucket. Use an AWS Lambda function to periodically compare the IAM policies with the JSON document that is stored in the S3 bucket."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0109"}, "reference": null, "difficulty": "medium", "explanation": "CloudFormation drift detection is designed to detect any configuration changes made outside\nCloudFormation (such as manual edits to IAM policies). By wiring CloudTrail → EventBridge →\nLambda → Drift Detection → SNS, you automatically trigger drift checks when relevant changes\noccur and notify the CloudOps engineer if the actual IAM policies differ from the CloudFormation\ntemplate. This leverages managed services and avoids building your own comparison logic,\nproviding the least administrative effort among the options.", "question_text": "A company has multiple AWS accounts. A CloudOps engineer uses a sandbox account to create and verify IAM policies for use in a production account. The CloudOps engineer uses AWS CloudFormation to deploy policies to the sandbox account for testing. When tests pass, the CloudOps engineer deploys the policies to production. The CloudOps engineer has configured AWS CloudTrail in both the sandbox account and the production account. The CloudOps engineer wants to detect any changes to the IAM policies after the policies have been deployed by CloudFormation. The CloudOps engineer must receive notifications for any changes to the policies. Which solution will meet these requirements with the LEAST administrative effort?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '3d601e0a721f10c61d66ffceb835873543ac712ae85e520cd36a04324a49f294', 1458, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (944, 146, 111, 'qblock_pdf', '{"option_a": "Create an interface VPC endpoint for QuickSight. Configure the endpoint to connect to QuickSight within the VPC by using AWS PrivateLink. Create a manifest file that points to the S3 data. Grant QuickSight permission to access the S3 bucket.", "option_b": "Set up a VPC endpoint for QuickSight. Use an Amazon EC2 instance as a proxy to establish a direct connection between the VPC and QuickSight. Create a manifest file that points to the S3 data. Store the manifest on the EC2 instance. Grant QuickSight permission to access the EC2 instance.", "option_c": "Configure an Amazon S3 VPC gateway endpoint. Route all data from QuickSight through the endpoint to transfer data. Grant QuickSight permission to access the S3 bucket. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_d": "Configure a NAT gateway in the company’s VPC. Route all data from QuickSight through the NAT gateway to transfer data. Grant QuickSight permission to access the S3 bucket.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "To keep all QuickSight traffic and data access within the VPC boundary, you must use an\ninterface VPC endpoint for QuickSight via AWS PrivateLink. This provides a private connection\nfrom your VPC to the QuickSight service without traversing the public internet. Then QuickSight\ncan read data from S3 (referenced via a manifest file) while staying within the VPC path, as long\nas the proper S3 permissions are granted.", "question_text": "A finance company stores confidential data in an Amazon S3 bucket. The company uses Amazon QuickSight to analyze the data and create dashboard reports. The company requires that all data access and connections to QuickSight remain within the company''s VPC network boundary. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0110"}', '{"tags": null, "topic": null, "options": [["A", "Create an interface VPC endpoint for QuickSight. Configure the endpoint to connect to QuickSight within the VPC by using AWS PrivateLink. Create a manifest file that points to the S3 data. Grant QuickSight permission to access the S3 bucket."], ["B", "Set up a VPC endpoint for QuickSight. Use an Amazon EC2 instance as a proxy to establish a direct connection between the VPC and QuickSight. Create a manifest file that points to the S3 data. Store the manifest on the EC2 instance. Grant QuickSight permission to access the EC2 instance."], ["C", "Configure an Amazon S3 VPC gateway endpoint. Route all data from QuickSight through the endpoint to transfer data. Grant QuickSight permission to access the S3 bucket. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["D", "Configure a NAT gateway in the company’s VPC. Route all data from QuickSight through the NAT gateway to transfer data. Grant QuickSight permission to access the S3 bucket."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0110"}, "reference": null, "difficulty": "medium", "explanation": "To keep all QuickSight traffic and data access within the VPC boundary, you must use an\ninterface VPC endpoint for QuickSight via AWS PrivateLink. This provides a private connection\nfrom your VPC to the QuickSight service without traversing the public internet. Then QuickSight\ncan read data from S3 (referenced via a manifest file) while staying within the VPC path, as long\nas the proper S3 permissions are granted.", "question_text": "A finance company stores confidential data in an Amazon S3 bucket. The company uses Amazon QuickSight to analyze the data and create dashboard reports. The company requires that all data access and connections to QuickSight remain within the company''s VPC network boundary. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'f7ed341255e2544f346ec1f7c997b925292ad1d369262982a33bdf171fafad48', 1459, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (945, 146, 112, 'qblock_pdf', '{"option_a": "Create a single AWS Storage Gateway file gateway.", "option_b": "Create an Amazon FSx for Windows File Server Multi-AZ file system.", "option_c": "Deploy two AWS Storage Gateway file gateways across two Availability Zones. Configure an Application Load Balancer in front", "option_d": "Deploy two Amazon FSx for Windows File Server Single-AZ 2 file systems Configure Microsoft Distributed File System Replication (DFSR).", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Amazon FSx for Windows File Server is a fully managed Windows file system that supports SMB\nand Windows ACLs natively. The Multi-AZ deployment option provides built-in high availability\nacross two Availability Zones, with automatic failover during AZ outages or maintenance,\nensuring continuous access to the file share without additional custom replication or load\nbalancing.", "question_text": "A company is migrating its production file server to AWS. All data that is stored on the file server must remain accessible if an Availability Zone becomes unavailable or when system maintenance is performed. Users must be able to interact with the file server through the SMB protocol Users also must have the ability to manage file permissions by using Windows ACLs. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0111"}', '{"tags": null, "topic": null, "options": [["A", "Create a single AWS Storage Gateway file gateway."], ["B", "Create an Amazon FSx for Windows File Server Multi-AZ file system."], ["C", "Deploy two AWS Storage Gateway file gateways across two Availability Zones. Configure an Application Load Balancer in front"], ["D", "Deploy two Amazon FSx for Windows File Server Single-AZ 2 file systems Configure Microsoft Distributed File System Replication (DFSR)."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0111"}, "reference": null, "difficulty": "medium", "explanation": "Amazon FSx for Windows File Server is a fully managed Windows file system that supports SMB\nand Windows ACLs natively. The Multi-AZ deployment option provides built-in high availability\nacross two Availability Zones, with automatic failover during AZ outages or maintenance,\nensuring continuous access to the file share without additional custom replication or load\nbalancing.", "question_text": "A company is migrating its production file server to AWS. All data that is stored on the file server must remain accessible if an Availability Zone becomes unavailable or when system maintenance is performed. Users must be able to interact with the file server through the SMB protocol Users also must have the ability to manage file permissions by using Windows ACLs. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '14b8ce1d9e61f590f4663fb039f89a3a31274c88f53eb7a5cc6b9cf54a4d52c8', 1460, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (946, 146, 113, 'qblock_pdf', '{"option_a": "Configure the Amazon CloudWatch agent procstat plugin to capture CPU process metrics.", "option_b": "Configure an AWS Lambda function to run every minute to capture the PID and send a notification.", "option_c": "Log in to the EC2 instance by using a .pem key each night. Then run the top command.", "option_d": "Use the default Amazon CloudWatch CPU utilization metric to capture the PID in CloudWatch.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The CloudWatch agent procstat plugin can be configured to automatically collect detailed per-\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nprocess CPU utilization metrics, including process IDs (PIDs), with minimal setup effort. This\neliminates the need for manual monitoring or custom scripts, and integrates directly with\nCloudWatch for visualization, alerting, and analysis - making it the most efficient and scalable\nsolution.", "question_text": "A company has a web application that is experiencing performance problems many times each night. A root cause analysis reveals sudden increases in CPU utilization that last 5 minutes on an Amazon EC2 Linux instance. A CloudOps engineer must find the process ID (PID) of the service or process that is consuming more CPU. What should the CloudOps engineer do to collect the process utilization information with the LEAST amount of effort?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0112"}', '{"tags": null, "topic": null, "options": [["A", "Configure the Amazon CloudWatch agent procstat plugin to capture CPU process metrics."], ["B", "Configure an AWS Lambda function to run every minute to capture the PID and send a notification."], ["C", "Log in to the EC2 instance by using a .pem key each night. Then run the top command."], ["D", "Use the default Amazon CloudWatch CPU utilization metric to capture the PID in CloudWatch."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0112"}, "reference": null, "difficulty": "medium", "explanation": "The CloudWatch agent procstat plugin can be configured to automatically collect detailed per-\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nprocess CPU utilization metrics, including process IDs (PIDs), with minimal setup effort. This\neliminates the need for manual monitoring or custom scripts, and integrates directly with\nCloudWatch for visualization, alerting, and analysis - making it the most efficient and scalable\nsolution.", "question_text": "A company has a web application that is experiencing performance problems many times each night. A root cause analysis reveals sudden increases in CPU utilization that last 5 minutes on an Amazon EC2 Linux instance. A CloudOps engineer must find the process ID (PID) of the service or process that is consuming more CPU. What should the CloudOps engineer do to collect the process utilization information with the LEAST amount of effort?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '76760369aab8617bba766de22911703f092a5f8145fe8c3f4c094832196ca054', 1461, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (947, 146, 114, 'qblock_pdf', '{"option_a": "Create an Amazon CloudWatch alarm that is based on the website’s logs that are published to a CloudWatch Logs log group. Configure the alarm to publish an SNS notification if the number of HTTP 4xx errors and 5xx errors exceeds a specified threshold.", "option_b": "Create an Amazon CloudWatch alarm that is based on the website''s published metrics in CloudWatch. Configure the alarm to publish an SNS notification that is based on anomaly detection.", "option_c": "Create an Amazon CloudWatch Synthetics heartbeat monitoring canary. Associate the canary with the website''s URL for end users. Create a CloudWatch alarm for the canary. Configure the alarm to publish an SNS notification if the value of the", "option_d": "Create an Amazon CloudWatch Synthetics broken link checker monitoring canary. Associate the canary with the website''s URL for end users. Create a CloudWatch alarm for the canary. Configure the alarm to publish an SNS notification if the value of the SuccessPercent metric is less than 99%.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "CloudWatch Synthetics heartbeat canaries simulate real user traffic to continuously monitor\nwebsite availability and performance from an end-user perspective. By setting a CloudWatch\nalarm on the SuccessPercent metric and configuring it to send SNS notifications when uptime\nfalls below 99%, the company gains accurate, automated monitoring of actual user experience\nwith minimal operational effort.", "question_text": "A company needs to monitor its website''s availability to end users. The company needs a solution to provide an Amazon Simple Notification Service (Amazon SNS) notification if the website''s uptime decreases to less than 99%. The monitoring must provide an accurate view of the user experience on the website. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0113"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon CloudWatch alarm that is based on the website’s logs that are published to a CloudWatch Logs log group. Configure the alarm to publish an SNS notification if the number of HTTP 4xx errors and 5xx errors exceeds a specified threshold."], ["B", "Create an Amazon CloudWatch alarm that is based on the website''s published metrics in CloudWatch. Configure the alarm to publish an SNS notification that is based on anomaly detection."], ["C", "Create an Amazon CloudWatch Synthetics heartbeat monitoring canary. Associate the canary with the website''s URL for end users. Create a CloudWatch alarm for the canary. Configure the alarm to publish an SNS notification if the value of the"], ["D", "Create an Amazon CloudWatch Synthetics broken link checker monitoring canary. Associate the canary with the website''s URL for end users. Create a CloudWatch alarm for the canary. Configure the alarm to publish an SNS notification if the value of the SuccessPercent metric is less than 99%."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0113"}, "reference": null, "difficulty": "medium", "explanation": "CloudWatch Synthetics heartbeat canaries simulate real user traffic to continuously monitor\nwebsite availability and performance from an end-user perspective. By setting a CloudWatch\nalarm on the SuccessPercent metric and configuring it to send SNS notifications when uptime\nfalls below 99%, the company gains accurate, automated monitoring of actual user experience\nwith minimal operational effort.", "question_text": "A company needs to monitor its website''s availability to end users. The company needs a solution to provide an Amazon Simple Notification Service (Amazon SNS) notification if the website''s uptime decreases to less than 99%. The monitoring must provide an accurate view of the user experience on the website. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '833d079920dbb8f06601ce5531fb1646bbc2688cac1c938fba92892569ebae8e', 1462, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (948, 146, 115, 'qblock_pdf', '{"option_a": "Replace the existing NAT gateway with a NAT instance in the same subnet.", "option_b": "Update VPC route tables to target the existing NAT gateway for internet traffic.", "option_c": "Update VPC route tables to target an internet gateway for internet traffic.", "option_d": "Add secondary IP addresses to the existing NAT gateway.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "After consolidating to a single NAT gateway, private subnets in other Availability Zones might still\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nhave routes pointing to old or deleted NAT gateways. To restore internet connectivity, the\nCloudOps engineer must update each private subnet’s route table so that 0.0.0.0/0 points to the\ncurrent NAT gateway. This ensures that all private subnets send outbound internet traffic\ncorrectly through the existing NAT gateway.", "question_text": "A company uses Amazon EC2 Auto Scaling across multiple Availability Zones. The company must ensure that EC2 instances are provisioned in private subnets. The company recently optimized its cloud infrastructure by reducing the number of NAT gateways in the company’s VPC to one. Some EC2 instances lost internet connectivity after the infrastructure update. A CloudOps engineer must resolve the connectivity issue. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0114"}', '{"tags": null, "topic": null, "options": [["A", "Replace the existing NAT gateway with a NAT instance in the same subnet."], ["B", "Update VPC route tables to target the existing NAT gateway for internet traffic."], ["C", "Update VPC route tables to target an internet gateway for internet traffic."], ["D", "Add secondary IP addresses to the existing NAT gateway."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0114"}, "reference": null, "difficulty": "medium", "explanation": "After consolidating to a single NAT gateway, private subnets in other Availability Zones might still\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nhave routes pointing to old or deleted NAT gateways. To restore internet connectivity, the\nCloudOps engineer must update each private subnet’s route table so that 0.0.0.0/0 points to the\ncurrent NAT gateway. This ensures that all private subnets send outbound internet traffic\ncorrectly through the existing NAT gateway.", "question_text": "A company uses Amazon EC2 Auto Scaling across multiple Availability Zones. The company must ensure that EC2 instances are provisioned in private subnets. The company recently optimized its cloud infrastructure by reducing the number of NAT gateways in the company’s VPC to one. Some EC2 instances lost internet connectivity after the infrastructure update. A CloudOps engineer must resolve the connectivity issue. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '22eadc1d403d7294ec05483762ad261bbce2ad2176f00322d61c3e3e8063f842', 1463, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (949, 146, 116, 'qblock_pdf', '{"option_a": "Set the DeletionPolicy attribute to Snapshot for the EC2 instance resource in the CloudFormation template.", "option_b": "Automate backups by using Amazon Data Lifecycle Manager (Amazon DLM).", "option_c": "Create a backup plan in AWS Backup.", "option_d": "Set the DeletionPolicy attribute to Retain for the EC2 instance resource in the CloudFormation template.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "In AWS CloudFormation, setting the DeletionPolicy attribute to Retain ensures that the resource\n(in this case, the EC2 instance and its associated data) is not deleted when the stack is deleted.\nThis preserves the instance and its data outside of the stack lifecycle, meeting the requirement to\nkeep everything even if the stack is removed.", "question_text": "A company uses AWS CloudFormation to manage a stack of Amazon EC2 instances on AWS. A CloudOps engineer needs to keep the instances and all of the instances’ data, even if someone deletes the stack. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0115"}', '{"tags": null, "topic": null, "options": [["A", "Set the DeletionPolicy attribute to Snapshot for the EC2 instance resource in the CloudFormation template."], ["B", "Automate backups by using Amazon Data Lifecycle Manager (Amazon DLM)."], ["C", "Create a backup plan in AWS Backup."], ["D", "Set the DeletionPolicy attribute to Retain for the EC2 instance resource in the CloudFormation template."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0115"}, "reference": null, "difficulty": "medium", "explanation": "In AWS CloudFormation, setting the DeletionPolicy attribute to Retain ensures that the resource\n(in this case, the EC2 instance and its associated data) is not deleted when the stack is deleted.\nThis preserves the instance and its data outside of the stack lifecycle, meeting the requirement to\nkeep everything even if the stack is removed.", "question_text": "A company uses AWS CloudFormation to manage a stack of Amazon EC2 instances on AWS. A CloudOps engineer needs to keep the instances and all of the instances’ data, even if someone deletes the stack. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'b2c18924ac3440ca508479b595ee95481fcd0ff8477d84e32efa9856cdb31ee2', 1464, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (950, 146, 117, 'qblock_pdf', '{"option_a": "Create a script that uses Packer. Schedule a cron job to run the script.", "option_b": "Install the application and its dependencies on an EC2 instance. Create an AMI of the EC2 instance.", "option_c": "Use EC2 Image Builder with a custom recipe to install the application and its dependencies.", "option_d": "Invoke the EC2 CreateImage API operation by using an Amazon EventBridge scheduled rule.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "EC2 Image Builder is a managed service that automates AMI creation on a schedule, including\ninstalling dependencies, applying weekly application updates, and running steps such as\nvulnerability scans as part of the image build pipeline. It provides versioning, automated builds,\nand integration with scanners via components, giving a highly automated and operationally\nefficient solution compared to manual scripts or ad hoc AMI creation.", "question_text": "A CloudOps engineer is preparing to deploy an application to Amazon EC2 instances that are in an Auto Scaling group. The application requires dependencies to be installed. Application updates are issued weekly. The CloudOps engineer needs to implement a solution to incorporate the application updates on a regular basis. The solution also must conduct a vulnerability scan during Amazon Machine Image (AMI) creation. What is the MOST operationally efficient solution that meets these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0116"}', '{"tags": null, "topic": null, "options": [["A", "Create a script that uses Packer. Schedule a cron job to run the script."], ["B", "Install the application and its dependencies on an EC2 instance. Create an AMI of the EC2 instance."], ["C", "Use EC2 Image Builder with a custom recipe to install the application and its dependencies."], ["D", "Invoke the EC2 CreateImage API operation by using an Amazon EventBridge scheduled rule."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0116"}, "reference": null, "difficulty": "medium", "explanation": "EC2 Image Builder is a managed service that automates AMI creation on a schedule, including\ninstalling dependencies, applying weekly application updates, and running steps such as\nvulnerability scans as part of the image build pipeline. It provides versioning, automated builds,\nand integration with scanners via components, giving a highly automated and operationally\nefficient solution compared to manual scripts or ad hoc AMI creation.", "question_text": "A CloudOps engineer is preparing to deploy an application to Amazon EC2 instances that are in an Auto Scaling group. The application requires dependencies to be installed. Application updates are issued weekly. The CloudOps engineer needs to implement a solution to incorporate the application updates on a regular basis. The solution also must conduct a vulnerability scan during Amazon Machine Image (AMI) creation. What is the MOST operationally efficient solution that meets these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '41d465172e7ed9b5e4f767061496b1b8779513f484355bc878714a73ff87d6e0', 1465, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (951, 146, 118, 'qblock_pdf', '{"option_a": "Amazon Simple Queue Service (Amazon SQS) queue", "option_b": "Application Load Balancer", "option_c": "AWS Global Accelerator", "option_d": "Network Load Balancer", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "A Network Load Balancer (NLB) is optimized for high performance and ultra-low latency, capable\nof handling millions of requests per second. It supports static IP addresses per Availability Zone,\nmaking it ideal for applications requiring zonal IP stability and rapid scaling to handle sudden\ntraffic surges. In contrast, Application Load Balancers don’t support static IPs directly, and other\noptions like SQS or Global Accelerator don’t provide direct traffic distribution to EC2 instances.", "question_text": "Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com A company is planning to host an application on a set of Amazon EC2 instances that are distributed across multiple Availability Zones. The application must be able to scale to millions of requests each second. A CloudOps engineer must design a solution to distribute the traffic to the EC2 instances. The solution must be optimized to handle sudden and volatile traffic patterns while using a single static IP address for each Availability Zone. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0117"}', '{"tags": null, "topic": null, "options": [["A", "Amazon Simple Queue Service (Amazon SQS) queue"], ["B", "Application Load Balancer"], ["C", "AWS Global Accelerator"], ["D", "Network Load Balancer"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0117"}, "reference": null, "difficulty": "medium", "explanation": "A Network Load Balancer (NLB) is optimized for high performance and ultra-low latency, capable\nof handling millions of requests per second. It supports static IP addresses per Availability Zone,\nmaking it ideal for applications requiring zonal IP stability and rapid scaling to handle sudden\ntraffic surges. In contrast, Application Load Balancers don’t support static IPs directly, and other\noptions like SQS or Global Accelerator don’t provide direct traffic distribution to EC2 instances.", "question_text": "Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com A company is planning to host an application on a set of Amazon EC2 instances that are distributed across multiple Availability Zones. The application must be able to scale to millions of requests each second. A CloudOps engineer must design a solution to distribute the traffic to the EC2 instances. The solution must be optimized to handle sudden and volatile traffic patterns while using a single static IP address for each Availability Zone. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'd0e3392e8556fc5ca37263683f6999e69b408ba603b13eb07f6eb4f208212773', 1466, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (952, 146, 119, 'qblock_pdf', '{"option_a": "Change to the least outstanding requests algorithm on the ALB target group.", "option_b": "Configure cookie forwarding in the CloudFront distribution cache behavior.", "option_c": "Configure header forwarding in the CloudFront distribution cache behavior.", "option_d": "Enable group-level stickiness on the ALB listener rule.", "option_e": "Enable sticky sessions on the ALB target group.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Configure cookie forwarding in the CloudFront distribution cache behavior.\nIf CloudFront is not forwarding cookies, the origin (ALB/app) will not consistently receive the\nsession cookie, causing users to appear “new” and get logged out. Forwarding cookies ensures\nthe application can maintain user sessions correctly.\nEnable sticky sessions on the ALB target group.\nThe application is stateful and stores session data on individual EC2 instances. Enabling ALB\ntarget group stickiness keeps a user’s requests going to the same instance, preventing session\nloss and random logouts as traffic shifts between instances.", "question_text": "A company has a stateful web application that is hosted on Amazon EC2 instances in an Auto Scaling group. The instances run behind an Application Load Balancer (ALB) that has a single target group. The ALB is configured as the origin in an Amazon CloudFront distribution. Users are reporting random logouts from the web application. Which combination of actions should a CloudOps engineer take to resolve this problem? (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "BE", "external_question_id": "Q0118"}', '{"tags": null, "topic": null, "options": [["A", "Change to the least outstanding requests algorithm on the ALB target group."], ["B", "Configure cookie forwarding in the CloudFront distribution cache behavior."], ["C", "Configure header forwarding in the CloudFront distribution cache behavior."], ["D", "Enable group-level stickiness on the ALB listener rule."], ["E", "Enable sticky sessions on the ALB target group."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0118"}, "reference": null, "difficulty": "medium", "explanation": "Configure cookie forwarding in the CloudFront distribution cache behavior.\nIf CloudFront is not forwarding cookies, the origin (ALB/app) will not consistently receive the\nsession cookie, causing users to appear “new” and get logged out. Forwarding cookies ensures\nthe application can maintain user sessions correctly.\nEnable sticky sessions on the ALB target group.\nThe application is stateful and stores session data on individual EC2 instances. Enabling ALB\ntarget group stickiness keeps a user’s requests going to the same instance, preventing session\nloss and random logouts as traffic shifts between instances.", "question_text": "A company has a stateful web application that is hosted on Amazon EC2 instances in an Auto Scaling group. The instances run behind an Application Load Balancer (ALB) that has a single target group. The ALB is configured as the origin in an Amazon CloudFront distribution. Users are reporting random logouts from the web application. Which combination of actions should a CloudOps engineer take to resolve this problem? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "E"]}', 'imported', NULL, NULL, '3397e2a8165928617f58c324632287a03e82fa39fcdaf2cc92d77dc6bcf3d195', 1467, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (959, 146, 126, 'qblock_pdf', '{"option_a": "Perform a CloudWatch Logs Insights query that uses the stats command and count function.", "option_b": "Perform a CloudWatch Logs search that uses the groupby keyword and count function.", "option_c": "Perform an Amazon Athena query that uses the SELECT and GROUP BV keywords.", "option_d": "Perform an Amazon RDS query that uses the SELECT and GROUP BY keywords.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "CloudWatch Logs Insights is purpose-built for querying and aggregating log data across multiple\nlog groups. Using the stats command with the count() function allows the CloudOps engineer to\nefficiently group and count specific error types from all Lambda log groups in one query, providing\nan aggregated view of application errors with minimal effort and without data export or external\ntools.", "question_text": "A company has a critical serverless application that uses multiple AWS Lambda functions. Each Lambda function generates 1 GB of log data daily in its own Amazon CloudWatch Logs log group. The company’s security team asks for a count of application errors, grouped by type, across all of the log groups. What should a CloudOps engineer do to meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0125"}', '{"tags": null, "topic": null, "options": [["A", "Perform a CloudWatch Logs Insights query that uses the stats command and count function."], ["B", "Perform a CloudWatch Logs search that uses the groupby keyword and count function."], ["C", "Perform an Amazon Athena query that uses the SELECT and GROUP BV keywords."], ["D", "Perform an Amazon RDS query that uses the SELECT and GROUP BY keywords."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0125"}, "reference": null, "difficulty": "medium", "explanation": "CloudWatch Logs Insights is purpose-built for querying and aggregating log data across multiple\nlog groups. Using the stats command with the count() function allows the CloudOps engineer to\nefficiently group and count specific error types from all Lambda log groups in one query, providing\nan aggregated view of application errors with minimal effort and without data export or external\ntools.", "question_text": "A company has a critical serverless application that uses multiple AWS Lambda functions. Each Lambda function generates 1 GB of log data daily in its own Amazon CloudWatch Logs log group. The company’s security team asks for a count of application errors, grouped by type, across all of the log groups. What should a CloudOps engineer do to meet this requirement?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'ad9bb5d820c4de39ae52743211b07601bf3386f5dc9fc552e4dac8691a231432', 1474, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (953, 146, 120, 'qblock_pdf', '{"option_a": "Create a transit gateway in the central shared AWS account. Share the transit gateway with the company''s AWS accounts. Connect all VPCs to the central transit gateway.", "option_b": "Create a separate transit gateway in every Region where the company has deployed resources. Share the transit gateways with company''s AWS accounts. Connect the VPC in each Region to the transit gateway that is in the same Region. Peer the transit gateways. Create appropriate routes in all route tables.", "option_c": "Create a virtual private gateway for the shared VPCs. Create a customer gateway for the workload VPCs. Configure an AWS Site-to-Site VPN connection between the directory VPC, the monitoring VPC, and every workload VPC.", "option_d": "Create VPC peering connections between the central shared VPC, the shared monitoring VPC, and every workload VPC", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Transit Gateway is regional, so you cannot directly attach VPCs from multiple Regions to a\nsingle transit gateway. The scalable, compliant design is to:\n- Create one transit gateway per Region.\n- Attach all workload VPCs and the shared directory/monitoring VPCs in that Region to the local\ntransit gateway.\n- Share the transit gateways with other accounts via AWS RAM.\n- Peer the transit gateways across Regions and configure routes so each workload VPC can\nreach the central shared VPC and the shared monitoring VPC.\nThis provides a hub-and-spoke, multi-account, multi-Region network with far less complexity than\nmany VPC peering links or multiple VPNs, and it scales cleanly as you add more accounts or\nRegions.", "question_text": "A global company uses an organization in AWS Organizations to manage multiple AWS Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com accounts. To comply with regulations, the company deploys workload environments to five AWS Regions. The company has a separate AWS account for each Region. The company needs to connect every environment''s VPC to a central shared VPC that serves as a directory and to a shared monitoring VPC. The shared accounts are each in separate AWS accounts. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0119"}', '{"tags": null, "topic": null, "options": [["A", "Create a transit gateway in the central shared AWS account. Share the transit gateway with the company''s AWS accounts. Connect all VPCs to the central transit gateway."], ["B", "Create a separate transit gateway in every Region where the company has deployed resources. Share the transit gateways with company''s AWS accounts. Connect the VPC in each Region to the transit gateway that is in the same Region. Peer the transit gateways. Create appropriate routes in all route tables."], ["C", "Create a virtual private gateway for the shared VPCs. Create a customer gateway for the workload VPCs. Configure an AWS Site-to-Site VPN connection between the directory VPC, the monitoring VPC, and every workload VPC."], ["D", "Create VPC peering connections between the central shared VPC, the shared monitoring VPC, and every workload VPC"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0119"}, "reference": null, "difficulty": "medium", "explanation": "AWS Transit Gateway is regional, so you cannot directly attach VPCs from multiple Regions to a\nsingle transit gateway. The scalable, compliant design is to:\n- Create one transit gateway per Region.\n- Attach all workload VPCs and the shared directory/monitoring VPCs in that Region to the local\ntransit gateway.\n- Share the transit gateways with other accounts via AWS RAM.\n- Peer the transit gateways across Regions and configure routes so each workload VPC can\nreach the central shared VPC and the shared monitoring VPC.\nThis provides a hub-and-spoke, multi-account, multi-Region network with far less complexity than\nmany VPC peering links or multiple VPNs, and it scales cleanly as you add more accounts or\nRegions.", "question_text": "A global company uses an organization in AWS Organizations to manage multiple AWS Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com accounts. To comply with regulations, the company deploys workload environments to five AWS Regions. The company has a separate AWS account for each Region. The company needs to connect every environment''s VPC to a central shared VPC that serves as a directory and to a shared monitoring VPC. The shared accounts are each in separate AWS accounts. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '99e90e810e3c7a13d8d6bfcc9b41237a08ebf5bb7532152f60bba41c7f738e1b', 1468, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (954, 146, 121, 'qblock_pdf', '{"option_a": "Use Amazon RDS Performance Insights to analyze the SQL queries that most affect database performance. Update the SQL queries based on the analysis findings.", "option_b": "Use Amazon CloudWatch Logs Insights to analyze the database queries and identify performance bottlenecks. Update the queries based on the analysis findings.", "option_c": "Use Amazon RDS for PostgreSQL with a single Availability Zone.", "option_d": "Disable connection pooling entirely to ensure that all user connections are treated equally, even during peak hours. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_e": "Implement RDS Proxy with connection pooling.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Performance Insights helps identify the top wait events and most resource-intensive queries so\nyou can optimize or index them, directly reducing CPU utilization and query latency.\nRDS Proxy manages and pools database connections, smoothing out connection spikes and\nreducing overhead on the database during surges, which improves performance and reduces\ntimeouts.", "question_text": "A company stores critical information in an Amazon RDS for PostgreSQL database. The company notices degraded performance, high CPU utilization, increased query latency, and connection timeouts during peak shopping hours. The company also identifies surges in user connections during peak hours. The connection surges affect the read performance of the database. The company wants to resolve the database performance issues. Which combination of steps will meet this requirement? (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "AE", "external_question_id": "Q0120"}', '{"tags": null, "topic": null, "options": [["A", "Use Amazon RDS Performance Insights to analyze the SQL queries that most affect database performance. Update the SQL queries based on the analysis findings."], ["B", "Use Amazon CloudWatch Logs Insights to analyze the database queries and identify performance bottlenecks. Update the queries based on the analysis findings."], ["C", "Use Amazon RDS for PostgreSQL with a single Availability Zone."], ["D", "Disable connection pooling entirely to ensure that all user connections are treated equally, even during peak hours. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["E", "Implement RDS Proxy with connection pooling."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0120"}, "reference": null, "difficulty": "medium", "explanation": "Performance Insights helps identify the top wait events and most resource-intensive queries so\nyou can optimize or index them, directly reducing CPU utilization and query latency.\nRDS Proxy manages and pools database connections, smoothing out connection spikes and\nreducing overhead on the database during surges, which improves performance and reduces\ntimeouts.", "question_text": "A company stores critical information in an Amazon RDS for PostgreSQL database. The company notices degraded performance, high CPU utilization, increased query latency, and connection timeouts during peak shopping hours. The company also identifies surges in user connections during peak hours. The connection surges affect the read performance of the database. The company wants to resolve the database performance issues. Which combination of steps will meet this requirement? (Choose two.)", "question_type": "multiple", "correct_answer": ["A", "E"]}', 'imported', NULL, NULL, '7128524af95a2cd1dc84bac69de1e5fba176a39eedd8d8cd1f5b26c35ce3adff', 1469, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (955, 146, 122, 'qblock_pdf', '{"option_a": "Create an Amazon CloudWatch alarm to monitor application latency and increase the size of each EC2 instance if the desired threshold is reached.", "option_b": "Create an Amazon EventBridge rule to monitor application latency and add an EC2 instance to the ALB if the desired threshold is reached.", "option_c": "Deploy the application to an Auto Scaling group of EC2 instances with a target tracking scaling policy. Attach the ALB to the Auto Scaling group.", "option_d": "Deploy the application to an Auto Scaling group of EC2 instances with a scheduled scaling policy. Attach the ALB to the Auto Scaling group.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "An Auto Scaling group (ASG) with a target tracking scaling policy automatically adjusts the\nnumber of EC2 instances based on real-time demand (for example, CPU utilization or request\ncount). This allows the application to handle sudden, volatile traffic spikes seamlessly while\nmaintaining performance. The Application Load Balancer (ALB) distributes traffic evenly among\nthe instances in the ASG, ensuring scalability and fault tolerance without manual intervention.", "question_text": "A company runs a web application on three Amazon EC2 instances behind an Application Load Balancer (ALB). The company notices that random periods of increased traffic cause a degradation in the application’s performance. A CloudOps engineer must scale the application to meet the increased traffic. Which solution meets these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0121"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon CloudWatch alarm to monitor application latency and increase the size of each EC2 instance if the desired threshold is reached."], ["B", "Create an Amazon EventBridge rule to monitor application latency and add an EC2 instance to the ALB if the desired threshold is reached."], ["C", "Deploy the application to an Auto Scaling group of EC2 instances with a target tracking scaling policy. Attach the ALB to the Auto Scaling group."], ["D", "Deploy the application to an Auto Scaling group of EC2 instances with a scheduled scaling policy. Attach the ALB to the Auto Scaling group."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0121"}, "reference": null, "difficulty": "medium", "explanation": "An Auto Scaling group (ASG) with a target tracking scaling policy automatically adjusts the\nnumber of EC2 instances based on real-time demand (for example, CPU utilization or request\ncount). This allows the application to handle sudden, volatile traffic spikes seamlessly while\nmaintaining performance. The Application Load Balancer (ALB) distributes traffic evenly among\nthe instances in the ASG, ensuring scalability and fault tolerance without manual intervention.", "question_text": "A company runs a web application on three Amazon EC2 instances behind an Application Load Balancer (ALB). The company notices that random periods of increased traffic cause a degradation in the application’s performance. A CloudOps engineer must scale the application to meet the increased traffic. Which solution meets these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '35dac5feca08b3c50a35a41dc0c1318ef312d9add4fadae5b35bf7629129ae0b', 1470, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (956, 146, 123, 'qblock_pdf', '{"option_a": "Configure an Amazon ElastiCache cluster in front of the RDS instance. Update the reporting job to query the ElastiCache cluster.", "option_b": "Deploy an RDS read replica. Update the reporting job to query the reader endpoint.", "option_c": "Create an Amazon CloudFront distribution. Set the RDS instance as the origin. Update the reporting job to query the CloudFront distribution. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_d": "Increase the size of the RDS instance.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "A read replica offloads read traffic from the primary RDS instance to a separate replica, improving\nboth performance (by reducing read load and IOPS on the primary) and availability (the replica\ncan also be promoted in a failure scenario). Pointing the reporting job to the reader endpoint\nensures that heavy reporting reads no longer compete with the primary’s transactional workload,\nreducing query latency and speeding up the reports.", "question_text": "A company’s reporting job that used to run in 15 minutes is now taking an hour to run. An application generates the reports. The application runs on Amazon EC2 instances and extracts data from an Amazon RDS for MySQL database. A CloudOps engineer checks the Amazon CloudWatch dashboard for the RDS instance and notices that the Read IOPS metrics are high, even when the reports are not running. The CloudOps engineer needs to improve the performance and the availability of the RDS instance. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0122"}', '{"tags": null, "topic": null, "options": [["A", "Configure an Amazon ElastiCache cluster in front of the RDS instance. Update the reporting job to query the ElastiCache cluster."], ["B", "Deploy an RDS read replica. Update the reporting job to query the reader endpoint."], ["C", "Create an Amazon CloudFront distribution. Set the RDS instance as the origin. Update the reporting job to query the CloudFront distribution. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["D", "Increase the size of the RDS instance."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0122"}, "reference": null, "difficulty": "medium", "explanation": "A read replica offloads read traffic from the primary RDS instance to a separate replica, improving\nboth performance (by reducing read load and IOPS on the primary) and availability (the replica\ncan also be promoted in a failure scenario). Pointing the reporting job to the reader endpoint\nensures that heavy reporting reads no longer compete with the primary’s transactional workload,\nreducing query latency and speeding up the reports.", "question_text": "A company’s reporting job that used to run in 15 minutes is now taking an hour to run. An application generates the reports. The application runs on Amazon EC2 instances and extracts data from an Amazon RDS for MySQL database. A CloudOps engineer checks the Amazon CloudWatch dashboard for the RDS instance and notices that the Read IOPS metrics are high, even when the reports are not running. The CloudOps engineer needs to improve the performance and the availability of the RDS instance. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '6622668968dc2e72cf88c19d8c64cb9003e460bd8f1888177f6fc30ee17921d3', 1471, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (957, 146, 124, 'qblock_pdf', '{"option_a": "Deploy AWS Shield Advanced to filter and block malicious DNS queries. Set up domain filtering policies.", "option_b": "Use AWS WAF to inspect DNS traffic for malicious domains. Create custom rules to block known threats.", "option_c": "Configure Amazon Route 53 Resolver to forward DNS queries to Route 53 Resolver DNS Firewall Advanced to detect and filter threats.", "option_d": "Configure AWS Config to monitor DNS queries and DNS traffic patterns. Use an AWS Lambda function to prevent access to malicious domains.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Amazon Route 53 Resolver DNS Firewall provides DNS-based threat protection by allowing you\nto create rule groups that block queries to known malicious domains and apply domain filtering\npolicies across your VPCs. By configuring the Route 53 Resolver to forward DNS queries through\nthe DNS Firewall, you ensure that all DNS traffic is inspected and filtered, effectively blocking\nDNS-based attacks and malicious domains while keeping DNS resolution within your AWS\nenvironment.", "question_text": "A company that runs multiple workloads on AWS wants to enhance its security posture by implementing DNS-based threat protection. The company must block DNS-based attacks. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0123"}', '{"tags": null, "topic": null, "options": [["A", "Deploy AWS Shield Advanced to filter and block malicious DNS queries. Set up domain filtering policies."], ["B", "Use AWS WAF to inspect DNS traffic for malicious domains. Create custom rules to block known threats."], ["C", "Configure Amazon Route 53 Resolver to forward DNS queries to Route 53 Resolver DNS Firewall Advanced to detect and filter threats."], ["D", "Configure AWS Config to monitor DNS queries and DNS traffic patterns. Use an AWS Lambda function to prevent access to malicious domains."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0123"}, "reference": null, "difficulty": "medium", "explanation": "Amazon Route 53 Resolver DNS Firewall provides DNS-based threat protection by allowing you\nto create rule groups that block queries to known malicious domains and apply domain filtering\npolicies across your VPCs. By configuring the Route 53 Resolver to forward DNS queries through\nthe DNS Firewall, you ensure that all DNS traffic is inspected and filtered, effectively blocking\nDNS-based attacks and malicious domains while keeping DNS resolution within your AWS\nenvironment.", "question_text": "A company that runs multiple workloads on AWS wants to enhance its security posture by implementing DNS-based threat protection. The company must block DNS-based attacks. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, 'e9585dfb883e025317c904eb8ca9b81573ec997bc72633a878b42a116358a012', 1472, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (958, 146, 125, 'qblock_pdf', '{"option_a": "Take a snapshot of the RDS DB instance in the production account. Amend the KMS key policy of the production-rds-key KMS key to give access to the migration account’s root user. Share the snapshot with the migration account.", "option_b": "Create an RDS read replica in the migration account. Configure the KMS key policy to replicate the production-rds-key KMS key to the migration account.", "option_c": "Take a snapshot of the RDS DB instance in the production account. Share the snapshot with the migration account. In the migration account, create a new KMS key that has an identical alias.", "option_d": "Use native database toolsets to export the RDS DB instance to Amazon S3. Create an S3 bucket and an S3 bucket policy for cross-account access between the production account and the migration account. Use native database toolsets to import the database from Amazon S3 to a Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com new RDS DB instance.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Encrypted RDS snapshots can be shared across accounts only if the KMS key that encrypts them\nallows the target account to use the key. The CloudOps engineer should (1) take a snapshot of\nthe encrypted RDS instance, (2) update the production-rds-key KMS key policy to grant the\nmigration account access, and then (3) share the snapshot with the migration account. This is the\nsimplest, fully managed approach with the least administrative overhead.", "question_text": "A CloudOps engineer wants to share a copy of a production database with a migration account. The production database is hosted on an Amazon RDS DB instance and is encrypted at rest with an AWS Key Management Service (AWS KMS) key that has an alias of production-rds-key. What must the CloudOps engineer do to meet these requirements with the LEAST administrative overhead?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0124"}', '{"tags": null, "topic": null, "options": [["A", "Take a snapshot of the RDS DB instance in the production account. Amend the KMS key policy of the production-rds-key KMS key to give access to the migration account’s root user. Share the snapshot with the migration account."], ["B", "Create an RDS read replica in the migration account. Configure the KMS key policy to replicate the production-rds-key KMS key to the migration account."], ["C", "Take a snapshot of the RDS DB instance in the production account. Share the snapshot with the migration account. In the migration account, create a new KMS key that has an identical alias."], ["D", "Use native database toolsets to export the RDS DB instance to Amazon S3. Create an S3 bucket and an S3 bucket policy for cross-account access between the production account and the migration account. Use native database toolsets to import the database from Amazon S3 to a Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com new RDS DB instance."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0124"}, "reference": null, "difficulty": "medium", "explanation": "Encrypted RDS snapshots can be shared across accounts only if the KMS key that encrypts them\nallows the target account to use the key. The CloudOps engineer should (1) take a snapshot of\nthe encrypted RDS instance, (2) update the production-rds-key KMS key policy to grant the\nmigration account access, and then (3) share the snapshot with the migration account. This is the\nsimplest, fully managed approach with the least administrative overhead.", "question_text": "A CloudOps engineer wants to share a copy of a production database with a migration account. The production database is hosted on an Amazon RDS DB instance and is encrypted at rest with an AWS Key Management Service (AWS KMS) key that has an alias of production-rds-key. What must the CloudOps engineer do to meet these requirements with the LEAST administrative overhead?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '3ccd189c027e4b745fc16a0811ea530cbbde2522831e0ca2f7ad96d72463f708', 1473, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (960, 146, 127, 'qblock_pdf', '{"option_a": "Configure an Amazon CloudWatch alarm that evaluates the CPU utilization of the instance. Configure the alarm to invoke an AWS Lambda function to publish a message to an Amazon Simple Notification Service (Amazon SNS) topic when the CloudWatch alarm activates. Configure the Lambda function to reboot the EC2 instance. Subscribe the developer to the SNS topic.", "option_b": "Create an Amazon CloudWatch alarm that evaluates the CPU utilization of the instance. Configure the alarm to publish a notification to an Amazon Simple Notification Service (Amazon SNS) topic and to perform an EC2 action to reboot the instance. Subscribe the developer to the SNS topic.", "option_c": "Create an Amazon CloudWatch alarm that evaluates the CPU utilization of the instance Configure the alarm to invoke an AWS Systems Manager action to create an incident to notify the developer and request the reboot.", "option_d": "Create an AWS Systems Manager runbook script to publish a message to an Amazon Simple Notification Service (Amazon SNS) topic and to reboot the EC2 instance. Subscribe the Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com developer to the SNS topic. Configure an Amazon CloudWatch alarm to run the Systems Manager runbook when CPU utilization for the instance remains above 90% for more than 15 minutes.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "A CloudWatch alarm can directly trigger two actions when the threshold is breached:\n- EC2 action to reboot the instance.\n- SNS notification to alert the developer.\nThis requires no Lambda or Systems Manager runbooks and is therefore the simplest and least\nadministrative option that fully meets the requirements (CPU > 90% for 15 minutes, automatic\nreboot, and notification).", "question_text": "A developer uses an Amazon Linux Amazon Machine Image (AMI) to launch an EC2 instance that hosts a third-party application. The application occasionally becomes unstable. The CloudOps engineer needs a solution to automatically reboot the EC2 instance whenever utilization is above 90% for 15 minutes and to notify the developer about the reboot. Which solution will meet these requirements with the LEAST administrative effort?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0126"}', '{"tags": null, "topic": null, "options": [["A", "Configure an Amazon CloudWatch alarm that evaluates the CPU utilization of the instance. Configure the alarm to invoke an AWS Lambda function to publish a message to an Amazon Simple Notification Service (Amazon SNS) topic when the CloudWatch alarm activates. Configure the Lambda function to reboot the EC2 instance. Subscribe the developer to the SNS topic."], ["B", "Create an Amazon CloudWatch alarm that evaluates the CPU utilization of the instance. Configure the alarm to publish a notification to an Amazon Simple Notification Service (Amazon SNS) topic and to perform an EC2 action to reboot the instance. Subscribe the developer to the SNS topic."], ["C", "Create an Amazon CloudWatch alarm that evaluates the CPU utilization of the instance Configure the alarm to invoke an AWS Systems Manager action to create an incident to notify the developer and request the reboot."], ["D", "Create an AWS Systems Manager runbook script to publish a message to an Amazon Simple Notification Service (Amazon SNS) topic and to reboot the EC2 instance. Subscribe the Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com developer to the SNS topic. Configure an Amazon CloudWatch alarm to run the Systems Manager runbook when CPU utilization for the instance remains above 90% for more than 15 minutes."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0126"}, "reference": null, "difficulty": "medium", "explanation": "A CloudWatch alarm can directly trigger two actions when the threshold is breached:\n- EC2 action to reboot the instance.\n- SNS notification to alert the developer.\nThis requires no Lambda or Systems Manager runbooks and is therefore the simplest and least\nadministrative option that fully meets the requirements (CPU &gt; 90% for 15 minutes, automatic\nreboot, and notification).", "question_text": "A developer uses an Amazon Linux Amazon Machine Image (AMI) to launch an EC2 instance that hosts a third-party application. The application occasionally becomes unstable. The CloudOps engineer needs a solution to automatically reboot the EC2 instance whenever utilization is above 90% for 15 minutes and to notify the developer about the reboot. Which solution will meet these requirements with the LEAST administrative effort?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '9371bfe33fe3ec86f1e67ea52ba4e8881b85ac0a671988a3d5786b64d757687a', 1475, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (962, 146, 129, 'qblock_pdf', '{"option_a": "Change the slow_start.duration_seconds target group attribute to 120 seconds. Before rebooting the instances, deregister the instances from the target group. After rebooting the instances, register the instances with the target group.", "option_b": "Change the HealthCheckTimeoutSeconds paramotor in the target group to 120 seconds. Before rebooting the instances, deregister the instances from the target group. After rebooting the Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com instances, register the instances with the target group.", "option_c": "Configure an Amazon CloudWatch alarm to monitor the health check status. Configure the action of the alarm to restart an EC2 instance if a health check fails. Change the loadbalancing.algorithm.type target group attribute to be weighted_random.", "option_d": "Create an Amazon EC2 Auto Scaling group. Attach the existing EC2 instances to the Auto Scaling group. Configure an EC2 Auto Scaling lifecycle hook to move starting instances to the Pending Wait state. Update the application to complete the lifecycle hook when the local cache has been populated.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The slow start feature of an ALB target group (slow_start.duration_seconds) is specifically\ndesigned to let new or newly healthy targets ramp up gradually, giving them a smaller, increasing\nshare of traffic over a defined period. Setting it to 120 seconds allows each instance to warm its\nlocal cache during that time instead of receiving a full share of requests immediately, which\nmatches the 2-minute cache warm-up requirement.", "question_text": "An application runs on Amazon EC2 instances behind an Application Load Balancer (ALB). The application takes up to 2 minutes to populate a local cache after the application is started. The application reports as healthy in the target group health check a few seconds after starting. A CloudOps engineer observes that after some of the instances are rebooted, the instances receive an equal share of the traffic immediately after each instance reports as healthy. The application needs to receive a gradually increasing share of the traffic while the application cache is populated. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0128"}', '{"tags": null, "topic": null, "options": [["A", "Change the slow_start.duration_seconds target group attribute to 120 seconds. Before rebooting the instances, deregister the instances from the target group. After rebooting the instances, register the instances with the target group."], ["B", "Change the HealthCheckTimeoutSeconds paramotor in the target group to 120 seconds. Before rebooting the instances, deregister the instances from the target group. After rebooting the Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com instances, register the instances with the target group."], ["C", "Configure an Amazon CloudWatch alarm to monitor the health check status. Configure the action of the alarm to restart an EC2 instance if a health check fails. Change the loadbalancing.algorithm.type target group attribute to be weighted_random."], ["D", "Create an Amazon EC2 Auto Scaling group. Attach the existing EC2 instances to the Auto Scaling group. Configure an EC2 Auto Scaling lifecycle hook to move starting instances to the Pending Wait state. Update the application to complete the lifecycle hook when the local cache has been populated."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0128"}, "reference": null, "difficulty": "medium", "explanation": "The slow start feature of an ALB target group (slow_start.duration_seconds) is specifically\ndesigned to let new or newly healthy targets ramp up gradually, giving them a smaller, increasing\nshare of traffic over a defined period. Setting it to 120 seconds allows each instance to warm its\nlocal cache during that time instead of receiving a full share of requests immediately, which\nmatches the 2-minute cache warm-up requirement.", "question_text": "An application runs on Amazon EC2 instances behind an Application Load Balancer (ALB). The application takes up to 2 minutes to populate a local cache after the application is started. The application reports as healthy in the target group health check a few seconds after starting. A CloudOps engineer observes that after some of the instances are rebooted, the instances receive an equal share of the traffic immediately after each instance reports as healthy. The application needs to receive a gradually increasing share of the traffic while the application cache is populated. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '3f169cfd886337250cb0a3b319072f234bc52590bbbb2b0ae97f34b7d08720ba', 1476, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (963, 146, 130, 'qblock_pdf', '{"option_a": "Use the Aurora Backtrack feature to rewind the database to a specified time, 2 hours in the past.", "option_b": "Perform a point-in-time recovery on the existing database to restore the database to a specified point in time, 2 hours in the past.", "option_c": "Perform a point-in-time recovery and create a new database to restore the database to a specified point in time, 2 hours in the past. Reconfigure the application to use a new database endpoint.", "option_d": "Create a new Aurora cluster. Choose the Restore data from S3 bucket option. Choose log files up to the failure time 2 hours in the past.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Aurora Backtrack is not supported for Aurora PostgreSQL, so option A is not valid here.\nPoint-in-time recovery (PITR) for Aurora always restores to a new cluster, not in place. You\nchoose a time (e.g., just before the table was dropped, 2 hours ago), Aurora creates a new\ncluster at that state, and you then:\n- Either point the application to the new cluster endpoint, or\n- Copy the recovered table/data back to the original cluster.", "question_text": "A company runs an application on Amazon EC2 instances. The application stores and retrieves data from an Amazon Aurora PostgreSQL database. A developer accidentally drops a table from the database, which causes application errors. Two hours later, a CloudOps engineer needs to recover the data and make the application function again. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0129"}', '{"tags": null, "topic": null, "options": [["A", "Use the Aurora Backtrack feature to rewind the database to a specified time, 2 hours in the past."], ["B", "Perform a point-in-time recovery on the existing database to restore the database to a specified point in time, 2 hours in the past."], ["C", "Perform a point-in-time recovery and create a new database to restore the database to a specified point in time, 2 hours in the past. Reconfigure the application to use a new database endpoint."], ["D", "Create a new Aurora cluster. Choose the Restore data from S3 bucket option. Choose log files up to the failure time 2 hours in the past."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0129"}, "reference": null, "difficulty": "medium", "explanation": "Aurora Backtrack is not supported for Aurora PostgreSQL, so option A is not valid here.\nPoint-in-time recovery (PITR) for Aurora always restores to a new cluster, not in place. You\nchoose a time (e.g., just before the table was dropped, 2 hours ago), Aurora creates a new\ncluster at that state, and you then:\n- Either point the application to the new cluster endpoint, or\n- Copy the recovered table/data back to the original cluster.", "question_text": "A company runs an application on Amazon EC2 instances. The application stores and retrieves data from an Amazon Aurora PostgreSQL database. A developer accidentally drops a table from the database, which causes application errors. Two hours later, a CloudOps engineer needs to recover the data and make the application function again. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '14f9bd3153c21bacb3163bb3b1053fd283aa22ddcf5bb71eab374f20a88e9fea', 1477, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (964, 146, 131, 'qblock_pdf', '{"option_a": "Create five Amazon CloudWatch alarms, one for each Trusted Advisor service quota metric. Configure an Amazon Simple Notification Service (Amazon SNS) topic for email notification each time that usage exceeds 60% of one of the service quotas. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "option_b": "Create five Amazon CloudWatch alarms, one for each Trusted Advisor service quota metric. Configure an Amazon Simple Queue Service (Amazon SQS) queue for email notification each time that usage exceeds 60% of one of the service quotas.", "option_c": "Use the AWS Health Dashboard to monitor each Trusted Advisor service quota metric. Configure an Amazon Simple Queue Service (Amazon SQS) queue for email notification each time that usage exceeds 60% of one of the service quotas.", "option_d": "Use the AWS Health Dashboard to monitor each Trusted Advisor service quota metric. Configure an Amazon Simple Notification Service (Amazon SNS) topic for email notification each time that usage exceeds 60% of one of the service quotas.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Trusted Advisor service quota usage is exposed as CloudWatch metrics, so the simplest\napproach is to create CloudWatch alarms on each metric with a threshold at 60% utilization and\nconfigure them to publish to an SNS topic for email notifications. SNS is the native service for\nsending email from CloudWatch alarms, making this the most direct and operationally efficient\nsolution.", "question_text": "A company runs several workloads on AWS. The company identifies five AWS Trusted Advisor service quota metrics to monitor in a specific AWS Region. The company wants to receive email notification each time resource usage exceeds 60% of one of the service quotas. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0130"}', '{"tags": null, "topic": null, "options": [["A", "Create five Amazon CloudWatch alarms, one for each Trusted Advisor service quota metric. Configure an Amazon Simple Notification Service (Amazon SNS) topic for email notification each time that usage exceeds 60% of one of the service quotas. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"], ["B", "Create five Amazon CloudWatch alarms, one for each Trusted Advisor service quota metric. Configure an Amazon Simple Queue Service (Amazon SQS) queue for email notification each time that usage exceeds 60% of one of the service quotas."], ["C", "Use the AWS Health Dashboard to monitor each Trusted Advisor service quota metric. Configure an Amazon Simple Queue Service (Amazon SQS) queue for email notification each time that usage exceeds 60% of one of the service quotas."], ["D", "Use the AWS Health Dashboard to monitor each Trusted Advisor service quota metric. Configure an Amazon Simple Notification Service (Amazon SNS) topic for email notification each time that usage exceeds 60% of one of the service quotas."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0130"}, "reference": null, "difficulty": "medium", "explanation": "Trusted Advisor service quota usage is exposed as CloudWatch metrics, so the simplest\napproach is to create CloudWatch alarms on each metric with a threshold at 60% utilization and\nconfigure them to publish to an SNS topic for email notifications. SNS is the native service for\nsending email from CloudWatch alarms, making this the most direct and operationally efficient\nsolution.", "question_text": "A company runs several workloads on AWS. The company identifies five AWS Trusted Advisor service quota metrics to monitor in a specific AWS Region. The company wants to receive email notification each time resource usage exceeds 60% of one of the service quotas. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'afdcaa33c698d38a430b1c414b790680ff807b18828ca8d76bfeef8ac689f8a8', 1478, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (965, 146, 132, 'qblock_pdf', '{"option_a": "Ensure that the DNS resolution option and the DNS hostnames option are turned on in the VPC. Add the synthetics:GetCanaryRuns permission to the VPC. On the S3 bucket, add the IgnorePublicAcls permission to the CloudWatch Synthetics role.", "option_b": "Ensure that the DNS resolution option and the DNS hostnames option are turned off in the VPC. Create a gateway VPC endpoint for Amazon S3. Add the permissions to allow CloudWatch Synthetics to use the S3 endpoint.", "option_c": "Ensure that the DNS resolution option and the DNS hostnames option are turned off in the VPC. Add a security group to the canary to allow outbound traffic on the DNS port. Add the permissions to allow CloudWatch Synthetics to write to the S3 bucket.", "option_d": "Ensure that the DNS resolution option and the DNS hostnames option are turned on in the VPC. Create an interface VPC endpoint for CloudWatch. Create a gateway VPC endpoint for Amazon S3. Add the permissions to allow CloudWatch Synthetics to use both endpoints.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "When a CloudWatch Synthetics canary runs inside a private VPC, it must access CloudWatch\nand S3 privately for publishing logs, metrics, and storing results. Because there is no internet\naccess, the canary requires:\n- DNS resolution and hostnames enabled for proper endpoint resolution.\n- An interface VPC endpoint for CloudWatch, so the canary can communicate with the\nCloudWatch service privately.\n- A gateway VPC endpoint for S3, to allow results to be written to the S3 bucket without internet\naccess.", "question_text": "A CloudOps engineer is troubleshooting an implementation of Amazon CloudWatch Synthetics. The CloudWatch Synthetics results must be sent to an Amazon S3 bucket. The CloudOps engineer has copied the configuration of an existing canary that runs on a VPC that has an internet gateway attached. However, the CloudOps engineer cannot get the canary to successfully start on a private VPC that has no internet access. What should the CloudOps engineer do to successfully run the canary on the private VPC?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0131"}', '{"tags": null, "topic": null, "options": [["A", "Ensure that the DNS resolution option and the DNS hostnames option are turned on in the VPC. Add the synthetics:GetCanaryRuns permission to the VPC. On the S3 bucket, add the IgnorePublicAcls permission to the CloudWatch Synthetics role."], ["B", "Ensure that the DNS resolution option and the DNS hostnames option are turned off in the VPC. Create a gateway VPC endpoint for Amazon S3. Add the permissions to allow CloudWatch Synthetics to use the S3 endpoint."], ["C", "Ensure that the DNS resolution option and the DNS hostnames option are turned off in the VPC. Add a security group to the canary to allow outbound traffic on the DNS port. Add the permissions to allow CloudWatch Synthetics to write to the S3 bucket."], ["D", "Ensure that the DNS resolution option and the DNS hostnames option are turned on in the VPC. Create an interface VPC endpoint for CloudWatch. Create a gateway VPC endpoint for Amazon S3. Add the permissions to allow CloudWatch Synthetics to use both endpoints."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0131"}, "reference": null, "difficulty": "medium", "explanation": "When a CloudWatch Synthetics canary runs inside a private VPC, it must access CloudWatch\nand S3 privately for publishing logs, metrics, and storing results. Because there is no internet\naccess, the canary requires:\n- DNS resolution and hostnames enabled for proper endpoint resolution.\n- An interface VPC endpoint for CloudWatch, so the canary can communicate with the\nCloudWatch service privately.\n- A gateway VPC endpoint for S3, to allow results to be written to the S3 bucket without internet\naccess.", "question_text": "A CloudOps engineer is troubleshooting an implementation of Amazon CloudWatch Synthetics. The CloudWatch Synthetics results must be sent to an Amazon S3 bucket. The CloudOps engineer has copied the configuration of an existing canary that runs on a VPC that has an internet gateway attached. However, the CloudOps engineer cannot get the canary to successfully start on a private VPC that has no internet access. What should the CloudOps engineer do to successfully run the canary on the private VPC?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '5c3364d9b28310246011fc18d34c77c729e06e3e1ad2fb396ac445ee44c4b716', 1479, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (966, 146, 133, 'qblock_pdf', '{"option_a": "Reconfigure the Lambda function so that the function is not connected to the VPC.", "option_b": "Deploy an RDS proxy. Configure the Lambda function to connect to the DB instance through the proxy.", "option_c": "Deploy a NAT gateway. Update the private subnet''s route table to route all traffic to the NAT gateway.", "option_d": "Create an interface endpoint for Amazon SQS in the VPC.", "option_e": "Create a gateway endpoint for Amazon SQS in the VPC.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The Lambda function now runs inside a private subnet. To reach public AWS service endpoints\nlike SQS over the internet, resources in private subnets need an egress path, typically via a NAT\ngateway. Adding a NAT gateway and updating the route table lets the Lambda function call the\nSQS public endpoint while still accessing the RDS instance in the private subnet.\nAlternatively, you can keep the subnet private and create an interface VPC endpoint for SQS.\nThis gives the Lambda function a private, VPC-internal path to SQS without requiring internet\naccess.", "question_text": "Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com A company deploys AWS infrastructure in a VPC that has an internet gateway. The VPC has public subnets and private subnets. An Amazon RDS for MySQL DB instance is deployed in a private subnet. An AWS Lambda function uses the same private subnet and connects to the DB instance to query data. A developer modifies the Lambda function to require the function to publish messages to an Amazon Simple Queue Service (Amazon SQS) queue. After these changes, the Lambda function times out when it tries to publish messages to the SQS queue. Which solutions will resolve this issue? (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "CD", "external_question_id": "Q0132"}', '{"tags": null, "topic": null, "options": [["A", "Reconfigure the Lambda function so that the function is not connected to the VPC."], ["B", "Deploy an RDS proxy. Configure the Lambda function to connect to the DB instance through the proxy."], ["C", "Deploy a NAT gateway. Update the private subnet''s route table to route all traffic to the NAT gateway."], ["D", "Create an interface endpoint for Amazon SQS in the VPC."], ["E", "Create a gateway endpoint for Amazon SQS in the VPC."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0132"}, "reference": null, "difficulty": "medium", "explanation": "The Lambda function now runs inside a private subnet. To reach public AWS service endpoints\nlike SQS over the internet, resources in private subnets need an egress path, typically via a NAT\ngateway. Adding a NAT gateway and updating the route table lets the Lambda function call the\nSQS public endpoint while still accessing the RDS instance in the private subnet.\nAlternatively, you can keep the subnet private and create an interface VPC endpoint for SQS.\nThis gives the Lambda function a private, VPC-internal path to SQS without requiring internet\naccess.", "question_text": "Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com A company deploys AWS infrastructure in a VPC that has an internet gateway. The VPC has public subnets and private subnets. An Amazon RDS for MySQL DB instance is deployed in a private subnet. An AWS Lambda function uses the same private subnet and connects to the DB instance to query data. A developer modifies the Lambda function to require the function to publish messages to an Amazon Simple Queue Service (Amazon SQS) queue. After these changes, the Lambda function times out when it tries to publish messages to the SQS queue. Which solutions will resolve this issue? (Choose two.)", "question_type": "multiple", "correct_answer": ["C", "D"]}', 'imported', NULL, NULL, 'ceb2506addce50d55512c9a1807dc72d2f20a0680182310e4fc78b5801e2bfc9', 1480, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (967, 146, 134, 'qblock_pdf', '{"option_a": "Create an Amazon CloudWatch alarm for the AWS Config rule''s status metric. Create an AWS Lambda function that can remove the noncompliant rule from the security group. Configure the alarm action to invoke the Lambda function.", "option_b": "Configure an automatic remediation action on the AWS Config rule. Specify the AWS- DisablolncomingSSHOnPort22 remediation action.", "option_c": "Configure an Amazon EventBridge rule for AWS Config configuration item change events. Create an AWS Lambda function that can remove the noncompliant rule from the security group Configure the rule to invoke the Lambda function.", "option_d": "Create an AWS Lambda function that can analyze a security group’s inbound rules to check for unrestricted SSH access. Configure the Lambda function to remove the noncompliant rule from the security group. Configure an Amazon EventBridge rule to invoke the Lambda function every hour. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Config supports automatic remediation by invoking a Systems Manager Automation\nrunbook when a rule is noncompliant. For unrestricted SSH, you can attach the managed\nremediation action AWS-DisableIncomingSSHOnPort22 to the existing AWS Config rule so that\nany noncompliant security group is automatically corrected without custom Lambda code or\npolling logic.", "question_text": "A company''s security policy requires incoming SSH traffic to be restricted to a defined set of addresses. The company is using an AWS Config rule to check whether security groups allow unrestricted incoming SSH traffic. A CloudOps engineer discovers a noncompliant resource and fixes the security group manually. The CloudOps engineer wants to automate the remediation of other noncompliant resources. What is the MOST operationally efficient solution that meets these requirements?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0133"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon CloudWatch alarm for the AWS Config rule''s status metric. Create an AWS Lambda function that can remove the noncompliant rule from the security group. Configure the alarm action to invoke the Lambda function."], ["B", "Configure an automatic remediation action on the AWS Config rule. Specify the AWS- DisablolncomingSSHOnPort22 remediation action."], ["C", "Configure an Amazon EventBridge rule for AWS Config configuration item change events. Create an AWS Lambda function that can remove the noncompliant rule from the security group Configure the rule to invoke the Lambda function."], ["D", "Create an AWS Lambda function that can analyze a security group’s inbound rules to check for unrestricted SSH access. Configure the Lambda function to remove the noncompliant rule from the security group. Configure an Amazon EventBridge rule to invoke the Lambda function every hour. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0133"}, "reference": null, "difficulty": "medium", "explanation": "AWS Config supports automatic remediation by invoking a Systems Manager Automation\nrunbook when a rule is noncompliant. For unrestricted SSH, you can attach the managed\nremediation action AWS-DisableIncomingSSHOnPort22 to the existing AWS Config rule so that\nany noncompliant security group is automatically corrected without custom Lambda code or\npolling logic.", "question_text": "A company''s security policy requires incoming SSH traffic to be restricted to a defined set of addresses. The company is using an AWS Config rule to check whether security groups allow unrestricted incoming SSH traffic. A CloudOps engineer discovers a noncompliant resource and fixes the security group manually. The CloudOps engineer wants to automate the remediation of other noncompliant resources. What is the MOST operationally efficient solution that meets these requirements?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '1aaf8ba601055e0e129f8ed51607977d7948840ac9292be1f28b8e6870567e8d', 1481, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (968, 146, 135, 'qblock_pdf', '{"option_a": "VPC Flow Logs", "option_b": "AWS CloudTrail logs", "option_c": "ALB access logs", "option_d": "CloudFront access logs", "option_e": "RDS logs", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "ALB access logs include detailed HTTP Layer 7 information such as request paths, user agents,\nand status codes returned by the application.\nCloudFront access logs record all viewer requests served through CloudFront distributions,\nincluding HTTP status codes (2xx, 4xx, 5xx).\nThese two log sources together provide complete visibility into HTTP status code behavior from\nboth the edge (CloudFront) and origin (ALB) layers, allowing the CloudOps engineer to\ninvestigate web application performance and errors effectively.", "question_text": "A CloudOps engineer is maintaining a web application using an Amazon CloudFront web distribution, an Application Load Balancer (ALB), Amazon RDS, and Amazon EC2 in a VPC. All services have logging enabled. The CloudOps engineer needs to investigate HTTP Layer 7 status codes from the web application. Which log sources contain the status codes? (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "CD", "external_question_id": "Q0134"}', '{"tags": null, "topic": null, "options": [["A", "VPC Flow Logs"], ["B", "AWS CloudTrail logs"], ["C", "ALB access logs"], ["D", "CloudFront access logs"], ["E", "RDS logs"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0134"}, "reference": null, "difficulty": "medium", "explanation": "ALB access logs include detailed HTTP Layer 7 information such as request paths, user agents,\nand status codes returned by the application.\nCloudFront access logs record all viewer requests served through CloudFront distributions,\nincluding HTTP status codes (2xx, 4xx, 5xx).\nThese two log sources together provide complete visibility into HTTP status code behavior from\nboth the edge (CloudFront) and origin (ALB) layers, allowing the CloudOps engineer to\ninvestigate web application performance and errors effectively.", "question_text": "A CloudOps engineer is maintaining a web application using an Amazon CloudFront web distribution, an Application Load Balancer (ALB), Amazon RDS, and Amazon EC2 in a VPC. All services have logging enabled. The CloudOps engineer needs to investigate HTTP Layer 7 status codes from the web application. Which log sources contain the status codes? (Choose two.)", "question_type": "multiple", "correct_answer": ["C", "D"]}', 'imported', NULL, NULL, '152d044df8ee031fba1386bd74c8b47c56602bf058e80e6c2c024f422a9ad2f7', 1482, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (969, 146, 136, 'qblock_pdf', '{"option_a": "Create an Amazon CloudWatch alarm for the EC2 instance with basic monitoring. Add an action to restart the instance.", "option_b": "Create an Amazon CloudWatch alarm for the EC2 instance with detailed monitoring. Add an action to restart the instance.", "option_c": "Create an AWS Lambda function to restart the EC2 instance, invoked on a scheduled basis every 2 minutes.", "option_d": "Create an AWS Lambda function to restart the EC2 instance, invoked by EC2 health checks.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "With detailed monitoring enabled, CloudWatch collects EC2 metrics (such as CPUUtilization) at\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\n1-minute intervals, allowing accurate detection of sustained 100% CPU usage. You can then\nconfigure a CloudWatch alarm that triggers when CPU utilization remains above a threshold (e.g.,\n99%) for more than 2 consecutive minutes and set the alarm action to automatically restart the\nEC2 instance. This provides a fully automated, low-maintenance solution.", "question_text": "An errant process is known to use an entire processor and run at 100%. A CloudOps engineer wants to automate restarting an Amazon EC2 instance when the problem occurs for more than 2 minutes. How can this be accomplished?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0135"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon CloudWatch alarm for the EC2 instance with basic monitoring. Add an action to restart the instance."], ["B", "Create an Amazon CloudWatch alarm for the EC2 instance with detailed monitoring. Add an action to restart the instance."], ["C", "Create an AWS Lambda function to restart the EC2 instance, invoked on a scheduled basis every 2 minutes."], ["D", "Create an AWS Lambda function to restart the EC2 instance, invoked by EC2 health checks."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0135"}, "reference": null, "difficulty": "medium", "explanation": "With detailed monitoring enabled, CloudWatch collects EC2 metrics (such as CPUUtilization) at\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\n1-minute intervals, allowing accurate detection of sustained 100% CPU usage. You can then\nconfigure a CloudWatch alarm that triggers when CPU utilization remains above a threshold (e.g.,\n99%) for more than 2 consecutive minutes and set the alarm action to automatically restart the\nEC2 instance. This provides a fully automated, low-maintenance solution.", "question_text": "An errant process is known to use an entire processor and run at 100%. A CloudOps engineer wants to automate restarting an Amazon EC2 instance when the problem occurs for more than 2 minutes. How can this be accomplished?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'd881e2ab35a46e3ba93c3fa34b0d6a558a0165ce30b3bb04cfa1406189d3a707', 1483, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (970, 146, 137, 'qblock_pdf', '{"option_a": "Add the users to an IAM service-linked role. Attach the policy to the role.", "option_b": "Add the users to an IAM user group. Attach the policy to the group.", "option_c": "Create an AWS managed policy.", "option_d": "Create a customer managed policy.", "option_e": "Create an inline policy.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Attaching a policy to a group allows centralized management of permissions for multiple users. All\nusers in the group automatically inherit the policy permissions.\nA customer managed policy is reusable, versioned, and editable. You can create new versions of\nthe policy and update or roll back as needed. Combining this with a user group provides flexible,\nscalable, and maintainable permission management.", "question_text": "A CloudOps engineer wants to provide access to AWS services by attaching an IAM policy to multiple IAM users The CloudOps engineer also wants to be able to change the policy and create new versions. Which combination of actions will meet these requirements? (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "BD", "external_question_id": "Q0136"}', '{"tags": null, "topic": null, "options": [["A", "Add the users to an IAM service-linked role. Attach the policy to the role."], ["B", "Add the users to an IAM user group. Attach the policy to the group."], ["C", "Create an AWS managed policy."], ["D", "Create a customer managed policy."], ["E", "Create an inline policy."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0136"}, "reference": null, "difficulty": "medium", "explanation": "Attaching a policy to a group allows centralized management of permissions for multiple users. All\nusers in the group automatically inherit the policy permissions.\nA customer managed policy is reusable, versioned, and editable. You can create new versions of\nthe policy and update or roll back as needed. Combining this with a user group provides flexible,\nscalable, and maintainable permission management.", "question_text": "A CloudOps engineer wants to provide access to AWS services by attaching an IAM policy to multiple IAM users The CloudOps engineer also wants to be able to change the policy and create new versions. Which combination of actions will meet these requirements? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'imported', NULL, NULL, 'c4b02ac26db2e8e087dd5e24e9a2c224bed5b644b1cedf53ee5c51777d7fcdf7', 1484, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (971, 146, 138, 'qblock_pdf', '{"option_a": "Change the launch configuration to use a larger instance size.", "option_b": "Increase the minimum number of instances in the Auto Scaling group.", "option_c": "Add a predictive scaling policy to the Auto Scaling group.", "option_d": "Add a warm pool to the Auto Scaling group.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "An Auto Scaling warm pool keeps a set of pre-initialized EC2 instances in a “stopped” or\n“running” state, ready to be quickly added to the active instance pool when scaling out. This\nsignificantly reduces scale-out latency caused by lengthy boot scripts, without permanently\nrunning extra instances (avoiding overprovisioning). Once demand increases, instances from the\nwarm pool can be launched almost instantly.", "question_text": "A company runs an application on Amazon EC2 instances that are in an Amazon EC2 Auto Scaling group. Scale-out actions take a long time to become complete because of long-running boot scripts. A CloudOps engineer must implement a solution to reduce the required time for scale-out actions without overprovisioning the Auto Scaling group. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0137"}', '{"tags": null, "topic": null, "options": [["A", "Change the launch configuration to use a larger instance size."], ["B", "Increase the minimum number of instances in the Auto Scaling group."], ["C", "Add a predictive scaling policy to the Auto Scaling group."], ["D", "Add a warm pool to the Auto Scaling group."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0137"}, "reference": null, "difficulty": "medium", "explanation": "An Auto Scaling warm pool keeps a set of pre-initialized EC2 instances in a “stopped” or\n“running” state, ready to be quickly added to the active instance pool when scaling out. This\nsignificantly reduces scale-out latency caused by lengthy boot scripts, without permanently\nrunning extra instances (avoiding overprovisioning). Once demand increases, instances from the\nwarm pool can be launched almost instantly.", "question_text": "A company runs an application on Amazon EC2 instances that are in an Amazon EC2 Auto Scaling group. Scale-out actions take a long time to become complete because of long-running boot scripts. A CloudOps engineer must implement a solution to reduce the required time for scale-out actions without overprovisioning the Auto Scaling group. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'a0d0c93e04fe3d29e8a48e14068d65947fd5246933717f12a60c5f4516601388', 1485, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (972, 146, 139, 'qblock_pdf', '{"option_a": "Edit the private subnet to change the CIDR block to /27.", "option_b": "Edit the private subnet to extend across a second Availability Zone.", "option_c": "Assign additional Elastic IP addresses to the private subnet.", "option_d": "Create a new private subnet to hold the required EC2 instances.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "A subnet’s CIDR block size determines how many IP addresses it can allocate to resources.\nOnce all IP addresses in the subnet are used, you cannot expand or resize the CIDR block of an\nexisting subnet. The only solution is to create a new subnet (with a larger or different CIDR range)\nwithin the same VPC and launch additional EC2 instances there. This allows scaling without IP\naddress exhaustion.", "question_text": "A CloudOps engineer creates a new VPC that includes a public subnet and a private subnet. The CloudOps engineer successfully launches 11 Amazon EC2 instances in the private subnet The Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com CloudOps engineer attempts to launch one more EC2 instance in the same subnet. However, the CloudOps engineer receives an error message that states that not enough free IP addresses are available. What must the CloudOps engineer do to deploy more EC2 instances?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0138"}', '{"tags": null, "topic": null, "options": [["A", "Edit the private subnet to change the CIDR block to /27."], ["B", "Edit the private subnet to extend across a second Availability Zone."], ["C", "Assign additional Elastic IP addresses to the private subnet."], ["D", "Create a new private subnet to hold the required EC2 instances."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0138"}, "reference": null, "difficulty": "medium", "explanation": "A subnet’s CIDR block size determines how many IP addresses it can allocate to resources.\nOnce all IP addresses in the subnet are used, you cannot expand or resize the CIDR block of an\nexisting subnet. The only solution is to create a new subnet (with a larger or different CIDR range)\nwithin the same VPC and launch additional EC2 instances there. This allows scaling without IP\naddress exhaustion.", "question_text": "A CloudOps engineer creates a new VPC that includes a public subnet and a private subnet. The CloudOps engineer successfully launches 11 Amazon EC2 instances in the private subnet The Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com CloudOps engineer attempts to launch one more EC2 instance in the same subnet. However, the CloudOps engineer receives an error message that states that not enough free IP addresses are available. What must the CloudOps engineer do to deploy more EC2 instances?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '8a3dea077e2521509def6fd506f354d5bd00d4975a69f26602c8c2e9f5dbc65e', 1486, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (974, 146, 141, 'qblock_pdf', '{"option_a": "The template referenced an IAM user that is not available in eu-west-1.", "option_b": "The template referenced an Amazon Machine Image (AMI) that is not available in eu-west-1.", "option_c": "The template did not have the proper level of permissions to deploy the resources.", "option_d": "The template requested services that do not exist in eu-west-1.", "option_e": "CloudFormation templates can be used only to update existing services", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AMIs are Region-specific, so an AMI ID valid in us-west-2 will not exist in eu-west-1. This causes\nresource creation failures when CloudFormation tries to launch EC2 instances using that\nunavailable AMI.\nSome AWS services or resource types are not available in every Region. If the template includes\nsuch a service, the deployment will fail in Regions where the service is unavailable.\nTogether, these are the most common causes of CloudFormation stack failures when deploying\ntemplates across Regions.", "question_text": "A CloudOps engineer has an AWS CloudFormation template of the company''s existing infrastructure in us-west-2. The CloudOps engineer attempts to use the template to launch a new stack in eu-west-1, but the stack only partially deploys, receives an error message, and then rolls back. Why would this template fail to deploy? (Choose two.) Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "source_format": "qblock_pdf", "correct_answer": "BD", "external_question_id": "Q0140"}', '{"tags": null, "topic": null, "options": [["A", "The template referenced an IAM user that is not available in eu-west-1."], ["B", "The template referenced an Amazon Machine Image (AMI) that is not available in eu-west-1."], ["C", "The template did not have the proper level of permissions to deploy the resources."], ["D", "The template requested services that do not exist in eu-west-1."], ["E", "CloudFormation templates can be used only to update existing services"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0140"}, "reference": null, "difficulty": "medium", "explanation": "AMIs are Region-specific, so an AMI ID valid in us-west-2 will not exist in eu-west-1. This causes\nresource creation failures when CloudFormation tries to launch EC2 instances using that\nunavailable AMI.\nSome AWS services or resource types are not available in every Region. If the template includes\nsuch a service, the deployment will fail in Regions where the service is unavailable.\nTogether, these are the most common causes of CloudFormation stack failures when deploying\ntemplates across Regions.", "question_text": "A CloudOps engineer has an AWS CloudFormation template of the company''s existing infrastructure in us-west-2. The CloudOps engineer attempts to use the template to launch a new stack in eu-west-1, but the stack only partially deploys, receives an error message, and then rolls back. Why would this template fail to deploy? (Choose two.) Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'imported', NULL, NULL, 'e8166e9b9d44684a30d77241621df6a64a408bfa0d440a790b2d22cda520ae9f', 1488, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (975, 146, 142, 'qblock_pdf', '{"option_a": "Create a copy of the AMI. Specify the destination S3 bucket. Set the launch permissions to implicit.", "option_b": "Archive the snapshot that is associated with the AMI. Specify the S3 bucket as the archive destination.", "option_c": "Create a store image task. Specify the image ID and the destination S3 bucket.", "option_d": "Use the AWS CLI copy-image command. Specify the image ID and the destination S3 bucket.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Because this is the only AWS-supported solution that allows an AMI to be backed up to Amazon\nS3 and later restored while preserving the original AMI ID. This capability is essential for\nregulatory and compliance requirements where immutable identifiers must be retained.\nAccording to AWS CloudOps documentation for Amazon EC2 AMI lifecycle management, the\nAMI store and restore feature is specifically designed for long-term retention, audit, and\ncompliance scenarios. When an AMI is stored using a store image task, AWS packages the\nAMI''s configuration, metadata, and associated snapshots and saves them as encrypted objects in\nan Amazon S3 bucket. When the AMI is restored, AWS explicitly states that the restored AMI\nretains the same AMI ID as the original image, ensuring continuity for compliance tracking and\noperational dependencies.", "question_text": "To comply with regulations, a SysOps administrator needs to back up an Amazon EC2 Amazon Machine Image (AMI) to an Amazon S3 bucket. If the SysOps administrator restores the AMI from the bucket in the future, the AMI must use the same AMI image ID as the original AMI. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0141"}', '{"tags": null, "topic": null, "options": [["A", "Create a copy of the AMI. Specify the destination S3 bucket. Set the launch permissions to implicit."], ["B", "Archive the snapshot that is associated with the AMI. Specify the S3 bucket as the archive destination."], ["C", "Create a store image task. Specify the image ID and the destination S3 bucket."], ["D", "Use the AWS CLI copy-image command. Specify the image ID and the destination S3 bucket."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0141"}, "reference": null, "difficulty": "medium", "explanation": "Because this is the only AWS-supported solution that allows an AMI to be backed up to Amazon\nS3 and later restored while preserving the original AMI ID. This capability is essential for\nregulatory and compliance requirements where immutable identifiers must be retained.\nAccording to AWS CloudOps documentation for Amazon EC2 AMI lifecycle management, the\nAMI store and restore feature is specifically designed for long-term retention, audit, and\ncompliance scenarios. When an AMI is stored using a store image task, AWS packages the\nAMI''s configuration, metadata, and associated snapshots and saves them as encrypted objects in\nan Amazon S3 bucket. When the AMI is restored, AWS explicitly states that the restored AMI\nretains the same AMI ID as the original image, ensuring continuity for compliance tracking and\noperational dependencies.", "question_text": "To comply with regulations, a SysOps administrator needs to back up an Amazon EC2 Amazon Machine Image (AMI) to an Amazon S3 bucket. If the SysOps administrator restores the AMI from the bucket in the future, the AMI must use the same AMI image ID as the original AMI. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '3aa0747ac1f336a9c41717c79b4de2eb7a086e949c9224e5d7b4ccc64653f05a', 1489, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (976, 146, 143, 'qblock_pdf', '{"option_a": "Enable S3 Transfer Acceleration for the S3 bucket. Create an S3 access point for the bucket. Update the application to use the access point.", "option_b": "Create an S3 Lifecycle configuration for the S3 bucket to move all objects to the S3 Express One Zone storage class. Update the application to use an S3 Regional endpoint.", "option_c": "Create a second general purpose S3 bucket in the same Region. Copy the objects from the original bucket to the new bucket. Use the S3 Express One Zone storage class to store the objects in the new bucket. Update the application to use an S3 Regional endpoint.", "option_d": "Create an S3 directory bucket in the same Availability Zone. Import objects from the original bucket to the new bucket. Use the S3 Express One Zone storage class to store the objects in the new bucket. Update the application to use an S3 Zonal endpoint.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Amazon S3 Express One Zone with directory buckets and zonal endpoints is specifically\ndesigned for single瑼vailability Zone, high-performance workloads such as HPC, machine\nlearning, and analytics applications running on Amazon EC2. AWS CloudOps documentation\nstates that S3 Express One Zone delivers single-digit millisecond latency and up to 10x higher\nrequest performance compared to general purpose S3 buckets when data is accessed from the\nsame Availability Zone.\nAn S3 directory bucket is required to use the S3 Express One Zone storage class. These buckets\nare explicitly associated with a single Availability Zone and use zonal endpoints, which eliminate\ncross-AZ network hops and significantly reduce latency. Importing the data from the existing\ngeneral purpose bucket ensures compatibility while achieving maximum throughput and lowest\nlatency.", "question_text": "A company runs a high performance computing (HPC) data-processing application on Amazon EC2 instances in one Availability Zone within a development environment. The application uses a dataset that the company stores on an Amazon S3 general purpose bucket in the same AWS Region as the EC2 instances. A SysOps administrator must improve the application''s performance for retrieval of objects from Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Amazon S3. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0142"}', '{"tags": null, "topic": null, "options": [["A", "Enable S3 Transfer Acceleration for the S3 bucket. Create an S3 access point for the bucket. Update the application to use the access point."], ["B", "Create an S3 Lifecycle configuration for the S3 bucket to move all objects to the S3 Express One Zone storage class. Update the application to use an S3 Regional endpoint."], ["C", "Create a second general purpose S3 bucket in the same Region. Copy the objects from the original bucket to the new bucket. Use the S3 Express One Zone storage class to store the objects in the new bucket. Update the application to use an S3 Regional endpoint."], ["D", "Create an S3 directory bucket in the same Availability Zone. Import objects from the original bucket to the new bucket. Use the S3 Express One Zone storage class to store the objects in the new bucket. Update the application to use an S3 Zonal endpoint."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0142"}, "reference": null, "difficulty": "medium", "explanation": "Amazon S3 Express One Zone with directory buckets and zonal endpoints is specifically\ndesigned for single瑼vailability Zone, high-performance workloads such as HPC, machine\nlearning, and analytics applications running on Amazon EC2. AWS CloudOps documentation\nstates that S3 Express One Zone delivers single-digit millisecond latency and up to 10x higher\nrequest performance compared to general purpose S3 buckets when data is accessed from the\nsame Availability Zone.\nAn S3 directory bucket is required to use the S3 Express One Zone storage class. These buckets\nare explicitly associated with a single Availability Zone and use zonal endpoints, which eliminate\ncross-AZ network hops and significantly reduce latency. Importing the data from the existing\ngeneral purpose bucket ensures compatibility while achieving maximum throughput and lowest\nlatency.", "question_text": "A company runs a high performance computing (HPC) data-processing application on Amazon EC2 instances in one Availability Zone within a development environment. The application uses a dataset that the company stores on an Amazon S3 general purpose bucket in the same AWS Region as the EC2 instances. A SysOps administrator must improve the application''s performance for retrieval of objects from Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Amazon S3. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'c16e2372c5a0843a4c8caf71aa7f9326b5279244f6b19c5ceb5fd9c3714df017', 1490, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (977, 146, 144, 'qblock_pdf', '{"option_a": "Create AWS KMS symmetric customer managed keys. Enable automatic key rotation.", "option_b": "Use AWS owned AWS KMS keys across the company''s AWS environment.", "option_c": "Create AWS KMS asymmetric customer managed keys. Enable automatic key rotation.", "option_d": "Create AWS KMS symmetric customer managed keys by using imported key material. Rotate the keys on a yearly basis.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS KMS symmetric customer managed keys with automatic key rotation provide encryption,\naccess control, and compliance with minimal operational effort. AWS CloudOps documentation\nstates that Amazon EBS encryption supports AWS KMS symmetric keys only, and customer\nmanaged keys allow administrators to define custom key policies to control access.\nAutomatic key rotation is supported for symmetric customer managed keys and rotates the\nbacking key material once every year, fully satisfying the company''s rotation requirement without\nmanual intervention. This approach minimizes operational overhead while maintaining strong\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nsecurity controls and auditability.", "question_text": "A company has a new security policy that requires all Amazon Elastic Block Store (Amazon EBS) volumes to be encrypted at rest. The company needs to use a custom key policy to manage access to the encryption keys. The company must rotate the keys once each year. Which solution will meet these requirements with the LEAST operational overhead?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0143"}', '{"tags": null, "topic": null, "options": [["A", "Create AWS KMS symmetric customer managed keys. Enable automatic key rotation."], ["B", "Use AWS owned AWS KMS keys across the company''s AWS environment."], ["C", "Create AWS KMS asymmetric customer managed keys. Enable automatic key rotation."], ["D", "Create AWS KMS symmetric customer managed keys by using imported key material. Rotate the keys on a yearly basis."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0143"}, "reference": null, "difficulty": "medium", "explanation": "AWS KMS symmetric customer managed keys with automatic key rotation provide encryption,\naccess control, and compliance with minimal operational effort. AWS CloudOps documentation\nstates that Amazon EBS encryption supports AWS KMS symmetric keys only, and customer\nmanaged keys allow administrators to define custom key policies to control access.\nAutomatic key rotation is supported for symmetric customer managed keys and rotates the\nbacking key material once every year, fully satisfying the company''s rotation requirement without\nmanual intervention. This approach minimizes operational overhead while maintaining strong\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nsecurity controls and auditability.", "question_text": "A company has a new security policy that requires all Amazon Elastic Block Store (Amazon EBS) volumes to be encrypted at rest. The company needs to use a custom key policy to manage access to the encryption keys. The company must rotate the keys once each year. Which solution will meet these requirements with the LEAST operational overhead?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'fe794ce76d83440c2783d29808fe7167f703050476528387cfe4a583b27a0eaa', 1491, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (978, 146, 145, 'qblock_pdf', '{"option_a": "Create a scheduled scaling action. Configure the action to run at times when the application typically experiences an increase in traffic.", "option_b": "Configure a simple scaling policy. Create an Amazon CloudWatch alarm that enters ALARM state when CPU utilization is greater than 40%. Associate the alarm with the scaling policy.", "option_c": "Configure a step scaling policy. Create an Amazon CloudWatch alarm that enters ALARM state when CPU utilization is greater than 40%. Associate the alarm with the scaling policy.", "option_d": "Configure a target tracking scaling policy. Specify a target value of 40 for average CPU utilization.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Target tracking scaling policies are designed to automatically maintain a specific metric at a\ndesired target value with the least administrative effort. AWS CloudOps documentation states that\ntarget tracking works like a thermostat, continuously adjusting capacity to keep the selected\nmetric close to the defined target.\nBy specifying a target value of 40% average CPU utilization, the Auto Scaling group automatically\nscales out or in based on real-time demand without requiring manual thresholds, multiple alarms,\nor predefined scaling steps. This approach is fully managed by AWS and is the most\noperationally efficient option.", "question_text": "A SysOps administrator is configuring an Auto Scaling group of Amazon EC2 instances for an application. The average CPU utilization of the instances in the Auto Scaling group must remain at approximately 40% when the load on the application changes. Which solution will meet this requirement in the MOST operationally efficient manner?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0144"}', '{"tags": null, "topic": null, "options": [["A", "Create a scheduled scaling action. Configure the action to run at times when the application typically experiences an increase in traffic."], ["B", "Configure a simple scaling policy. Create an Amazon CloudWatch alarm that enters ALARM state when CPU utilization is greater than 40%. Associate the alarm with the scaling policy."], ["C", "Configure a step scaling policy. Create an Amazon CloudWatch alarm that enters ALARM state when CPU utilization is greater than 40%. Associate the alarm with the scaling policy."], ["D", "Configure a target tracking scaling policy. Specify a target value of 40 for average CPU utilization."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0144"}, "reference": null, "difficulty": "medium", "explanation": "Target tracking scaling policies are designed to automatically maintain a specific metric at a\ndesired target value with the least administrative effort. AWS CloudOps documentation states that\ntarget tracking works like a thermostat, continuously adjusting capacity to keep the selected\nmetric close to the defined target.\nBy specifying a target value of 40% average CPU utilization, the Auto Scaling group automatically\nscales out or in based on real-time demand without requiring manual thresholds, multiple alarms,\nor predefined scaling steps. This approach is fully managed by AWS and is the most\noperationally efficient option.", "question_text": "A SysOps administrator is configuring an Auto Scaling group of Amazon EC2 instances for an application. The average CPU utilization of the instances in the Auto Scaling group must remain at approximately 40% when the load on the application changes. Which solution will meet this requirement in the MOST operationally efficient manner?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '6c60eacc99e4bbb67eeb755dd5c096fc3ed92a58f9ac91ce269f9809e70ef839', 1492, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (979, 146, 146, 'qblock_pdf', '{"option_a": "Define targets of the patch policy by specifying node tags that match the company''s tagging strategy.", "option_b": "Configure an AWS Lambda function to scan for new instances and to add the instances to the targets of the patch policy.", "option_c": "Create resource groups. Add the existing instances to the resource groups. Configure an AWS Lambda function to scan for new instances and to add the instances to the resource groups at regular intervals. Attach the resource groups to the patch policy.", "option_d": "Create resource groups. Add the existing instances to the resource groups. Create an Amazon EventBridge rule that uses an appropriately defined filter to add new instances to the resource groups. Attach the resource groups to the patch policy.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nAWS Systems Manager Patch Manager natively supports tag-based targeting, which\nautomatically includes both existing and future instances that match specified tag criteria. AWS\nCloudOps documentation states that patch policies can target managed nodes by instance tags,\nallowing administrators to dynamically scope patching operations without additional automation.\nBy defining the patch policy target as instances with an environment tag value of \"Prod,\" Patch\nManager automatically applies patch baselines to all matching instances. Any new EC2 instance\nlaunched with the same tag is included automatically, requiring no manual intervention or\nadditional services. This approach delivers the least operational overhead while remaining fully\nscalable and compliant.", "question_text": "A company runs applications on Amazon EC2 instances. Many of the instances are not patched. The company has a tagging policy. All the instances are tagged with details about the owners, application, and environment. AWS Systems Manager Agent (SSM Agent) is installed on all the instances. A SysOps administrator must implement a solution to automatically patch all existing and future instances that have \"Prod\" in the environment tag. The SysOps administrator plans to create a patch policy in Systems Manager Patch Manager. Which solution will meet the patching requirements with the LEAST operational overhead?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0145"}', '{"tags": null, "topic": null, "options": [["A", "Define targets of the patch policy by specifying node tags that match the company''s tagging strategy."], ["B", "Configure an AWS Lambda function to scan for new instances and to add the instances to the targets of the patch policy."], ["C", "Create resource groups. Add the existing instances to the resource groups. Configure an AWS Lambda function to scan for new instances and to add the instances to the resource groups at regular intervals. Attach the resource groups to the patch policy."], ["D", "Create resource groups. Add the existing instances to the resource groups. Create an Amazon EventBridge rule that uses an appropriately defined filter to add new instances to the resource groups. Attach the resource groups to the patch policy."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0145"}, "reference": null, "difficulty": "medium", "explanation": "Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nAWS Systems Manager Patch Manager natively supports tag-based targeting, which\nautomatically includes both existing and future instances that match specified tag criteria. AWS\nCloudOps documentation states that patch policies can target managed nodes by instance tags,\nallowing administrators to dynamically scope patching operations without additional automation.\nBy defining the patch policy target as instances with an environment tag value of \"Prod,\" Patch\nManager automatically applies patch baselines to all matching instances. Any new EC2 instance\nlaunched with the same tag is included automatically, requiring no manual intervention or\nadditional services. This approach delivers the least operational overhead while remaining fully\nscalable and compliant.", "question_text": "A company runs applications on Amazon EC2 instances. Many of the instances are not patched. The company has a tagging policy. All the instances are tagged with details about the owners, application, and environment. AWS Systems Manager Agent (SSM Agent) is installed on all the instances. A SysOps administrator must implement a solution to automatically patch all existing and future instances that have \"Prod\" in the environment tag. The SysOps administrator plans to create a patch policy in Systems Manager Patch Manager. Which solution will meet the patching requirements with the LEAST operational overhead?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '1fb23d81130b9d8fc973bba61f81538b0bbc024a6da5809156d7b7c0a33e79c8', 1493, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (980, 146, 147, 'qblock_pdf', '{"option_a": "Configure an RDS proxy to store the credentials.", "option_b": "Add the credentials to AWS Secrets Manager.", "option_c": "Add the credentials to AWS Systems Manager Parameter Store.", "option_d": "Create an AWS Lambda function to rotate the credentials.", "option_e": "Create an AWS Systems Manager Automation runbook to rotate the credentials.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS CloudOps documentation clearly states that AWS Secrets Manager is the recommended\nservice for storing and managing database credentials securely. Secrets Manager integrates\nnatively with Amazon RDS and supports automatic, scheduled secret rotation.\nTo rotate credentials weekly, Secrets Manager requires a Lambda rotation function. AWS\nprovides managed rotation templates for Amazon RDS for MySQL that update the database\npassword and the stored secret atomically. This combination ensures credentials are protected,\nrotated automatically, and audited with minimal operational effort.", "question_text": "A SysOps administrator needs to implement a solution that protects credentials for an Amazon RDS for MySQL DB instance. The solution must rotate the credentials automatically one time every week. Which combination of steps will meet these requirements? (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "BD", "external_question_id": "Q0146"}', '{"tags": null, "topic": null, "options": [["A", "Configure an RDS proxy to store the credentials."], ["B", "Add the credentials to AWS Secrets Manager."], ["C", "Add the credentials to AWS Systems Manager Parameter Store."], ["D", "Create an AWS Lambda function to rotate the credentials."], ["E", "Create an AWS Systems Manager Automation runbook to rotate the credentials."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0146"}, "reference": null, "difficulty": "medium", "explanation": "AWS CloudOps documentation clearly states that AWS Secrets Manager is the recommended\nservice for storing and managing database credentials securely. Secrets Manager integrates\nnatively with Amazon RDS and supports automatic, scheduled secret rotation.\nTo rotate credentials weekly, Secrets Manager requires a Lambda rotation function. AWS\nprovides managed rotation templates for Amazon RDS for MySQL that update the database\npassword and the stored secret atomically. This combination ensures credentials are protected,\nrotated automatically, and audited with minimal operational effort.", "question_text": "A SysOps administrator needs to implement a solution that protects credentials for an Amazon RDS for MySQL DB instance. The solution must rotate the credentials automatically one time every week. Which combination of steps will meet these requirements? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'imported', NULL, NULL, '5a2f9ad5f9e77381b955a763f075766884434c2a38929142441115055aba8264', 1494, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (981, 146, 148, 'qblock_pdf', '{"option_a": "In the member account, add sts:AssumeRole permissions to the role''s policy. In the identity account, add a trust policy to the group that specifies the account number of the member account.", "option_b": "In the member account, add the group Amazon Resource Name (ARN) to the role''s trust policy. In the identity account, add an inline policy to the group with sts:AssumeRole permissions.", "option_c": "In the member account, add the group Amazon Resource Name (ARN) to the role''s trust policy. In the identity account, add an inline policy to the group with sts:PassRole permissions.", "option_d": "In the member account, add the group Amazon Resource Name (ARN) to the role''s inline policy. In Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com the identity account, add a trust policy to the group with sts:AssumeRole permissions.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Cross-account role assumption requires two explicit permissions. AWS CloudOps documentation\nstates that the target role must trust the principal, and the principal must be allowed to call\nsts:AssumeRole.\nIn the member account, the role''s trust policy must list the IAM group ARN (or the identity\naccount) as a trusted principal. In the identity account, the IAM group must have an inline or\nattached policy that allows the sts:AssumeRole action for the target role ARN. This dual\nconfiguration enables secure and controlled cross-account access.", "question_text": "A company has a multi-account AWS environment that includes the following: - A central identity account that contains all IAM users and groups - Several member accounts that contain IAM roles A SysOps administrator must grant permissions for a particular IAM group to assume a role in one of the member accounts. How should the SysOps administrator accomplish this task?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0147"}', '{"tags": null, "topic": null, "options": [["A", "In the member account, add sts:AssumeRole permissions to the role''s policy. In the identity account, add a trust policy to the group that specifies the account number of the member account."], ["B", "In the member account, add the group Amazon Resource Name (ARN) to the role''s trust policy. In the identity account, add an inline policy to the group with sts:AssumeRole permissions."], ["C", "In the member account, add the group Amazon Resource Name (ARN) to the role''s trust policy. In the identity account, add an inline policy to the group with sts:PassRole permissions."], ["D", "In the member account, add the group Amazon Resource Name (ARN) to the role''s inline policy. In Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com the identity account, add a trust policy to the group with sts:AssumeRole permissions."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0147"}, "reference": null, "difficulty": "medium", "explanation": "Cross-account role assumption requires two explicit permissions. AWS CloudOps documentation\nstates that the target role must trust the principal, and the principal must be allowed to call\nsts:AssumeRole.\nIn the member account, the role''s trust policy must list the IAM group ARN (or the identity\naccount) as a trusted principal. In the identity account, the IAM group must have an inline or\nattached policy that allows the sts:AssumeRole action for the target role ARN. This dual\nconfiguration enables secure and controlled cross-account access.", "question_text": "A company has a multi-account AWS environment that includes the following: - A central identity account that contains all IAM users and groups - Several member accounts that contain IAM roles A SysOps administrator must grant permissions for a particular IAM group to assume a role in one of the member accounts. How should the SysOps administrator accomplish this task?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'e89b5268d84c2235ed86324a583c9acc40e870de2f5035b0a1d7a6e28f953f07', 1495, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (982, 146, 149, 'qblock_pdf', '{"option_a": "Reduce the maximum TTL and default TTL of the CloudFront distribution behavior to 0.", "option_b": "Add a final step in the deployment process to invalidate all files in the CloudFront distribution.", "option_c": "Add a final step in the deployment process to invalidate only the changed JavaScript files in the CloudFront distribution.", "option_d": "Remove CloudFront from the path of serving JavaScript files. Serve the JavaScript files directly through the ALB.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Selective CloudFront invalidation ensures that only updated JavaScript files are refreshed across\nedge locations. AWS CloudOps documentation explains that invalidations remove cached objects\nso that CloudFront fetches the latest version from the origin on the next request.\nInvalidating only changed files minimizes cost, reduces operational impact, and avoids\nunnecessary origin requests. This approach ensures users always receive the latest application\nassets without degrading backend performance.", "question_text": "A company is performing deployments of an application at regular intervals. Users report that the application sometimes does not work properly. The company discovers that some users'' browsers are fetching previous versions of the JavaScript files. The application runs on Amazon EC2 instances behind an Application Load Balancer (ALB). The ALB is the origin for an Amazon CloudFront distribution. A SysOps administrator must implement a solution to ensure that CloudFront serves the latest version of the JavaScript files. The solution must not affect application server performance. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0148"}', '{"tags": null, "topic": null, "options": [["A", "Reduce the maximum TTL and default TTL of the CloudFront distribution behavior to 0."], ["B", "Add a final step in the deployment process to invalidate all files in the CloudFront distribution."], ["C", "Add a final step in the deployment process to invalidate only the changed JavaScript files in the CloudFront distribution."], ["D", "Remove CloudFront from the path of serving JavaScript files. Serve the JavaScript files directly through the ALB."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0148"}, "reference": null, "difficulty": "medium", "explanation": "Selective CloudFront invalidation ensures that only updated JavaScript files are refreshed across\nedge locations. AWS CloudOps documentation explains that invalidations remove cached objects\nso that CloudFront fetches the latest version from the origin on the next request.\nInvalidating only changed files minimizes cost, reduces operational impact, and avoids\nunnecessary origin requests. This approach ensures users always receive the latest application\nassets without degrading backend performance.", "question_text": "A company is performing deployments of an application at regular intervals. Users report that the application sometimes does not work properly. The company discovers that some users'' browsers are fetching previous versions of the JavaScript files. The application runs on Amazon EC2 instances behind an Application Load Balancer (ALB). The ALB is the origin for an Amazon CloudFront distribution. A SysOps administrator must implement a solution to ensure that CloudFront serves the latest version of the JavaScript files. The solution must not affect application server performance. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '9501dd0bf79cbd886d4cb62acad30182d1f2100ed62330d1152bec96ac3e5882', 1496, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (983, 146, 150, 'qblock_pdf', '{"option_a": "Use Amazon CloudWatch Logs to collect message content from Amazon SNS and Amazon SQS. Deliver logs to an Amazon S3 bucket for querying.", "option_b": "Set up AWS CloudTrail. Enable tracking of data events for Amazon SNS and Amazon SQS. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Deliver logs to an Amazon S3 bucket for querying.", "option_c": "Create Amazon EventBridge rules to gather Amazon SNS and Amazon SQS events. Store the events in an Amazon S3 bucket.", "option_d": "Configure VPC endpoints for Amazon SNS and Amazon SQS. Inspect the vpcEndpointId field in the AWS CloudTrail logs.", "option_e": "Configure VPC endpoints for Amazon SNS and Amazon SQS. Inspect the vpcEndpoint field in the Amazon CloudWatch logs.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "To meet the requirement to log and audit any principal that publishes to SNS topics and interacts\nwith SQS queues, the correct service is AWS CloudTrail, because CloudTrail records API activity\n(who did what, when, and from where). Enabling data events (where supported/required for\ndeeper visibility) provides detailed records for operations such as publishing messages and\nsending/receiving messages. Delivering CloudTrail logs to Amazon S3 provides durable retention\nand supports querying workflows.\nTo ensure that communication uses VPC endpoints, the company should configure VPC\nendpoints for SNS and SQS and then validate usage by inspecting CloudTrail event records.\nCloudTrail includes endpoint-related context fields (for example, a VPC endpoint identifier) that\nallow auditors to confirm that the request path used a VPC endpoint rather than traversing the\npublic internet. This directly addresses the \"must use VPC endpoints\" control with auditable\nevidence.", "question_text": "A company needs to log and audit any principal that publishes messages to Amazon Simple Notification Service (Amazon SNS) topics and Amazon Simple Queue Service (Amazon SQS) queues. The company wants to ensure that all communication with these services uses VPC endpoints. Which combination of solutions will meet these requirements? (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "BD", "external_question_id": "Q0149"}', '{"tags": null, "topic": null, "options": [["A", "Use Amazon CloudWatch Logs to collect message content from Amazon SNS and Amazon SQS. Deliver logs to an Amazon S3 bucket for querying."], ["B", "Set up AWS CloudTrail. Enable tracking of data events for Amazon SNS and Amazon SQS. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Deliver logs to an Amazon S3 bucket for querying."], ["C", "Create Amazon EventBridge rules to gather Amazon SNS and Amazon SQS events. Store the events in an Amazon S3 bucket."], ["D", "Configure VPC endpoints for Amazon SNS and Amazon SQS. Inspect the vpcEndpointId field in the AWS CloudTrail logs."], ["E", "Configure VPC endpoints for Amazon SNS and Amazon SQS. Inspect the vpcEndpoint field in the Amazon CloudWatch logs."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0149"}, "reference": null, "difficulty": "medium", "explanation": "To meet the requirement to log and audit any principal that publishes to SNS topics and interacts\nwith SQS queues, the correct service is AWS CloudTrail, because CloudTrail records API activity\n(who did what, when, and from where). Enabling data events (where supported/required for\ndeeper visibility) provides detailed records for operations such as publishing messages and\nsending/receiving messages. Delivering CloudTrail logs to Amazon S3 provides durable retention\nand supports querying workflows.\nTo ensure that communication uses VPC endpoints, the company should configure VPC\nendpoints for SNS and SQS and then validate usage by inspecting CloudTrail event records.\nCloudTrail includes endpoint-related context fields (for example, a VPC endpoint identifier) that\nallow auditors to confirm that the request path used a VPC endpoint rather than traversing the\npublic internet. This directly addresses the \"must use VPC endpoints\" control with auditable\nevidence.", "question_text": "A company needs to log and audit any principal that publishes messages to Amazon Simple Notification Service (Amazon SNS) topics and Amazon Simple Queue Service (Amazon SQS) queues. The company wants to ensure that all communication with these services uses VPC endpoints. Which combination of solutions will meet these requirements? (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'imported', NULL, NULL, '3cc70fc77bcbab92891d0280f34f72ad2c92a353f41c7a32435284558fcd0f67', 1497, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (984, 146, 151, 'qblock_pdf', '{"option_a": "Implement a Route 53 health check and a failover routing policy for the hosted zone. Configure the failover routing policy to automatically redirect traffic to the resources in us-west-2.", "option_b": "Implement a Route 53 health check and a latency routing policy for the hosted zone. Configure the latency routing policy to automatically redirect traffic to the resources in us-west-2.", "option_c": "In us-east-1, create an Amazon CloudWatch alarm that enters ALARM state when an EC2 instance is terminated. In us-west-2, create an AWS Lambda function that modifies the Route 53 hosted zone records to send traffic to us-west-2. Configure the CloudWatch alarm to invoke the Lambda function.", "option_d": "In us-west-2, create an Amazon CloudWatch alarm that enters ALARM state when resources in us- east-1 cannot be resolved. In us-west-2, create an AWS Lambda function that modifies the Route 53 hosted zone records to send traffic to us-west-2. Configure the CloudWatch alarm to invoke the Lambda function.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The requirement is classic active-passive (production in us-east-1, DR in us-west-2 \"only for\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nfailover\"). The most operationally efficient and purpose-built solution is Route 53 failover routing\ncombined with health checks. With failover routing, Route 53 designates one record as PRIMARY\n(us- east-1) and another as SECONDARY (us-west-2). Route 53 continuously evaluates the\nhealth check associated with the primary endpoint (commonly the ALB DNS name or a specific\nhealth-check path). If the primary fails, Route 53 automatically returns the secondary record,\ndirecting client DNS resolution to the DR region. This ensures us-west-2 is used only when us-\neast-1 is unhealthy, directly matching the requirement.", "question_text": "A web application runs on Amazon EC2 instances in the us-east-1 Region and the us-west-2 Region. The instances run behind an Application Load Balancer (ALB) in each Region. An Amazon Route 53 hosted zone controls DNS records. The instances in us-east-1 are production resources. The instances in us-west-2 are for disaster recovery. EC2 Auto Scaling groups are configured based on the ALBRequestCountPerTarget metric in both Regions. A SysOps administrator must implement a solution that provides failover from us-east-1 to us- west-2. The instances in us-west-2 must be used only for failover. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0150"}', '{"tags": null, "topic": null, "options": [["A", "Implement a Route 53 health check and a failover routing policy for the hosted zone. Configure the failover routing policy to automatically redirect traffic to the resources in us-west-2."], ["B", "Implement a Route 53 health check and a latency routing policy for the hosted zone. Configure the latency routing policy to automatically redirect traffic to the resources in us-west-2."], ["C", "In us-east-1, create an Amazon CloudWatch alarm that enters ALARM state when an EC2 instance is terminated. In us-west-2, create an AWS Lambda function that modifies the Route 53 hosted zone records to send traffic to us-west-2. Configure the CloudWatch alarm to invoke the Lambda function."], ["D", "In us-west-2, create an Amazon CloudWatch alarm that enters ALARM state when resources in us- east-1 cannot be resolved. In us-west-2, create an AWS Lambda function that modifies the Route 53 hosted zone records to send traffic to us-west-2. Configure the CloudWatch alarm to invoke the Lambda function."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0150"}, "reference": null, "difficulty": "medium", "explanation": "The requirement is classic active-passive (production in us-east-1, DR in us-west-2 \"only for\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nfailover\"). The most operationally efficient and purpose-built solution is Route 53 failover routing\ncombined with health checks. With failover routing, Route 53 designates one record as PRIMARY\n(us- east-1) and another as SECONDARY (us-west-2). Route 53 continuously evaluates the\nhealth check associated with the primary endpoint (commonly the ALB DNS name or a specific\nhealth-check path). If the primary fails, Route 53 automatically returns the secondary record,\ndirecting client DNS resolution to the DR region. This ensures us-west-2 is used only when us-\neast-1 is unhealthy, directly matching the requirement.", "question_text": "A web application runs on Amazon EC2 instances in the us-east-1 Region and the us-west-2 Region. The instances run behind an Application Load Balancer (ALB) in each Region. An Amazon Route 53 hosted zone controls DNS records. The instances in us-east-1 are production resources. The instances in us-west-2 are for disaster recovery. EC2 Auto Scaling groups are configured based on the ALBRequestCountPerTarget metric in both Regions. A SysOps administrator must implement a solution that provides failover from us-east-1 to us- west-2. The instances in us-west-2 must be used only for failover. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'f03f52ea5af5b8bfc9f21591c2bbeeca3260775187f0f9813bdc30587188bb51', 1498, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (985, 146, 152, 'qblock_pdf', '{"option_a": "Configure VPC sharing between the Lambda VPC and the S3 bucket.", "option_b": "Attach a transit gateway to the Lambda VPC to allow the Lambda function to connect to the S3 bucket.", "option_c": "Create a NAT gateway. Associate the NAT gateway with the subnet where the Lambda function is configured to run.", "option_d": "Create an S3 interface endpoint. Change the Lambda function to use the new S3 DNS name.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The requirement is that traffic from a VPC-connected Lambda to Amazon S3 must not use public\nIP addresses. The AWS-native way to keep traffic private is to use VPC endpoints, which provide\nprivate connectivity to supported AWS services without traversing the public internet. Among the\noptions, creating an S3 VPC endpoint is the only approach that satisfies \"no public IP addresses\"\nwhile allowing access to the bucket. Option D is the best match because it explicitly configures an\nS3 endpoint and directs the Lambda function to use the endpoint-specific DNS name for private\nrouting.", "question_text": "A SysOps administrator needs to give an existing AWS Lambda function access to an existing Amazon S3 bucket. Traffic between the Lambda function and the S3 bucket must not use public IP addresses. The Lambda function has been configured to run in a VPC. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0151"}', '{"tags": null, "topic": null, "options": [["A", "Configure VPC sharing between the Lambda VPC and the S3 bucket."], ["B", "Attach a transit gateway to the Lambda VPC to allow the Lambda function to connect to the S3 bucket."], ["C", "Create a NAT gateway. Associate the NAT gateway with the subnet where the Lambda function is configured to run."], ["D", "Create an S3 interface endpoint. Change the Lambda function to use the new S3 DNS name."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0151"}, "reference": null, "difficulty": "medium", "explanation": "The requirement is that traffic from a VPC-connected Lambda to Amazon S3 must not use public\nIP addresses. The AWS-native way to keep traffic private is to use VPC endpoints, which provide\nprivate connectivity to supported AWS services without traversing the public internet. Among the\noptions, creating an S3 VPC endpoint is the only approach that satisfies \"no public IP addresses\"\nwhile allowing access to the bucket. Option D is the best match because it explicitly configures an\nS3 endpoint and directs the Lambda function to use the endpoint-specific DNS name for private\nrouting.", "question_text": "A SysOps administrator needs to give an existing AWS Lambda function access to an existing Amazon S3 bucket. Traffic between the Lambda function and the S3 bucket must not use public IP addresses. The Lambda function has been configured to run in a VPC. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, 'fce07df76c16b6749da9047af2c148c55130312b9ba8f63d6ed5628c8c7c044a', 1499, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (986, 146, 153, 'qblock_pdf', '{"option_a": "Configure command session logging on each EC2 instance. Configure the unified Amazon CloudWatch agent to send session logs to Amazon CloudWatch Logs. Set up query filters and alerts by using Amazon Athena.", "option_b": "Require all users to use a central bastion host when they need command line access to an EC2 instance. Configure the unified Amazon CloudWatch agent on the bastion host to send session logs to Amazon CloudWatch Logs. Set up a metric filter and a metric alarm for relevant security findings in CloudWatch Logs.", "option_c": "Require all users to use AWS Systems Manager Session Manager when they need command line access to an EC2 instance. Configure Session Manager to stream session logs to Amazon CloudWatch Logs. Set up a metric filter and a metric alarm for relevant security findings in CloudWatch Logs.", "option_d": "Configure command session logging on each EC2 instance. Require all users to use AWS Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Systems Manager Run Command documents when they need command line access to an EC2 instance. Configure the unified Amazon CloudWatch agent to send session logs to Amazon CloudWatch Logs. Set up CloudWatch alarms that are based on Amazon Athena query results.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The most operationally efficient solution is C because AWS Systems Manager Session Manager\nis purpose-built for secure, auditable interactive access to EC2 instances at scale--without\nmanaging bastion hosts or distributing SSH keys. Session Manager can be configured to log\nsession activity, including commands and output, to durable destinations such as Amazon\nCloudWatch Logs (and optionally Amazon S3). This directly satisfies the requirement to record\ninteractive sessions and store logs durably.\nFor automated notifications and alarms, CloudWatch Logs supports metric filters that transform\nmatching log patterns into CloudWatch metrics. Those metrics can then drive CloudWatch alarms\nand notifications (for example, via Amazon SNS). This is a standard CloudOps pattern: centralize\nlogs, derive metrics from security-relevant patterns, and alert automatically.", "question_text": "A company runs thousands of Amazon EC2 instances that are based on the Amazon Linux 2 Amazon Machine Image (AMI). A SysOps administrator must implement a solution to record commands and output from any user that needs an interactive session on one of the EC2 instances. The solution must log the data to a durable storage location. The solution also must provide automated notifications and alarms that are based on the log data. Which solution will meet these requirements with the MOST operational efficiency?", "source_format": "qblock_pdf", "correct_answer": "C", "external_question_id": "Q0152"}', '{"tags": null, "topic": null, "options": [["A", "Configure command session logging on each EC2 instance. Configure the unified Amazon CloudWatch agent to send session logs to Amazon CloudWatch Logs. Set up query filters and alerts by using Amazon Athena."], ["B", "Require all users to use a central bastion host when they need command line access to an EC2 instance. Configure the unified Amazon CloudWatch agent on the bastion host to send session logs to Amazon CloudWatch Logs. Set up a metric filter and a metric alarm for relevant security findings in CloudWatch Logs."], ["C", "Require all users to use AWS Systems Manager Session Manager when they need command line access to an EC2 instance. Configure Session Manager to stream session logs to Amazon CloudWatch Logs. Set up a metric filter and a metric alarm for relevant security findings in CloudWatch Logs."], ["D", "Configure command session logging on each EC2 instance. Require all users to use AWS Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Systems Manager Run Command documents when they need command line access to an EC2 instance. Configure the unified Amazon CloudWatch agent to send session logs to Amazon CloudWatch Logs. Set up CloudWatch alarms that are based on Amazon Athena query results."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0152"}, "reference": null, "difficulty": "medium", "explanation": "The most operationally efficient solution is C because AWS Systems Manager Session Manager\nis purpose-built for secure, auditable interactive access to EC2 instances at scale--without\nmanaging bastion hosts or distributing SSH keys. Session Manager can be configured to log\nsession activity, including commands and output, to durable destinations such as Amazon\nCloudWatch Logs (and optionally Amazon S3). This directly satisfies the requirement to record\ninteractive sessions and store logs durably.\nFor automated notifications and alarms, CloudWatch Logs supports metric filters that transform\nmatching log patterns into CloudWatch metrics. Those metrics can then drive CloudWatch alarms\nand notifications (for example, via Amazon SNS). This is a standard CloudOps pattern: centralize\nlogs, derive metrics from security-relevant patterns, and alert automatically.", "question_text": "A company runs thousands of Amazon EC2 instances that are based on the Amazon Linux 2 Amazon Machine Image (AMI). A SysOps administrator must implement a solution to record commands and output from any user that needs an interactive session on one of the EC2 instances. The solution must log the data to a durable storage location. The solution also must provide automated notifications and alarms that are based on the log data. Which solution will meet these requirements with the MOST operational efficiency?", "question_type": "single", "correct_answer": ["C"]}', 'imported', NULL, NULL, '20b71c1b951dce6c18bc08f41597be165e4c5ca7a24cfeeb6e1c4fa16b27319a', 1500, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (987, 146, 154, 'qblock_pdf', '{"option_a": "Copy the AMI to each Region by using the aws ec2 copy-image command. Update the CloudFormation template to include mappings for the copied AMIs.", "option_b": "Create a snapshot of the running instance. Copy the snapshot to the other Regions. Create an AMI from the snapshots. Update the CloudFormation template for each Region to use the new AMI.", "option_c": "Run the existing CloudFormation template in each additional Region based on the success of the template that is used currently in us-east-1.", "option_d": "Update the CloudFormation template to include the additional Regions in the Auto Scaling group. Update the existing stack in us-east-1.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Copy the AMI to each target Region using copy-image and update the CloudFormation template\nto reference the correct AMI IDs per Region (commonly via Mappings or parameters). AMIs are\nregional resources, so an AMI built in us-east-1 cannot be launched directly in other Regions\nwithout copying. The copy-image operation is the standard, supported method to replicate an AMI\nacross Regions while preserving the image configuration and backing snapshots in the\ndestination Region.\nOnce AMIs exist in each Region, CloudFormation can be executed in each Region using the\nsame template logic. Adding mappings for AMI IDs keeps the deployment consistent and\nrepeatable, aligning with Infrastructure as Code practices and minimizing manual steps.", "question_text": "A company asks a SysOps administrator to provision an additional environment for an application in four additional AWS Regions. The application is running on more than 100 Amazon EC2 instances in the us-east-1 Region, using fully configured Amazon Machine Images (AMIs). The company has an AWS CloudFormation template to deploy resources in us-east-1. What should the SysOps administrator do to provision the application in the MOST operationally efficient manner?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0153"}', '{"tags": null, "topic": null, "options": [["A", "Copy the AMI to each Region by using the aws ec2 copy-image command. Update the CloudFormation template to include mappings for the copied AMIs."], ["B", "Create a snapshot of the running instance. Copy the snapshot to the other Regions. Create an AMI from the snapshots. Update the CloudFormation template for each Region to use the new AMI."], ["C", "Run the existing CloudFormation template in each additional Region based on the success of the template that is used currently in us-east-1."], ["D", "Update the CloudFormation template to include the additional Regions in the Auto Scaling group. Update the existing stack in us-east-1."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0153"}, "reference": null, "difficulty": "medium", "explanation": "Copy the AMI to each target Region using copy-image and update the CloudFormation template\nto reference the correct AMI IDs per Region (commonly via Mappings or parameters). AMIs are\nregional resources, so an AMI built in us-east-1 cannot be launched directly in other Regions\nwithout copying. The copy-image operation is the standard, supported method to replicate an AMI\nacross Regions while preserving the image configuration and backing snapshots in the\ndestination Region.\nOnce AMIs exist in each Region, CloudFormation can be executed in each Region using the\nsame template logic. Adding mappings for AMI IDs keeps the deployment consistent and\nrepeatable, aligning with Infrastructure as Code practices and minimizing manual steps.", "question_text": "A company asks a SysOps administrator to provision an additional environment for an application in four additional AWS Regions. The application is running on more than 100 Amazon EC2 instances in the us-east-1 Region, using fully configured Amazon Machine Images (AMIs). The company has an AWS CloudFormation template to deploy resources in us-east-1. What should the SysOps administrator do to provision the application in the MOST operationally efficient manner?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '8126b405cf16679940405244bfd97c3da489f2c702afb390813017f5cfa5a5d2', 1501, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (988, 146, 155, 'qblock_pdf', '{"option_a": "Configure CloudFront to send the X-Forwarded-For header to the origin and to redirect video requests to Amazon S3 instead of the ALB.", "option_b": "Configure a new CloudFront cache behavior to route to Amazon S3 as a new origin, based on matching a URL path pattern.", "option_c": "Configure URL signing in the CloudFront distribution by using a custom policy. Ensure that video files are accessed through signed URLs only.", "option_d": "Configure a CloudFront origin group. Specify the required HTTP status codes to direct connection attempts to a secondary origin.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "To ensure video files are cached at CloudFront edge locations after migrating the files to Amazon\nS3, CloudFront must be able to fetch those video objects directly from S3 as an origin. The most\noperationally straightforward pattern is to add S3 as a second origin and create a separate cache\nbehavior that routes requests for video paths (for example, /video/* or /*.mp4) to the S3 origin.\nWith this configuration, CloudFront caches the S3-served objects at edge locations according to\nthe cache policy/headers, while the existing ALB origin continues serving dynamic application\npaths. This isolates static media delivery from the application tier and improves performance by\nmaximizing cache hits at the edge.", "question_text": "A company has created a new video-on-demand (VOD) application. The application runs on a fleet of Amazon EC2 instances behind an Application Load Balancer (ALB). The company Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com configured an Amazon CloudFront distribution and set the ALB as the origin. Because of increasing application demand, the company wants to move all video files to a central Amazon S3 bucket. A SysOps administrator needs to ensure that video files can be cached at edge locations after the company migrates the files to Amazon S3. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0154"}', '{"tags": null, "topic": null, "options": [["A", "Configure CloudFront to send the X-Forwarded-For header to the origin and to redirect video requests to Amazon S3 instead of the ALB."], ["B", "Configure a new CloudFront cache behavior to route to Amazon S3 as a new origin, based on matching a URL path pattern."], ["C", "Configure URL signing in the CloudFront distribution by using a custom policy. Ensure that video files are accessed through signed URLs only."], ["D", "Configure a CloudFront origin group. Specify the required HTTP status codes to direct connection attempts to a secondary origin."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0154"}, "reference": null, "difficulty": "medium", "explanation": "To ensure video files are cached at CloudFront edge locations after migrating the files to Amazon\nS3, CloudFront must be able to fetch those video objects directly from S3 as an origin. The most\noperationally straightforward pattern is to add S3 as a second origin and create a separate cache\nbehavior that routes requests for video paths (for example, /video/* or /*.mp4) to the S3 origin.\nWith this configuration, CloudFront caches the S3-served objects at edge locations according to\nthe cache policy/headers, while the existing ALB origin continues serving dynamic application\npaths. This isolates static media delivery from the application tier and improves performance by\nmaximizing cache hits at the edge.", "question_text": "A company has created a new video-on-demand (VOD) application. The application runs on a fleet of Amazon EC2 instances behind an Application Load Balancer (ALB). The company Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com configured an Amazon CloudFront distribution and set the ALB as the origin. Because of increasing application demand, the company wants to move all video files to a central Amazon S3 bucket. A SysOps administrator needs to ensure that video files can be cached at edge locations after the company migrates the files to Amazon S3. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'd0b9ca0b29702ea85e3c35d9ea8e8ee44471025f944def3b77d703968be4a338', 1502, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (989, 146, 156, 'qblock_pdf', '{"option_a": "Create an S3 access point in eu-west-2 to use as the destination for S3 replication from ap- southeast-2. Ensure all users switch to the new S3 access point.", "option_b": "Create an Amazon Route 53 hosted zone with a geolocation routing policy. Choose the Alias to S3 website endpoint option. Specify the S3 bucket that is in ap-southeast-2 as the source bucket.", "option_c": "Create a new S3 bucket in eu-west-2. Copy all contents from ap-southeast-2 to the new bucket in eu-west-2. Create an S3 access point, and associate it with both buckets. Ensure users use the new S3 access point.", "option_d": "Configure and activate S3 Transfer Acceleration on the S3 bucket. Use the new S3 acceleration endpoint''s domain name for access.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "For users in eu-west-2 transferring large files to/from an S3 bucket in ap-southeast-2 over the\npublic internet, S3 Transfer Acceleration is designed to improve performance by leveraging the\nAWS global edge network. With Transfer Acceleration enabled, users access the bucket via the\nacceleration endpoint. Requests enter AWS at the nearest edge location and then traverse the\nAWS backbone network to the bucket''s Region, which typically reduces latency variability and\ncan improve throughput for long-distance transfers.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A company hosts an encrypted Amazon S3 bucket in the ap-southeast-2 Region. Users from the eu- west-2 Region access the S3 bucket through the internet. The users from eu-west-2 need faster transfers to and from the S3 bucket for large files. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0155"}', '{"tags": null, "topic": null, "options": [["A", "Create an S3 access point in eu-west-2 to use as the destination for S3 replication from ap- southeast-2. Ensure all users switch to the new S3 access point."], ["B", "Create an Amazon Route 53 hosted zone with a geolocation routing policy. Choose the Alias to S3 website endpoint option. Specify the S3 bucket that is in ap-southeast-2 as the source bucket."], ["C", "Create a new S3 bucket in eu-west-2. Copy all contents from ap-southeast-2 to the new bucket in eu-west-2. Create an S3 access point, and associate it with both buckets. Ensure users use the new S3 access point."], ["D", "Configure and activate S3 Transfer Acceleration on the S3 bucket. Use the new S3 acceleration endpoint''s domain name for access."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0155"}, "reference": null, "difficulty": "medium", "explanation": "For users in eu-west-2 transferring large files to/from an S3 bucket in ap-southeast-2 over the\npublic internet, S3 Transfer Acceleration is designed to improve performance by leveraging the\nAWS global edge network. With Transfer Acceleration enabled, users access the bucket via the\nacceleration endpoint. Requests enter AWS at the nearest edge location and then traverse the\nAWS backbone network to the bucket''s Region, which typically reduces latency variability and\ncan improve throughput for long-distance transfers.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A company hosts an encrypted Amazon S3 bucket in the ap-southeast-2 Region. Users from the eu- west-2 Region access the S3 bucket through the internet. The users from eu-west-2 need faster transfers to and from the S3 bucket for large files. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '66bbe488a8a9f7b7f91fd5aefb80e326d453cea7345730f70a013c9e4b834d34', 1503, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (990, 146, 157, 'qblock_pdf', '{"option_a": "Use Amazon EFS replication to create a new file system. Copy the data and metadata from the existing file system to the new file system. Specify the KMS customer managed key in the replication configuration. When the replication process finishes, fail over to the new encrypted file system.", "option_b": "Directly modify the file system to use encryption. Specify the KMS customer managed key.", "option_c": "Use Amazon EFS replication to create a new file system. Copy the data and metadata from the existing file system to the new file system. Generate a new TLS certificate. Specify the TLS certificate in the replication configuration. When the replication process finishes, fail over to the new encrypted file system.", "option_d": "Create a new EFS file system that is encrypted with the KMS customer managed key. Create an Amazon EC2 instance to copy the files. Mount the encrypted file system and unencrypted file system on the instance. Copy all data from the unencrypted file system to the encrypted file system. Unmount the unencrypted file system and remove the temporary instance.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Amazon EFS encryption at rest is a file system creation attribute; an unencrypted EFS file system\ncannot be \"turned on\" for encryption in place. Therefore, meeting the requirement (\"encrypt an\nexisting EFS using an existing KMS customer managed key\") requires creating a new encrypted\nfile system and migrating data.\nOption A is the most operationally efficient because EFS replication is a managed mechanism\nthat continuously copies data and metadata from a source file system to a destination file system.\nBy specifying the existing KMS customer managed key for the destination, the new file system is\nencrypted at rest under the required key. After replication has caught up, the administrator can\nperform a controlled cutover (failover) so applications mount the encrypted destination instead of\nthe original source. This reduces manual copying effort, supports ongoing synchronization during\nmigration, and simplifies the cutover window.", "question_text": "A SysOps administrator needs to encrypt an existing Amazon Elastic File System (Amazon EFS) file system by using an existing AWS KMS customer managed key. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0156"}', '{"tags": null, "topic": null, "options": [["A", "Use Amazon EFS replication to create a new file system. Copy the data and metadata from the existing file system to the new file system. Specify the KMS customer managed key in the replication configuration. When the replication process finishes, fail over to the new encrypted file system."], ["B", "Directly modify the file system to use encryption. Specify the KMS customer managed key."], ["C", "Use Amazon EFS replication to create a new file system. Copy the data and metadata from the existing file system to the new file system. Generate a new TLS certificate. Specify the TLS certificate in the replication configuration. When the replication process finishes, fail over to the new encrypted file system."], ["D", "Create a new EFS file system that is encrypted with the KMS customer managed key. Create an Amazon EC2 instance to copy the files. Mount the encrypted file system and unencrypted file system on the instance. Copy all data from the unencrypted file system to the encrypted file system. Unmount the unencrypted file system and remove the temporary instance."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0156"}, "reference": null, "difficulty": "medium", "explanation": "Amazon EFS encryption at rest is a file system creation attribute; an unencrypted EFS file system\ncannot be \"turned on\" for encryption in place. Therefore, meeting the requirement (\"encrypt an\nexisting EFS using an existing KMS customer managed key\") requires creating a new encrypted\nfile system and migrating data.\nOption A is the most operationally efficient because EFS replication is a managed mechanism\nthat continuously copies data and metadata from a source file system to a destination file system.\nBy specifying the existing KMS customer managed key for the destination, the new file system is\nencrypted at rest under the required key. After replication has caught up, the administrator can\nperform a controlled cutover (failover) so applications mount the encrypted destination instead of\nthe original source. This reduces manual copying effort, supports ongoing synchronization during\nmigration, and simplifies the cutover window.", "question_text": "A SysOps administrator needs to encrypt an existing Amazon Elastic File System (Amazon EFS) file system by using an existing AWS KMS customer managed key. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '495a69912e10226a1c92373bf9f3bd81fd9af4ce164106e2df296ca6948eec21', 1504, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (991, 146, 158, 'qblock_pdf', '{"option_a": "Add a Cache-Control header field with max-age=0 to the S3 object.", "option_b": "Change the CloudFront cache policy to Managed-CachingOptimized.", "option_c": "Disable bucket versioning in the S3 bucket configuration.", "option_d": "Enable content compression in the CloudFront configuration.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nWith the Managed-CachingDisabled policy, CloudFront is configured to minimize edge caching,\nso the remaining caching behavior users experience often comes from browser (client-side)\ncaching. If users refresh and still see old content, it typically indicates the browser is allowed to\nreuse a cached copy without revalidating. The correct fix is to control client caching using HTTP\nresponse headers on the S3 object.\nAdding a Cache-Control: max-age=0 header instructs browsers that the object becomes stale\nimmediately and should be revalidated on subsequent requests (often resulting in conditional\nrequests using If-Modified-Since or ETag behavior). This preserves correctness--users will fetch\nor revalidate the latest file--without requiring heavier operational actions like frequent CloudFront\ninvalidations or changing to an optimized caching policy that may increase edge caching.", "question_text": "A company hosts a static website on Amazon S3. An Amazon CloudFront distribution presents this site to global users. The company uses the Managed-CachingDisabled CloudFront cache policy. The company''s developers confirm that they frequently update a file in Amazon S3 with new information. Users report that the website presents correct information when the website first loads the file. However, the users'' browsers do not retrieve the updated file after a refresh. What should a SysOps administrator recommend to fix this issue?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0157"}', '{"tags": null, "topic": null, "options": [["A", "Add a Cache-Control header field with max-age=0 to the S3 object."], ["B", "Change the CloudFront cache policy to Managed-CachingOptimized."], ["C", "Disable bucket versioning in the S3 bucket configuration."], ["D", "Enable content compression in the CloudFront configuration."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0157"}, "reference": null, "difficulty": "medium", "explanation": "Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nWith the Managed-CachingDisabled policy, CloudFront is configured to minimize edge caching,\nso the remaining caching behavior users experience often comes from browser (client-side)\ncaching. If users refresh and still see old content, it typically indicates the browser is allowed to\nreuse a cached copy without revalidating. The correct fix is to control client caching using HTTP\nresponse headers on the S3 object.\nAdding a Cache-Control: max-age=0 header instructs browsers that the object becomes stale\nimmediately and should be revalidated on subsequent requests (often resulting in conditional\nrequests using If-Modified-Since or ETag behavior). This preserves correctness--users will fetch\nor revalidate the latest file--without requiring heavier operational actions like frequent CloudFront\ninvalidations or changing to an optimized caching policy that may increase edge caching.", "question_text": "A company hosts a static website on Amazon S3. An Amazon CloudFront distribution presents this site to global users. The company uses the Managed-CachingDisabled CloudFront cache policy. The company''s developers confirm that they frequently update a file in Amazon S3 with new information. Users report that the website presents correct information when the website first loads the file. However, the users'' browsers do not retrieve the updated file after a refresh. What should a SysOps administrator recommend to fix this issue?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'f7417c42941e0c3e9f7ff4d2e6ac6db0330e826a8212eb8f653105f384202eba', 1505, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (992, 146, 159, 'qblock_pdf', '{"option_a": "Configure an Amazon CloudWatch alarm that invokes an AWS Systems Manager Automation runbook to vertically scale the EC2 instance when the CPU utilization exceeds 80%.", "option_b": "Configure an AWS Systems Manager Automation runbook to run a script that automatically restarts the application when CPU utilization exceeds 80%.", "option_c": "Configure an Amazon EventBridge rule that invokes an AWS Systems Manager Automation document. Configure the document to increase the EC2 instance size when CPU utilization exceeds 80%.", "option_d": "Set up an Auto Scaling group with an Amazon CloudWatch alarm that triggers a scaling policy to launch additional EC2 instances when the CPU utilization exceeds 80%.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The requirement is to fix performance degradation from predictable peak CPU load without\nservice disruptions. The most reliable and operationally standard approach is horizontal scaling\nwith an Auto Scaling group driven by CloudWatch metrics/alarms (or target tracking). Launching\nadditional instances and distributing traffic (typically behind a load balancer) increases capacity\nwhile keeping existing instances serving requests--no reboot or stop/start required.\nOption D meets the requirement because Auto Scaling can add capacity when CPU exceeds a\nthreshold and remove capacity when demand falls. This improves performance during peak\nperiods and maintains availability. It is also operationally efficient: scaling actions are automated,\nconsistent, and can be tuned with cooldowns/health checks.", "question_text": "A SysOps administrator monitors and maintains the availability of resources in an AWS environment. The SysOps administrator notices that the CPU utilization of an Amazon EC2 instance that runs web server software peaks above 80% at various times during each day. The CPU spikes correlate with peak daily loads. The high CPU load has resulted in performance issues for customers. The SysOps administrator needs to resolve the system performance issue without causing any service disruptions. Which solution will meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0158"}', '{"tags": null, "topic": null, "options": [["A", "Configure an Amazon CloudWatch alarm that invokes an AWS Systems Manager Automation runbook to vertically scale the EC2 instance when the CPU utilization exceeds 80%."], ["B", "Configure an AWS Systems Manager Automation runbook to run a script that automatically restarts the application when CPU utilization exceeds 80%."], ["C", "Configure an Amazon EventBridge rule that invokes an AWS Systems Manager Automation document. Configure the document to increase the EC2 instance size when CPU utilization exceeds 80%."], ["D", "Set up an Auto Scaling group with an Amazon CloudWatch alarm that triggers a scaling policy to launch additional EC2 instances when the CPU utilization exceeds 80%."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0158"}, "reference": null, "difficulty": "medium", "explanation": "The requirement is to fix performance degradation from predictable peak CPU load without\nservice disruptions. The most reliable and operationally standard approach is horizontal scaling\nwith an Auto Scaling group driven by CloudWatch metrics/alarms (or target tracking). Launching\nadditional instances and distributing traffic (typically behind a load balancer) increases capacity\nwhile keeping existing instances serving requests--no reboot or stop/start required.\nOption D meets the requirement because Auto Scaling can add capacity when CPU exceeds a\nthreshold and remove capacity when demand falls. This improves performance during peak\nperiods and maintains availability. It is also operationally efficient: scaling actions are automated,\nconsistent, and can be tuned with cooldowns/health checks.", "question_text": "A SysOps administrator monitors and maintains the availability of resources in an AWS environment. The SysOps administrator notices that the CPU utilization of an Amazon EC2 instance that runs web server software peaks above 80% at various times during each day. The CPU spikes correlate with peak daily loads. The high CPU load has resulted in performance issues for customers. The SysOps administrator needs to resolve the system performance issue without causing any service disruptions. Which solution will meet these requirements?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '874957653d919699dd8452b010bc681335d4f0406aa2536a39ddac52981ffe2a', 1506, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (993, 146, 160, 'qblock_pdf', '{"option_a": "Collect Amazon CloudWatch logs for the Lambda function. Create a metric filter to extract the PostRuntimeExtensionsDuration metric from the logs. Create a CloudWatch alarm to publish a notification to the SNS topic when the function runtime exceeds 10 seconds.", "option_b": "Collect Amazon CloudWatch metrics for the Lambda function to extract the function runtime. Create a CloudWatch alarm to publish a notification to the SNS topic when the runtime exceeds 10 seconds.", "option_c": "Configure an Amazon CloudWatch metric filter to capture the runtime of the Lambda function. Set the function''s timeout setting to 10 seconds. Create an SNS subscription to alert the SysOps administrator if the function times out.", "option_d": "Use Amazon CloudWatch Logs Insights to query Lambda logs for the function runtime. Set up a CloudWatch alarm based on the query result. Configure Amazon SNS to send notifications when function runtime exceeds 10 seconds.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "AWS Lambda automatically publishes operational metrics to Amazon CloudWatch, including\nDuration, which represents the time a function invocation takes to run. To alert when processing\ntime exceeds 10 seconds, the most direct and operationally efficient solution is to create a\nCloudWatch alarm on the Lambda Duration metric and configure the alarm action to publish to an\nSNS topic. This meets the monitoring requirement without requiring log parsing or additional\nquery mechanisms.\nOption B fits best because it uses the built-in metric stream for Lambda observability:\nCloudWatch metrics are near real-time, require minimal configuration, and alarms are a standard\nCloudOps practice for proactive notification. The alarm can be configured with the appropriate\nstatistic (for example, Maximum or p99 via metric math where applicable) and a threshold of\n10,000 milliseconds, ensuring the operations team is notified before performance degrades\nfurther.", "question_text": "A company uses an AWS Lambda function to process user uploads to an Amazon S3 bucket. The Lambda function runs in response to Amazon S3 PutObject events. A SysOps administrator needs to set up monitoring for the Lambda function. The SysOps administrator wants to receive a notification through an Amazon Simple Notification Service (Amazon SNS) topic if the function takes more than 10 seconds to process an event. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0159"}', '{"tags": null, "topic": null, "options": [["A", "Collect Amazon CloudWatch logs for the Lambda function. Create a metric filter to extract the PostRuntimeExtensionsDuration metric from the logs. Create a CloudWatch alarm to publish a notification to the SNS topic when the function runtime exceeds 10 seconds."], ["B", "Collect Amazon CloudWatch metrics for the Lambda function to extract the function runtime. Create a CloudWatch alarm to publish a notification to the SNS topic when the runtime exceeds 10 seconds."], ["C", "Configure an Amazon CloudWatch metric filter to capture the runtime of the Lambda function. Set the function''s timeout setting to 10 seconds. Create an SNS subscription to alert the SysOps administrator if the function times out."], ["D", "Use Amazon CloudWatch Logs Insights to query Lambda logs for the function runtime. Set up a CloudWatch alarm based on the query result. Configure Amazon SNS to send notifications when function runtime exceeds 10 seconds."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0159"}, "reference": null, "difficulty": "medium", "explanation": "AWS Lambda automatically publishes operational metrics to Amazon CloudWatch, including\nDuration, which represents the time a function invocation takes to run. To alert when processing\ntime exceeds 10 seconds, the most direct and operationally efficient solution is to create a\nCloudWatch alarm on the Lambda Duration metric and configure the alarm action to publish to an\nSNS topic. This meets the monitoring requirement without requiring log parsing or additional\nquery mechanisms.\nOption B fits best because it uses the built-in metric stream for Lambda observability:\nCloudWatch metrics are near real-time, require minimal configuration, and alarms are a standard\nCloudOps practice for proactive notification. The alarm can be configured with the appropriate\nstatistic (for example, Maximum or p99 via metric math where applicable) and a threshold of\n10,000 milliseconds, ensuring the operations team is notified before performance degrades\nfurther.", "question_text": "A company uses an AWS Lambda function to process user uploads to an Amazon S3 bucket. The Lambda function runs in response to Amazon S3 PutObject events. A SysOps administrator needs to set up monitoring for the Lambda function. The SysOps administrator wants to receive a notification through an Amazon Simple Notification Service (Amazon SNS) topic if the function takes more than 10 seconds to process an event. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '2f6a30b5aba229b373443267f9bcb39c19d42f01d90f62a6a121b6adf6530bc1', 1507, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (994, 146, 161, 'qblock_pdf', '{"option_a": "Send client requests from a single geographic region. Configure the load test so that each client makes an identical DNS request. Focus the client requests on the IP address that the DNS returns.", "option_b": "Send client requests from a single geographic region. Configure the load test so that each client makes an independent DNS request. Spread the client requests across the set of IP addresses that the DNS returns.", "option_c": "Send client requests from multiple geographic regions. Configure the load test so that each client makes an identical DNS request. Focus the client requests on the IP address that the DNS returns.", "option_d": "Send client requests from multiple geographic regions. Configure the load test so that each client makes an independent DNS request. Spread the client requests across the set of IP addresses that the DNS returns.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "CloudFront is a global edge network service, and its performance (latency and data transfer\nbehavior) depends heavily on the geographic location of viewers and the edge locations that\nserve them. Therefore, a valid load test must generate traffic from multiple geographic regions to\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nreflect real user distribution and to measure end-to-end latency across diverse network paths.\nAdditionally, CloudFront uses DNS to return multiple possible edge IP addresses and can direct\nclients to different edge locations based on resolver behavior and network conditions. For a\nrealistic test, each client should make an independent DNS request and distribute traffic across\nthe returned IP addresses, rather than pinning all load to a single IP. Spreading requests across\nthe returned set avoids biasing the test to one edge path and better represents how real browsers\nand applications resolve and connect to CloudFront.", "question_text": "A SysOps administrator must load test a new Amazon CloudFront distribution to assess data transfer and latency performance. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "D", "external_question_id": "Q0160"}', '{"tags": null, "topic": null, "options": [["A", "Send client requests from a single geographic region. Configure the load test so that each client makes an identical DNS request. Focus the client requests on the IP address that the DNS returns."], ["B", "Send client requests from a single geographic region. Configure the load test so that each client makes an independent DNS request. Spread the client requests across the set of IP addresses that the DNS returns."], ["C", "Send client requests from multiple geographic regions. Configure the load test so that each client makes an identical DNS request. Focus the client requests on the IP address that the DNS returns."], ["D", "Send client requests from multiple geographic regions. Configure the load test so that each client makes an independent DNS request. Spread the client requests across the set of IP addresses that the DNS returns."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0160"}, "reference": null, "difficulty": "medium", "explanation": "CloudFront is a global edge network service, and its performance (latency and data transfer\nbehavior) depends heavily on the geographic location of viewers and the edge locations that\nserve them. Therefore, a valid load test must generate traffic from multiple geographic regions to\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com\nreflect real user distribution and to measure end-to-end latency across diverse network paths.\nAdditionally, CloudFront uses DNS to return multiple possible edge IP addresses and can direct\nclients to different edge locations based on resolver behavior and network conditions. For a\nrealistic test, each client should make an independent DNS request and distribute traffic across\nthe returned IP addresses, rather than pinning all load to a single IP. Spreading requests across\nthe returned set avoids biasing the test to one edge path and better represents how real browsers\nand applications resolve and connect to CloudFront.", "question_text": "A SysOps administrator must load test a new Amazon CloudFront distribution to assess data transfer and latency performance. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["D"]}', 'imported', NULL, NULL, '9d6ee329cd11fe39fae62fb442ffbae419d39e6468e6ddca1a91a56d449a941a', 1508, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (995, 146, 162, 'qblock_pdf', '{"option_a": "Implement a tag policy for the company''s organization to require users to set the ApprovedAMI tag to launch new EC2 instances.", "option_b": "Implement an IAM policy that includes an aws:ResourceTag/ApprovedAMI condition.", "option_c": "Set up an AWS Config required-tags rule to prevent users from launching any nonapproved AMIs.", "option_d": "Use Amazon GuardDuty to constantly monitor DefenseEvasion:EC2/UnusualDoHActivity findings.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "To ensure users can launch instances only from approved AMIs, the control must be enforced at\nauthorization time, not after the fact. An IAM policy with a condition that evaluates the resource\ntags on the AMI is the correct method. By using an aws:ResourceTag/ApprovedAMI condition\n(paired with allowing ec2:RunInstances only when the chosen AMI has the required tag/value),\nthe organization can prevent launches from untagged or unapproved images. This implements\npreventative control and aligns with least privilege.", "question_text": "A company uses AWS Organizations to manage its AWS environment. The company implements a process that uses prebuilt Amazon Machine Images (AMIs) to launch instances as a security measure. All AMIs are tagged automatically with a key named ApprovedAMI. The company wants to ensure that employees can use only the approved prebuilt AMIs to launch new instances. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0161"}', '{"tags": null, "topic": null, "options": [["A", "Implement a tag policy for the company''s organization to require users to set the ApprovedAMI tag to launch new EC2 instances."], ["B", "Implement an IAM policy that includes an aws:ResourceTag/ApprovedAMI condition."], ["C", "Set up an AWS Config required-tags rule to prevent users from launching any nonapproved AMIs."], ["D", "Use Amazon GuardDuty to constantly monitor DefenseEvasion:EC2/UnusualDoHActivity findings."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0161"}, "reference": null, "difficulty": "medium", "explanation": "To ensure users can launch instances only from approved AMIs, the control must be enforced at\nauthorization time, not after the fact. An IAM policy with a condition that evaluates the resource\ntags on the AMI is the correct method. By using an aws:ResourceTag/ApprovedAMI condition\n(paired with allowing ec2:RunInstances only when the chosen AMI has the required tag/value),\nthe organization can prevent launches from untagged or unapproved images. This implements\npreventative control and aligns with least privilege.", "question_text": "A company uses AWS Organizations to manage its AWS environment. The company implements a process that uses prebuilt Amazon Machine Images (AMIs) to launch instances as a security measure. All AMIs are tagged automatically with a key named ApprovedAMI. The company wants to ensure that employees can use only the approved prebuilt AMIs to launch new instances. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, 'e367f1e2bc73ae58432fb42f6567b1e9aab1e0b7065ca15be7740f3746af47d3', 1509, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (996, 146, 163, 'qblock_pdf', '{"option_a": "Add a tag to the approved AMIs. Create an IAM policy that includes a tag condition that allows users to launch EC2 instances from only the tagged AMIs.", "option_b": "Create a service-linked role. Attach a policy that denies the ability to launch EC2 instances from a list of unapproved AMIs. Assign the role to users.", "option_c": "Use AWS Config with an AWS Lambda function to check for EC2 instances that are launched from unapproved AMIs. Program the Lambda function to send an Amazon Simple Notification Service (Amazon SNS) message to the SysOps administrator to terminate those EC2 instances.", "option_d": "Use AWS Trusted Advisor to check for EC2 instances that are launched from unapproved AMIs. Configure Trusted Advisor to invoke an AWS Lambda function to terminate those EC2 instances. Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The requirement is preventative: stop users from launching from unapproved AMIs. The most\nscalable approach with 75 approved AMIs is to tag all approved AMIs (for example,\nApprovedAMI=true) and enforce usage through an IAM policy condition that only allows\nec2:RunInstances when the ec2:ImageId resource (the AMI) includes the required tag. This\navoids maintaining long allow/deny lists of AMI IDs and supports continuous updates: as new\napproved AMIs are created, tagging them automatically brings them under the policy without\npolicy rewrites.", "question_text": "A company maintains a list of 75 approved Amazon Machine Images (AMIs) that can be used across an organization in AWS Organizations. The company''s development team has been launching Amazon EC2 instances from unapproved AMIs. A SysOps administrator must prevent users from launching EC2 instances from unapproved AMIs. Which solution will meet this requirement?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0162"}', '{"tags": null, "topic": null, "options": [["A", "Add a tag to the approved AMIs. Create an IAM policy that includes a tag condition that allows users to launch EC2 instances from only the tagged AMIs."], ["B", "Create a service-linked role. Attach a policy that denies the ability to launch EC2 instances from a list of unapproved AMIs. Assign the role to users."], ["C", "Use AWS Config with an AWS Lambda function to check for EC2 instances that are launched from unapproved AMIs. Program the Lambda function to send an Amazon Simple Notification Service (Amazon SNS) message to the SysOps administrator to terminate those EC2 instances."], ["D", "Use AWS Trusted Advisor to check for EC2 instances that are launched from unapproved AMIs. Configure Trusted Advisor to invoke an AWS Lambda function to terminate those EC2 instances. Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0162"}, "reference": null, "difficulty": "medium", "explanation": "The requirement is preventative: stop users from launching from unapproved AMIs. The most\nscalable approach with 75 approved AMIs is to tag all approved AMIs (for example,\nApprovedAMI=true) and enforce usage through an IAM policy condition that only allows\nec2:RunInstances when the ec2:ImageId resource (the AMI) includes the required tag. This\navoids maintaining long allow/deny lists of AMI IDs and supports continuous updates: as new\napproved AMIs are created, tagging them automatically brings them under the policy without\npolicy rewrites.", "question_text": "A company maintains a list of 75 approved Amazon Machine Images (AMIs) that can be used across an organization in AWS Organizations. The company''s development team has been launching Amazon EC2 instances from unapproved AMIs. A SysOps administrator must prevent users from launching EC2 instances from unapproved AMIs. Which solution will meet this requirement?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'd95814cb88b90082a53d1f979fc87c89e6c8f327af78033f6d84f7f7e01a854e', 1510, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (997, 146, 164, 'qblock_pdf', '{"option_a": "Create an Amazon CloudWatch alarm that uses the ConsumedReadCapacityUnits metric. Set the alarm threshold to a value that is close to the DynamoDB table''s provisioned capacity. Configure the alarm to publish notifications to the SNS topic.", "option_b": "Turn on auto scaling on the DynamoDB table. Configure an Amazon EventBridge rule to publish notifications to the SNS topic during scaling events.", "option_c": "Turn on Amazon CloudWatch Logs for the DynamoDB table. Create an Amazon CloudWatch metric filter to pattern match the THROTTLING_EXCEPTION status code from DynamoDB. Create a CloudWatch alarm for the metric. Select the SNS topic for notifications.", "option_d": "Configure the application to store logs in Amazon CloudWatch Logs. Create an Amazon CloudWatch metric filter to pattern match the THROTTLING_EXCEPTION status code from DynamoDB. Create a CloudWatch alarm for the metric. Select the SNS topic for notifications.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The requirement is to alert before throttling occurs. For a DynamoDB table in provisioned\ncapacity mode, throttling happens when demand approaches or exceeds provisioned throughput.\nCloudWatch provides direct table metrics such as ConsumedReadCapacityUnits and\nProvisionedReadCapacityUnits (and related utilization signals). Creating an alarm on\nConsumedReadCapacityUnits with a threshold set close to the table''s provisioned read capacity\nprovides an early warning that the table is nearing its limit--before actual throttling prevents reads.\nThe alarm can publish directly to the existing SNS topic so the operations team is notified\nproactively.", "question_text": "A media company hosts a public news and video portal on AWS. The portal uses an Amazon DynamoDB table with provisioned capacity to maintain an index of video files that are stored in an Amazon S3 bucket. During a recent event, millions of visitors came to the portal for news. This increase in traffic caused read requests to be throttled in the DynamoDB table. Videos could not be displayed in the portal. The company''s operations team manually increased the provisioned capacity on a temporary basis to meet the demand. The company wants the operations team to receive an alert before the table is throttled in the future. The company has created an Amazon Simple Notification Service (Amazon SNS) topic and has subscribed the operations team''s email address to the SNS topic. What should the company do next to meet these requirements?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0163"}', '{"tags": null, "topic": null, "options": [["A", "Create an Amazon CloudWatch alarm that uses the ConsumedReadCapacityUnits metric. Set the alarm threshold to a value that is close to the DynamoDB table''s provisioned capacity. Configure the alarm to publish notifications to the SNS topic."], ["B", "Turn on auto scaling on the DynamoDB table. Configure an Amazon EventBridge rule to publish notifications to the SNS topic during scaling events."], ["C", "Turn on Amazon CloudWatch Logs for the DynamoDB table. Create an Amazon CloudWatch metric filter to pattern match the THROTTLING_EXCEPTION status code from DynamoDB. Create a CloudWatch alarm for the metric. Select the SNS topic for notifications."], ["D", "Configure the application to store logs in Amazon CloudWatch Logs. Create an Amazon CloudWatch metric filter to pattern match the THROTTLING_EXCEPTION status code from DynamoDB. Create a CloudWatch alarm for the metric. Select the SNS topic for notifications."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0163"}, "reference": null, "difficulty": "medium", "explanation": "The requirement is to alert before throttling occurs. For a DynamoDB table in provisioned\ncapacity mode, throttling happens when demand approaches or exceeds provisioned throughput.\nCloudWatch provides direct table metrics such as ConsumedReadCapacityUnits and\nProvisionedReadCapacityUnits (and related utilization signals). Creating an alarm on\nConsumedReadCapacityUnits with a threshold set close to the table''s provisioned read capacity\nprovides an early warning that the table is nearing its limit--before actual throttling prevents reads.\nThe alarm can publish directly to the existing SNS topic so the operations team is notified\nproactively.", "question_text": "A media company hosts a public news and video portal on AWS. The portal uses an Amazon DynamoDB table with provisioned capacity to maintain an index of video files that are stored in an Amazon S3 bucket. During a recent event, millions of visitors came to the portal for news. This increase in traffic caused read requests to be throttled in the DynamoDB table. Videos could not be displayed in the portal. The company''s operations team manually increased the provisioned capacity on a temporary basis to meet the demand. The company wants the operations team to receive an alert before the table is throttled in the future. The company has created an Amazon Simple Notification Service (Amazon SNS) topic and has subscribed the operations team''s email address to the SNS topic. What should the company do next to meet these requirements?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, '1b3b6a9f8c20998b084854601f4a0f9bdd5607ca73a4bd56bab1ee596491a802', 1511, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (998, 146, 165, 'qblock_pdf', '{"option_a": "Attach the certificate to each EC2 instance.", "option_b": "Attach the certificate to the ALB.", "option_c": "Create a private certificate in AWS Certificate Manager (ACM).", "option_d": "Create a public certificate in AWS Certificate Manager (ACM).", "option_e": "Export the certificate, and attach it to the website.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "To secure inbound web traffic over HTTPS when using an Application Load Balancer, AWS\nCloudOps best practices recommend terminating TLS at the load balancer. This is achieved by\nattaching an SSL/TLS certificate directly to the ALB listener. Therefore, option B is required. By\nterminating HTTPS at the ALB, traffic between clients and the load balancer is encrypted, and the\nALB can then forward traffic to backend EC2 instances using HTTP or HTTPS based on design\nrequirements.\nThe certificate used for a public-facing retail website must be trusted by internet browsers. AWS\nCertificate Manager (ACM) public certificates are specifically designed for this purpose and are\ntrusted by common browsers and operating systems. Therefore, option D is required. ACM\nmanages certificate provisioning, renewal, and deployment automatically, which significantly\nreduces operational overhead.", "question_text": "A company runs a retail website on multiple Amazon EC2 instances behind an Application Load Balancer (ALB). The company must secure traffic to the website over an HTTPS connection. Which combination of actions should a SysOps administrator take to meet these requirements? Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com (Choose two.)", "source_format": "qblock_pdf", "correct_answer": "BD", "external_question_id": "Q0164"}', '{"tags": null, "topic": null, "options": [["A", "Attach the certificate to each EC2 instance."], ["B", "Attach the certificate to the ALB."], ["C", "Create a private certificate in AWS Certificate Manager (ACM)."], ["D", "Create a public certificate in AWS Certificate Manager (ACM)."], ["E", "Export the certificate, and attach it to the website."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0164"}, "reference": null, "difficulty": "medium", "explanation": "To secure inbound web traffic over HTTPS when using an Application Load Balancer, AWS\nCloudOps best practices recommend terminating TLS at the load balancer. This is achieved by\nattaching an SSL/TLS certificate directly to the ALB listener. Therefore, option B is required. By\nterminating HTTPS at the ALB, traffic between clients and the load balancer is encrypted, and the\nALB can then forward traffic to backend EC2 instances using HTTP or HTTPS based on design\nrequirements.\nThe certificate used for a public-facing retail website must be trusted by internet browsers. AWS\nCertificate Manager (ACM) public certificates are specifically designed for this purpose and are\ntrusted by common browsers and operating systems. Therefore, option D is required. ACM\nmanages certificate provisioning, renewal, and deployment automatically, which significantly\nreduces operational overhead.", "question_text": "A company runs a retail website on multiple Amazon EC2 instances behind an Application Load Balancer (ALB). The company must secure traffic to the website over an HTTPS connection. Which combination of actions should a SysOps administrator take to meet these requirements? Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com (Choose two.)", "question_type": "multiple", "correct_answer": ["B", "D"]}', 'imported', NULL, NULL, 'ee79733c4c8d760d28fcb53f965a2baeb842b0c7690bd322a1a926384d51f4b0', 1512, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (999, 146, 166, 'qblock_pdf', '{"option_a": "Increase the read capacity units (RCUs) and the write capacity units (WCUs) on the database.", "option_b": "Configure RDS Proxy. Update the application with the RDS Proxy endpoint.", "option_c": "Turn on enhanced networking for the DB instances.", "option_d": "Modify the DB cluster to use a burstable instance type.", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "The correct solution is B. Configure RDS Proxy, because RDS Proxy is specifically designed to\nmanage and pool database connections for Amazon Aurora and Amazon RDS. AWS CloudOps\ndocumentation states that RDS Proxy reduces database load and prevents connection\nexhaustion by reusing existing connections and managing spikes in application demand.\nIn this scenario, the ecommerce application maintains many idle connections, which consume\ndatabase connection slots even when not actively used. During peak traffic, new connections\ncannot be established, resulting in the \"Too many connections\" error. RDS Proxy sits between\nthe application and the Aurora DB cluster, maintaining a smaller, efficient pool of database\nconnections and multiplexing application requests over those connections.", "question_text": "A company is running an ecommerce application on AWS. The application maintains many open but idle connections to an Amazon Aurora DB cluster. During times of peak usage, the database produces the following error message: \"Too many connections.\" The database clients are also experiencing errors. Which solution will resolve these errors?", "source_format": "qblock_pdf", "correct_answer": "B", "external_question_id": "Q0165"}', '{"tags": null, "topic": null, "options": [["A", "Increase the read capacity units (RCUs) and the write capacity units (WCUs) on the database."], ["B", "Configure RDS Proxy. Update the application with the RDS Proxy endpoint."], ["C", "Turn on enhanced networking for the DB instances."], ["D", "Modify the DB cluster to use a burstable instance type."]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0165"}, "reference": null, "difficulty": "medium", "explanation": "The correct solution is B. Configure RDS Proxy, because RDS Proxy is specifically designed to\nmanage and pool database connections for Amazon Aurora and Amazon RDS. AWS CloudOps\ndocumentation states that RDS Proxy reduces database load and prevents connection\nexhaustion by reusing existing connections and managing spikes in application demand.\nIn this scenario, the ecommerce application maintains many idle connections, which consume\ndatabase connection slots even when not actively used. During peak traffic, new connections\ncannot be established, resulting in the \"Too many connections\" error. RDS Proxy sits between\nthe application and the Aurora DB cluster, maintaining a smaller, efficient pool of database\nconnections and multiplexing application requests over those connections.", "question_text": "A company is running an ecommerce application on AWS. The application maintains many open but idle connections to an Amazon Aurora DB cluster. During times of peak usage, the database produces the following error message: \"Too many connections.\" The database clients are also experiencing errors. Which solution will resolve these errors?", "question_type": "single", "correct_answer": ["B"]}', 'imported', NULL, NULL, '4c58135b9ef233248f5b25ae61b310222dff8df991b350fe4867e5863520ca79', 1513, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
INSERT INTO public.import_items (id, import_id, row_number, sheet_name, raw_data, normalized_data, status, error_message, warning_message, content_hash, question_id, created_at, updated_at) VALUES (1000, 146, 167, 'qblock_pdf', '{"option_a": "Copy the AMI to the additional Regions", "option_b": "Make the AMI public in the Community AMIs section of the AWS Management Console", "option_c": "Share the AMI to the additional Regions. Assign the required access permissions.", "option_d": "Copy the AMI to a new Amazon S3 bucket. Assign access permissions to the AMI for the additional Regions", "source_url": "/srv/exam-platform/uploads/imports/146.pdf", "explanation": "Amazon Machine Images (AMIs) are Region-specific resources. AWS CloudOps documentation\nexplicitly states that an AMI created in one Region cannot be used to launch instances in another\nRegion unless it is copied to the target Region. Therefore, the SysOps administrator must copy\nthe AMI to both us-east-1 and us-east-2.\nThe AMI copy process creates a new AMI in each destination Region and automatically copies\nthe underlying snapshots. Once the AMIs exist in the target Regions, they can be referenced in\nlaunch templates, Auto Scaling groups, or AWS CloudFormation templates for consistent multi-\nRegion deployments.\nGet Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A SysOps administrator creates a custom Amazon Machine Image (AMI) in the eu-west-2 Region and uses the AMI to launch Amazon EC2 instances. The SysOps administrator needs to use the Get Latest & Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com same AMI to launch EC2 instances in two other Regions: us-east-1 and us-east-2. What must the SysOps administrator do to use the custom AMI in the additional Regions?", "source_format": "qblock_pdf", "correct_answer": "A", "external_question_id": "Q0166"}', '{"tags": null, "topic": null, "options": [["A", "Copy the AMI to the additional Regions"], ["B", "Make the AMI public in the Community AMIs section of the AWS Management Console"], ["C", "Share the AMI to the additional Regions. Assign the required access permissions."], ["D", "Copy the AMI to a new Amazon S3 bucket. Assign access permissions to the AMI for the additional Regions"]], "community": {"discussion_url": null, "discussion_count": null, "vote_distribution": null, "external_question_id": "Q0166"}, "reference": null, "difficulty": "medium", "explanation": "Amazon Machine Images (AMIs) are Region-specific resources. AWS CloudOps documentation\nexplicitly states that an AMI created in one Region cannot be used to launch instances in another\nRegion unless it is copied to the target Region. Therefore, the SysOps administrator must copy\nthe AMI to both us-east-1 and us-east-2.\nThe AMI copy process creates a new AMI in each destination Region and automatically copies\nthe underlying snapshots. Once the AMIs exist in the target Regions, they can be referenced in\nlaunch templates, Auto Scaling groups, or AWS CloudFormation templates for consistent multi-\nRegion deployments.\nGet Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader.\nhttps://www.passleader.com", "question_text": "A SysOps administrator creates a custom Amazon Machine Image (AMI) in the eu-west-2 Region and uses the AMI to launch Amazon EC2 instances. The SysOps administrator needs to use the Get Latest &amp; Actual SOA-C03 Exam''s Question and Answers from Passleader. https://www.passleader.com same AMI to launch EC2 instances in two other Regions: us-east-1 and us-east-2. What must the SysOps administrator do to use the custom AMI in the additional Regions?", "question_type": "single", "correct_answer": ["A"]}', 'imported', NULL, NULL, 'd729ff48b04334c42fc86f27ea940d53fa2ba23ad28a0d096ff707d7c909a3d1', 1514, '2026-05-04 15:49:16.257521+00', '2026-05-04 15:49:23.153851+00');
